type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'STOCK' | 'ASSETS';

const COLORS = ['#db2777', '#4f46e5', '#10b981', '#f59e0b', '#6366f1', '#ec4899'];

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    setNotifications,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);
  const [isMaxRange, setIsMaxRange] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [txFilter, setTxFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE' | 'PENDING'>('ALL');

  // IA Insights
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // --- TRANSAÇÕES STATES ---
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({ type: 'EXPENSE', amount: 0, isRecurring: false });
  const [installmentCount, setInstallmentCount] = useState(1);

  // --- ESTOQUE & ATIVOS (STATES MANTIDOS) ---
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [stockModalMode, setStockModalMode] = useState<'EDIT' | 'CREATE' | 'RESTOCK'>('CREATE');
  const [editingStockItem, setEditingStockItem] = useState<Partial<StockItem>>({});
  const [restockQuantity, setRestockQuantity] = useState(0);

  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({});

  // --- CÁLCULOS DASHBOARD ---
  const financialStats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const filtered = transactions.filter(t => isMaxRange || (t.dueDate >= startDate && t.dueDate <= endDate));

    const incomeRealized = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);
    const expenseRealized = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);

    const incomeProjected = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);
    const expenseProjected = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);

    const accountsPayableToday = transactions.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);
    const accountsReceivableToday = transactions.filter(t => t.type === 'INCOME' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);

    return { 
        realizedBalance: incomeRealized - expenseRealized, 
        projectedBalance: (incomeRealized + incomeProjected) - (expenseRealized + expenseProjected), 
        incomeRealized, expenseRealized,
        incomeProjected, expenseProjected,
        apToday: accountsPayableToday,
        arToday: accountsReceivableToday
    };
  }, [transactions, startDate, endDate, isMaxRange]);

  const handleSaveTx = () => {
    if (!editingTx.description || !editingTx.amount || !editingTx.dueDate) return;

    const groupId = `group-${Date.now()}`;
    const newRecords: FinancialRecord[] = [];

    if (installmentCount > 1) {
        // Lançamento Parcelado
        const baseDate = new Date(editingTx.dueDate);
        for (let i = 1; i <= installmentCount; i++) {
            const dueDate = new Date(baseDate);
            dueDate.setMonth(baseDate.getMonth() + (i - 1));

            newRecords.push({
                ...editingTx,
                id: `tx-${Date.now()}-${i}`,
                status: 'PENDING',
                dueDate: dueDate.toISOString().split('T')[0],
                installment: {
                    current: i,
                    total: installmentCount,
                    groupId
                }
            } as FinancialRecord);
        }
    } else {
        // Lançamento Único
        newRecords.push({
            ...editingTx,
            id: `tx-${Date.now()}`,
            status: 'PENDING'
        } as FinancialRecord);
    }

