              <button onClick={() => setActiveTab('TRANSACTIONS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'TRANSACTIONS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><FileText size={14}/> Fluxo de Caixa</button>
              <button onClick={() => setActiveTab('STOCK')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'STOCK' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Box size={14}/> Estoque</button>
              <button onClick={() => setActiveTab('ASSETS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'ASSETS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><HardDrive size={14}/> Patrimônio</button>
          </div>

          <div className="flex items-center gap-2 bg-white p-2 rounded-xl border shadow-sm">
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
              <span className="text-slate-300">|</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
          </div>
      </div>

      <div className="min-h-[500px]">
          {activeTab === 'DASHBOARD' && renderDashboard()}
          {activeTab === 'TRANSACTIONS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4">
                      <div className="flex gap-2">
                          {['ALL', 'INCOME', 'EXPENSE', 'PENDING'].map(f => (
                              <button key={f} onClick={() => setTxFilter(f as any)} className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase border transition-all ${txFilter === f ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400'}`}>
                                  {f === 'ALL' ? 'Todos' : f === 'INCOME' ? 'Receitas' : f === 'EXPENSE' ? 'Despesas' : 'Pendentes'}
                              </button>
                          ))}
                      </div>
                      <button onClick={() => { setEditingTx({ type: 'EXPENSE', dueDate: new Date().toISOString().split('T')[0], amount: 0, isRecurring: false }); setIsTxModalOpen(true); }} className="bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg shadow-pink-500/20"><Plus size={14}/> Novo Lançamento</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {transactions
                                .filter(t => {
                                    if (txFilter === 'ALL') return true;
                                    if (txFilter === 'PENDING') return t.status === 'PENDING';
                                    return t.type === txFilter;
                                })
                                .filter(t => t.description.toLowerCase().includes(searchTerm.toLowerCase()))
                                .map(t => (
                                <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                    <td className="p-4 font-medium text-slate-400">
                                        <div className="flex flex-col">
                                            <span>{t.dueDate.split('-').reverse().join('/')}</span>
                                            {t.isRecurring && <span className="text-[9px] text-indigo-500 font-black uppercase flex items-center gap-0.5"><Repeat size={8}/> Recorrente</span>}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <p className="font-bold text-slate-800">{t.description}</p>
                                        {t.installment && (
                                            <p className="text-[10px] text-slate-400 font-bold uppercase">Parcela {t.installment.current}/{t.installment.total}</p>
                                        )}
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-red-50 text-red-600 border border-red-100'}`}>
                                            {t.type === 'INCOME' ? 'Receita' : 'Despesa'}
                                        </span>
                                    </td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600 animate-pulse'}`}>{t.status === 'PAID' ? 'Liquidado' : 'Pendente'}</span></td>
                                    <td className={`p-4 text-right font-black ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className={`p-1.5 rounded-lg ${t.status === 'PAID' ? 'text-amber-500 hover:bg-amber-50' : 'text-emerald-500 hover:bg-emerald-50'}`} title="Alternar Liquidação"><CheckCircle size={16}/></button>
                                            <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}
          {activeTab === 'STOCK' && (
              <div className="animate-pop text-center p-20 bg-white rounded-2xl border border-dashed border-slate-200">
                  <Package size={48} className="mx-auto text-slate-300 mb-4"/>
                  <h3 className="font-bold text-slate-500">Módulo de Estoque Ativo</h3>
                  <p className="text-sm text-slate-400 mt-1">Nenhuma alteração necessária nesta área.</p>
              </div>
          )}
          {activeTab === 'ASSETS' && (
              <div className="animate-pop text-center p-20 bg-white rounded-2xl border border-dashed border-slate-200">
                  <HardDrive size={48} className="mx-auto text-slate-300 mb-4"/>
                  <h3 className="font-bold text-slate-500">Módulo de Patrimônio Ativo</h3>
                  <p className="text-sm text-slate-400 mt-1">Nenhuma alteração necessária nesta área.</p>
              </div>
          )}
      </div>

      {/* MODAL TRANSAÇÃO MELHORADO (PARCELADO / RECORRENTE) */}
      {isTxModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 flex items-center justify-between text-white ${editingTx.type === 'INCOME' ? 'bg-emerald-600' : 'bg-slate-900'}`}>
                      <div className="flex items-center gap-3">
                        <CreditCard size={24}/>
                        <h3 className="text-xl font-black uppercase tracking-tighter">Novo Lançamento</h3>
                      </div>
                      <button onClick={() => setIsTxModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                           <button onClick={() => setEditingTx({...editingTx, type: 'INCOME'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}>Receita (+)</button>
                           <button onClick={() => setEditingTx({...editingTx, type: 'EXPENSE'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-400'}`}>Despesa (-)</button>
                      </div>

                      <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Descrição do Lançamento</label>
                            <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none font-bold bg-slate-50 transition-all focus:bg-white" placeholder="Ex: Adobe Creative Cloud, Pagamento Cliente X..." value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Valor R$</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-lg font-black outline-none bg-slate-50 focus:bg-white" placeholder="0.00" value={editingTx.amount || ''} onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Data de Vencimento</label>
                                <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 focus:bg-white outline-none" value={editingTx.dueDate || ''} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                            </div>
                        </div>

                        <div className="pt-4 border-t border-slate-50 space-y-4">
                            <div className="flex items-center justify-between bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><Repeat size={16}/></div>
                                    <div>
                                        <p className="text-xs font-bold text-slate-700">Lançamento Recorrente</p>
                                        <p className="text-[9px] text-slate-400 uppercase">Repete mensalmente</p>
                                    </div>
                                </div>
                                <div onClick={() => setEditingTx({...editingTx, isRecurring: !editingTx.isRecurring})} className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${editingTx.isRecurring ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                                    <div className={`w-4 h-4 bg-white rounded-full transition-transform ${editingTx.isRecurring ? 'translate-x-6' : 'translate-x-0'}`}></div>
                                </div>
                            </div>

                            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-pink-100 text-pink-600 rounded-lg"><CreditCard size={16}/></div>
                                        <div>
                                            <p className="text-xs font-bold text-slate-700">Parcelamento</p>
                                            <p className="text-[9px] text-slate-400 uppercase">Gerar várias faturas</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => setInstallmentCount(Math.max(1, installmentCount - 1))} className="w-8 h-8 rounded-lg bg-white border flex items-center justify-center text-slate-400 hover:text-pink-600">-</button>
                                        <span className="w-8 text-center font-black text-sm">{installmentCount}x</span>
                                        <button onClick={() => setInstallmentCount(installmentCount + 1)} className="w-8 h-8 rounded-lg bg-white border flex items-center justify-center text-slate-400 hover:text-pink-600">+</button>
                                    </div>
                                </div>
                                {installmentCount > 1 && (
                                    <p className="text-[10px] text-pink-600 font-bold uppercase text-center bg-pink-50 p-2 rounded-lg">Serão gerados {installmentCount} lançamentos de R$ {(editingTx.amount || 0).toLocaleString()} mensais.</p>
                                )}
                            </div>
                        </div>
                      </div>

                      <button onClick={handleSaveTx} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                          <CheckCircle size={20}/> Gravar no Financeiro
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { FinancialRecord, Asset, StockItem, User, Notification, ConfirmOptions } from '../types';
import { initialStock } from '../utils/mockData';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell } from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Settings, Box, HardDrive, 
    ShieldCheck, BarChart3, Wallet, Scale, CheckCircle, RefreshCcw, ShoppingCart, Ban, 
    AlertCircle, Sparkles, Repeat, CreditCard, ChevronRight, Clock, Info,
    ArrowDownLeft, ArrowUpRight, X
} from 'lucide-react';
import { analyzeFinancialHealth } from '../services/aiService';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'STOCK' | 'ASSETS';

const COLORS = ['#db2777', '#4f46e5', '#10b981', '#f59e0b', '#6366f1', '#ec4899'];

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    setNotifications,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);
  const [isMaxRange, setIsMaxRange] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [txFilter, setTxFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE' | 'PENDING'>('ALL');

  // IA Insights
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // --- TRANSAÇÕES STATES ---
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({ type: 'EXPENSE', amount: 0, isRecurring: false });
  const [installmentCount, setInstallmentCount] = useState(1);

  // --- ESTOQUE & ATIVOS (STATES MANTIDOS) ---
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [stockModalMode, setStockModalMode] = useState<'EDIT' | 'CREATE' | 'RESTOCK'>('CREATE');
  const [editingStockItem, setEditingStockItem] = useState<Partial<StockItem>>({});
  const [restockQuantity, setRestockQuantity] = useState(0);

  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({});

  // --- CÁLCULOS DASHBOARD ---
  const financialStats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const filtered = transactions.filter(t => isMaxRange || (t.dueDate >= startDate && t.dueDate <= endDate));

    const incomeRealized = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);
    const expenseRealized = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);

    const incomeProjected = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);
    const expenseProjected = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);

    const accountsPayableToday = transactions.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);
    const accountsReceivableToday = transactions.filter(t => t.type === 'INCOME' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);

    return { 
        realizedBalance: incomeRealized - expenseRealized, 
        projectedBalance: (incomeRealized + incomeProjected) - (expenseRealized + expenseProjected), 
        incomeRealized, expenseRealized,
        incomeProjected, expenseProjected,
        apToday: accountsPayableToday,
        arToday: accountsReceivableToday
    };
  }, [transactions, startDate, endDate, isMaxRange]);

  const handleSaveTx = () => {
    if (!editingTx.description || !editingTx.amount || !editingTx.dueDate) return;

    const groupId = `group-${Date.now()}`;
    const newRecords: FinancialRecord[] = [];

    if (installmentCount > 1) {
        // Lançamento Parcelado
        const baseDate = new Date(editingTx.dueDate);
        for (let i = 1; i <= installmentCount; i++) {
            const dueDate = new Date(baseDate);
            dueDate.setMonth(baseDate.getMonth() + (i - 1));

            newRecords.push({
                ...editingTx,
                id: `tx-${Date.now()}-${i}`,
                status: 'PENDING',
                dueDate: dueDate.toISOString().split('T')[0],
                installment: {
                    current: i,
                    total: installmentCount,
                    groupId
                }
            } as FinancialRecord);
        }
    } else {
        // Lançamento Único
        newRecords.push({
            ...editingTx,
            id: `tx-${Date.now()}`,
            status: 'PENDING'
        } as FinancialRecord);
    }

    setTransactions(prev => [...newRecords, ...prev]);
    setIsTxModalOpen(false);
    setInstallmentCount(1);
    setEditingTx({ type: 'EXPENSE', amount: 0, isRecurring: false });
  };

  const handleGetAiInsight = async () => {
      setAiLoading(true);
      const insight = await analyzeFinancialHealth(transactions);
      setAiInsight(insight);
      setAiLoading(false);
  };

  const renderDashboard = () => (
      <div className="space-y-6 animate-pop">
          {/* Radar de Liquidez */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Realizado (Caixa)</p>
                  <h3 className={`text-2xl font-black mt-2 ${financialStats.realizedBalance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {financialStats.realizedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold">
                      <span className="text-emerald-600">+ R$ {financialStats.incomeRealized.toLocaleString()}</span>
                      <span className="text-slate-300">|</span>
                      <span className="text-red-600">- R$ {financialStats.expenseRealized.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                  <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção 30 Dias</p>
                  <h3 className="text-2xl font-black mt-2">R$ {financialStats.projectedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold opacity-80">
                      <span className="text-emerald-400">Previsto: + R$ {financialStats.incomeProjected.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-red-100 shadow-sm">
                  {/* Added missing ArrowDownLeft icon */}
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest flex items-center gap-1"><ArrowDownLeft size={12}/> Contas a Pagar (Hoje)</p>
                  <h3 className="text-2xl font-black text-red-600 mt-2">R$ {financialStats.apToday.toLocaleString()}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Aguardando Liquidação</p>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-emerald-100 shadow-sm">
                  {/* Added missing ArrowUpRight icon */}
                  <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-1"><ArrowUpRight size={12}/> Contas a Receber (Hoje)</p>
                  <h3 className="text-2xl font-black text-emerald-600 mt-2">R$ {financialStats.arToday.toLocaleString()}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Previsto para hoje</p>
              </div>
          </div>

          {/* AI Advisor Banner */}
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-6 rounded-2xl text-white shadow-lg flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-4">
                  <div className="p-3 bg-white/20 rounded-xl"><Sparkles size={24}/></div>
                  <div>
                      <h4 className="font-bold text-lg">Consultoria Financeira IA</h4>
                      <p className="text-indigo-100 text-sm">Receba diagnósticos preditivos baseados no seu fluxo de caixa.</p>
                  </div>
              </div>
              <button 
                onClick={handleGetAiInsight}
                disabled={aiLoading}
                className="bg-white text-indigo-600 px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-2"
              >
                  {aiLoading ? <RefreshCcw size={16} className="animate-spin"/> : <Sparkles size={16}/>}
                  {aiInsight ? 'Atualizar Análise' : 'Analisar Saúde Financeira'}
              </button>
          </div>

          {aiInsight && (
              <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl animate-pop">
                  <div className="flex items-center gap-2 mb-4 text-indigo-700 font-black text-xs uppercase tracking-widest">
                      <Info size={16}/> Insight Estratégico
                  </div>
                  <div className="prose prose-sm text-indigo-900 max-w-none" dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>') }} />
              </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                  <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2"><TrendingUp size={16} className="text-pink-600"/> Histórico vs. Projeção</h3>
                  <div className="h-64">
                      <ResponsiveContainer width="100%" height="100%">
                          <AreaChart data={transactions.slice(0, 15).reverse()}>
                              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                              <XAxis dataKey="dueDate" hide />
                              <YAxis axisLine={false} tickLine={false} fontSize={10} stroke="#94a3b8" />
                              <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                              <Area type="monotone" dataKey="amount" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.1} strokeWidth={3} />
                          </AreaChart>
                      </ResponsiveContainer>
                  </div>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
                  <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2"><Clock size={16} className="text-indigo-600"/> Próximos Vencimentos</h3>
                  <div className="space-y-3 flex-1 overflow-y-auto max-h-[250px] pr-2 custom-scrollbar">
                      {transactions.filter(t => t.status === 'PENDING').slice(0, 5).map(t => (
                          <div key={t.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                              <div className="flex items-center gap-3">
                                  <div className={`p-2 rounded-lg ${t.type === 'EXPENSE' ? 'bg-red-50 text-red-500' : 'bg-emerald-50 text-emerald-500'}`}>
                                      {/* Added missing ArrowDownLeft and ArrowUpRight icons */}
                                      {t.type === 'EXPENSE' ? <ArrowDownLeft size={16}/> : <ArrowUpRight size={16}/>}
                                  </div>
                                  <div>
                                      <p className="text-sm font-bold text-slate-800 line-clamp-1">{t.description}</p>
                                      <p className="text-[10px] text-slate-400 font-bold uppercase">{t.dueDate.split('-').reverse().join('/')}</p>
                                  </div>
                              </div>
                              <p className={`font-black text-sm ${t.type === 'EXPENSE' ? 'text-red-600' : 'text-emerald-600'}`}>R$ {t.amount.toLocaleString()}</p>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-end md:items-center gap-4">
          <div className="flex flex-wrap bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-fit">
              <button onClick={() => setActiveTab('DASHBOARD')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'DASHBOARD' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><TrendingUp size={14}/> Radar Financeiro</button>
              <button onClick={() => setActiveTab('TRANSACTIONS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'TRANSACTIONS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><FileText size={14}/> Fluxo de Caixa</button>
              <button onClick={() => setActiveTab('STOCK')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'STOCK' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Box size={14}/> Estoque</button>
              <button onClick={() => setActiveTab('ASSETS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'ASSETS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><HardDrive size={14}/> Patrimônio</button>
          </div>

          <div className="flex items-center gap-2 bg-white p-2 rounded-xl border shadow-sm">
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
              <span className="text-slate-300">|</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
          </div>
      </div>

      <div className="min-h-[500px]">
          {activeTab === 'DASHBOARD' && renderDashboard()}
          {activeTab === 'TRANSACTIONS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4">
                      <div className="flex gap-2">
                          {['ALL', 'INCOME', 'EXPENSE', 'PENDING'].map(f => (
                              <button key={f} onClick={() => setTxFilter(f as any)} className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase border transition-all ${txFilter === f ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400'}`}>
                                  {f === 'ALL' ? 'Todos' : f === 'INCOME' ? 'Receitas' : f === 'EXPENSE' ? 'Despesas' : 'Pendentes'}
                              </button>
                          ))}
                      </div>
                      <button onClick={() => { setEditingTx({ type: 'EXPENSE', dueDate: new Date().toISOString().split('T')[0], amount: 0, isRecurring: false }); setIsTxModalOpen(true); }} className="bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg shadow-pink-500/20"><Plus size={14}/> Novo Lançamento</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {transactions
                                .filter(t => {
                                    if (txFilter === 'ALL') return true;
                                    if (txFilter === 'PENDING') return t.status === 'PENDING';
                                    return t.type === txFilter;
                                })
                                .filter(t => t.description.toLowerCase().includes(searchTerm.toLowerCase()))
                                .map(t => (
                                <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                    <td className="p-4 font-medium text-slate-400">
                                        <div className="flex flex-col">
                                            <span>{t.dueDate.split('-').reverse().join('/')}</span>
                                            {t.isRecurring && <span className="text-[9px] text-indigo-500 font-black uppercase flex items-center gap-0.5"><Repeat size={8}/> Recorrente</span>}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <p className="font-bold text-slate-800">{t.description}</p>
                                        {t.installment && (
                                            <p className="text-[10px] text-slate-400 font-bold uppercase">Parcela {t.installment.current}/{t.installment.total}</p>
                                        )}
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-red-50 text-red-600 border border-red-100'}`}>
                                            {t.type === 'INCOME' ? 'Receita' : 'Despesa'}
                                        </span>
                                    </td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600 animate-pulse'}`}>{t.status === 'PAID' ? 'Liquidado' : 'Pendente'}</span></td>
                                    <td className={`p-4 text-right font-black ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className={`p-1.5 rounded-lg ${t.status === 'PAID' ? 'text-amber-500 hover:bg-amber-50' : 'text-emerald-500 hover:bg-emerald-50'}`} title="Alternar Liquidação"><CheckCircle size={16}/></button>
                                            <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}
          {activeTab === 'STOCK' && (
              <div className="animate-pop text-center p-20 bg-white rounded-2xl border border-dashed border-slate-200">
                  <Package size={48} className="mx-auto text-slate-300 mb-4"/>
                  <h3 className="font-bold text-slate-500">Módulo de Estoque Ativo</h3>
                  <p className="text-sm text-slate-400 mt-1">Nenhuma alteração necessária nesta área.</p>
              </div>
          )}
          {activeTab === 'ASSETS' && (
              <div className="animate-pop text-center p-20 bg-white rounded-2xl border border-dashed border-slate-200">
                  <HardDrive size={48} className="mx-auto text-slate-300 mb-4"/>
                  <h3 className="font-bold text-slate-500">Módulo de Patrimônio Ativo</h3>
                  <p className="text-sm text-slate-400 mt-1">Nenhuma alteração necessária nesta área.</p>
              </div>
          )}
      </div>

      {/* MODAL TRANSAÇÃO MELHORADO (PARCELADO / RECORRENTE) */}
      {isTxModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 flex items-center justify-between text-white ${editingTx.type === 'INCOME' ? 'bg-emerald-600' : 'bg-slate-900'}`}>
                      <div className="flex items-center gap-3">
                        <CreditCard size={24}/>
                        <h3 className="text-xl font-black uppercase tracking-tighter">Novo Lançamento</h3>
                      </div>
                      {/* Added missing X icon */}
                      <button onClick={() => setIsTxModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                           <button onClick={() => setEditingTx({...editingTx, type: 'INCOME'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}>Receita (+)</button>
                           <button onClick={() => setEditingTx({...editingTx, type: 'EXPENSE'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-400'}`}>Despesa (-)</button>
                      </div>

                      <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Descrição do Lançamento</label>
                            <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none font-bold bg-slate-50 transition-all focus:bg-white" placeholder="Ex: Adobe Creative Cloud, Pagamento Cliente X..." value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Valor R$</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-lg font-black outline-none bg-slate-50 focus:bg-white" placeholder="0.00" value={editingTx.amount || ''} onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 block">Data de Vencimento</label>
                                <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 focus:bg-white outline-none" value={editingTx.dueDate || ''} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                            </div>
                        </div>

                        <div className="pt-4 border-t border-slate-50 space-y-4">
                            <div className="flex items-center justify-between bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><Repeat size={16}/></div>
                                    <div>
                                        <p className="text-xs font-bold text-slate-700">Lançamento Recorrente</p>
                                        <p className="text-[9px] text-slate-400 uppercase">Repete mensalmente</p>
                                    </div>
                                </div>
                                <div onClick={() => setEditingTx({...editingTx, isRecurring: !editingTx.isRecurring})} className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${editingTx.isRecurring ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                                    <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${editingTx.isRecurring ? 'translate-x-6' : 'translate-x-0'}`}></div>
                                </div>
                            </div>

                            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-pink-100 text-pink-600 rounded-lg"><CreditCard size={16}/></div>
                                        <div>
                                            <p className="text-xs font-bold text-slate-700">Parcelamento</p>
                                            <p className="text-[9px] text-slate-400 uppercase">Gerar várias faturas</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => setInstallmentCount(Math.max(1, installmentCount - 1))} className="w-8 h-8 rounded-lg bg-white border flex items-center justify-center text-slate-400 hover:text-pink-600">-</button>
                                        <span className="w-8 text-center font-black text-sm">{installmentCount}x</span>
                                        <button onClick={() => setInstallmentCount(installmentCount + 1)} className="w-8 h-8 rounded-lg bg-white border flex items-center justify-center text-slate-400 hover:text-pink-600">+</button>
                                    </div>
                                </div>
                                {installmentCount > 1 && (
                                    <p className="text-[10px] text-pink-600 font-bold uppercase text-center bg-pink-50 p-2 rounded-lg">Serão gerados {installmentCount} lançamentos de R$ {(editingTx.amount || 0).toLocaleString()} mensais.</p>
                                )}
                            </div>
                        </div>
                      </div>

                      <button onClick={handleSaveTx} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                          <CheckCircle size={20}/> Gravar no Financeiro
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { FinancialRecord, Asset, StockItem, User, Notification, ConfirmOptions } from '../types';
import { initialStock } from '../utils/mockData';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell } from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Settings, Box, HardDrive, 
    ShieldCheck, BarChart3, Wallet, Scale, CheckCircle, RefreshCcw, ShoppingCart, Ban, 
    AlertCircle, Sparkles, Repeat, CreditCard, ChevronRight, Clock, Info,
    ArrowDownLeft, ArrowUpRight, X, ArrowUp
} from 'lucide-react';
import { analyzeFinancialHealth } from '../services/aiService';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    setNotifications,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);
  const [isMaxRange, setIsMaxRange] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [txFilter, setTxFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE' | 'PENDING'>('ALL');

  // IA Insights
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // --- TRANSAÇÕES STATES ---
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({ type: 'EXPENSE', amount: 0, isRecurring: false });
  const [installmentCount, setInstallmentCount] = useState(1);

  // --- ESTOQUE STATES ---
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStockItem, setEditingStockItem] = useState<Partial<StockItem>>({});
  const [restockMode, setRestockMode] = useState(false);

  // --- ATIVOS STATES ---
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({ type: 'HARDWARE', status: 'ACTIVE' });

  // --- CÁLCULOS DASHBOARD ---
  const financialStats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const filtered = transactions.filter(t => isMaxRange || (t.dueDate >= startDate && t.dueDate <= endDate));

    const incomeRealized = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);
    const expenseRealized = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);

    const incomeProjected = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);
    const expenseProjected = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);

    const accountsPayableToday = transactions.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);
    const accountsReceivableToday = transactions.filter(t => t.type === 'INCOME' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);

    return { 
        realizedBalance: incomeRealized - expenseRealized, 
        projectedBalance: (incomeRealized + incomeProjected) - (expenseRealized + expenseProjected), 
        incomeRealized, expenseRealized,
        incomeProjected, expenseProjected,
        apToday: accountsPayableToday,
        arToday: accountsReceivableToday
    };
  }, [transactions, startDate, endDate, isMaxRange]);

  const handleSaveTx = () => {
    if (!editingTx.description || !editingTx.amount || !editingTx.dueDate) return;

    const groupId = `group-${Date.now()}`;
    const newRecords: FinancialRecord[] = [];

    if (installmentCount > 1) {
        const baseDate = new Date(editingTx.dueDate);
        for (let i = 1; i <= installmentCount; i++) {
            const dueDate = new Date(baseDate);
            dueDate.setMonth(baseDate.getMonth() + (i - 1));
            newRecords.push({
                ...editingTx,
                id: `tx-${Date.now()}-${i}`,
                status: 'PENDING',
                dueDate: dueDate.toISOString().split('T')[0],
                installment: { current: i, total: installmentCount, groupId }
            } as FinancialRecord);
        }
    } else {
        newRecords.push({ ...editingTx, id: `tx-${Date.now()}`, status: 'PENDING' } as FinancialRecord);
    }

    setTransactions(prev => [...newRecords, ...prev]);
    setIsTxModalOpen(false);
    setInstallmentCount(1);
    setEditingTx({ type: 'EXPENSE', amount: 0, isRecurring: false });
  };

  const handleGetAiInsight = async () => {
      setAiLoading(true);
      const insight = await analyzeFinancialHealth(transactions);
      setAiInsight(insight);
      setAiLoading(false);
  };

  const handleSaveStock = () => {
      if (!editingStockItem.name || editingStockItem.quantity === undefined) return;
      if (editingStockItem.id) {
          setStock(prev => prev.map(s => s.id === editingStockItem.id ? { ...s, ...editingStockItem } as StockItem : s));
      } else {
          setStock(prev => [...prev, { ...editingStockItem, id: `stk-${Date.now()}`, lastRestock: new Date().toISOString().split('T')[0] } as StockItem]);
      }
      setIsStockModalOpen(false);
      setEditingStockItem({});
      setRestockMode(false);
  };

  const handleSaveAsset = () => {
      if (!editingAsset.name || !editingAsset.cost) return;
      if (editingAsset.id) {
          setAssets(prev => prev.map(a => a.id === editingAsset.id ? { ...a, ...editingAsset } as Asset : a));
      } else {
          setAssets(prev => [...prev, { ...editingAsset, id: `ast-${Date.now()}` } as Asset]);
      }
      setIsAssetModalOpen(false);
      setEditingAsset({ type: 'HARDWARE', status: 'ACTIVE' });
  };

  const renderDashboard = () => (
      <div className="space-y-6 animate-pop">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Realizado (Caixa)</p>
                  <h3 className={`text-2xl font-black mt-2 ${financialStats.realizedBalance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {financialStats.realizedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold">
                      <span className="text-emerald-600">+ R$ {financialStats.incomeRealized.toLocaleString()}</span>
                      <span className="text-slate-300">|</span>
                      <span className="text-red-600">- R$ {financialStats.expenseRealized.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                  <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção 30 Dias</p>
                  <h3 className="text-2xl font-black mt-2">R$ {financialStats.projectedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold opacity-80">
                      <span className="text-emerald-400">Previsto: + R$ {financialStats.incomeProjected.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-red-100 shadow-sm">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest flex items-center gap-1"><ArrowDownLeft size={12}/> Contas a Pagar (Hoje)</p>
                  <h3 className="text-2xl font-black text-red-600 mt-2">R$ {financialStats.apToday.toLocaleString()}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Aguardando Liquidação</p>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-emerald-100 shadow-sm">
