interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'CASH_REGISTER' | 'REPORTS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    setNotifications,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);
  const [isMaxRange, setIsMaxRange] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [txFilter, setTxFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE' | 'PENDING'>('ALL');

  // IA Insights
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // --- TRANSAÇÕES STATES ---
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({ type: 'EXPENSE', amount: 0, isRecurring: false });
  const [installmentCount, setInstallmentCount] = useState(1);

  // --- CAIXA STATES ---
  const [cashAccounts, setCashAccounts] = useState<CashAccount[]>(initialCashAccounts);
  const [cashSessions, setCashSessions] = useState<CashRegister[]>([]);
  const [cashMovements, setCashMovements] = useState<CashMovement[]>([]);
  const [isCashOpenModalOpen, setIsCashOpenModalOpen] = useState(false);
  const [isCashCloseModalOpen, setIsCashCloseModalOpen] = useState(false);
  const [isMovementModalOpen, setIsMovementModalOpen] = useState(false);
  const [editingMovement, setEditingMovement] = useState<Partial<CashMovement>>({});
  const [selectedSessionForReport, setSelectedSessionForReport] = useState<CashRegister | null>(null);

  // --- ESTOQUE STATES ---
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStockItem, setEditingStockItem] = useState<Partial<StockItem>>({});
  const [restockMode, setRestockMode] = useState(false);

  // --- ATIVOS STATES ---
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({ type: 'HARDWARE', status: 'ACTIVE' });

  // Permissão
  const hasFinancePermission = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';

  // --- LOGS DE DESENVOLVIMENTO ---
  const logDev = (action: string, data: any) => {
      if (process.env.NODE_ENV === 'development') {
          console.log(`[${new Date().toISOString()}] DEV_LOG: ${action}`, { user: currentUser.name, ...data });
      }
  };

  // --- CÁLCULOS DASHBOARD ---
  const financialStats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const filtered = transactions.filter(t => isMaxRange || (t.dueDate >= startDate && t.dueDate <= endDate));

    const incomeRealized = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);
    const expenseRealized = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);

    const incomeProjected = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);
    const expenseProjected = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);

    const accountsPayableToday = transactions.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);
    const accountsReceivableToday = transactions.filter(t => t.type === 'INCOME' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);

    return { 
        realizedBalance: incomeRealized - expenseRealized, 
        projectedBalance: (incomeRealized + incomeProjected) - (expenseRealized + expenseProjected), 
        incomeRealized, expenseRealized,
        incomeProjected, expenseProjected,
        apToday: accountsPayableToday,
        arToday: accountsReceivableToday
    };
  }, [transactions, startDate, endDate, isMaxRange]);

  // --- GESTÃO DE CAIXA HANDLERS ---
  const handleOpenCashRegister = (accountId: string, amount: number) => {
      const alreadyOpen = cashSessions.some(s => s.cashAccountId === accountId && s.status === 'OPEN');
      if (alreadyOpen) {
          alert("Esta conta já possui um caixa aberto.");
          return;
      }
      const newSession: CashRegister = {
          id: `cr-${Date.now()}`,
          cashAccountId: accountId,
          openedBy: currentUser.id,
          openedAt: Date.now(),
          initialAmount: amount,
          expectedFinalAmount: amount,
          status: 'OPEN'
      };
      setCashSessions(prev => [newSession, ...prev]);
      setIsCashOpenModalOpen(false);
      logDev('CAIXA_OPEN', { accountId, initialAmount: amount });
  };

  const handleCloseCashRegister = (sessionId: string, countedAmount: number, observations: string) => {
      const session = cashSessions.find(s => s.id === sessionId);
      if (!session) return;

      const difference = countedAmount - session.expectedFinalAmount;
      const updatedSession: CashRegister = {
          ...session,
          closedBy: currentUser.id,
          closedAt: Date.now(),
          countedFinalAmount: countedAmount,
          differenceAmount: difference,
          status: 'CLOSED',
          observations
      };

      setCashSessions(prev => prev.map(s => s.id === sessionId ? updatedSession : s));
      setIsCashCloseModalOpen(false);
      logDev('CAIXA_CLOSE', { sessionId, difference });
  };

  const handleCreateMovement = (move: Partial<CashMovement>) => {
      if (!move.cashRegisterId || !move.amount) return;

      const newMovement: CashMovement = {
          ...move,
          id: `mv-${Date.now()}`,
          date: new Date().toISOString(),
          createdBy: currentUser.id
      } as CashMovement;

      setCashMovements(prev => [...prev, newMovement]);

      // Atualiza o valor esperado da sessão
      setCashSessions(prev => prev.map(s => {
          if (s.id === move.cashRegisterId) {
              const impact = (move.type === 'RECEBIMENTO' || move.type === 'SUPRIMENTO') ? move.amount! : -move.amount!;
              return { ...s, expectedFinalAmount: s.expectedFinalAmount + impact };
          }
          return s;
      }));

      // Integração com Financeiro Geral
      if (move.type === 'RECEBIMENTO' || move.type === 'PAGAMENTO') {
          const newLedgerEntry: FinancialRecord = {
              id: `ledger-${newMovement.id}`,
              description: `[CAIXA] ${move.description}`,
              amount: move.amount!,
              type: move.type === 'RECEBIMENTO' ? 'INCOME' : 'EXPENSE',
              status: 'PAID',
              dueDate: new Date().toISOString().split('T')[0],
              paymentDate: new Date().toISOString(),
              cashRegisterId: move.cashRegisterId
          };
          setTransactions(prev => [newLedgerEntry, ...prev]);
      }

      setIsMovementModalOpen(false);
      logDev('CAIXA_MOVEMENT', newMovement);
  };

  // --- FINANCEIRO GERAL HANDLERS ---
  const handleSaveTx = () => {
    if (!editingTx.description || !editingTx.amount || !editingTx.dueDate) return;

    const groupId = `group-${Date.now()}`;
    const newRecords: FinancialRecord[] = [];

    if (installmentCount > 1) {
        const baseDate = new Date(editingTx.dueDate);
        for (let i = 1; i <= installmentCount; i++) {
            const dueDate = new Date(baseDate);
            dueDate.setMonth(baseDate.getMonth() + (i - 1));
            newRecords.push({
                ...editingTx,
                id: `tx-${Date.now()}-${i}`,
                status: 'PENDING',
                dueDate: dueDate.toISOString().split('T')[0],
                installment: { current: i, total: installmentCount, groupId }
            } as FinancialRecord);
        }
    } else {
        newRecords.push({ ...editingTx, id: `tx-${Date.now()}`, status: 'PENDING' } as FinancialRecord);
    }

    setTransactions(prev => [...newRecords, ...prev]);
    setIsTxModalOpen(false);
    setInstallmentCount(1);
    setEditingTx({ type: 'EXPENSE', amount: 0, isRecurring: false });
  };

