                              <button key={f} onClick={() => setTxFilter(f as any)} className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase border transition-all ${txFilter === f ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400'}`}>
                                  {f === 'ALL' ? 'Todos' : f === 'INCOME' ? 'Receitas' : f === 'EXPENSE' ? 'Despesas' : 'Pendentes'}
                              </button>
                          ))}
                      </div>
                      <button onClick={() => { setEditingTx({ type: 'EXPENSE', dueDate: new Date().toISOString().split('T')[0], amount: 0, isRecurring: false }); setIsTxModalOpen(true); }} className="bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg shadow-pink-500/20"><Plus size={14}/> Novo Lançamento</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {transactions
                                .filter(t => {
                                    if (txFilter === 'ALL') return true;
                                    if (txFilter === 'PENDING') return t.status === 'PENDING';
                                    return t.type === txFilter;
                                })
                                .filter(t => t.description.toLowerCase().includes(searchTerm.toLowerCase()))
                                .map(t => (
                                <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                    <td className="p-4 font-medium text-slate-400">
                                        <div className="flex flex-col">
                                            <span>{t.dueDate.split('-').reverse().join('/')}</span>
                                            {t.isRecurring && <span className="text-[9px] text-indigo-500 font-black uppercase flex items-center gap-0.5"><Repeat size={8}/> Recorrente</span>}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <p className="font-bold text-slate-800">{t.description}</p>
                                        {t.installment && <p className="text-[10px] text-slate-400 font-bold uppercase">Parcela {t.installment.current}/{t.installment.total}</p>}
                                    </td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-red-50 text-red-600 border border-red-100'}`}>{t.type === 'INCOME' ? 'Receita' : 'Despesa'}</span></td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600 animate-pulse'}`}>{t.status === 'PAID' ? 'Liquidado' : 'Pendente'}</span></td>
                                    <td className={`p-4 text-right font-black ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className={`p-1.5 rounded-lg ${t.status === 'PAID' ? 'text-amber-500 hover:bg-amber-50' : 'text-emerald-500 hover:bg-emerald-50'}`} title="Alternar Liquidação"><CheckCircle size={16}/></button>
                                            <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 rounded-lg text-slate-300 hover:text-red-500 hover:bg-red-50"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}

          {activeTab === 'STOCK' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><Package size={18} className="text-pink-600"/> Controle de Insumos</h3>
                      <button onClick={() => { setEditingStockItem({ category: 'OFFICE' }); setIsStockModalOpen(true); }} className="bg-slate-900 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Cadastrar Item</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Item</th><th className="p-4 text-center">Qtd Atual</th><th className="p-4 text-center">Qtd Mín</th><th className="p-4">Preço Unit</th><th className="p-4 text-center">Status</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {stock.map(item => {
                                const isCritical = item.quantity <= item.minQuantity;
                                return (
                                    <tr key={item.id} className="hover:bg-slate-50 group transition-colors">
                                        <td className="p-4"><p className="font-bold text-slate-800">{item.name}</p><p className="text-[10px] text-slate-400 uppercase font-black">{item.category}</p></td>
                                        <td className={`p-4 text-center font-black ${isCritical ? 'text-red-600 animate-pulse' : 'text-slate-800'}`}>{item.quantity}</td>
                                        <td className="p-4 text-center font-medium text-slate-400">{item.minQuantity}</td>
                                        <td className="p-4 font-bold text-slate-600">R$ {item.unitPrice.toLocaleString()}</td>
                                        <td className="p-4 text-center"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${isCritical ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>{isCritical ? 'Estoque Crítico' : 'Normal'}</span></td>
                                        <td className="p-4 text-center">
                                            <div className="flex justify-center gap-1">
                                                <button onClick={() => { setEditingStockItem(item); setRestockMode(true); setIsStockModalOpen(true); }} className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded-lg" title="Abastecer"><ArrowUp size={16}/></button>
                                                <button onClick={() => { setEditingStockItem(item); setRestockMode(false); setIsStockModalOpen(true); }} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                                <button onClick={() => setStock(prev => prev.filter(s => s.id !== item.id))} className="p-1.5 text-slate-300 hover:text-red-600 rounded-lg"><Trash2 size={16}/></button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}

          {activeTab === 'ASSETS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
