                      <button onClick={() => { setEditingAsset({ type: 'HARDWARE', status: 'ACTIVE' }); setIsAssetModalOpen(true); }} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Novo Ativo</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Ativo</th><th className="p-4">Categoria</th><th className="p-4">Custo</th><th className="p-4">Aquisição</th><th className="p-4">Status</th><th className="p-4 text-center">Ações</th></tr>
