                                    <td className="p-4 font-black text-slate-800">R$ {asset.cost.toLocaleString()}</td>
                                    <td className="p-4 text-slate-500 text-xs">{new Date(asset.purchaseDate).toLocaleDateString()}</td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${asset.status === 'ACTIVE' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>{asset.status === 'ACTIVE' ? 'Em Uso' : 'Inativo'}</span></td>
