                                        <div className="flex justify-center gap-1">
                                            <button onClick={() => { setEditingAsset(asset); setIsAssetModalOpen(true); }} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                            <button onClick={() => setAssets(prev => prev.filter(a => a.id !== asset.id))} className="p-1.5 text-slate-300 hover:text-red-600 rounded-lg"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}
