                        </div>
                        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center justify-between">
                            <div className="flex items-center gap-3"><CreditCard size={16}/><span className="text-xs font-bold text-slate-700">Parcelamento</span></div>
                            <div className="flex items-center gap-2"><button onClick={() => setInstallmentCount(Math.max(1, installmentCount - 1))} className="w-8 h-8 rounded-lg bg-white border text-slate-400">-</button><span className="w-8 text-center font-black text-sm">{installmentCount}x</span><button onClick={() => setInstallmentCount(installmentCount + 1)} className="w-8 h-8 rounded-lg bg-white border text-slate-400">+</button></div>
                        </div>
                      </div>
                      <button onClick={handleSaveTx} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2"><CheckCircle size={20}/> Gravar no Financeiro</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAIS ESTOQUE E PATRIMÔNIO (MANTIDOS) */}
      {isStockModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-pink-600 flex items-center justify-between text-white">
                      <div className="flex items-center gap-3"><Package size={24}/><h3 className="text-xl font-black uppercase">{restockMode ? 'Abastecer Estoque' : 'Gerenciar Item'}</h3></div>
                      <button onClick={() => setIsStockModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      {restockMode ? (
                          <div>
                              <p className="text-sm text-slate-500 mb-4">Adicionando unidades ao item <b>{editingStockItem.name}</b>.</p>
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Quantidade a Adicionar</label>
                              <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-xl font-black outline-none focus:border-emerald-500 transition-all" value={editingStockItem.quantity || 0} onChange={e => setEditingStockItem({...editingStockItem, quantity: parseInt(e.target.value)})} />
                          </div>
                      ) : (
                          <div className="space-y-4">
                              <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nome do insumo" value={editingStockItem.name || ''} onChange={e => setEditingStockItem({...editingStockItem, name: e.target.value})} />
                              <div className="grid grid-cols-2 gap-4">
                                  <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Qtd Mínima" value={editingStockItem.minQuantity || ''} onChange={e => setEditingStockItem({...editingStockItem, minQuantity: parseInt(e.target.value)})} />
                                  <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Preço Unit" value={editingStockItem.unitPrice || ''} onChange={e => setEditingStockItem({...editingStockItem, unitPrice: parseFloat(e.target.value)})} />
                              </div>
                              <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none" value={editingStockItem.category} onChange={e => setEditingStockItem({...editingStockItem, category: e.target.value as any})}>
                                  <option value="OFFICE">Escritório</option>
                                  <option value="IT">TI / Hardware</option>
                                  <option value="CLEANING">Limpeza</option>
                                  <option value="MARKETING">Marketing/Brindes</option>
                              </select>
                          </div>
                      )}
                      <button onClick={handleSaveStock} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2"><CheckCircle size={20}/> Salvar no Estoque</button>
                  </div>
              </div>
          </div>
      )}

      {isAssetModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsAssetModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-indigo-600 flex items-center justify-between text-white">
                      <div className="flex items-center gap-3"><HardDrive size={24}/><h3 className="text-xl font-black uppercase">Novo Ativo</h3></div>
                      <button onClick={() => setIsAssetModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-5">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nome do Ativo (ex: MacBook Pro M3)" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none" value={editingAsset.type} onChange={e => setEditingAsset({...editingAsset, type: e.target.value as any})}>
                              <option value="HARDWARE">Hardware</option>
                              <option value="SOFTWARE">Software / SaaS</option>
                              <option value="OFFICE">Mobiliário</option>
                          </select>
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" value={editingAsset.purchaseDate || ''} onChange={e => setEditingAsset({...editingAsset, purchaseDate: e.target.value})} />
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nº de Série" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2"><CheckCircle size={20}/> Registrar Ativo</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
    FinancialRecord, Asset, StockItem, User, Notification, ConfirmOptions, 
    CashAccount, CashRegister, CashMovement 
} from '../types';
import { initialStock, initialCashAccounts, initialCategories } from '../utils/mockData';
import { 
    AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, 
    CartesianGrid, PieChart, Pie, Cell, BarChart, Bar, Legend 
} from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Settings, Box, HardDrive, 
    ShieldCheck, BarChart3, Wallet, Scale, CheckCircle, RefreshCcw, ShoppingCart, Ban, 
    AlertCircle, Sparkles, Repeat, CreditCard, ChevronRight, Clock, Info,
    ArrowDownLeft, ArrowUpRight, X, ArrowUp, Lock, Unlock, History, Download, Eye, FileSpreadsheet,
    // Add missing Calculator icon
    Calculator
} from 'lucide-react';
import { analyzeFinancialHealth } from '../services/aiService';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'CASH_REGISTER' | 'REPORTS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    setNotifications,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);
  const [isMaxRange, setIsMaxRange] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [txFilter, setTxFilter] = useState<'ALL' | 'INCOME' | 'EXPENSE' | 'PENDING'>('ALL');

  // IA Insights
  const [aiLoading, setAiLoading] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // --- TRANSAÇÕES STATES ---
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({ type: 'EXPENSE', amount: 0, isRecurring: false });
  const [installmentCount, setInstallmentCount] = useState(1);

  // --- CAIXA STATES ---
  const [cashAccounts, setCashAccounts] = useState<CashAccount[]>(initialCashAccounts);
  const [cashSessions, setCashSessions] = useState<CashRegister[]>([]);
  const [cashMovements, setCashMovements] = useState<CashMovement[]>([]);
  const [isCashOpenModalOpen, setIsCashOpenModalOpen] = useState(false);
  const [isCashCloseModalOpen, setIsCashCloseModalOpen] = useState(false);
  const [isMovementModalOpen, setIsMovementModalOpen] = useState(false);
  const [editingMovement, setEditingMovement] = useState<Partial<CashMovement>>({});
  const [selectedSessionForReport, setSelectedSessionForReport] = useState<CashRegister | null>(null);

  // --- ESTOQUE STATES ---
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStockItem, setEditingStockItem] = useState<Partial<StockItem>>({});
  const [restockMode, setRestockMode] = useState(false);

  // --- ATIVOS STATES ---
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({ type: 'HARDWARE', status: 'ACTIVE' });

  // Permissão
  const hasFinancePermission = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';

  // --- LOGS DE DESENVOLVIMENTO ---
  const logDev = (action: string, data: any) => {
      if (process.env.NODE_ENV === 'development') {
          console.log(`[${new Date().toISOString()}] DEV_LOG: ${action}`, { user: currentUser.name, ...data });
      }
  };

  // --- CÁLCULOS DASHBOARD ---
  const financialStats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const filtered = transactions.filter(t => isMaxRange || (t.dueDate >= startDate && t.dueDate <= endDate));

    const incomeRealized = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);
    const expenseRealized = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((acc, t) => acc + t.amount, 0);

    const incomeProjected = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);
    const expenseProjected = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((acc, t) => acc + t.amount, 0);

    const accountsPayableToday = transactions.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);
    const accountsReceivableToday = transactions.filter(t => t.type === 'INCOME' && t.status === 'PENDING' && t.dueDate <= today).reduce((acc, t) => acc + t.amount, 0);

    return { 
        realizedBalance: incomeRealized - expenseRealized, 
        projectedBalance: (incomeRealized + incomeProjected) - (expenseRealized + expenseProjected), 
        incomeRealized, expenseRealized,
        incomeProjected, expenseProjected,
        apToday: accountsPayableToday,
        arToday: accountsReceivableToday
    };
  }, [transactions, startDate, endDate, isMaxRange]);

  // --- GESTÃO DE CAIXA HANDLERS ---
  const handleOpenCashRegister = (accountId: string, amount: number) => {
      const alreadyOpen = cashSessions.some(s => s.cashAccountId === accountId && s.status === 'OPEN');
      if (alreadyOpen) {
          alert("Esta conta já possui um caixa aberto.");
          return;
      }
      const newSession: CashRegister = {
          id: `cr-${Date.now()}`,
          cashAccountId: accountId,
          openedBy: currentUser.id,
          openedAt: Date.now(),
          initialAmount: amount,
          expectedFinalAmount: amount,
          status: 'OPEN'
      };
      setCashSessions(prev => [newSession, ...prev]);
      setIsCashOpenModalOpen(false);
      logDev('CAIXA_OPEN', { accountId, initialAmount: amount });
  };

  const handleCloseCashRegister = (sessionId: string, countedAmount: number, observations: string) => {
      const session = cashSessions.find(s => s.id === sessionId);
      if (!session) return;

      const difference = countedAmount - session.expectedFinalAmount;
      const updatedSession: CashRegister = {
          ...session,
          closedBy: currentUser.id,
          closedAt: Date.now(),
          countedFinalAmount: countedAmount,
          differenceAmount: difference,
          status: 'CLOSED',
          observations
      };

      setCashSessions(prev => prev.map(s => s.id === sessionId ? updatedSession : s));
      setIsCashCloseModalOpen(false);
      logDev('CAIXA_CLOSE', { sessionId, difference });
  };

  const handleCreateMovement = (move: Partial<CashMovement>) => {
      if (!move.cashRegisterId || !move.amount) return;

      const newMovement: CashMovement = {
          ...move,
          id: `mv-${Date.now()}`,
          date: new Date().toISOString(),
          createdBy: currentUser.id
      } as CashMovement;

      setCashMovements(prev => [...prev, newMovement]);

      // Atualiza o valor esperado da sessão
      setCashSessions(prev => prev.map(s => {
          if (s.id === move.cashRegisterId) {
              const impact = (move.type === 'RECEBIMENTO' || move.type === 'SUPRIMENTO') ? move.amount! : -move.amount!;
              return { ...s, expectedFinalAmount: s.expectedFinalAmount + impact };
          }
          return s;
      }));

      // Integração com Financeiro Geral
      if (move.type === 'RECEBIMENTO' || move.type === 'PAGAMENTO') {
          const newLedgerEntry: FinancialRecord = {
              id: `ledger-${newMovement.id}`,
              description: `[CAIXA] ${move.description}`,
              amount: move.amount!,
              type: move.type === 'RECEBIMENTO' ? 'INCOME' : 'EXPENSE',
              status: 'PAID',
              dueDate: new Date().toISOString().split('T')[0],
              paymentDate: new Date().toISOString(),
              cashRegisterId: move.cashRegisterId
          };
          setTransactions(prev => [newLedgerEntry, ...prev]);
      }

      setIsMovementModalOpen(false);
      logDev('CAIXA_MOVEMENT', newMovement);
  };

  // --- FINANCEIRO GERAL HANDLERS ---
  const handleSaveTx = () => {
    if (!editingTx.description || !editingTx.amount || !editingTx.dueDate) return;

    const groupId = `group-${Date.now()}`;
    const newRecords: FinancialRecord[] = [];

    if (installmentCount > 1) {
        const baseDate = new Date(editingTx.dueDate);
        for (let i = 1; i <= installmentCount; i++) {
            const dueDate = new Date(baseDate);
            dueDate.setMonth(baseDate.getMonth() + (i - 1));
            newRecords.push({
                ...editingTx,
                id: `tx-${Date.now()}-${i}`,
                status: 'PENDING',
                dueDate: dueDate.toISOString().split('T')[0],
                installment: { current: i, total: installmentCount, groupId }
            } as FinancialRecord);
        }
    } else {
        newRecords.push({ ...editingTx, id: `tx-${Date.now()}`, status: 'PENDING' } as FinancialRecord);
    }

    setTransactions(prev => [...newRecords, ...prev]);
    setIsTxModalOpen(false);
    setInstallmentCount(1);
    setEditingTx({ type: 'EXPENSE', amount: 0, isRecurring: false });
  };

  const handleGetAiInsight = async () => {
      setAiLoading(true);
      const insight = await analyzeFinancialHealth(transactions);
      setAiInsight(insight);
      setAiLoading(false);
  };

  // --- ESTOQUE E PATRIMÔNIO HANDLERS ---
  const handleSaveStock = () => {
      if (!editingStockItem.name || editingStockItem.quantity === undefined) return;
      if (editingStockItem.id) {
          setStock(prev => prev.map(s => s.id === editingStockItem.id ? { ...s, ...editingStockItem } as StockItem : s));
      } else {
          setStock(prev => [...prev, { ...editingStockItem, id: `stk-${Date.now()}`, lastRestock: new Date().toISOString().split('T')[0] } as StockItem]);
      }
      setIsStockModalOpen(false);
      setEditingStockItem({});
      setRestockMode(false);
  };

  const handleSaveAsset = () => {
      if (!editingAsset.name || !editingAsset.cost) return;
      if (editingAsset.id) {
          setAssets(prev => prev.map(a => a.id === editingAsset.id ? { ...a, ...editingAsset } as Asset : a));
      } else {
          setAssets(prev => [...prev, { ...editingAsset, id: `ast-${Date.now()}` } as Asset]);
      }
      setIsAssetModalOpen(false);
      setEditingAsset({ type: 'HARDWARE', status: 'ACTIVE' });
  };

  if (!hasFinancePermission) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[500px] text-center p-8 bg-white rounded-2xl border border-slate-200">
              <Ban size={64} className="text-red-400 mb-4 animate-pulse"/>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Acesso Restrito</h2>
              <p className="text-slate-500 max-w-md mt-2">Você não possui permissão de <b>Administrador</b> ou <b>Financeiro</b> para acessar este módulo.</p>
          </div>
      );
  }

  const renderDashboard = () => (
      <div className="space-y-6 animate-pop">
          {/* Radar Financeiro */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Realizado (Caixa)</p>
                  <h3 className={`text-2xl font-black mt-2 ${financialStats.realizedBalance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {financialStats.realizedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold">
                      <span className="text-emerald-600">+ R$ {financialStats.incomeRealized.toLocaleString()}</span>
                      <span className="text-slate-300">|</span>
                      <span className="text-red-600">- R$ {financialStats.expenseRealized.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                  <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção 30 Dias</p>
                  <h3 className="text-2xl font-black mt-2">R$ {financialStats.projectedBalance.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold opacity-80">
                      <span className="text-emerald-400">Previsto: + R$ {financialStats.incomeProjected.toLocaleString()}</span>
                  </div>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-red-100 shadow-sm">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest flex items-center gap-1"><ArrowDownLeft size={12}/> Contas a Pagar (Hoje)</p>
                  <h3 className="text-2xl font-black text-red-600 mt-2">R$ {financialStats.apToday.toLocaleString()}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Vencimentos do dia</p>
              </div>
              <div className="bg-white p-5 rounded-2xl border border-emerald-100 shadow-sm">
                  <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-1"><ArrowUpRight size={12}/> Contas a Receber (Hoje)</p>
                  <h3 className="text-2xl font-black text-emerald-600 mt-2">R$ {financialStats.arToday.toLocaleString()}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Entradas previstas</p>
              </div>
          </div>

          {/* IA Insights */}
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-6 rounded-2xl text-white shadow-lg flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-4">
                  <div className="p-3 bg-white/20 rounded-xl"><Sparkles size={24}/></div>
                  <div>
                      <h4 className="font-bold text-lg">Consultoria Financeira IA</h4>
                      <p className="text-indigo-100 text-sm">Diagnóstico estratégico baseado no seu histórico e projeções.</p>
                  </div>
              </div>
              <button onClick={handleGetAiInsight} disabled={aiLoading} className="bg-white text-indigo-600 px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-2">
                  {aiLoading ? <RefreshCcw size={16} className="animate-spin"/> : <Sparkles size={16}/>}
                  {aiInsight ? 'Atualizar Análise' : 'Analisar Saúde Financeira'}
              </button>
          </div>

          {aiInsight && (
              <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl animate-pop">
                  <div className="flex items-center gap-2 mb-4 text-indigo-700 font-black text-xs uppercase tracking-widest"><Info size={16}/> Insight Estratégico</div>
                  <div className="prose prose-sm text-indigo-900 max-w-none" dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>') }} />
              </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                  <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2"><TrendingUp size={16} className="text-pink-600"/> Histórico de Entradas e Saídas</h3>
                  <div className="h-64">
                      <ResponsiveContainer width="100%" height="100%">
                          <AreaChart data={transactions.slice(0, 15).reverse()}>
                              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                              <XAxis dataKey="dueDate" hide />
                              <YAxis axisLine={false} tickLine={false} fontSize={10} stroke="#94a3b8" />
                              <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                              <Area type="monotone" dataKey="amount" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.1} strokeWidth={3} />
                          </AreaChart>
                      </ResponsiveContainer>
                  </div>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
                  <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2"><Clock size={16} className="text-indigo-600"/> Próximos Vencimentos</h3>
                  <div className="space-y-3 flex-1 overflow-y-auto max-h-[250px] pr-2 custom-scrollbar">
                      {transactions.filter(t => t.status === 'PENDING').slice(0, 5).map(t => (
                          <div key={t.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                              <div className="flex items-center gap-3">
