                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none bg-slate-50 focus:bg-white" placeholder="0.00" onChange={e => setEditingMovement({ ...editingMovement, amount: parseFloat(e.target.value) })} />
                      </div>
                      <button onClick={() => handleOpenCashRegister(editingMovement.cashAccountId!, editingMovement.amount!)} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"><Unlock size={20}/> Iniciar Operações</button>
                  </div>
              </div>
          </div>
      )}

      {isMovementModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsMovementModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 text-white flex items-center justify-between ${editingMovement.type === 'RECEBIMENTO' || editingMovement.type === 'SUPRIMENTO' ? 'bg-emerald-600' : 'bg-red-600'}`}>
                      <div className="flex items-center gap-3"><ArrowUpRight size={24}/><h3 className="text-xl font-black uppercase tracking-tighter">{editingMovement.type}</h3></div>
                      <button onClick={() => setIsMovementModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white transition-all" placeholder="Descrição curta do movimento" value={editingMovement.description || ''} onChange={e => setEditingMovement({...editingMovement, description: e.target.value})} />
                      <div className="grid grid-cols-1 gap-4">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 block">Valor do Movimento R$</label>
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-3xl font-black outline-none bg-slate-50 focus:bg-white" placeholder="0.00" value={editingMovement.amount || ''} onChange={e => setEditingMovement({...editingMovement, amount: parseFloat(e.target.value)})} />
                      </div>
                      <button onClick={() => handleCreateMovement(editingMovement)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2"><CheckCircle size={20}/> Confirmar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashCloseModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsCashCloseModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between">
                      <div className="flex items-center gap-3"><Lock size={24}/><h3 className="text-xl font-black uppercase">Fechar Turno</h3></div>
                      <button onClick={() => setIsCashCloseModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Saldo Esperado pelo Sistema</p>
                          <p className="text-2xl font-black text-slate-800">R$ {cashSessions.find(s => s.id === editingMovement.cashRegisterId)?.expectedFinalAmount.toLocaleString()}</p>
                      </div>
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Saldo Contado (R$)</label>
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none bg-slate-50 focus:bg-white" placeholder="0.00" onChange={e => setEditingMovement({ ...editingMovement, amount: parseFloat(e.target.value) })} />
                      </div>
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Observações de Fechamento</label>
                          <textarea className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-medium bg-slate-50 outline-none focus:bg-white resize-none h-24" placeholder="Alguma divergência ou ocorrência?" onChange={e => setEditingMovement({ ...editingMovement, description: e.target.value })} />
                      </div>
                      <button onClick={() => handleCloseCashRegister(editingMovement.cashRegisterId!, editingMovement.amount!, editingMovement.description || '')} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-red-700 transition-all flex items-center justify-center gap-2"><Lock size={20}/> Encerrar Caixa</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL DETALHES DE FECHAMENTO (RELATÓRIO) */}
      {selectedSessionForReport && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setSelectedSessionForReport(null)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[85vh] shadow-2xl animate-pop overflow-hidden flex flex-col" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between">
                      <div className="flex items-center gap-3"><History size={24}/><h3 className="text-xl font-black uppercase tracking-tighter">Resumo de Turno #{selectedSessionForReport.id.split('-')[1]}</h3></div>
                      <button onClick={() => setSelectedSessionForReport(null)} className="p-1 hover:bg-white/10 rounded-full transition-colors"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Abertura</p><p className="font-bold text-slate-700">R$ {selectedSessionForReport.initialAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Esperado</p><p className="font-bold text-slate-700">R$ {selectedSessionForReport.expectedFinalAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Informado</p><p className="font-black text-indigo-600">R$ {selectedSessionForReport.countedFinalAmount?.toLocaleString()}</p></div>
                      </div>

                      <div className="space-y-4">
                          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 border-b border-slate-100 pb-2">Movimentações do Turno</h4>
                          <div className="space-y-2">
                              {cashMovements.filter(m => m.cashRegisterId === selectedSessionForReport.id).map(m => (
                                  <div key={m.id} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                                      <div className="flex items-center gap-3">
                                          <div className={`p-1.5 rounded-lg ${m.type === 'RECEBIMENTO' || m.type === 'SUPRIMENTO' ? 'text-emerald-500 bg-emerald-50' : 'text-red-500 bg-red-50'}`}>
                                              {m.type === 'RECEBIMENTO' || m.type === 'SUPRIMENTO' ? <ArrowUpRight size={14}/> : <ArrowDownLeft size={14}/>}
                                          </div>
                                          <div><p className="text-xs font-bold text-slate-800">{m.description}</p><p className="text-[9px] text-slate-400 uppercase">{m.type}</p></div>
                                      </div>
                                      <p className={`font-black text-sm ${m.type === 'RECEBIMENTO' || m.type === 'SUPRIMENTO' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {m.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                              {cashMovements.filter(m => m.cashRegisterId === selectedSessionForReport.id).length === 0 && (
                                  <p className="text-center text-xs text-slate-400 py-6 italic">Sem movimentações registradas.</p>
                              )}
                          </div>
                      </div>

                      {selectedSessionForReport.observations && (
                          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
                              <p className="text-[10px] font-black text-amber-700 uppercase tracking-widest mb-1">Observações do Operador</p>
                              <p className="text-xs text-amber-800 italic leading-relaxed">"{selectedSessionForReport.observations}"</p>
                          </div>
                      )}
                  </div>
                  <div className="p-6 border-t border-slate-100 flex justify-end gap-3 bg-slate-50/50">
                      <button onClick={() => window.print()} className="px-6 py-2.5 rounded-xl text-slate-500 font-bold text-xs uppercase tracking-widest hover:bg-slate-200 transition-colors flex items-center gap-2"><Download size={14}/> Exportar PDF</button>
                      <button onClick={() => setSelectedSessionForReport(null)} className="px-8 py-2.5 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors">Fechar Resumo</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL TRANSAÇÃO GERAL (MANTIDO) */}
      {isTxModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 flex items-center justify-between text-white ${editingTx.type === 'INCOME' ? 'bg-emerald-600' : 'bg-slate-900'}`}>
                      <div className="flex items-center gap-3"><CreditCard size={24}/><h3 className="text-xl font-black uppercase tracking-tighter">Novo Lançamento</h3></div>
                      <button onClick={() => setIsTxModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                           <button onClick={() => setEditingTx({...editingTx, type: 'INCOME'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}>Receita (+)</button>
                           <button onClick={() => setEditingTx({...editingTx, type: 'EXPENSE'})} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-400'}`}>Despesa (-)</button>
                      </div>
                      <div className="space-y-4">
                        <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white transition-all" placeholder="Descrição do lançamento" value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                        <div className="grid grid-cols-2 gap-4">
                            <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-lg font-black outline-none bg-slate-50 focus:bg-white" placeholder="R$ 0.00" value={editingTx.amount || ''} onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                            <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 focus:bg-white outline-none" value={editingTx.dueDate || ''} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                        </div>
                        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center justify-between">
                            <div className="flex items-center gap-3"><CreditCard size={16}/><span className="text-xs font-bold text-slate-700">Parcelamento</span></div>
                            <div className="flex items-center gap-2"><button onClick={() => setInstallmentCount(Math.max(1, installmentCount - 1))} className="w-8 h-8 rounded-lg bg-white border text-slate-400">-</button><span className="w-8 text-center font-black text-sm">{installmentCount}x</span><button onClick={() => setInstallmentCount(installmentCount + 1)} className="w-8 h-8 rounded-lg bg-white border text-slate-400">+</button></div>
                        </div>
                      </div>
                      <button onClick={handleSaveTx} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2"><CheckCircle size={20}/> Gravar no Financeiro</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAIS ESTOQUE E PATRIMÔNIO (MANTIDOS) */}
      {isStockModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-pink-600 flex items-center justify-between text-white">
                      <div className="flex items-center gap-3"><Package size={24}/><h3 className="text-xl font-black uppercase">{restockMode ? 'Abastecer Estoque' : 'Gerenciar Item'}</h3></div>
                      <button onClick={() => setIsStockModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      {restockMode ? (
                          <div>
                              <p className="text-sm text-slate-500 mb-4">Adicionando unidades ao item <b>{editingStockItem.name}</b>.</p>
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Quantidade a Adicionar</label>
                              <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-xl font-black outline-none focus:border-emerald-500 transition-all" value={editingStockItem.quantity || 0} onChange={e => setEditingStockItem({...editingStockItem, quantity: parseInt(e.target.value)})} />
                          </div>
                      ) : (
                          <div className="space-y-4">
                              <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nome do insumo" value={editingStockItem.name || ''} onChange={e => setEditingStockItem({...editingStockItem, name: e.target.value})} />
                              <div className="grid grid-cols-2 gap-4">
                                  <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Qtd Mínima" value={editingStockItem.minQuantity || ''} onChange={e => setEditingStockItem({...editingStockItem, minQuantity: parseInt(e.target.value)})} />
                                  <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Preço Unit" value={editingStockItem.unitPrice || ''} onChange={e => setEditingStockItem({...editingStockItem, unitPrice: parseFloat(e.target.value)})} />
                              </div>
                              <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none" value={editingStockItem.category} onChange={e => setEditingStockItem({...editingStockItem, category: e.target.value as any})}>
                                  <option value="OFFICE">Escritório</option>
                                  <option value="IT">TI / Hardware</option>
                                  <option value="CLEANING">Limpeza</option>
                                  <option value="MARKETING">Marketing/Brindes</option>
                              </select>
                          </div>
                      )}
                      <button onClick={handleSaveStock} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2"><CheckCircle size={20}/> Salvar no Estoque</button>
                  </div>
              </div>
          </div>
      )}

      {isAssetModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsAssetModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-indigo-600 flex items-center justify-between text-white">
                      <div className="flex items-center gap-3"><HardDrive size={24}/><h3 className="text-xl font-black uppercase">Novo Ativo</h3></div>
                      <button onClick={() => setIsAssetModalOpen(false)} className="p-1 hover:bg-white/10 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-5">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nome do Ativo (ex: MacBook Pro M3)" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none" value={editingAsset.type} onChange={e => setEditingAsset({...editingAsset, type: e.target.value as any})}>
                              <option value="HARDWARE">Hardware</option>
                              <option value="SOFTWARE">Software / SaaS</option>
                              <option value="OFFICE">Mobiliário</option>
                          </select>
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" value={editingAsset.purchaseDate || ''} onChange={e => setEditingAsset({...editingAsset, purchaseDate: e.target.value})} />
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 outline-none focus:bg-white" placeholder="Nº de Série" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2"><CheckCircle size={20}/> Registrar Ativo</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export type Role = 'ADMIN' | 'MANAGER' | 'EMPLOYEE' | 'FREELANCER' | 'CLIENT' | 'FINANCE';

export interface ConfirmOptions {
    title: string;
    description: string;
    confirmText?: string;
    cancelText?: string;
    variant?: 'danger' | 'info';
}

export interface SystemSettings {
    agencyName: string;
    logo: string;
    primaryColor: string;
    sidebarColor: string;
}

export interface UserPreferences {
    theme: 'light' | 'dark';
    emailNotifications: boolean;
    systemNotifications: boolean;
    compactMode: boolean;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  avatar: string;
  squad?: string;
  clientId?: string;
  hourlyRate?: number;
  salary?: number;
  birthDate?: string;
  documents?: string[];
  bankDetails?: string;
  admissionDate?: string;
  hasSystemAccess?: boolean;
  password?: string;
  preferences?: UserPreferences;
}

export type TaskStatus = 'BACKLOG' | 'TODO' | 'IN_PROGRESS' | 'REVIEW' | 'DONE';

export interface Comment {
  id: string;
  userId: string;
  text: string;
  timestamp: number;
}

export interface ChecklistItem {
  id: string;
  text: string;
  isCompleted: boolean;
  dueDate?: string;
  assigneeId?: string;
}

export interface HistoryLog {
  id: string;
  action: string;
  userId: string;
  timestamp: number;
}

export interface TimeLog {
  userId: string;
  startTime: number;
  endTime?: number;
  duration: number;
}

export interface TaskCover {
    type: 'COLOR' | 'IMAGE';
    value: string;
}

export interface Task {
  id: string;
  title: string;
  description: string;
  status: string;
  assigneeIds: string[];
  squadId?: string;
  priority: 'LOW' | 'MEDIUM' | 'HIGH';
  dueDate: string;
  completedAt?: number;
  estimatedTime: number;
  timeLogs: TimeLog[];
  isTracking: boolean;
  clientRequest?: boolean;
  approvalStatus?: 'PENDING' | 'APPROVED' | 'REJECTED';
  checklists: ChecklistItem[];
  comments: Comment[];
  history: HistoryLog[];
  archived?: boolean;
  cover?: TaskCover;
}

export interface LeadTask {
    id: string;
    text: string;
    completed: boolean;
    dueDate?: string;
    time?: string;
    type?: 'CALL' | 'MEETING' | 'EMAIL' | 'TASK';
}

export interface Lead {
  id: string;
  name: string;
  company: string;
  value: number;
  stage: string;
  email: string;
  phone?: string;
  lastContact: string;
  source?: string;
  rating?: number;
  tasks?: LeadTask[];
  notes?: string;
}

export interface ClientContact {
    name: string;
    email: string;
    phone: string;
    role: string;
    birthDate?: string;
}

export interface Client {
    id: string;
    name: string;
    legalName?: string;
    status: 'ACTIVE' | 'INACTIVE' | 'CHURNED';
    isRecurring: boolean;
    level: 'BASIC' | 'INTERMEDIATE' | 'ADVANCED'; 
    summary?: string; 
    contractUrl?: string;
    assetsFolderUrl?: string;
    contacts: ClientContact[];
    squadId?: string;
    monthlyValue?: number;
    contractStartDate?: string;
    serviceIds?: string[];
}

export interface AgencyService {
    id: string;
    name: string;
    description: string;
    basePrice: number;
    active: boolean;
}

export interface FinancialCategory {
    id: string;
    name: string;
    type: 'INCOME' | 'EXPENSE' | 'BOTH';
    color: string;
}

export interface Supplier {
    id: string;
    name: string;
    legalName?: string;
    document?: string;
    email?: string;
    phone?: string;
    bankDetails?: string;
    category?: string;
}

export interface FinancialRecord {
  id: string;
  description: string;
  amount: number;
  type: 'INCOME' | 'EXPENSE';
  status: 'PAID' | 'PENDING' | 'OVERDUE' | 'CANCELLED';
  dueDate: string;
  paymentDate?: string;
  categoryId?: string;
  entityId?: string;
  entityName?: string;
  isRecurring?: boolean;
  installment?: {
      current: number;
      total: number;
      groupId: string;
  };
  cashRegisterId?: string; 
}

export interface CashAccount {
    id: string;
    name: string;
    isCashRegister: boolean;
    currentBalance: number;
    isActive: boolean;
}

export interface CashRegister {
    id: string;
    cashAccountId: string;
    openedBy: string;
    openedAt: number;
    monthReference: string; // Ex: "2024-11"
    initialAmount: number;
    closedBy?: string;
    closedAt?: number;
    expectedFinalAmount: number;
    countedFinalAmount?: number;
    differenceAmount?: number;
    status: 'OPEN' | 'CLOSED';
    observations?: string;
}

export interface CashMovement {
    id: string;
    cashRegisterId: string;
    type: 'RECEBIMENTO' | 'PAGAMENTO' | 'SUPRIMENTO' | 'SANGRIA';
    amount: number;
    description: string;
    date: string;
    createdBy: string;
    financialRecordId?: string;
}

export interface StockItem {
  id: string;
  name: string;
  category: 'OFFICE' | 'IT' | 'CLEANING' | 'MARKETING';
  quantity: number;
  minQuantity: number;
  unitPrice: number;
  lastRestock: string;
}

export interface Asset {
  id: string;
  name: string;
  type: 'SOFTWARE' | 'HARDWARE' | 'OFFICE';
  cost: number;
  purchaseDate: string;
  serialNumber: string;
  status: 'ACTIVE' | 'DECOMMISSIONED';
  decommissionDate?: string;
  decommissionReason?: string;
}

export interface Requisition {
    id: string;
    requesterId: string;
    title: string;
    description: string;
    estimatedCost: number;
    status: 'PENDING' | 'APPROVED' | 'REJECTED' | 'PURCHASED';
    date: string;
    category: string;
    approvedBy?: string;
    approvedAt?: string;
    rejectedBy?: string;
    rejectedAt?: string;
    rejectedReason?: string;
}

export interface Squad {
  id: string;
  name: string;
  members: string[];
}

export interface ColumnConfig {
    id: string;
    label: string;
    color: string;
    order: number;
    wipLimit?: number | null;
    isArchived: boolean;
}

export type NotificationPriority = 'HIGH' | 'MEDIUM' | 'LOW';
export type NotificationStatus = 'UNREAD' | 'READ' | 'ARCHIVED';
export type SystemModule = 'KANBAN' | 'CRM' | 'FINANCE' | 'REQUISITIONS' | 'CLIENTS' | 'ADMIN' | 'HELP' | 'DASHBOARD';

export interface Notification {
    id: string;
    title: string;
    message: string;
    type: 'INFO' | 'WARNING' | 'SUCCESS' | 'Birthday' | 'REJECTED' | 'SECURITY';
    priority: NotificationPriority;
    status: NotificationStatus;
    originModule: SystemModule;
    timestamp: number;
    targetUserId?: string;
    targetRole?: Role;
    navToView?: string;
    actionLabel?: string;
    metadata?: any; 
}

export type RolePermissions = Record<Role, string[]>;

import React, { useState, useMemo } from 'react';
import { 
    FinancialRecord, Asset, StockItem, User, ConfirmOptions, 
    CashAccount, CashRegister, CashMovement 
} from '../types';
import { initialStock, initialCashAccounts } from '../utils/mockData';
import { 
    AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, 
    CartesianGrid, PieChart, Pie, Cell 
} from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Box, HardDrive, Calculator, 
    Wallet, Scale, CheckCircle, RefreshCcw, ArrowDownLeft, ArrowUpRight, 
    X, ArrowUp, Lock, Unlock, History, Download, Eye, ChevronRight, Clock, Ban
} from 'lucide-react';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'CASH_MONTHLY' | 'REPORTS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);

  // -- Permissões --
  const hasAccess = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';

  // -- Estados Locais --
  const [cashAccounts] = useState<CashAccount[]>(initialCashAccounts);
  const [cashSessions, setCashSessions] = useState<CashRegister[]>([]);
  const [cashMovements, setCashMovements] = useState<CashMovement[]>([]);
  const [stock, setStock] = useState<StockItem[]>(initialStock);

  // -- Modais --
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({});

  const [isCashOpenModalOpen, setIsCashOpenModalOpen] = useState(false);
  const [isCashCloseModalOpen, setIsCashCloseModalOpen] = useState(false);
  const [isMoveModalOpen, setIsMoveModalOpen] = useState(false);
  const [editingMove, setEditingMove] = useState<Partial<CashMovement>>({});

  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStock, setEditingStock] = useState<Partial<StockItem>>({});

  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({});

  const [selectedReportCycle, setSelectedReportCycle] = useState<CashRegister | null>(null);

  // -- Logs de Auditoria --
  const logAction = (action: string, metadata: any) => {
      console.log(`[FINANCE_AUDIT] ${new Date().toISOString()} | User: ${currentUser.name} | Action: ${action}`, metadata);
  };

  // -- Cálculos Dashboard --
  const stats = useMemo(() => {
      const filtered = transactions.filter(t => t.dueDate >= startDate && t.dueDate <= endDate);
      const income = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const expense = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const pendingInc = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      const pendingExp = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      return { balance: income - expense, income, expense, projected: (income + pendingInc) - (expense + pendingExp) };
  }, [transactions, startDate, endDate]);

  // -- Handlers: Caixa Mensal --
  const handleOpenCash = (accId: string, amount: number) => {
      const month = new Date().toISOString().substring(0, 7);
      if (cashSessions.some(s => s.cashAccountId === accId && s.status === 'OPEN')) {
          alert("Já existe um caixa aberto para esta conta.");
          return;
      }
      const newSession: CashRegister = {
          id: `cr-${Date.now()}`,
          cashAccountId: accId,
          openedBy: currentUser.id,
          openedAt: Date.now(),
          monthReference: month,
          initialAmount: amount,
          expectedFinalAmount: amount,
          status: 'OPEN'
      };
      setCashSessions(prev => [newSession, ...prev]);
      setIsCashOpenModalOpen(false);
      logAction('CAIXA_OPEN', { accId, month });
  };

  const handleCreateMovement = (move: Partial<CashMovement>) => {
      if (!move.amount || !move.cashRegisterId) return;
      const newMove: CashMovement = {
          ...move,
          id: `mv-${Date.now()}`,
          date: new Date().toISOString(),
          createdBy: currentUser.id
      } as CashMovement;

      setCashMovements(prev => [...prev, newMove]);

      // Atualiza valor esperado do caixa
      setCashSessions(prev => prev.map(s => {
          if (s.id === move.cashRegisterId) {
              const impact = (move.type === 'RECEBIMENTO' || move.type === 'SUPRIMENTO') ? move.amount! : -move.amount!;
              return { ...s, expectedFinalAmount: s.expectedFinalAmount + impact };
          }
          return s;
      }));

      // Integra com financeiro geral se for entrada/saída
      if (move.type === 'RECEBIMENTO' || move.type === 'PAGAMENTO') {
          const ledgerEntry: FinancialRecord = {
              id: `lg-${Date.now()}`,
              description: `[CAIXA] ${move.description}`,
              amount: move.amount!,
              type: move.type === 'RECEBIMENTO' ? 'INCOME' : 'EXPENSE',
              status: 'PAID',
              dueDate: new Date().toISOString().split('T')[0],
              paymentDate: new Date().toISOString(),
              cashRegisterId: move.cashRegisterId
          };
          setTransactions(prev => [ledgerEntry, ...prev]);
      }

      setIsMoveModalOpen(false);
      logAction('CAIXA_MOVEMENT', newMove);
  };

  const handleCloseCash = (sessionId: string, counted: number, obs: string) => {
      setCashSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
              const diff = counted - s.expectedFinalAmount;
              return { ...s, status: 'CLOSED', countedFinalAmount: counted, differenceAmount: diff, closedBy: currentUser.id, closedAt: Date.now(), observations: obs };
          }
          return s;
      }));
      setIsCashCloseModalOpen(false);
      logAction('CAIXA_CLOSE', { sessionId, counted });
  };

  // -- Handlers: Estoque e Patrimônio --
  const handleSaveStock = () => {
      if (!editingStock.name || editingStock.quantity === undefined) return;
      if (editingStock.id) {
          setStock(prev => prev.map(i => i.id === editingStock.id ? { ...i, ...editingStock } as StockItem : i));
      } else {
          setStock(prev => [...prev, { ...editingStock, id: `stk-${Date.now()}`, lastRestock: new Date().toISOString() } as StockItem]);
      }
      setIsStockModalOpen(false);
      setEditingStock({});
  };

  const handleSaveAsset = () => {
      if (!editingAsset.name || !editingAsset.cost) return;
      if (editingAsset.id) {
          setAssets(prev => prev.map(a => a.id === editingAsset.id ? { ...a, ...editingAsset } as Asset : a));
      } else {
          setAssets(prev => [...prev, { ...editingAsset, id: `ast-${Date.now()}`, status: 'ACTIVE' } as Asset]);
      }
      setIsAssetModalOpen(false);
      setEditingAsset({});
  };

  const handleDeleteAsset = async (id: string) => {
      const ok = await openConfirm({ title: "Remover Ativo?", description: "Esta ação removerá o ativo do patrimônio permanentemente.", variant: 'danger' });
      if (ok) setAssets(prev => prev.filter(a => a.id !== id));
  };

  // -- Bloqueio de Acesso --
  if (!hasAccess) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl border border-slate-200 p-12 text-center">
              <Ban size={64} className="text-red-400 mb-4" />
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Acesso Restrito ao Financeiro</h2>
              <p className="text-slate-500 max-w-md mt-2">Somente usuários com perfil de <b>Administrador</b> ou <b>Financeiro</b> podem gerenciar o caixa e patrimônio da agência.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6 animate-pop">
      {/* Navegação de Módulos Financeiros */}
      <div className="flex flex-col md:flex-row justify-between items-end md:items-center gap-4">
          <div className="flex flex-wrap bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-fit">
              <button onClick={() => setActiveTab('DASHBOARD')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'DASHBOARD' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><TrendingUp size={14}/> Visão Geral</button>
              <button onClick={() => setActiveTab('TRANSACTIONS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'TRANSACTIONS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><FileText size={14}/> Fluxo Geral</button>
              <button onClick={() => setActiveTab('CASH_MONTHLY')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'CASH_MONTHLY' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Calculator size={14}/> Caixa Mensal</button>
              <button onClick={() => setActiveTab('REPORTS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'REPORTS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><History size={14}/> Fechamentos</button>
              <button onClick={() => setActiveTab('STOCK')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'STOCK' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Box size={14}/> Estoque</button>
              <button onClick={() => setActiveTab('ASSETS')} className={`px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 transition-all ${activeTab === 'ASSETS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><HardDrive size={14}/> Patrimônio</button>
          </div>

          <div className="flex items-center gap-2 bg-white p-2 rounded-xl border shadow-sm">
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
              <span className="text-slate-300">|</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-xs outline-none font-bold text-slate-700 bg-transparent"/>
          </div>
      </div>

      <div className="min-h-[500px]">
          {/* TAB: DASHBOARD */}
          {activeTab === 'DASHBOARD' && (
              <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Realizado em Caixa</p>
                          <h3 className={`text-2xl font-black mt-2 ${stats.balance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {stats.balance.toLocaleString()}</h3>
                          <div className="mt-4 flex items-center gap-1.5 text-[10px] font-bold">
                              <span className="text-emerald-600">+ R$ {stats.income.toLocaleString()}</span>
                              <span className="text-slate-300">|</span>
                              <span className="text-red-600">- R$ {stats.expense.toLocaleString()}</span>
                          </div>
                      </div>
                      <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                          <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção de Saldo</p>
                          <h3 className="text-2xl font-black mt-2">R$ {stats.projected.toLocaleString()}</h3>
                          <p className="mt-4 text-[10px] font-bold text-slate-400 uppercase">Considerando pendências</p>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><ArrowUpRight size={12} className="text-blue-600"/> MRR Estimado</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {(stats.income * 1.1).toLocaleString()}</h3>
                          <p className="mt-4 text-[10px] font-bold text-slate-400 uppercase">Tendência do período</p>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Box size={12} className="text-pink-600"/> Patrimônio Ativo</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {assets.reduce((a,b)=>a+b.cost, 0).toLocaleString()}</h3>
                          <p className="mt-4 text-[10px] font-bold text-slate-400 uppercase">Valor de aquisição</p>
                      </div>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-80">
                          <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6">Fluxo de Caixa (Realizado)</h3>
                          <ResponsiveContainer width="100%" height="100%">
                              <AreaChart data={transactions.slice(-10)}>
                                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                                  <XAxis dataKey="dueDate" hide />
                                  <YAxis hide />
                                  <Tooltip />
                                  <Area type="monotone" dataKey="amount" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.1} />
                              </AreaChart>
                          </ResponsiveContainer>
                      </div>
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
                          <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6 flex justify-between items-center">
                              <span>Próximos Vencimentos</span>
                              <button onClick={()=>setActiveTab('TRANSACTIONS')} className="text-[10px] text-pink-600 hover:underline">Ver Todos</button>
                          </h3>
                          <div className="space-y-3 flex-1 overflow-y-auto max-h-[200px] custom-scrollbar">
                              {transactions.filter(t => t.status === 'PENDING').slice(0, 5).map(t => (
                                  <div key={t.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                                      <div className="flex items-center gap-3">
                                          <div className={`p-2 rounded-lg ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                                              {t.type === 'INCOME' ? <ArrowUpRight size={14}/> : <ArrowDownLeft size={14}/>}
                                          </div>
                                          <div><p className="text-sm font-bold text-slate-800 line-clamp-1">{t.description}</p><p className="text-[10px] text-slate-400 font-black uppercase">{t.dueDate.split('-').reverse().join('/')}</p></div>
                                      </div>
                                      <p className="font-black text-sm text-slate-800">R$ {t.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>
          )}

          {/* TAB: TRANSACTIONS (Fluxo Geral) */}
          {activeTab === 'TRANSACTIONS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest flex items-center gap-2"><FileText size={16} className="text-indigo-600"/> Livro Razão Geral</h3>
                      <button onClick={()=>{setEditingTx({type:'EXPENSE', dueDate: new Date().toISOString().split('T')[0]}); setIsTxModalOpen(true)}} className="bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Novo Lançamento</button>
                  </div>
                  <div className="overflow-x-auto">
                      <table className="w-full text-sm text-left">
                          <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                              <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {transactions.map(t => (
                                  <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                      <td className="p-4 text-slate-400 font-medium">{t.dueDate.split('-').reverse().join('/')}</td>
                                      <td className="p-4 font-bold text-slate-800">{t.description}</td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-red-50 text-red-600 border border-red-100'}`}>{t.type === 'INCOME' ? 'Receita' : 'Despesa'}</span></td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600 animate-pulse'}`}>{t.status === 'PAID' ? 'Liquidado' : 'Pendente'}</span></td>
                                      <td className={`p-4 text-right font-black ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                      <td className="p-4 text-center">
                                          <div className="flex justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                              <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-emerald-600"><CheckCircle size={16}/></button>
                                              <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                                          </div>
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          )}

          {/* TAB: CAIXA MENSAL */}
          {activeTab === 'CASH_MONTHLY' && (
              <div className="space-y-6 animate-pop">
                  <div className="flex justify-between items-center bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                       <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter flex items-center gap-2"><Calculator size={24} className="text-pink-600"/> Gestão de Caixa Mensal</h3><p className="text-sm text-slate-500">Ciclos de operação mensal e conferência de fundo de reserva.</p></div>
                       <button onClick={() => setIsCashOpenModalOpen(true)} className="bg-slate-900 text-white px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 shadow-xl hover:bg-slate-800 transition-all"><Lock size={16} className="text-emerald-400"/> Abrir Turno Mensal</button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {cashSessions.filter(s => s.status === 'OPEN').map(session => {
                          const account = cashAccounts.find(a => a.id === session.cashAccountId);
                          return (
                              <div key={session.id} className="bg-white rounded-3xl border-2 border-indigo-100 shadow-xl overflow-hidden animate-pop">
                                  <div className="p-6 bg-indigo-600 text-white">
                                       <div className="flex justify-between items-start mb-4"><div className="p-2 bg-white/20 rounded-xl"><Unlock size={20}/></div><span className="bg-emerald-400 text-emerald-950 px-2 py-0.5 rounded text-[10px] font-black uppercase">Caixa Ativo</span></div>
                                       <h4 className="text-xl font-black uppercase tracking-tighter">{account?.name}</h4>
                                       <p className="text-[10px] text-indigo-100 font-bold mt-1 uppercase">Mês de Referência: {session.monthReference}</p>
                                  </div>
                                  <div className="p-6 space-y-4">
                                       <div className="flex justify-between items-end border-b border-slate-100 pb-4">
                                           <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Saldo Atual Estimado</p><p className="text-2xl font-black text-slate-800">R$ {session.expectedFinalAmount.toLocaleString()}</p></div>
                                           <div className="text-right"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Fundo Inicial</p><p className="font-bold text-slate-600">R$ {session.initialAmount.toLocaleString()}</p></div>
                                       </div>
                                       <div className="grid grid-cols-2 gap-2">
                                           <button onClick={() => { setEditingMove({ cashRegisterId: session.id, type: 'RECEBIMENTO' }); setIsMoveModalOpen(true); }} className="bg-emerald-50 text-emerald-600 py-3 rounded-xl font-black text-[10px] uppercase border border-emerald-100 hover:bg-emerald-100 transition-all flex items-center justify-center gap-2"><ArrowUpRight size={14}/> Recebimento</button>
                                           <button onClick={() => { setEditingMove({ cashRegisterId: session.id, type: 'PAGAMENTO' }); setIsMoveModalOpen(true); }} className="bg-red-50 text-red-600 py-3 rounded-xl font-black text-[10px] uppercase border border-red-100 hover:bg-red-100 transition-all flex items-center justify-center gap-2"><ArrowDownLeft size={14}/> Pagamento</button>
                                       </div>
                                       <div className="grid grid-cols-2 gap-2">
                                           <button onClick={() => { setEditingMove({ cashRegisterId: session.id, type: 'SUPRIMENTO' }); setIsMoveModalOpen(true); }} className="bg-indigo-50 text-indigo-600 py-2.5 rounded-xl font-black text-[10px] uppercase hover:bg-indigo-100 transition-all">Suprimento</button>
                                           <button onClick={() => { setEditingMove({ cashRegisterId: session.id, type: 'SANGRIA' }); setIsMoveModalOpen(true); }} className="bg-amber-50 text-amber-600 py-2.5 rounded-xl font-black text-[10px] uppercase hover:bg-amber-100 transition-all">Sangria</button>
                                       </div>
                                       <button onClick={() => { setEditingMove({ cashRegisterId: session.id }); setIsCashCloseModalOpen(true); }} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all mt-4">Fechar Caixa Mensal</button>
                                  </div>
                              </div>
                          );
                      })}
                      {cashSessions.filter(s => s.status === 'OPEN').length === 0 && (
                          <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-200 rounded-3xl bg-slate-50/50">
                              <Calculator size={48} className="mx-auto text-slate-300 mb-4"/>
                              <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Nenhum caixa operacional aberto para este mês.</p>
                              <button onClick={() => setIsCashOpenModalOpen(true)} className="mt-4 text-indigo-600 font-black text-xs uppercase underline">Iniciar novo ciclo mensal</button>
                          </div>
                      )}
                  </div>
              </div>
          )}

          {/* TAB: REPORTS */}
          {activeTab === 'REPORTS' && (
              <div className="space-y-6 animate-pop">
                  <div className="bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col">
                      <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                          <h3 className="font-bold text-slate-700 flex items-center gap-2 uppercase tracking-tighter"><History size={18} className="text-indigo-600"/> Auditoria de Fechamentos</h3>
                      </div>
                      <table className="w-full text-sm text-left">
                          <thead className="bg-white text-[10px] font-black text-slate-400 uppercase tracking-widest border-b">
                              <tr><th className="p-4">Mês Ref.</th><th className="p-4">Conta</th><th className="p-4 text-right">Saldo Esperado</th><th className="p-4 text-right">Saldo Real</th><th className="p-4 text-center">Diferença</th><th className="p-4 text-center">Status</th><th className="p-4 text-center">Ações</th></tr>
                          </thead>
                          <tbody className="divide-y divide-slate-50">
                              {cashSessions.filter(s => s.status === 'CLOSED').map(s => {
                                  const account = cashAccounts.find(a => a.id === s.cashAccountId);
                                  const hasDiff = s.differenceAmount !== 0;
                                  return (
                                      <tr key={s.id} className="hover:bg-slate-50">
                                          <td className="p-4 font-bold text-slate-600">{s.monthReference}</td>
                                          <td className="p-4 text-slate-500">{account?.name}</td>
                                          <td className="p-4 text-right font-medium">R$ {s.expectedFinalAmount.toLocaleString()}</td>
                                          <td className="p-4 text-right font-black text-slate-800">R$ {s.countedFinalAmount?.toLocaleString()}</td>
                                          <td className="p-4 text-center"><span className={`px-2 py-0.5 rounded text-[10px] font-black ${hasDiff ? 'bg-red-50 text-red-600' : 'bg-emerald-50 text-emerald-600'}`}>{hasDiff ? `R$ ${s.differenceAmount?.toLocaleString()}` : 'OK'}</span></td>
                                          <td className="p-4 text-center font-black text-[10px] text-slate-400 uppercase">FECHADO</td>
                                          <td className="p-4 text-center">
                                              <button onClick={()=>setSelectedReportCycle(s)} className="text-indigo-500 hover:scale-110 transition-transform"><Eye size={16}/></button>
                                          </td>
                                      </tr>
                                  );
                              })}
                          </tbody>
                      </table>
                  </div>
              </div>
          )}

          {/* TAB: STOCK */}
          {activeTab === 'STOCK' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><Box size={18} className="text-pink-600"/> Insumos e Materiais</h3>
                      <button onClick={() => {setEditingStock({category:'OFFICE', quantity:0, minQuantity:5}); setIsStockModalOpen(true)}} className="bg-slate-900 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2"><Plus size={14}/> Novo Item</button>
                  </div>
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                          <tr><th className="p-4">Item</th><th className="p-4 text-center">Qtd Atual</th><th className="p-4 text-center">Min.</th><th className="p-4">Preço Unit.</th><th className="p-4 text-center">Ações</th></tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {stock.map(item => (
                              <tr key={item.id} className="hover:bg-slate-50 group">
                                  <td className="p-4"><p className="font-bold text-slate-800">{item.name}</p><p className="text-[10px] text-slate-400 uppercase font-black">{item.category}</p></td>
                                  <td className={`p-4 text-center font-black ${item.quantity <= item.minQuantity ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</td>
                                  <td className="p-4 text-center text-slate-400">{item.minQuantity}</td>
                                  <td className="p-4 font-medium">R$ {item.unitPrice.toLocaleString()}</td>
                                  <td className="p-4 text-center">
                                      <div className="flex justify-center gap-1">
                                          <button onClick={()=>{setEditingStock(item); setIsStockModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                          <button onClick={()=>setStock(prev => prev.filter(i => i.id !== item.id))} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                                      </div>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          )}

          {/* TAB: ASSETS */}
          {activeTab === 'ASSETS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><HardDrive size={18} className="text-indigo-600"/> Ativos Fixos (Hardware/Software)</h3>
                      <button onClick={()=>{setEditingAsset({type:'HARDWARE'}); setIsAssetModalOpen(true)}} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Registrar Ativo</button>
                  </div>
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                          <tr><th className="p-4">Ativo / SN</th><th className="p-4">Tipo</th><th className="p-4">Custo</th><th className="p-4">Status</th><th className="p-4 text-center">Ações</th></tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {assets.map(asset => (
                              <tr key={asset.id} className="hover:bg-slate-50 group">
                                  <td className="p-4"><p className="font-bold text-slate-800">{asset.name}</p><p className="text-[10px] text-slate-400 font-black">{asset.serialNumber}</p></td>
                                  <td className="p-4 text-xs font-bold text-slate-500 uppercase">{asset.type}</td>
                                  <td className="p-4 font-black">R$ {asset.cost.toLocaleString()}</td>
                                  <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${asset.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>{asset.status === 'ACTIVE' ? 'Em Uso' : 'Baixado'}</span></td>
                                  <td className="p-4 text-center">
                                      <div className="flex justify-center gap-1">
                                          <button onClick={()=>{setEditingAsset(asset); setIsAssetModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                          <button onClick={()=>handleDeleteAsset(asset.id)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                                      </div>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          )}
      </div>

      {/* --- MODAIS DE GESTÃO --- */}

      {/* MODAL: ABERTURA CAIXA */}
      {isCashOpenModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsCashOpenModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between"><h3 className="text-xl font-black uppercase tracking-tighter">Novo Ciclo Mensal</h3><button onClick={()=>setIsCashOpenModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Conta Operacional</label><select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50" onChange={e => setEditingMove({ ...editingMove, cashAccountId: e.target.value })}><option value="">Selecione...</option>{cashAccounts.filter(a => a.isCashRegister).map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Fundo Inicial de Reserva (R$)</label><input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none focus:bg-white" placeholder="0.00" onChange={e => setEditingMove({ ...editingMove, amount: parseFloat(e.target.value) })} /></div>
                      <button onClick={() => handleOpenCash(editingMove.cashAccountId!, editingMove.amount!)} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"><Unlock size={20}/> Iniciar Ciclo</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: MOVIMENTAÇÃO CAIXA */}
      {isMoveModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsMoveModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 text-white flex justify-between ${editingMove.type === 'RECEBIMENTO' || editingMove.type === 'SUPRIMENTO' ? 'bg-emerald-600' : 'bg-red-600'}`}><h3 className="text-xl font-black uppercase tracking-tighter">{editingMove.type}</h3><button onClick={()=>setIsMoveModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Descrição da operação..." value={editingMove.description || ''} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-3xl font-black outline-none" placeholder="0.00" value={editingMove.amount || ''} onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => handleCreateMovement(editingMove)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Confirmar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: FECHAMENTO CAIXA */}
      {isCashCloseModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsCashCloseModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between"><h3 className="text-xl font-black uppercase">Fechar Turno</h3><button onClick={()=>setIsCashCloseModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center"><p className="text-[10px] font-black text-slate-400 uppercase">Saldo Esperado</p><p className="text-2xl font-black">R$ {cashSessions.find(s => s.id === editingMove.cashRegisterId)?.expectedFinalAmount.toLocaleString()}</p></div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none" placeholder="Saldo Real Contado" onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <textarea className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm resize-none" placeholder="Observações..." rows={3} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <button onClick={() => handleCloseCash(editingMove.cashRegisterId!, editingMove.amount!, editingMove.description || '')} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase">Encerrar Ciclo Mensal</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: ESTOQUE */}
      {isStockModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tight">{editingStock.id ? 'Editar Item' : 'Novo Item em Estoque'}</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Insumo" value={editingStock.name || ''} onChange={e => setEditingStock({...editingStock, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Qtd. Atual" value={editingStock.quantity || ''} onChange={e => setEditingStock({...editingStock, quantity: parseInt(e.target.value)})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Qtd. Min." value={editingStock.minQuantity || ''} onChange={e => setEditingStock({...editingStock, minQuantity: parseInt(e.target.value)})} />
                      </div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Preço Unit." value={editingStock.unitPrice || ''} onChange={e => setEditingStock({...editingStock, unitPrice: parseFloat(e.target.value)})} />
                      <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingStock.category} onChange={e => setEditingStock({...editingStock, category: e.target.value as any})}><option value="OFFICE">Escritório</option><option value="IT">TI / Tecnologia</option><option value="CLEANING">Limpeza</option><option value="MARKETING">Eventos/Brindes</option></select>
                      <button onClick={handleSaveStock} className="w-full bg-pink-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-pink-700 transition-all">Salvar no Estoque</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: PATRIMÔNIO */}
      {isAssetModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsAssetModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tight">Registro de Patrimônio</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Ativo (ex: MacBook Pro)" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nº Série / Licença" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.purchaseDate || ''} onChange={e => setEditingAsset({...editingAsset, purchaseDate: e.target.value})} />
                          <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.type} onChange={e => setEditingAsset({...editingAsset, type: e.target.value as any})}><option value="HARDWARE">Hardware</option><option value="SOFTWARE">Software (SaaS)</option><option value="OFFICE">Mobiliário</option></select>
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Registrar Ativo</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL: DETALHES FECHAMENTO */}
      {selectedReportCycle && (
          <div className="fixed inset-0 bg-black/60 z-[130] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setSelectedReportCycle(null)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[80vh] shadow-2xl animate-pop overflow-hidden flex flex-col" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="text-xl font-black uppercase tracking-tighter">Resumo Mensal: {selectedReportCycle.monthReference}</h3><button onClick={()=>setSelectedReportCycle(null)}><X/></button></div>
                  <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Abertura</p><p className="font-bold">R$ {selectedReportCycle.initialAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Esperado</p><p className="font-bold">R$ {selectedReportCycle.expectedFinalAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Furo / Dif.</p><p className={`font-black ${selectedReportCycle.differenceAmount === 0 ? 'text-emerald-600' : 'text-red-600'}`}>R$ {selectedReportCycle.differenceAmount?.toLocaleString()}</p></div>
                      </div>
                      <div>
                          <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-3 border-b pb-2">Movimentos do Período</h4>
                          <div className="space-y-2">
                              {cashMovements.filter(m => m.cashRegisterId === selectedReportCycle.id).map(m => (
                                  <div key={m.id} className="flex justify-between items-center p-3 bg-white border border-slate-50 rounded-xl shadow-sm">
                                      <div><p className="text-xs font-bold text-slate-800">{m.description}</p><p className="text-[9px] text-slate-400 uppercase">{m.type}</p></div>
                                      <p className={`font-black text-sm ${m.type === 'RECEBIMENTO' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {m.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                      {selectedReportCycle.observations && <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100"><p className="text-[10px] font-black text-amber-700 uppercase mb-1">Notas de Auditoria</p><p className="text-xs italic text-amber-900">"{selectedReportCycle.observations}"</p></div>}
                  </div>
                  <div className="p-6 border-t bg-slate-50 flex justify-end gap-3"><button onClick={() => window.print()} className="px-6 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold text-xs uppercase transition-all flex items-center gap-2"><Download size={14}/> Imprimir PDF</button><button onClick={()=>setSelectedReportCycle(null)} className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase">Fechar Relatório</button></div>
              </div>
          </div>
      )}

      {/* MODAL: LANÇAMENTO GERAL */}
      {isTxModalOpen && (
          <div className="fixed inset-0 bg-black/60 z-[120] flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase">Novo Lançamento Geral</h3>
                  <div className="space-y-4">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl"><button onClick={()=>setEditingTx({...editingTx, type:'INCOME'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600' : 'text-slate-400'}`}>Receita (+)</button><button onClick={()=>setEditingTx({...editingTx, type:'EXPENSE'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600' : 'text-slate-400'}`}>Despesa (-)</button></div>
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Descrição do Lançamento" value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Valor R$" onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingTx.dueDate} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                      </div>
                      <button onClick={() => {if(editingTx.amount && editingTx.description){setTransactions(p=>[{...editingTx, id:`tx-${Date.now()}`, status:'PAID'} as FinancialRecord, ...p]); setIsTxModalOpen(false); setEditingTx({})}}} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Gravar no Fluxo</button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { NotificationService } from './services/notificationService';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, LeadTask, ConfirmOptions } from './types';
import { Users, Settings, Bell, Check, Gift, AlertTriangle, Info, Clock, CheckCircle, Shield, Trash2, Archive, Eye, DollarSign, Briefcase } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  // Sidebar State & Persistence
  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 1024;
      setIsMobile(mobile);
      if (mobile) setSidebarCompact(true);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
    console.log("SIDEBAR_STATE_CHANGE", { sidebarOpen, sidebarCompact, viewport: isMobile ? "mobile" : "desktop" });
  }, [sidebarOpen, sidebarCompact, isMobile]);

  const toggleSidebar = () => setSidebarOpen(!sidebarOpen);
  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  // Confirm Dialog Global State
  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  // State Management
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);

  // Dynamic CRM Sources
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);

  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const [activeNotifTab, setActiveNotifTab] = useState('ALL');
  const notificationRef = useRef<HTMLDivElement>(null);

  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- AUTOMATION ENGINE (BACKGROUND WORKER SIMULATOR) ---
  useEffect(() => {
      if (!currentUser) return;

      const checkAutomations = () => {
          const now = new Date();
          let updatedNotifs = [...notifications];

          // 1. FINANCEIRO: Faturas a vencer (7, 3 e 1 dia)
          transactions.forEach(tx => {
              if (tx.status === 'PENDING' && tx.type === 'INCOME') {
                  const dueDate = new Date(tx.dueDate);
                  const diffDays = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));

                  if ([7, 3, 1].includes(diffDays)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Fatura Próxima ao Vencimento',
                          message: `A fatura de R$ ${tx.amount} (${tx.description}) vence em ${diffDays} dia(s).`,
                          type: 'WARNING',
                          priority: diffDays === 1 ? 'HIGH' : 'MEDIUM',
                          originModule: 'FINANCE',
                          targetRole: 'FINANCE',
                          navToView: 'finance'
                      });
                  }
              }
          });

          // 2. CRM: Leads parados sem follow-up (> 3 dias)
          leads.forEach(lead => {
              if (!lead.lastContact) return;
              const lastContact = new Date(lead.lastContact);
              const diffDays = Math.ceil((now.getTime() - lastContact.getTime()) / (1000 * 60 * 60 * 24));
              if (diffDays >= 3 && lead.stage !== 'WON') {
                  updatedNotifs = NotificationService.create(updatedNotifs, {
                      title: 'Lead Sem Follow-up',
                      message: `O lead ${lead.company} está sem contato há ${diffDays} dias.`,
                      type: 'WARNING',
                      priority: 'MEDIUM',
                      originModule: 'CRM',
                      targetUserId: currentUser.id, 
                      navToView: 'crm'
                  });
              }
          });

          // 3. KANBAN: Prazos próximos (24h e 2h)
          tasks.forEach(task => {
              if (task.status !== 'DONE' && !task.archived) {
                  const dueDate = new Date(task.dueDate);
                  const diffMs = dueDate.getTime() - now.getTime();
                  const diffHours = diffMs / (1000 * 60 * 60);

                  if (diffHours > 0 && diffHours <= 24 && task.assigneeIds.includes(currentUser.id)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Prazo de Tarefa Próximo',
                          message: `A tarefa "${task.title}" vence em menos de 24h!`,
                          type: 'WARNING',
                          priority: diffHours <= 2 ? 'HIGH' : 'MEDIUM',
                          originModule: 'KANBAN',
                          targetUserId: currentUser.id,
                          navToView: 'kanban'
                      });
                  }
              }
          });

          if (updatedNotifs.length !== notifications.length) {
              setNotifications(updatedNotifs);
          }
      };

      const interval = setInterval(checkAutomations, 60000); 
      checkAutomations(); 
      return () => clearInterval(interval);
  }, [transactions, leads, tasks, currentUser, notifications]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const handleNotificationAction = (id: string, action: 'READ' | 'ARCHIVE') => {
      setNotifications(prev => prev.map(n => {
          if (n.id === id) {
              return { ...n, status: action === 'READ' ? 'READ' : 'ARCHIVED' };
          }
          return n;
      }));
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  const getPriorityStyle = (priority: string) => {
      if (priority === 'HIGH') return 'border-l-4 border-red-500 bg-red-50/30';
      return '';
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const filteredNotifs = NotificationService.filterByTab(notifications, activeNotifTab)
      .filter(n => !n.targetUserId || n.targetUserId === currentUser.id)
      .filter(n => !n.targetRole || n.targetRole === currentUser.role);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  // Layout Dynamic Classes
  const contentMargin = !sidebarOpen ? 'ml-0' : (sidebarCompact ? 'ml-20' : 'ml-64');

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main className={`flex-1 flex flex-col p-8 min-h-screen transition-all duration-300 ease-in-out ${contentMargin}`}>
        <div className="flex justify-end items-center mb-8 gap-4 relative shrink-0">
            <div className="relative" ref={notificationRef}>
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 rounded-full border transition-all relative bg-white">
                    <Bell size={20} className="text-slate-500" />
                    {unreadCount > 0 && (
                        <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-white animate-bounce">
                            {unreadCount > 9 ? '9+' : unreadCount}
                        </span>
                    )}
                </button>

                {showNotifications && (
                    <div className="absolute right-0 top-full mt-3 w-[420px] bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden z-[100] animate-pop origin-top-right">
                        <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                            <h3 className="font-bold text-slate-800">Central de Alertas</h3>
                            <button onClick={markAllAsRead} className="text-xs font-bold text-pink-600 hover:text-pink-700 flex items-center gap-1">
                                <Check size={14}/> Marcar todas como lidas
                            </button>
                        </div>

                        <div className="flex bg-white border-b overflow-x-auto hide-scrollbar">
                            {['ALL', 'HIGH', 'KANBAN', 'FINANCE', 'CRM'].map(tab => (
                                <button 
                                    key={tab}
                                    onClick={() => setActiveNotifTab(tab)}
                                    className={`px-4 py-3 text-[10px] font-bold uppercase tracking-wider whitespace-nowrap border-b-2 transition-colors ${activeNotifTab === tab ? 'border-pink-600 text-pink-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
                                >
                                    {tab === 'ALL' ? 'Todas' : tab === 'HIGH' ? 'Urgentes' : tab}
                                </button>
                            ))}
                        </div>

                        <div className="max-h-[450px] overflow-y-auto custom-scrollbar">
                            {filteredNotifs.length === 0 ? (
                                <div className="p-12 text-center flex flex-col items-center gap-3">
                                    <Bell size={32} className="text-slate-200"/>
                                    <p className="text-sm text-slate-400">Nenhuma notificação por aqui.</p>
                                </div>
                            ) : (
                                filteredNotifs.map(notif => (
                                    <div 
                                        key={notif.id} 
                                        className={`p-4 border-b border-slate-50 transition-all group relative ${getPriorityStyle(notif.priority)} ${notif.status === 'UNREAD' ? 'bg-blue-50/10' : 'opacity-70'}`}
                                    >
                                        <div className="flex gap-3">
                                            <div className={`p-2 rounded-lg h-fit ${notif.priority === 'HIGH' ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-500'}`}>
                                                {notif.originModule === 'FINANCE' ? <DollarSign size={16}/> : notif.originModule === 'CRM' ? <Briefcase size={16}/> : <Clock size={16}/>}
                                            </div>
                                            <div className="flex-1 cursor-pointer" onClick={() => { if(notif.navToView) setCurrentView(notif.navToView); handleNotificationAction(notif.id, 'READ'); setShowNotifications(false); }}>
                                                <div className="flex justify-between items-start mb-1">
                                                    <p className={`text-sm font-bold ${notif.status === 'UNREAD' ? 'text-slate-800' : 'text-slate-500'}`}>{notif.title}</p>
                                                    <span className="text-[10px] text-slate-400">{new Date(notif.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                </div>
                                                <p className="text-xs text-slate-600 leading-relaxed">{notif.message}</p>
                                                {notif.status === 'UNREAD' && <span className="inline-block w-2 h-2 bg-blue-500 rounded-full mt-2"></span>}
                                            </div>
                                            <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <button onClick={() => handleNotificationAction(notif.id, 'READ')} className="p-1.5 hover:bg-slate-100 rounded text-slate-400 hover:text-emerald-600" title="Lida"><Check size={14}/></button>
                                                <button onClick={() => handleNotificationAction(notif.id, 'ARCHIVE')} className="p-1.5 hover:bg-slate-100 rounded text-slate-400 hover:text-red-500" title="Arquivar"><Archive size={14}/></button>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                        <div className="p-3 bg-slate-50 border-t text-center">
                            <button onClick={() => { setActiveNotifTab('ALL'); setCurrentView('dashboard'); setShowNotifications(false); }} className="text-[10px] font-bold text-slate-400 hover:text-slate-600 uppercase tracking-widest">Ver Histórico Completo</button>
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-3 bg-white px-4 py-2 rounded-full shadow-sm border border-slate-100 hover:shadow-md transition-shadow cursor-pointer" onClick={() => setCurrentView('settings')}>
                <div className="text-right hidden md:block">
                    <p className="text-sm font-bold text-slate-800">{currentUser.name}</p>
                    <p className="text-xs text-slate-500">{currentUser.role}</p>
                </div>
                <img src={currentUser.avatar} alt="Perfil" className="w-10 h-10 rounded-full border-2 border-slate-100" />
            </div>
        </div>

        <div className="flex-1">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} setNotifications={setNotifications} />}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} setNotifications={setNotifications} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React from 'react';
import { 
  LayoutDashboard, Kanban, Users, DollarSign, Briefcase, LogOut, 
  PieChart, BarChart2, Shield, HeartHandshake, ShoppingBag, 
  ShoppingCart, Settings, HelpCircle, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { Role, RolePermissions, SystemSettings } from '../types';

interface SidebarProps {
  currentView: string;
  setView: (view: string) => void;
  currentUserRole: Role;
  permissions: RolePermissions;
  logout: () => void;
  systemSettings: SystemSettings;
  isOpen: boolean;
  onToggle: () => void;
  isCompact: boolean;
  onToggleCompact: () => void;
  isMobile: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  setView, 
  currentUserRole, 
  permissions, 
  logout, 
  systemSettings,
  isOpen,
  onToggle,
  isCompact,
  onToggleCompact,
  isMobile
}) => {
  const menuItems = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard },
    { id: 'kanban', label: 'Tarefas (Kanban)', icon: Kanban },
    { id: 'productivity', label: 'Produtividade', icon: BarChart2 },
    { id: 'requisitions', label: 'Solicitações', icon: ShoppingCart },
    { id: 'client-portal', label: 'Meus Pedidos', icon: PieChart },
    { id: 'clients', label: 'Gestão de Clientes', icon: HeartHandshake },
    { id: 'catalog', label: 'Produtos & Serviços', icon: ShoppingBag },
    { id: 'teams', label: 'Equipes & Squads', icon: Users },
    { id: 'crm', label: 'CRM / Vendas', icon: Briefcase },
    { id: 'finance', label: 'Financeiro', icon: DollarSign },
    { id: 'permissions', label: 'Acessos (Admin)', icon: Shield },
    { id: 'system-admin', label: 'Config. Sistema', icon: Settings },
    { id: 'help', label: 'Central de Ajuda', icon: HelpCircle },
  ];

  const allowedModules = permissions[currentUserRole] || [];

  const handleToggleAction = () => {
    if (isMobile) {
      // No mobile, se estiver aberto, fecha. Se estiver fechado, abre em modo compacto.
      onToggle();
    } else {
      onToggle();
    }
  };

  return (
    <div 
        className={`fixed left-0 top-0 h-screen z-50 transition-all duration-300 ease-in-out border-r border-slate-800 flex flex-col
          ${!isOpen ? '-translate-x-full' : 'translate-x-0'}
          ${isCompact ? 'w-20' : 'w-64'}
        `}
        style={{ backgroundColor: systemSettings.sidebarColor || '#0f172a' }}
    >
      {/* Sidebar Control Button */}
      <button 
        onClick={handleToggleAction}
        title={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        className={`absolute top-10 -right-4 w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-lg hover:scale-110 transition-all z-50
          ${!isOpen ? 'translate-x-4' : ''}
        `}
        style={{ color: systemSettings.sidebarColor }}
      >
        {isOpen ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
      </button>

      {/* Header / Logo */}
      <div className={`p-6 flex items-center transition-all duration-300 ${isCompact ? 'justify-center p-4' : 'gap-3'}`}>
        {systemSettings.logo ? (
            <img src={systemSettings.logo} alt="Logo" className="w-8 h-8 object-contain rounded bg-white p-0.5 shrink-0" />
        ) : (
            <div 
                className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shrink-0"
                style={{ backgroundColor: systemSettings.primaryColor }}
            >
                {systemSettings.agencyName.charAt(0)}
            </div>
        )}
        {!isCompact && (
          <span className="text-lg font-bold text-white tracking-tight truncate animate-pop" title={systemSettings.agencyName}>
              {systemSettings.agencyName}
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 space-y-2 mt-4 overflow-y-auto hide-scrollbar">
        {menuItems.map((item) => {
           const isAllowed = allowedModules.includes(item.id) || item.id === 'help';
           if (!isAllowed) return null;

           const active = currentView === item.id;

           return (
            <button
              key={item.id}
              onClick={() => setView(item.id)}
              title={isCompact ? item.label : ""}
              className={`w-full flex items-center rounded-lg transition-all duration-200 
                ${isCompact ? 'justify-center py-3' : 'px-4 py-3 gap-3'}
                ${active ? 'text-white shadow-lg' : 'text-slate-400 hover:bg-black/20 hover:text-white'}
              `}
              style={active ? { backgroundColor: systemSettings.primaryColor, boxShadow: `0 10px 15px -3px ${systemSettings.primaryColor}40` } : {}}
            >
              <item.icon size={20} className="shrink-0" />
              {!isCompact && (
                <span className="font-medium truncate animate-pop">{item.label}</span>
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer / Logout */}
      <div className={`p-4 border-t border-white/10 ${isCompact ? 'flex justify-center' : ''}`}>
        <button 
          onClick={logout} 
          title={isCompact ? "Sair" : ""}
          className={`flex items-center text-red-400 hover:text-red-300 w-full hover:bg-red-500/10 rounded-lg transition-colors
            ${isCompact ? 'justify-center p-3' : 'px-4 py-3 gap-3'}
          `}
        >
          <LogOut size={20} className="shrink-0" />
          {!isCompact && <span className="animate-pop">Sair</span>}
        </button>
      </div>

      {/* Mobile-only toggle between Compact and Full when open */}
      {isMobile && isOpen && (
        <button 
          onClick={onToggleCompact}
          className="p-3 mx-4 mb-4 bg-white/5 hover:bg-white/10 rounded-lg flex items-center justify-center text-slate-400 transition-colors"
          title={isCompact ? "Expandir Menu" : "Recolher Menu"}
        >
          {isCompact ? <ChevronRight size={16}/> : <ChevronLeft size={16}/>}
        </button>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { NotificationService } from './services/notificationService';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, LeadTask, ConfirmOptions } from './types';
import { Users, Settings, Bell, Check, Gift, AlertTriangle, Info, Clock, CheckCircle, Shield, Trash2, Archive, Eye, DollarSign, Briefcase } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  // --- SIDEBAR STATE & PERSISTENCE ---
  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      // No mobile, se estiver aberto, garantimos que comece compacto para não tampar tudo
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
    console.log("SIDEBAR_TOGGLE", { isOpen: sidebarOpen, isCompact: sidebarCompact, viewport: isMobile ? "mobile" : "desktop" });
  }, [sidebarOpen, sidebarCompact, isMobile]);

  const toggleSidebar = () => {
      if (isMobile) {
          // No mobile: Oculto -> Compacto -> Oculto
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          // No desktop: Toggle Simples Aberto/Oculto
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  // --- REST OF STATE ---
  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const [activeNotifTab, setActiveNotifTab] = useState('ALL');
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Automations logic (Background worker simulator)
  useEffect(() => {
      if (!currentUser) return;
      const checkAutomations = () => {
          const now = new Date();
          let updatedNotifs = [...notifications];
          transactions.forEach(tx => {
              if (tx.status === 'PENDING' && tx.type === 'INCOME') {
                  const dueDate = new Date(tx.dueDate);
                  const diffDays = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
                  if ([7, 3, 1].includes(diffDays)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Fatura Próxima ao Vencimento',
                          message: `A fatura de R$ ${tx.amount} (${tx.description}) vence em ${diffDays} dia(s).`,
                          type: 'WARNING',
                          priority: diffDays === 1 ? 'HIGH' : 'MEDIUM',
                          originModule: 'FINANCE',
                          targetRole: 'FINANCE',
                          navToView: 'finance'
                      });
                  }
              }
          });
          leads.forEach(lead => {
              if (!lead.lastContact) return;
              const lastContact = new Date(lead.lastContact);
              const diffDays = Math.ceil((now.getTime() - lastContact.getTime()) / (1000 * 60 * 60 * 24));
              if (diffDays >= 3 && lead.stage !== 'WON') {
                  updatedNotifs = NotificationService.create(updatedNotifs, {
                      title: 'Lead Sem Follow-up',
                      message: `O lead ${lead.company} está sem contato há ${diffDays} dias.`,
                      type: 'WARNING',
                      priority: 'MEDIUM',
                      originModule: 'CRM',
                      targetUserId: currentUser.id, 
                      navToView: 'crm'
                  });
              }
          });
          tasks.forEach(task => {
              if (task.status !== 'DONE' && !task.archived) {
                  const dueDate = new Date(task.dueDate);
                  const diffMs = dueDate.getTime() - now.getTime();
                  const diffHours = diffMs / (1000 * 60 * 60);
                  if (diffHours > 0 && diffHours <= 24 && task.assigneeIds.includes(currentUser.id)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Prazo de Tarefa Próximo',
                          message: `A tarefa "${task.title}" vence em menos de 24h!`,
                          type: 'WARNING',
                          priority: diffHours <= 2 ? 'HIGH' : 'MEDIUM',
                          originModule: 'KANBAN',
                          targetUserId: currentUser.id,
                          navToView: 'kanban'
                      });
                  }
              }
          });
          if (updatedNotifs.length !== notifications.length) {
              setNotifications(updatedNotifs);
          }
      };
      const interval = setInterval(checkAutomations, 60000); 
      checkAutomations(); 
      return () => clearInterval(interval);
  }, [transactions, leads, tasks, currentUser, notifications]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const handleNotificationAction = (id: string, action: 'READ' | 'ARCHIVE') => {
      setNotifications(prev => prev.map(n => {
          if (n.id === id) {
              return { ...n, status: action === 'READ' ? 'READ' : 'ARCHIVED' };
          }
          return n;
      }));
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const filteredNotifs = NotificationService.filterByTab(notifications, activeNotifTab)
      .filter(n => !n.targetUserId || n.targetUserId === currentUser.id)
      .filter(n => !n.targetRole || n.targetRole === currentUser.role);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  // --- DYNAMIC LAYOUT CALCULATION ---
  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  const contentMargin = !isMobile ? getSidebarWidth() : '0px';
  // Se no mobile estiver aberto (mesmo que compacto), adicionamos um pequeno padding lateral ou overlay.
  // Para manter a usabilidade pedida (conteúdo legível ao lado), usaremos margin-left apenas se compact.
  const mobileMargin = (isMobile && sidebarOpen && sidebarCompact) ? '80px' : '0px';

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className="flex-1 flex flex-col min-h-screen transition-all duration-300 ease-in-out p-4 md:p-8"
        style={{ marginLeft: !isMobile ? contentMargin : mobileMargin }}
      >
        <div className="flex justify-between items-center mb-6 md:mb-8 gap-4 relative shrink-0">
            {/* Título de seção para mobile quando menu está oculto */}
            <div className="md:hidden font-black text-slate-400 text-xs uppercase tracking-widest truncate">
                {currentView}
            </div>

            <div className="flex items-center gap-2 ml-auto">
                <div className="relative" ref={notificationRef}>
                    <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 rounded-full border transition-all relative bg-white">
                        <Bell size={20} className="text-slate-500" />
                        {unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-white animate-bounce">
                                {unreadCount > 9 ? '9+' : unreadCount}
                            </span>
                        )}
                    </button>

                    {showNotifications && (
                        <div className="absolute right-0 top-full mt-3 w-[320px] md:w-[420px] bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden z-[100] animate-pop origin-top-right">
                            <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                                <h3 className="font-bold text-slate-800">Alertas</h3>
                                <button onClick={markAllAsRead} className="text-xs font-bold text-pink-600 hover:text-pink-700 flex items-center gap-1">
                                    <Check size={14}/> Lidas
                                </button>
                            </div>
                            <div className="max-h-[450px] overflow-y-auto custom-scrollbar">
                                {filteredNotifs.length === 0 ? (
                                    <div className="p-12 text-center flex flex-col items-center gap-3">
                                        <Bell size={32} className="text-slate-200"/>
                                        <p className="text-sm text-slate-400">Nenhuma notificação.</p>
                                    </div>
                                ) : (
                                    filteredNotifs.map(notif => (
                                        <div key={notif.id} className={`p-4 border-b border-slate-50 transition-all group relative ${notif.status === 'UNREAD' ? 'bg-blue-50/10' : 'opacity-70'}`}>
                                            <div className="flex gap-3">
                                                <div className="flex-1 cursor-pointer" onClick={() => { if(notif.navToView) setCurrentView(notif.navToView); handleNotificationAction(notif.id, 'READ'); setShowNotifications(false); }}>
                                                    <p className={`text-sm font-bold ${notif.status === 'UNREAD' ? 'text-slate-800' : 'text-slate-500'}`}>{notif.title}</p>
                                                    <p className="text-xs text-slate-600 leading-relaxed line-clamp-2">{notif.message}</p>
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="flex items-center gap-2 bg-white px-3 md:px-4 py-2 rounded-full shadow-sm border border-slate-100 hover:shadow-md transition-shadow cursor-pointer" onClick={() => setCurrentView('settings')}>
                    <div className="text-right hidden sm:block">
                        <p className="text-sm font-bold text-slate-800">{currentUser.name}</p>
                        <p className="text-[10px] text-slate-500 uppercase font-black">{currentUser.role}</p>
                    </div>
                    <img src={currentUser.avatar} alt="Perfil" className="w-8 h-8 md:w-10 md:h-10 rounded-full border-2 border-slate-100" />
                </div>
            </div>
        </div>

        <div className="flex-1 w-full max-w-full overflow-x-hidden">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} setNotifications={setNotifications} />}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React from 'react';
import { 
  LayoutDashboard, Kanban, Users, DollarSign, Briefcase, LogOut, 
  PieChart, BarChart2, Shield, HeartHandshake, ShoppingBag, 
  ShoppingCart, Settings, HelpCircle, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { Role, RolePermissions, SystemSettings } from '../types';

interface SidebarProps {
  currentView: string;
  setView: (view: string) => void;
  currentUserRole: Role;
  permissions: RolePermissions;
  logout: () => void;
  systemSettings: SystemSettings;
  isOpen: boolean;
  onToggle: () => void;
  isCompact: boolean;
  onToggleCompact: () => void;
  isMobile: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  setView, 
  currentUserRole, 
  permissions, 
  logout, 
  systemSettings,
  isOpen,
  onToggle,
  isCompact,
  onToggleCompact,
  isMobile
}) => {
  const menuItems = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard },
    { id: 'kanban', label: 'Tarefas (Kanban)', icon: Kanban },
    { id: 'productivity', label: 'Produtividade', icon: BarChart2 },
    { id: 'requisitions', label: 'Solicitações', icon: ShoppingCart },
    { id: 'client-portal', label: 'Meus Pedidos', icon: PieChart },
    { id: 'clients', label: 'Gestão de Clientes', icon: HeartHandshake },
    { id: 'catalog', label: 'Produtos & Serviços', icon: ShoppingBag },
    { id: 'teams', label: 'Equipes & Squads', icon: Users },
    { id: 'crm', label: 'CRM / Vendas', icon: Briefcase },
    { id: 'finance', label: 'Financeiro', icon: DollarSign },
    { id: 'permissions', label: 'Acessos (Admin)', icon: Shield },
    { id: 'system-admin', label: 'Config. Sistema', icon: Settings },
    { id: 'help', label: 'Central de Ajuda', icon: HelpCircle },
  ];

  const allowedModules = permissions[currentUserRole] || [];

  return (
    <div 
        className={`fixed left-0 top-0 h-screen z-[110] transition-all duration-300 ease-in-out border-r border-slate-800 flex flex-col
          ${!isOpen ? '-translate-x-full' : 'translate-x-0'}
          ${isCompact ? 'w-20' : 'w-64'}
        `}
        style={{ backgroundColor: systemSettings.sidebarColor || '#0f172a' }}
    >
      {/* SIDEBAR TOGGLE BUTTON (CHEVRON) */}
      <button 
        onClick={onToggle}
        aria-label={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        title={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        className={`absolute top-10 -right-4 w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-lg hover:scale-110 transition-all z-[120] text-slate-800
          ${!isOpen ? 'translate-x-12 opacity-100' : ''}
        `}
      >
        {isOpen ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
      </button>

      {/* Header / Logo */}
      <div className={`p-6 flex items-center transition-all duration-300 ${isCompact ? 'justify-center p-4' : 'gap-3'}`}>
        {systemSettings.logo ? (
            <img src={systemSettings.logo} alt="Logo" className="w-8 h-8 object-contain rounded bg-white p-0.5 shrink-0" />
        ) : (
            <div 
                className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shrink-0"
                style={{ backgroundColor: systemSettings.primaryColor }}
            >
                {systemSettings.agencyName.charAt(0)}
            </div>
        )}
        {!isCompact && (
          <span className="text-lg font-bold text-white tracking-tight truncate animate-pop" title={systemSettings.agencyName}>
              {systemSettings.agencyName}
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 space-y-2 mt-4 overflow-y-auto hide-scrollbar">
        {menuItems.map((item) => {
           const isAllowed = allowedModules.includes(item.id) || item.id === 'help';
           if (!isAllowed) return null;

           const active = currentView === item.id;

           return (
            <button
              key={item.id}
              onClick={() => {
                  setView(item.id);
                  if (isMobile && !isCompact) onToggle(); // Fecha se for menu full no mobile
              }}
              title={isCompact ? item.label : ""}
              className={`w-full flex items-center rounded-lg transition-all duration-200 
                ${isCompact ? 'justify-center py-3' : 'px-4 py-3 gap-3'}
                ${active ? 'text-white shadow-lg shadow-pink-500/20' : 'text-slate-400 hover:bg-black/20 hover:text-white'}
              `}
              style={active ? { backgroundColor: systemSettings.primaryColor } : {}}
            >
              <item.icon size={20} className="shrink-0" />
              {!isCompact && (
                <span className="font-medium truncate text-sm animate-pop">{item.label}</span>
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer / Logout */}
      <div className={`p-4 border-t border-white/10 ${isCompact ? 'flex justify-center' : ''}`}>
        <button 
          onClick={logout} 
          title={isCompact ? "Sair" : ""}
          className={`flex items-center text-red-400 hover:text-red-300 w-full hover:bg-red-500/10 rounded-lg transition-colors
            ${isCompact ? 'justify-center p-3' : 'px-4 py-3 gap-3'}
          `}
        >
          <LogOut size={20} className="shrink-0" />
          {!isCompact && <span className="text-sm font-bold">Sair</span>}
        </button>
      </div>

      {/* Desktop-only toggle between Compact and Full (Optional UX) */}
      {!isMobile && isOpen && (
        <button 
          onClick={onToggleCompact}
          className="p-3 mx-4 mb-4 bg-white/5 hover:bg-white/10 rounded-lg flex items-center justify-center text-slate-500 transition-colors"
          title={isCompact ? "Expandir Menu" : "Recolher Menu"}
        >
          {isCompact ? <ChevronRight size={16}/> : <ChevronLeft size={16}/>}
        </button>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Task, Lead, FinancialRecord, User } from '../types';
import { Layout, Zap, AlertTriangle, Archive, PieChart as PieChartIcon, BarChart2, TrendingUp, Calendar, AlertCircle, Clock } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell, Legend } from 'recharts';

interface DashboardProps {
  tasks: Task[];
  leads: Lead[];
  finance: FinancialRecord[];
  users: User[];
}

export const DashboardOverview: React.FC<DashboardProps> = ({ tasks, leads, finance, users }) => {
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [activePreset, setActivePreset] = useState<'7days' | '30days' | 'quarter' | 'custom'>('30days');

  const applyPreset = (days: number, presetName: '7days' | '30days' | 'quarter') => {
      const end = new Date();
      const start = new Date();
      start.setDate(end.getDate() - days);
      setEndDate(end.toISOString().split('T')[0]);
      setStartDate(start.toISOString().split('T')[0]);
      setActivePreset(presetName);
  };

  const handleCustomDateChange = (type: 'start' | 'end', value: string) => {
      if (type === 'start') setStartDate(value);
      else setEndDate(value);
      setActivePreset('custom');
  };

  const filterByDate = (dateStr: string) => {
      if (!dateStr) return false;
      return dateStr >= startDate && dateStr <= endDate;
  };

  const filteredTasks = useMemo(() => tasks.filter(t => filterByDate(t.dueDate) || t.status === 'IN_PROGRESS'), [tasks, startDate, endDate]);
  const filteredFinance = useMemo(() => finance.filter(f => filterByDate(f.dueDate)), [finance, startDate, endDate]);

  const activeTasks = tasks.filter(t => !t.archived && t.status !== 'DONE');
  const inProgressCount = activeTasks.filter(t => t.status === 'IN_PROGRESS').length;
  const overdueCount = tasks.filter(t => !t.archived && t.status !== 'DONE' && new Date(t.dueDate) < new Date(new Date().setHours(0,0,0,0))).length;
  const archivedCount = tasks.filter(t => t.archived).length;
  const revenue = filteredFinance.filter(f => f.type === 'INCOME' && f.status === 'PAID').reduce((acc, c) => acc + c.amount, 0);

  const statusDistribution = [
