                <span className="text-slate-400 text-xs">-</span>
                <input type="date" value={endDate} onChange={(e) => handleCustomDateChange('end', e.target.value)} className="text-[10px] text-slate-600 outline-none bg-white border border-slate-200 rounded px-2 py-1 flex-1 sm:flex-none" />
