                                             <div key={item.data.id} className="flex gap-4 animate-pop">
                                                 <img src={u.avatar} className="w-10 h-10 rounded-full border border-slate-100" />
                                                 <div className="flex-1"><div className="flex items-baseline gap-2 mb-1"><span className="font-black text-sm text-slate-800">{u.name}</span><span className="text-[10px] font-bold text-slate-400">{new Date(item.timestamp).toLocaleString()}</span></div><div className="bg-white p-4 rounded-2xl border border-slate-100 text-sm text-slate-600 shadow-sm leading-relaxed">{item.data.text}</div></div>
                                             </div>
                                         ) : (
                                            <div key={item.data.id} className="flex gap-4 items-center ml-3 opacity-60"><div className="w-4 h-4 bg-slate-100 rounded-full flex items-center justify-center"><div className="w-1.5 h-1.5 bg-slate-300 rounded-full"></div></div><div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase"><span className="text-slate-600">{u.name}</span><span>{item.data.action}</span><span>• {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span></div></div>
                                         );
