                    <div className="w-full md:w-56 space-y-3 shrink-0">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Ações Rápidas</h4>
                        {task.status !== 'DONE' && <button onClick={() => updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job')} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white p-3 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 transition-all active:scale-95"><CheckCircle size={16}/> Finalizar Job</button>}
                        <div className="py-2"></div>
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Gerenciar</h4>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'MEMBERS' ? null : 'MEMBERS')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'MEMBERS' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><Users size={16}/> Membros</button>
                            {activePopover === 'MEMBERS' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-72 bg-white rounded-2xl shadow-2xl border border-slate-100 z-50 p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-3 text-center">Atribuir Colaboradores</h5>
                                    <div className="relative mb-4"><Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-100 rounded-lg text-xs outline-none" placeholder="Buscar..." value={memberSearch} onChange={e => setMemberSearch(e.target.value)} /></div>
                                    <div className="space-y-1 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
                                        {users.filter(u => u.role !== 'CLIENT' && u.name.toLowerCase().includes(memberSearch.toLowerCase())).map(u => {
                                            const isSelected = task.assigneeIds.includes(u.id);
                                            return <button key={u.id} onClick={() => toggleMember(u.id)} className={`w-full flex items-center justify-between p-2 rounded-lg transition-colors ${isSelected ? 'bg-pink-50 text-pink-700' : 'hover:bg-slate-50 text-slate-600'}`}><div className="flex items-center gap-2 text-left"><img src={u.avatar} className="w-6 h-6 rounded-full" /><div><p className="text-xs font-bold">{u.name}</p><p className="text-[9px] opacity-60 uppercase">{u.role}</p></div></div>{isSelected && <Check size={14}/>}</button>;
                                        })}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'COVER' ? null : 'COVER')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'COVER' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><ImageIcon size={16}/> Capa</button>
                            {activePopover === 'COVER' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-64 bg-white rounded-2xl shadow-2xl border border-slate-100 z-50 p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-4 text-center">Cor de Capa</h5>
                                    <div className="grid grid-cols-4 gap-2">{PRESET_COLORS.map(c => <button key={c} onClick={() => setCoverColor(c)} className="w-full aspect-square rounded-lg shadow-sm hover:scale-105 transition-transform" style={{ backgroundColor: c }} />)}</div>
                                </div>
                            )}
                        </div>
                        <div className="py-2 border-t border-slate-100"></div>
                        <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'restaurou o job' : 'arquivou o job')} className="w-full text-left p-3 rounded-xl text-xs font-bold text-slate-500 hover:bg-slate-100 flex items-center gap-2 transition-all"><Archive size={16}/> {task.archived ? 'Desarquivar' : 'Arquivar'}</button>
                        {(currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER') && <button onClick={() => onDeleteTask(task.id)} className="w-full text-left p-3 rounded-xl text-xs font-bold text-red-400 hover:bg-red-50 flex items-center gap-2 transition-all"><Trash2 size={16}/> Excluir permanentemente</button>}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Plus, Calendar, Archive, Eye, Inbox, Play, Pause, Clock, MoreVertical, Settings, 
    GripHorizontal, X, Edit2, ArchiveRestore, AlertCircle, Info, Trash2
} from 'lucide-react';
import confetti from 'canvas-confetti';
import { TaskModal } from './TaskModal';
import { NotificationService } from '../services/notificationService';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ tasks, setTasks, users, currentUser, columns, setColumns, setNotifications, openConfirm }) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [columnMenuId, setColumnMenuId] = useState<string | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const isManagerOrAdmin = currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER';
  const pendingRequests = tasks.filter(t => t.clientRequest && t.approvalStatus === 'PENDING');

  useEffect(() => {
    if(isColumnModalOpen) console.log("POPUP_OPENED", { type: 'ColumnModal' });
    if(showArchivedColumns) console.log("POPUP_OPENED", { type: 'ArchivedColumnsModal' });
  }, [isColumnModalOpen, showArchivedColumns]);

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const archivedColumns = useMemo(() => 
    columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order),
  [columns]);

  const formatSeconds = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    if (h > 0) return `${h}h ${m}m`;
    return `${m}m`;
  };

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'col-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'border-slate-400',
            order: columns.length,
            wipLimit: editingColumn.wipLimit || null,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleArchiveColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;
      const hasTasks = tasks.some(t => t.status === colId && !t.archived);
      if (hasTasks) {
          alert("Mova as tarefas ativas desta coluna antes de arquivá-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Arquivar Lista?",
          description: `A lista "${col.label}" será ocultada.`,
          confirmText: "Arquivar"
      });
      if (ok) {
          setColumns(prev => prev.map(c => c.id === colId ? { ...c, isArchived: true } : c));
          setColumnMenuId(null);
      }
  };

  const handleDeleteColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;

      const hasTasks = tasks.some(t => t.status === colId);
      if (hasTasks) {
          alert("Esta coluna possui tarefas (ativas ou arquivadas). Exclua ou mova as tarefas antes de remover a coluna definitivamente.");
          return;
      }

      const ok = await openConfirm({
          title: "Excluir Lista Permanentemente?",
          description: `Deseja remover a lista "${col.label}" do sistema? Esta ação é irreversível.`,
          variant: "danger",
          confirmText: "Excluir Definitivamente"
      });

      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
          setColumnMenuId(null);
      }
  };

  const handleRestoreColumn = (colId: string) => {
      setColumns(prev => prev.map(c => c.id === colId ? { ...c, isArchived: false } : c));
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) {
          e.preventDefault();
          return;
      }
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
      e.dataTransfer.effectAllowed = 'move';
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const draggedIdx = columns.findIndex(c => c.id === draggedColumnId);
      const targetIdx = columns.findIndex(c => c.id === targetColId);
      const newCols = [...columns];
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  const handleApprove = (taskId: string) => {
      const task = tasks.find(t => t.id === taskId);
      if(!task) return;
      setTasks(prev => prev.map(t => t.id === taskId ? { 
          ...t, 
          approvalStatus: 'APPROVED', 
          status: activeColumns[0]?.id || 'BACKLOG',
          history: [...t.history, { id: Date.now().toString(), action: 'Aprovou a solicitação', userId: currentUser.id, timestamp: Date.now() }] 
      } : t));
      setNotifications(prev => NotificationService.create(prev, {
          title: 'Solicitação Aprovada',
          message: `O job "${task.title}" entrou em produção.`,
          type: 'SUCCESS',
          priority: 'MEDIUM',
          originModule: 'KANBAN',
          targetUserId: task.assigneeIds[0],
          navToView: 'kanban'
      }));
      confetti({ particleCount: 50, spread: 50, origin: { y: 0.6 } });
  };

  const updateTask = (updated: Task) => {
      setTasks(prev => {
          const exists = prev.some(t => t.id === updated.id);
          return exists ? prev.map(t => t.id === updated.id ? updated : t) : [...prev, updated];
      });
      if (selectedTask && selectedTask.id === updated.id) setSelectedTask(updated);
  };

  const toggleTimerQuick = (e: React.MouseEvent, task: Task) => {
    e.stopPropagation();
    const now = Date.now();
    let updatedTask = { ...task };
    if (task.isTracking) {
      const updatedLogs = task.timeLogs.map(log => {
        if (!log.endTime) {
          const endTime = now;
          const duration = Math.floor((endTime - log.startTime) / 1000);
          return { ...log, endTime, duration };
        }
        return log;
      });
      updatedTask = { ...task, isTracking: false, timeLogs: updatedLogs };
    } else {
      const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
      const newStatus = (task.status === 'BACKLOG' || task.status === 'TODO') ? 'IN_PROGRESS' : task.status;
      updatedTask = { ...task, isTracking: true, status: newStatus, timeLogs: [...task.timeLogs, newLog] };
    }
    updateTask(updatedTask);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (e.dataTransfer.getData('type') === 'column') return;
      if (!draggedTaskId) return;

      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          const col = columns.find(c => c.id === targetColId);
          const currentTasksInCol = tasks.filter(t => t.status === targetColId && !t.archived).length;
          if (col?.wipLimit && currentTasksInCol >= col.wipLimit) {
              alert(`Limite de WIP atingido para ${col.label} (${col.wipLimit}).`);
              setDraggedTaskId(null);
              return;
          }
          const isDone = targetColId === 'DONE';
          let updatedTask: Task = {
              ...task,
              status: targetColId,
              completedAt: isDone ? Date.now() : task.completedAt,
              history: [...task.history, { id: Date.now().toString(), action: `moveu para ${col?.label}`, userId: currentUser.id, timestamp: Date.now() }]
          };
          if (isDone && task.isTracking) {
            updatedTask.isTracking = false;
            updatedTask.timeLogs = task.timeLogs.map(log => {
              if (!log.endTime) {
                const endTime = Date.now();
                const duration = Math.floor((endTime - log.startTime) / 1000);
                return { ...log, endTime, duration };
              }
              return log;
            });
          }
          updateTask(updatedTask);
          if (targetColId === 'DONE') confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
      }
      setDraggedTaskId(null);
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Quadro de Jobs</h2>
          <p className="text-slate-500 text-sm font-medium">Fluxo ágil de produção e entregas</p>
        </div>
        <div className="flex gap-2">
            {isAdmin && (
                <button onClick={() => setShowArchivedColumns(true)} className="px-3 py-2 rounded-xl text-xs font-black bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 flex items-center gap-2 transition-all uppercase tracking-wider">
                    <Settings size={16}/> Listas
                </button>
            )}
            <button onClick={() => setShowArchived(!showArchived)} className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider flex items-center gap-2 transition-all border ${showArchived ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}>
                {showArchived ? <Eye size={16}/> : <Archive size={16}/>} {showArchived ? 'Ver Ativos' : 'Arquivados'}
            </button>
            <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: new Date().toISOString().split('T')[0], estimatedTime: 0, timeLogs: [], isTracking: false, assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], archived: false } as Task)} className="bg-pink-600 text-white px-5 py-2 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-500/30 hover:bg-pink-700 transition-all">
                <Plus size={18} strokeWidth={3} /> Novo Job
            </button>
        </div>
      </div>

      {isManagerOrAdmin && pendingRequests.length > 0 && (
          <div className="mb-6 bg-amber-50 border-2 border-amber-100 rounded-2xl p-5 animate-pop">
              <div className="flex items-center gap-2 mb-4">
                  <div className="bg-amber-500 p-2 rounded-lg text-white shadow-md"><Inbox size={20}/></div>
                  <h3 className="font-black text-amber-900 uppercase text-xs tracking-widest">Triagem: Solicitações de Clientes ({pendingRequests.length})</h3>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {pendingRequests.map(req => (
                      <div key={req.id} className="bg-white p-4 rounded-xl border border-amber-200 shadow-sm flex flex-col">
                          <h4 className="font-bold text-slate-800 text-sm mb-1">{req.title}</h4>
                          <p className="text-xs text-slate-500 mb-4 line-clamp-2 leading-relaxed">{req.description}</p>
                          <div className="flex gap-2 mt-auto">
                              <button onClick={() => handleApprove(req.id)} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg text-[10px] font-black uppercase hover:bg-emerald-700 transition-all shadow-sm">Aprovar</button>
                              <button onClick={() => updateTask({...req, archived: true, approvalStatus: 'REJECTED'})} className="flex-1 bg-slate-100 text-slate-500 py-2 rounded-lg text-[10px] font-black uppercase hover:bg-slate-200 transition-all">Recusar</button>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      <div className="flex-1 flex gap-5 overflow-x-auto pb-6 hide-scrollbar">
        {activeColumns.map(col => {
          const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived));
          const isOverWip = col.wipLimit && colTasks.length > col.wipLimit;

          return (
            <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()}
                onDrop={e => {
                    const type = e.dataTransfer.getData('type');
                    if (type === 'column') onColumnDrop(e, col.id);
                    else handleDropTask(e, col.id);
                }}
                className={`flex-shrink-0 w-80 flex flex-col rounded-2xl bg-slate-100/40 border border-slate-200/50 transition-all ${draggedColumnId === col.id ? 'opacity-20 scale-95' : ''}`}
            >
              <div 
                draggable={isAdmin}
                onDragStart={e => onColumnDragStart(e, col.id)}
                className={`p-4 font-black text-[10px] uppercase tracking-widest text-slate-500 flex justify-between items-center bg-white/80 backdrop-blur rounded-t-2xl border-b border-slate-200 cursor-default ${isAdmin ? 'cursor-grab active:cursor-grabbing hover:bg-white transition-colors' : ''}`}
              >
                 <div className="flex items-center gap-2">
                    {isAdmin && <GripHorizontal size={14} className="text-slate-300"/>}
                    <span className="text-slate-700">{col.label}</span>
                    {col.wipLimit && (
                        <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-black ${isOverWip ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-200 text-slate-500'}`}>
                            {colTasks.length}/{col.wipLimit}
                        </span>
                    )}
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">{colTasks.length}</span>
                    {isAdmin && (
                        <div className="relative">
                            <button onClick={() => setColumnMenuId(columnMenuId === col.id ? null : col.id)} className="p-1 hover:bg-slate-200 rounded-lg text-slate-400">
                                <MoreVertical size={16}/>
                            </button>
                            {columnMenuId === col.id && (
                                <div className="absolute right-0 top-full mt-2 w-52 bg-white shadow-2xl rounded-xl border border-slate-100 z-50 py-2 animate-pop">
                                    <button onClick={() => { setEditingColumn(col); setIsColumnModalOpen(true); setColumnMenuId(null); }} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                                        <Edit2 size={14} className="text-blue-500"/> Editar Lista
                                    </button>
                                    <button onClick={() => handleArchiveColumn(col.id)} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                                        <Archive size={14} className="text-slate-500"/> Arquivar Lista
                                    </button>
                                    <button onClick={() => handleDeleteColumn(col.id)} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-red-600 hover:bg-red-50 flex items-center gap-3 border-t border-slate-50 mt-1 pt-2">
                                        <Trash2 size={14}/> Excluir Definitivamente
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                 </div>
              </div>

              <div className="p-3 flex-1 overflow-y-auto space-y-3 custom-scrollbar min-h-[150px]">
                {colTasks.map(task => {
                    const totalSeconds = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
                    const isOverdue = task.dueDate && new Date(task.dueDate) < new Date() && task.status !== 'DONE';

                    return (
                      <div 
                        key={task.id} 
                        draggable 
                        onDragStart={e => { 
                            e.stopPropagation(); 
                            e.dataTransfer.setData('type', 'task'); 
                            setDraggedTaskId(task.id); 
                            e.dataTransfer.effectAllowed = 'move';
                        }} 
                        onClick={() => setSelectedTask(task)} 
                        className={`bg-white p-4 rounded-xl shadow-sm border-2 transition-all cursor-grab active:cursor-grabbing group ${task.isTracking ? 'border-pink-500 ring-4 ring-pink-50' : 'border-white hover:border-pink-200 hover:shadow-md'}`}
                      >
                          <div className="flex justify-between items-start mb-3">
                            <div className="flex flex-wrap gap-1">
                                {task.priority === 'HIGH' && <span className="bg-red-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-wider shadow-sm">Urgente</span>}
                                {task.isTracking && <span className="bg-amber-400 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-wider animate-pulse shadow-sm">Ativo</span>}
                            </div>
                            <div className="flex -space-x-2">
                                {task.assigneeIds.map(uid => {
                                    const u = users.find(u => u.id === uid);
                                    return <img key={uid} src={u?.avatar} className="w-6 h-6 rounded-full border-2 border-white shadow-sm" title={u?.name}/>
                                })}
                            </div>
                          </div>
                          <h4 className="text-sm font-bold text-slate-800 leading-snug mb-4 group-hover:text-pink-600 transition-colors">{task.title}</h4>

                          <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50">
                              <div className="flex flex-col gap-1.5">
                                  {task.dueDate && (
                                      <div className={`flex items-center gap-1.5 text-[9px] font-black uppercase tracking-tight ${isOverdue ? 'text-red-500' : 'text-slate-400'}`}>
                                          <Calendar size={12} className={isOverdue ? 'animate-pulse' : ''}/>
                                          {new Date(task.dueDate).toLocaleDateString()}
                                      </div>
                                  )}
                                  {totalSeconds > 0 && (
                                      <div className="flex items-center gap-1.5 text-[9px] font-black text-indigo-500 uppercase tracking-tight">
                                          <Clock size={12}/> {formatSeconds(totalSeconds)}
                                      </div>
                                  )}
                              </div>
                              <button 
                                  onClick={(e) => toggleTimerQuick(e, task)}
                                  className={`p-2 rounded-xl transition-all shadow-sm ${task.isTracking ? 'bg-amber-100 text-amber-600 hover:bg-amber-200' : 'bg-slate-50 text-slate-400 hover:bg-pink-50 hover:text-pink-600 opacity-0 group-hover:opacity-100'}`}
                                  title={task.isTracking ? "Pausar Produção" : "Iniciar Produção"}
                              >
                                  {task.isTracking ? <Pause size={16} fill="currentColor"/> : <Play size={16} fill="currentColor"/>}
                              </button>
                          </div>
                      </div>
                    );
                })}
              </div>
            </div>
          );
        })}

        {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }}
                className="flex-shrink-0 w-80 h-16 bg-slate-200/30 border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200/50 hover:text-slate-600 hover:border-slate-400 transition-all group"
            >
                <Plus size={20} className="group-hover:scale-125 transition-transform" /> Nova Lista
            </button>
        )}
      </div>

      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-sm p-8 shadow-2xl animate-pop" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-black text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                        <div className="p-2 bg-pink-100 text-pink-600 rounded-xl"><Settings size={20}/></div>
                        {editingColumn?.id ? 'Configurar Lista' : 'Nova Lista'}
                      </h3>
                      <button onClick={() => setIsColumnModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400"/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título da Lista</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 focus:bg-white transition-all bg-slate-50"
                            placeholder="Ex: Em Espera, Bloqueado..."
                            value={editingColumn?.label || ''}
                            onChange={e => setEditingColumn({...editingColumn, label: e.target.value})}
                          />
                      </div>

                      <div className="grid grid-cols-1 gap-6">
                          <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Limite WIP (Cartões)</label>
                              <input 
                                type="number"
                                className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 bg-slate-50"
                                placeholder="Ilimitado"
                                value={editingColumn?.wipLimit || ''}
                                onChange={e => setEditingColumn({...editingColumn, wipLimit: parseInt(e.target.value) || null})}
                              />
                          </div>
                      </div>

                      <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white font-black py-4 rounded-2xl hover:bg-slate-800 transition-all mt-4 uppercase tracking-widest text-xs shadow-xl shadow-slate-900/20 active:scale-95">
                          {editingColumn?.id ? 'Salvar Alterações' : 'Criar Lista'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {showArchivedColumns && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setShowArchivedColumns(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl animate-pop" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-black text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                        <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><Archive size={20}/></div>
                        Listas Arquivadas
                      </h3>
                      <button onClick={() => setShowArchivedColumns(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400"/></button>
                  </div>

                  <div className="space-y-3 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                      {archivedColumns.length === 0 && (
                          <div className="text-center p-12 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                              <Info size={40} className="mx-auto text-slate-300 mb-3"/>
                              <p className="text-xs text-slate-500 font-black uppercase tracking-widest">Nenhuma lista arquivada.</p>
                          </div>
                      )}
                      {archivedColumns.map(col => (
                          <div key={col.id} className="flex items-center justify-between p-5 bg-white border border-slate-200 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-4">
                                  <div className="w-3 h-3 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)]"></div>
                                  <span className="font-bold text-slate-800">{col.label}</span>
                              </div>
                              <div className="flex gap-2">
                                  <button 
                                    onClick={() => handleRestoreColumn(col.id)}
                                    className="px-4 py-2 bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-indigo-700 flex items-center gap-2 transition-all shadow-lg shadow-indigo-200"
                                  >
                                      <ArchiveRestore size={14}/> Reativar
                                  </button>
                                  <button 
                                    onClick={() => handleDeleteColumn(col.id)}
                                    className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                                    title="Excluir Permanentemente"
                                  >
                                      <Trash2 size={18}/>
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
                  <button onClick={() => setShowArchivedColumns(false)} className="w-full mt-8 py-4 bg-slate-100 text-slate-500 font-black uppercase tracking-widest text-[10px] rounded-2xl hover:bg-slate-200 transition-all">Fechar Janela</button>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={updateTask}
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }}
            currentUser={currentUser}
            setNotifications={setNotifications}
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
    FinancialRecord, Asset, StockItem, User, ConfirmOptions, 
    CashAccount, CashRegister, CashMovement, AssetDeletionHistory
} from '../types';
import { initialStock, initialCashAccounts } from '../utils/mockData';
import { 
    AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, 
    CartesianGrid, PieChart, Pie, Cell 
} from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Box, HardDrive, Calculator, 
    Wallet, Scale, CheckCircle, RefreshCcw, ArrowDownLeft, ArrowUpRight, 
    X, ArrowUp, Lock, Unlock, History, Download, Eye, ChevronRight, Clock, Ban
} from 'lucide-react';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'CASH_MONTHLY' | 'REPORTS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);

  const hasAccess = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';

  // -- Estados Locais --
  const [cashAccounts] = useState<CashAccount[]>(initialCashAccounts);
  const [cashSessions, setCashSessions] = useState<CashRegister[]>([]);
  const [cashMovements, setCashMovements] = useState<CashMovement[]>([]);
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [deletionHistory, setDeletionHistory] = useState<AssetDeletionHistory[]>([]);

  // -- Modais --
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({});
  const [isCashOpenModalOpen, setIsCashOpenModalOpen] = useState(false);
  const [isCashCloseModalOpen, setIsCashCloseModalOpen] = useState(false);
  const [isMoveModalOpen, setIsMoveModalOpen] = useState(false);
  const [editingMove, setEditingMove] = useState<Partial<CashMovement>>({});
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStock, setEditingStock] = useState<Partial<StockItem>>({});
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({});
  const [selectedReportCycle, setSelectedReportCycle] = useState<CashRegister | null>(null);

  // -- Modal de Exclusão de Patrimônio --
  const [isAssetDeleteModalOpen, setIsAssetDeleteModalOpen] = useState(false);
  const [assetToExclude, setAssetToExclude] = useState<Asset | null>(null);
  const [exclusionReason, setExclusionReason] = useState('');
  const [exclusionError, setExclusionError] = useState('');

  useEffect(() => {
    if (isTxModalOpen || isCashOpenModalOpen || isCashCloseModalOpen || isMoveModalOpen || isStockModalOpen || isAssetModalOpen || selectedReportCycle || isAssetDeleteModalOpen) {
        console.log("POPUP_OPENED", { type: 'FinancialModal' });
    }
  }, [isTxModalOpen, isCashOpenModalOpen, isCashCloseModalOpen, isMoveModalOpen, isStockModalOpen, isAssetModalOpen, selectedReportCycle, isAssetDeleteModalOpen]);

  const stats = useMemo(() => {
      const filtered = transactions.filter(t => t.dueDate >= startDate && t.dueDate <= endDate);
      const income = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const expense = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const pendingInc = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      const pendingExp = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      return { balance: income - expense, income, expense, projected: (income + pendingInc) - (expense + pendingExp) };
  }, [transactions, startDate, endDate]);

  // -- Handlers: Caixa Mensal --
  const handleOpenCash = (accId: string, amount: number) => {
      const month = new Date().toISOString().substring(0, 7);
      if (cashSessions.some(s => s.cashAccountId === accId && s.status === 'OPEN')) {
          alert("Já existe um caixa aberto.");
          return;
      }
      const newSession: CashRegister = { id: `cr-${Date.now()}`, cashAccountId: accId, openedBy: currentUser.id, openedAt: Date.now(), monthReference: month, initialAmount: amount, expectedFinalAmount: amount, status: 'OPEN' };
      setCashSessions(prev => [newSession, ...prev]);
      setIsCashOpenModalOpen(false);
  };

  const handleCreateMovement = (move: Partial<CashMovement>) => {
      if (!move.amount || !move.cashRegisterId) return;
      const newMove: CashMovement = { ...move, id: `mv-${Date.now()}`, date: new Date().toISOString(), createdBy: currentUser.id } as CashMovement;
      setCashMovements(prev => [...prev, newMove]);
      setCashSessions(prev => prev.map(s => {
          if (s.id === move.cashRegisterId) {
              const impact = (move.type === 'RECEBIMENTO' || move.type === 'SUPRIMENTO') ? move.amount! : -move.amount!;
              return { ...s, expectedFinalAmount: s.expectedFinalAmount + impact };
          }
          return s;
      }));
      if (move.type === 'RECEBIMENTO' || move.type === 'PAGAMENTO') {
          const ledgerEntry: FinancialRecord = { id: `lg-${Date.now()}`, description: `[CAIXA] ${move.description}`, amount: move.amount!, type: move.type === 'RECEBIMENTO' ? 'INCOME' : 'EXPENSE', status: 'PAID', dueDate: new Date().toISOString().split('T')[0], paymentDate: new Date().toISOString(), cashRegisterId: move.cashRegisterId };
          setTransactions(prev => [ledgerEntry, ...prev]);
      }
      setIsMoveModalOpen(false);
  };

  const handleCloseCash = (sessionId: string, counted: number, obs: string) => {
      setCashSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
              const diff = counted - s.expectedFinalAmount;
              return { ...s, status: 'CLOSED', countedFinalAmount: counted, differenceAmount: diff, closedBy: currentUser.id, closedAt: Date.now(), observations: obs };
          }
          return s;
      }));
      setIsCashCloseModalOpen(false);
  };

  // -- Handlers: Estoque e Patrimônio --
  const handleSaveStock = () => {
      if (!editingStock.name || editingStock.quantity === undefined) return;
      if (editingStock.id) setStock(prev => prev.map(i => i.id === editingStock.id ? { ...i, ...editingStock } as StockItem : i));
      else setStock(prev => [...prev, { ...editingStock, id: `stk-${Date.now()}`, lastRestock: new Date().toISOString() } as StockItem]);
      setIsStockModalOpen(false);
      setEditingStock({});
  };

  const handleSaveAsset = () => {
      if (!editingAsset.name || !editingAsset.cost) return;
      if (editingAsset.id) setAssets(prev => prev.map(a => a.id === editingAsset.id ? { ...a, ...editingAsset } as Asset : a));
      else setAssets(prev => [...prev, { ...editingAsset, id: `ast-${Date.now()}`, status: 'ACTIVE', isDeleted: false } as Asset]);
      setIsAssetModalOpen(false);
      setEditingAsset({});
  };

  // -- Lógica de Exclusão de Patrimônio (Soft Delete + Histórico) --
  const handleStartDeleteAsset = (asset: Asset) => {
      console.log("PATRIMONIO_DELETE_CLICK", { id: asset.id, name: asset.name });
      setAssetToExclude(asset);
      setExclusionReason('');
      setExclusionError('');
      setIsAssetDeleteModalOpen(true);
  };

  const handleCancelDeleteAsset = () => {
      setIsAssetDeleteModalOpen(false);
      setAssetToExclude(null);
      setExclusionReason('');
  };

  const handleConfirmDeleteAsset = () => {
      if (!assetToExclude) return;
      if (!exclusionReason.trim()) {
          setExclusionError("O motivo da exclusão é obrigatório.");
          return;
      }

      // 1. Criar Snapshot e Histórico
      const historyEntry: AssetDeletionHistory = {
          id: `del-${Date.now()}`,
          assetId: assetToExclude.id,
          deletedByUserId: currentUser.id,
          deletedAt: Date.now(),
          reason: exclusionReason,
          assetSnapshot: {
              name: assetToExclude.name,
              type: assetToExclude.type,
              cost: assetToExclude.cost,
              serialNumber: assetToExclude.serialNumber,
              purchaseDate: assetToExclude.purchaseDate
          }
      };

      setDeletionHistory(prev => [...prev, historyEntry]);

      // 2. Aplicar Soft Delete
      setAssets(prev => prev.map(a => 
          a.id === assetToExclude.id ? { ...a, isDeleted: true } : a
      ));

      // 3. Finalizar
      setIsAssetDeleteModalOpen(false);
      setAssetToExclude(null);
      setExclusionReason('');
  };

  // Filtragem de Ativos Não Deletados
  const activeAssets = useMemo(() => assets.filter(a => !a.isDeleted), [assets]);

  if (!hasAccess) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl border border-slate-200 p-8 text-center">
              <Ban size={48} className="text-red-400 mb-4" />
              <h2 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Acesso Restrito</h2>
              <p className="text-slate-500 max-w-sm mt-2 text-sm">Área exclusiva para CEOs e Diretores Financeiros.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6 animate-pop">
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
          <div className="flex flex-wrap bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-full md:w-fit overflow-x-auto">
              <button onClick={() => setActiveTab('DASHBOARD')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'DASHBOARD' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><TrendingUp size={14}/> Geral</button>
              <button onClick={() => setActiveTab('TRANSACTIONS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'TRANSACTIONS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><FileText size={14}/> Razão</button>
              <button onClick={() => setActiveTab('CASH_MONTHLY')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'CASH_MONTHLY' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Calculator size={14}/> Caixa</button>
              <button onClick={() => setActiveTab('REPORTS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'REPORTS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><History size={14}/> Auditoria</button>
              <button onClick={() => setActiveTab('STOCK')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'STOCK' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Box size={14}/> Estoque</button>
              <button onClick={() => setActiveTab('ASSETS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'ASSETS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><HardDrive size={14}/> Patrimônio</button>
          </div>

          <div className="flex items-center gap-2 bg-white p-2 rounded-xl border shadow-sm w-full md:w-auto overflow-x-auto">
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-[10px] outline-none font-bold text-slate-700 bg-transparent" />
              <span className="text-slate-300">|</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-[10px] outline-none font-bold text-slate-700 bg-transparent" />
          </div>
      </div>

      <div className="min-h-[500px]">
          {activeTab === 'DASHBOARD' && (
              <div className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Caixa Real</p>
                          <h3 className={`text-2xl font-black mt-2 ${stats.balance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {stats.balance.toLocaleString()}</h3>
                      </div>
                      <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                          <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção</p>
                          <h3 className="text-2xl font-black mt-2">R$ {stats.projected.toLocaleString()}</h3>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><ArrowUpRight size={12} className="text-blue-600"/> MRR Est.</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {(stats.income * 1.1).toLocaleString('pt-BR', { notation: 'compact' })}</h3>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Box size={12} className="text-pink-600"/> Ativos</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {activeAssets.reduce((a,b)=>a+b.cost, 0).toLocaleString('pt-BR', { notation: 'compact' })}</h3>
                      </div>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-80">
                          <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-6">Gráfico de Fluxo</h3>
                          <ResponsiveContainer width="100%" height="100%">
                              <AreaChart data={transactions.slice(-10)}>
                                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                                  <XAxis dataKey="dueDate" hide />
                                  <YAxis hide />
                                  <Tooltip />
                                  <Area type="monotone" dataKey="amount" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.1} />
                              </AreaChart>
                          </ResponsiveContainer>
                      </div>
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
                          <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-6">Vencimentos Próximos</h3>
                          <div className="space-y-3 flex-1 overflow-y-auto max-h-[200px] custom-scrollbar">
                              {transactions.filter(t => t.status === 'PENDING').slice(0, 5).map(t => (
                                  <div key={t.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                                      <div className="flex items-center gap-3">
                                          <div className={`p-2 rounded-lg ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                                              {t.type === 'INCOME' ? <ArrowUpRight size={14}/> : <ArrowDownLeft size={14}/>}
                                          </div>
                                          <div><p className="text-xs font-bold text-slate-800 line-clamp-1">{t.description}</p><p className="text-[10px] text-slate-400 font-black uppercase">{t.dueDate.split('-').reverse().join('/')}</p></div>
                                      </div>
                                      <p className="font-black text-xs text-slate-800 whitespace-nowrap">R$ {t.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>
          )}

          {activeTab === 'ASSETS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><HardDrive size={18} className="text-indigo-600"/> Ativos Fixos (Hardware/Software)</h3>
                      <button onClick={()=>{setEditingAsset({type:'HARDWARE'}); setIsAssetModalOpen(true)}} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Registrar Ativo</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                    <table className="w-full text-sm text-left min-w-[600px]">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Ativo / SN</th><th className="p-4">Tipo</th><th className="p-4">Custo</th><th className="p-4">Status</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {activeAssets.map(asset => (
                                <tr key={asset.id} className="hover:bg-slate-50 group">
                                    <td className="p-4"><p className="font-bold text-slate-800">{asset.name}</p><p className="text-[10px] text-slate-400 font-black">{asset.serialNumber}</p></td>
                                    <td className="p-4 text-xs font-bold text-slate-500 uppercase">{asset.type}</td>
                                    <td className="p-4 font-black">R$ {asset.cost.toLocaleString()}</td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${asset.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>{asset.status === 'ACTIVE' ? 'Em Uso' : 'Baixado'}</span></td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1">
                                            <button onClick={()=>{setEditingAsset(asset); setIsAssetModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                            <button onClick={()=>handleStartDeleteAsset(asset)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {activeAssets.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="p-12 text-center text-slate-400 font-medium italic">Nenhum ativo registrado no momento.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}

          {activeTab === 'TRANSACTIONS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50 flex flex-col sm:flex-row justify-between items-center gap-4">
                      <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest flex items-center gap-2"><FileText size={16} className="text-indigo-600"/> Razão Geral</h3>
                      <button onClick={()=>{setEditingTx({type:'EXPENSE', dueDate: new Date().toISOString().split('T')[0]}); setIsTxModalOpen(true)}} className="w-full sm:w-auto bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase shadow-lg"><Plus size={14}/> Lançamento</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                      <table className="w-full text-sm text-left min-w-[600px]">
                          <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                              <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {transactions.map(t => (
                                  <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                      <td className="p-4 text-slate-400 font-medium whitespace-nowrap">{t.dueDate.split('-').reverse().join('/')}</td>
                                      <td className="p-4 font-bold text-slate-800">{t.description}</td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>{t.type === 'INCOME' ? 'REC' : 'DES'}</span></td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600'}`}>{t.status === 'PAID' ? 'LIQ' : 'PEN'}</span></td>
                                      <td className={`p-4 text-right font-black whitespace-nowrap ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                      <td className="p-4 text-center">
                                          <div className="flex justify-center gap-1">
                                              <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-emerald-600"><CheckCircle size={14}/></button>
                                              <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
                                          </div>
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          )}

          {activeTab === 'STOCK' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2 text-sm"><Box size={18} className="text-pink-600"/> Insumos</h3>
                      <button onClick={() => {setEditingStock({category:'OFFICE', quantity:0, minQuantity:5}); setIsStockModalOpen(true)}} className="bg-slate-900 text-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase"><Plus size={12}/> Novo</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                    <table className="w-full text-sm text-left min-w-[500px]">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Item</th><th className="p-4 text-center">Qtd</th><th className="p-4 text-center">Min.</th><th className="p-4">Preço</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {stock.map(item => (
                                <tr key={item.id} className="hover:bg-slate-50">
                                    <td className="p-4"><p className="font-bold text-slate-800">{item.name}</p></td>
                                    <td className={`p-4 text-center font-black ${item.quantity <= item.minQuantity ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</td>
                                    <td className="p-4 text-center text-slate-400 font-bold">{item.minQuantity}</td>
                                    <td className="p-4 font-medium whitespace-nowrap">R$ {item.unitPrice.toLocaleString()}</td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1">
                                            <button onClick={()=>{setEditingStock(item); setIsStockModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={14}/></button>
                                            <button onClick={()=>setStock(prev => prev.filter(i => i.id !== item.id))} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={14}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}
      </div>

      {/* --- MODAIS DE GESTÃO --- */}

      {/* EXCLUSÃO DE PATRIMÔNIO */}
      {isAssetDeleteModalOpen && assetToExclude && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[140] flex items-center justify-center p-4 transition-all duration-300" onClick={handleCancelDeleteAsset}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border-t-4 border-red-600" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-50 border-b flex items-center justify-between">
                      <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Excluir Patrimônio</h3>
                      <button onClick={handleCancelDeleteAsset} className="text-slate-400 hover:text-slate-600"><X/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="bg-red-50 p-4 rounded-2xl border border-red-100 flex gap-3">
                          <AlertTriangle className="text-red-600 shrink-0" size={20}/>
                          <div className="text-xs text-red-800 leading-relaxed">
                              <p className="font-bold mb-1">Atenção!</p>
                              Esta exclusão removerá o item <b>{assetToExclude.name}</b> da visão operacional permanentemente. O registro será mantido apenas para histórico de auditoria.
                          </div>
                      </div>

                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2 ml-1">Motivo da Exclusão <span className="text-red-500">*</span></label>
                          <textarea 
                            className={`w-full border-2 rounded-2xl p-4 text-sm font-medium outline-none focus:bg-white transition-all resize-none h-32 ${exclusionError ? 'border-red-300 bg-red-50' : 'border-slate-100 bg-slate-50 focus:border-red-400'}`}
                            placeholder="Descreva detalhadamente o porquê desta exclusão (ex: venda, obsolescência, extravio...)"
                            value={exclusionReason}
                            onChange={e => { setExclusionReason(e.target.value); setExclusionError(''); }}
                          />
                          {exclusionError && <p className="text-[10px] text-red-500 font-bold mt-1 ml-1">{exclusionError}</p>}
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                          <button onClick={handleCancelDeleteAsset} className="w-full bg-slate-100 text-slate-500 py-4 rounded-2xl font-black uppercase text-xs hover:bg-slate-200 transition-all">Cancelar</button>
                          <button 
                            onClick={handleConfirmDeleteAsset} 
                            className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase text-xs shadow-xl shadow-red-200 hover:bg-red-700 active:scale-95 transition-all"
                          >
                              Confirmar Exclusão
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* PATRIMÔNIO (EDICAO/CADASTRO) */}
      {isAssetModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsAssetModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-black uppercase tracking-tight">{editingAsset.id ? 'Editar Patrimônio' : 'Registro de Patrimônio'}</h3>
                    <button onClick={()=>setIsAssetModalOpen(false)} className="text-slate-400 hover:text-slate-600"><X/></button>
                  </div>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Ativo (ex: MacBook Pro)" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nº Série / Licença" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.purchaseDate || ''} onChange={e => setEditingAsset({...editingAsset, purchaseDate: e.target.value})} />
                          <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.type} onChange={e => setEditingAsset({...editingAsset, type: e.target.value as any})}><option value="HARDWARE">Hardware</option><option value="SOFTWARE">Software (SaaS)</option><option value="OFFICE">Mobiliário</option></select>
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Salvar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashOpenModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashOpenModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between"><h3 className="text-xl font-black uppercase tracking-tighter">Novo Ciclo Mensal</h3><button onClick={()=>setIsCashOpenModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Conta Operacional</label><select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50" onChange={e => setEditingMove({ ...editingMove, cashAccountId: e.target.value })}><option value="">Selecione...</option>{cashAccounts.filter(a => a.isCashRegister).map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Fundo Inicial de Reserva (R$)</label><input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none focus:bg-white" placeholder="0.00" onChange={e => setEditingMove({ ...editingMove, amount: parseFloat(e.target.value) })} /></div>
                      <button onClick={() => handleOpenCash(editingMove.cashAccountId!, editingMove.amount!)} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"><Unlock size={20}/> Iniciar Ciclo</button>
                  </div>
              </div>
          </div>
      )}

      {isMoveModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsMoveModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 text-white flex justify-between ${editingMove.type === 'RECEBIMENTO' || editingMove.type === 'SUPRIMENTO' ? 'bg-emerald-600' : 'bg-red-600'}`}><h3 className="text-xl font-black uppercase tracking-tighter">{editingMove.type}</h3><button onClick={()=>setIsMoveModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Descrição da operação..." value={editingMove.description || ''} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-3xl font-black outline-none" placeholder="0.00" value={editingMove.amount || ''} onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => handleCreateMovement(editingMove)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Confirmar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashCloseModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashCloseModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between"><h3 className="text-xl font-black uppercase">Fechar Turno</h3><button onClick={()=>setIsCashCloseModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center"><p className="text-[10px] font-black text-slate-400 uppercase">Saldo Esperado</p><p className="text-2xl font-black">R$ {cashSessions.find(s => s.id === editingMove.cashRegisterId)?.expectedFinalAmount.toLocaleString()}</p></div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none" placeholder="Saldo Real Contado" onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <textarea className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm resize-none" placeholder="Observações..." rows={3} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <button onClick={() => handleCloseCash(editingMove.cashRegisterId!, editingMove.amount!, editingMove.description || '')} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase">Encerrar Ciclo Mensal</button>
                  </div>
              </div>
          </div>
      )}

      {selectedReportCycle && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[130] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setSelectedReportCycle(null)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[80vh] shadow-2xl animate-pop overflow-hidden flex flex-col" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="text-xl font-black uppercase tracking-tighter">Resumo Mensal: {selectedReportCycle.monthReference}</h3><button onClick={()=>setSelectedReportCycle(null)}><X/></button></div>
                  <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Abertura</p><p className="font-bold">R$ {selectedReportCycle.initialAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Esperado</p><p className="font-bold">R$ {selectedReportCycle.expectedFinalAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Furo / Dif.</p><p className={`font-black ${selectedReportCycle.differenceAmount === 0 ? 'text-emerald-600' : 'text-red-600'}`}>R$ {selectedReportCycle.differenceAmount?.toLocaleString()}</p></div>
                      </div>
                      <div>
                          <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-3 border-b pb-2">Movimentos do Período</h4>
                          <div className="space-y-2">
                              {cashMovements.filter(m => m.cashRegisterId === selectedReportCycle.id).map(m => (
                                  <div key={m.id} className="flex justify-between items-center p-3 bg-white border border-slate-50 rounded-xl shadow-sm">
                                      <div><p className="text-xs font-bold text-slate-800">{m.description}</p><p className="text-[9px] text-slate-400 uppercase">{m.type}</p></div>
                                      <p className={`font-black text-sm ${m.type === 'RECEBIMENTO' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {m.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                      {selectedReportCycle.observations && <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100"><p className="text-[10px] font-black text-amber-700 uppercase mb-1">Notas de Auditoria</p><p className="text-xs italic text-amber-900">"{selectedReportCycle.observations}"</p></div>}
                  </div>
                  <div className="p-6 border-t bg-slate-50 flex justify-end gap-3"><button onClick={() => window.print()} className="px-6 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold text-xs uppercase transition-all flex items-center gap-2"><Download size={14}/> Imprimir PDF</button><button onClick={()=>setSelectedReportCycle(null)} className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase">Fechar Relatório</button></div>
              </div>
          </div>
      )}

      {isStockModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tight">{editingStock.id ? 'Editar Item' : 'Novo Item em Estoque'}</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Insumo" value={editingStock.name || ''} onChange={e => setEditingStock({...editingStock, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Qtd. Atual" value={editingStock.quantity || ''} onChange={e => setEditingStock({...editingStock, quantity: parseInt(e.target.value)})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Qtd. Min." value={editingStock.minQuantity || ''} onChange={e => setEditingStock({...editingStock, minQuantity: parseInt(e.target.value)})} />
                      </div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Preço Unit." value={editingStock.unitPrice || ''} onChange={e => setEditingStock({...editingStock, unitPrice: parseFloat(e.target.value)})} />
                      <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingStock.category} onChange={e => setEditingStock({...editingStock, category: e.target.value as any})}><option value="OFFICE">Escritório</option><option value="IT">TI / Tecnologia</option><option value="CLEANING">Limpeza</option><option value="MARKETING">Eventos/Brindes</option></select>
                      <button onClick={handleSaveStock} className="w-full bg-pink-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-pink-700 transition-all">Salvar no Estoque</button>
                  </div>
              </div>
          </div>
      )}

      {isTxModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase">Novo Lançamento Geral</h3>
                  <div className="space-y-4">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl"><button onClick={()=>setEditingTx({...editingTx, type:'INCOME'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600' : 'text-slate-400'}`}>Receita (+)</button><button onClick={()=>setEditingTx({...editingTx, type:'EXPENSE'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600' : 'text-slate-400'}`}>Despesa (-)</button></div>
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Descrição do Lançamento" value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Valor R$" onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingTx.dueDate} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                      </div>
                      <button onClick={() => {if(editingTx.amount && editingTx.description){setTransactions(p=>[{...editingTx, id:`tx-${Date.now()}`, status:'PAID'} as FinancialRecord, ...p]); setIsTxModalOpen(false); setEditingTx({})}}} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Gravar no Fluxo</button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Lead, ColumnConfig, LeadTask, ConfirmOptions, User } from '../types';
import { 
    DollarSign, Plus, Star, CheckSquare, Calendar, Phone, Mail, MessageSquare, 
    Trash2, Clock, User as UserIcon, Briefcase, AlertCircle, Save, X, Settings,
    GripHorizontal, Edit2, ArchiveRestore, Info, Tag
} from 'lucide-react';

interface CRMProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  leadSources: string[];
  setLeadSources: React.Dispatch<React.SetStateAction<string[]>>;
  currentUser: User;
}

export const CRM: React.FC<CRMProps> = ({ leads, setLeads, columns, setColumns, openConfirm, leadSources, setLeadSources, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingLead, setEditingLead] = useState<Partial<Lead>>({ stage: columns[0]?.id || 'NEW', rating: 0, tasks: [] });
  const [activeTab, setActiveTab] = useState<'DETAILS' | 'ACTIVITIES'>('DETAILS');
  const [showValidation, setShowValidation] = useState(false);

  // Column/Settings State
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  // Origin Management
  const [newOrigin, setNewOrigin] = useState('');

  // Task Form State
  const [newTaskText, setNewTaskText] = useState('');
  const [newTaskDate, setNewTaskDate] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');
  const [newTaskType, setNewTaskType] = useState<'CALL' | 'EMAIL' | 'MEETING' | 'TASK'>('TASK');

  const isAdmin = currentUser.role === 'ADMIN';

  useEffect(() => {
    if(isModalOpen || isSettingsOpen || isColumnModalOpen) {
        console.log("POPUP_OPENED", { type: 'CRMModal' });
    }
  }, [isModalOpen, isSettingsOpen, isColumnModalOpen]);

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const handleSave = () => {
      if (!editingLead.company || !editingLead.name || (!editingLead.value && editingLead.value !== 0)) {
          setShowValidation(true);
          return;
      }

      if(editingLead.id) {
          setLeads(prev => prev.map(l => l.id === editingLead.id ? { ...l, ...editingLead } as Lead : l));
      } else {
          setLeads(prev => [...prev, { ...editingLead, id: Date.now().toString(), lastContact: new Date().toISOString() } as Lead]);
      }
      setIsModalOpen(false);
      resetForm();
  };

  const resetForm = () => {
    setEditingLead({ stage: activeColumns[0]?.id || 'NEW', rating: 0, tasks: [] });
    setActiveTab('DETAILS');
    setShowValidation(false);
  };

  // --- Pipeline Stages Management ---
  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'crm-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'bg-slate-50 border-slate-200',
            order: columns.length,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleDeleteColumn = async (colId: string) => {
      const hasLeads = leads.some(l => l.stage === colId);
      if (hasLeads) {
          alert("Mova os leads desta etapa antes de excluí-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Excluir Etapa?",
          description: "Esta ação removerá permanentemente esta etapa do funil.",
          confirmText: "Excluir"
      });
      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
      }
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) return;
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const newCols = [...columns];
      const draggedIdx = newCols.findIndex(c => c.id === draggedColumnId);
      const targetIdx = newCols.findIndex(c => c.id === targetColId);
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  // --- Origins Management ---
  const addOrigin = () => {
      if (!newOrigin.trim() || leadSources.includes(newOrigin)) return;
      setLeadSources(prev => [...prev, newOrigin.trim()]);
      setNewOrigin('');
  };

  const deleteOrigin = async (origin: string) => {
      const ok = await openConfirm({
          title: "Remover Origem?",
          description: `Deseja remover "${origin}" das opções? Leads existentes manterão esta origem.`,
          variant: "danger"
      });
      if (ok) setLeadSources(prev => prev.filter(o => o !== origin));
  };

  // --- Lead Management ---
  const handleDeleteLead = async (id: string) => {
      const ok = await openConfirm({
          title: "Excluir Oportunidade?",
          description: "Deseja remover permanentemente este Lead? Esta ação não pode ser desfeita.",
          variant: "danger",
          confirmText: "Excluir Definitivamente"
      });
      if (ok) {
          setLeads(prev => prev.filter(l => l.id !== id));
          setIsModalOpen(false);
          resetForm();
      }
  };

  const addTaskToLead = () => {
      if(!newTaskText) return;
      const newTask: LeadTask = { 
          id: Date.now().toString(), 
          text: newTaskText, 
          completed: false,
          dueDate: newTaskDate || new Date().toISOString().split('T')[0],
          time: newTaskTime || '09:00',
          type: newTaskType
      };
      setEditingLead({ ...editingLead, tasks: [newTask, ...(editingLead.tasks || [])] });
      setNewTaskText('');
      setNewTaskDate('');
      setNewTaskTime('');
  };

  const toggleTask = (taskId: string) => {
      const updatedTasks = editingLead.tasks?.map(t => t.id === taskId ? {...t, completed: !t.completed} : t);
      setEditingLead({...editingLead, tasks: updatedTasks});
  };

  const getTaskIcon = (type: string) => {
      switch(type) {
          case 'CALL': return <Phone size={14} className="text-blue-500"/>;
          case 'EMAIL': return <Mail size={14} className="text-yellow-500"/>;
          case 'MEETING': return <UserIcon size={14} className="text-purple-500"/>;
          default: return <CheckSquare size={14} className="text-emerald-500"/>;
      }
  };

  const handleDragStartLead = (e: React.DragEvent, leadId: string) => {
      setDraggedLeadId(leadId);
      e.dataTransfer.setData('type', 'lead');
      e.dataTransfer.effectAllowed = "move";
  };

  const handleDropLead = (e: React.DragEvent, targetStage: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;
      setLeads(prev => prev.map(l => l.id === draggedLeadId ? { ...l, stage: targetStage, lastContact: new Date().toISOString() } : l));
      setDraggedLeadId(null);
  };

  const getInputClass = (value: any) => {
      const baseClass = "w-full border rounded p-2 text-sm transition-all";
      if (showValidation && (!value || value === 0)) return `${baseClass} border-red-500 bg-red-50 focus:ring-red-200`;
      return `${baseClass} border-slate-200 focus:border-pink-500 focus:ring-4 focus:ring-pink-50 outline-none`;
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Pipeline de Vendas</h2>
          <p className="text-slate-500 text-sm font-medium">Gestão de oportunidades e previsão de fechamento</p>
        </div>
        <div className="flex gap-2">
            {isAdmin && (
                <button onClick={() => setIsSettingsOpen(true)} className="p-2.5 rounded-xl text-slate-500 bg-white border border-slate-200 hover:bg-slate-50 transition-all shadow-sm">
                    <Settings size={20}/>
                </button>
            )}
            <button onClick={() => { resetForm(); setIsModalOpen(true)}} className="bg-pink-600 hover:bg-pink-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-pink-500/20">
                <Plus size={18} /> Novo Lead
            </button>
        </div>
      </div>

      <div className="flex-1 flex gap-5 overflow-x-auto pb-6 hide-scrollbar">
          {activeColumns.map(col => (
              <div 
                key={col.id} 
                draggable={isAdmin}
                onDragStart={(e) => onColumnDragStart(e, col.id)}
                onDragOver={(e) => e.preventDefault()}
                onDrop={(e) => {
                    const type = e.dataTransfer.getData('type');
                    if (type === 'column') onColumnDrop(e, col.id);
                    else handleDropLead(e, col.id);
                }}
                className={`flex-shrink-0 w-80 flex flex-col rounded-2xl border transition-all ${col.color} bg-opacity-40 ${draggedColumnId === col.id ? 'opacity-20 scale-95' : ''}`}
              >
                  <div className="p-4 flex items-center justify-between border-b border-black/5 cursor-default">
                      <div className="flex items-center gap-2">
                         {isAdmin && <GripHorizontal size={14} className="text-slate-400 cursor-grab active:cursor-grabbing"/>}
                         <h3 className="font-black text-[10px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                      </div>
