  const [reqGoal, setReqGoal] = useState('');
  const [reqDate, setReqDate] = useState('');
  const [reqFormats, setReqFormats] = useState<string[]>([]);

  useEffect(() => {
    if(isModalOpen || contactModalOpen) console.log("POPUP_OPENED", { type: 'PortalModal' });
  }, [isModalOpen, contactModalOpen]);

  // Identifica o Cliente e Squad
  const myClientProfile = clients.find(c => c.id === currentUser.clientId);
  const mySquad = myClientProfile ? squads.find(s => s.id === myClientProfile.squadId) : null;

  const accountManager = mySquad 
    ? users.find(u => u.role === 'MANAGER' && mySquad.members.includes(u.id)) || users.find(u => u.role === 'ADMIN')
    : null;

  const myTasks = tasks.filter(t => 
    t.clientRequest && t.assigneeIds.includes(currentUser.id)
  );

  const activeTasks = myTasks.filter(t => t.status !== 'DONE' && !t.archived).sort((a,b) => b.id.localeCompare(a.id));
  const historyTasks = myTasks.filter(t => t.status === 'DONE' || t.archived).sort((a,b) => b.id.localeCompare(a.id));

  const pendingCount = activeTasks.filter(t => t.approvalStatus === 'PENDING').length;
  const inProgressCount = activeTasks.filter(t => t.status === 'IN_PROGRESS' || t.status === 'TODO').length;
  const reviewCount = activeTasks.filter(t => t.status === 'REVIEW').length;

  const recentActivities = useMemo(() => {
      const activities: { id: string, type: 'COMMENT' | 'STATUS', text: string, time: number, user?: User, taskTitle: string }[] = [];
      myTasks.forEach(task => {
          task.comments.forEach(c => {
              const u = users.find(user => user.id === c.userId);
              if (c.userId !== currentUser.id) {
                  activities.push({
                      id: c.id,
                      type: 'COMMENT',
                      text: c.text,
                      time: c.timestamp,
                      user: u,
                      taskTitle: task.title
                  });
              }
          });
      });
      return activities.sort((a,b) => b.time - a.time).slice(0, 5);
  }, [myTasks, users, currentUser.id]);

  const calculateProgress = (status: TaskStatus, approvalStatus?: string) => {
    if (approvalStatus === 'PENDING') return 5;
    if (approvalStatus === 'REJECTED') return 0;
    switch (status) {
        case 'BACKLOG': return 15;
        case 'TODO': return 25;
        case 'IN_PROGRESS': return 50;
        case 'REVIEW': return 85;
        case 'DONE': return 100;
        default: return 0;
    }
  };

  const getStatusLabel = (status: TaskStatus, approvalStatus?: string) => {
      if (approvalStatus === 'PENDING') return { text: 'Em Triagem', color: 'bg-orange-50 text-orange-600 border-orange-100' };
      if (approvalStatus === 'REJECTED') return { text: 'Recusado', color: 'bg-red-50 text-red-600 border-red-100' };
      switch (status) {
          case 'BACKLOG': return { text: 'Aguardando Início', color: 'bg-slate-100 text-slate-600 border-slate-200' };
          case 'TODO': return { text: 'Planejado', color: 'bg-blue-50 text-blue-600 border-blue-100' };
          case 'IN_PROGRESS': return { text: 'Em Produção', color: 'bg-indigo-50 text-indigo-600 border-indigo-100' };
          case 'REVIEW': return { text: 'Para sua Aprovação', color: 'bg-purple-50 text-purple-600 border-purple-100' };
          case 'DONE': return { text: 'Concluído', color: 'bg-emerald-50 text-emerald-600 border-emerald-100' };
          default: return { text: status, color: 'bg-gray-100' };
      }
  };

  const handleOpenContact = (type: 'CALL' | 'MEETING') => {
      setContactType(type);
      setContactReason('');
      setContactPreference('WHATSAPP');
      setContactModalOpen(true);
  };

  const handleSubmitContact = () => {
      if (!contactReason.trim() || !accountManager) return;
      const typeLabel = contactType === 'MEETING' ? 'Solicitação de Reunião' : 'Solicitação de Contato';

      setNotifications(prev => [{
          id: Date.now().toString(),
          title: typeLabel,
          message: `O cliente ${currentUser.name} solicita: ${contactReason}. Canal: ${contactPreference}`,
          type: 'INFO',
          status: 'UNREAD',
          priority: 'MEDIUM',
          originModule: 'CLIENTS',
          timestamp: Date.now(),
          targetUserId: accountManager.id,
          navToView: 'kanban'
      }, ...prev]);

      alert("Sua solicitação de contato foi enviada!");
      setContactModalOpen(false);
  };

  const handleOpenWizard = () => {
      setReqType(null);
      setReqTitle('');
      setReqDesc('');
      setReqGoal('');
      setReqDate('');
      setReqFormats([]);
      setCurrentStep(1);
      setFormError(null);
      setIsModalOpen(true);
  };

  const toggleFormat = (id: string) => {
    setReqFormats(prev => 
        prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]
    );
  };

  const handleNextStep = () => {
      setFormError(null);
      if (currentStep === 1 && !reqType) {
          setFormError("Por favor, selecione uma categoria para continuar.");
          return;
      }
      if (currentStep === 2) {
          if (!reqTitle.trim()) {
              setFormError("O Título do Job é obrigatório.");
              return;
          }
          if (!reqGoal.trim()) {
              setFormError("O Objetivo da demanda é obrigatório para que a equipe entenda o resultado esperado.");
              return;
          }
          if (!reqDesc.trim()) {
              setFormError("O Briefing detalhado é essencial para a produção.");
              return;
          }
      }
      setCurrentStep(prev => prev + 1);
  };

  const handleSubmit = () => {
      if (!reqTitle || !reqType) return;
      const typeLabel = REQUEST_TYPES.find(r => r.id === reqType)?.label;
      const formatString = reqFormats.length > 0 ? ` [Formatos: ${reqFormats.join(', ')}]` : '';

      const newTask: Task = {
          id: Date.now().toString(),
          title: reqTitle,
          description: `OBJETIVO: ${reqGoal}\n\nBRIEFING: ${reqDesc}\n\nCATEGORIA: ${typeLabel}${formatString}`,
          status: 'BACKLOG',
          priority: 'MEDIUM',
          dueDate: reqDate || new Date(new Date().setDate(new Date().getDate() + 7)).toISOString().split('T')[0],
          estimatedTime: 0,
          timeLogs: [],
          isTracking: false,
          clientRequest: true,
          approvalStatus: 'PENDING', 
          squadId: myClientProfile?.squadId || currentUser.squad || 'squad-1', 
          assigneeIds: [currentUser.id], 
          checklists: [],
          comments: [],
          history: [{ id: Date.now().toString(), action: 'Demanda criada pelo cliente', userId: currentUser.id, timestamp: Date.now() }],
          cover: { type: 'COLOR', value: '#ec4899' }
      };

      setTasks(prev => [newTask, ...prev]);
      setIsModalOpen(false);
  };

  return (
    <div className="space-y-8 animate-pop">
      <div className="bg-gradient-to-r from-slate-900 to-slate-800 rounded-2xl p-8 text-white shadow-xl relative overflow-hidden">
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-bold mb-2">Olá, {currentUser.name.split(' ')[0]}!</h1>
                <p className="text-slate-300">Hub de Marketing: Acompanhe e solicite novas demandas para sua marca.</p>
            </div>
            <button 
                onClick={handleOpenWizard}
                className="bg-pink-600 hover:bg-pink-700 text-white px-6 py-3 rounded-xl font-bold transition-all shadow-lg shadow-pink-600/30 flex items-center gap-2 transform hover:scale-105 active:scale-95"
            >
                <Plus size={20} /> Nova Demanda de Marketing
            </button>
        </div>
        <div className="absolute -bottom-10 -right-10 w-64 h-64 bg-pink-600/20 rounded-full blur-3xl"></div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
              <div><p className="text-xs font-bold text-slate-500 uppercase">Em Triagem</p><p className="text-2xl font-bold text-slate-800">{pendingCount}</p></div>
              <div className="p-3 bg-orange-50 text-orange-600 rounded-lg"><Settings2 size={20} /></div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
              <div><p className="text-xs font-bold text-slate-500 uppercase">Produzindo</p><p className="text-2xl font-bold text-indigo-600">{inProgressCount}</p></div>
              <div className="p-3 bg-indigo-50 text-indigo-600 rounded-lg"><Clock size={20} /></div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
              <div><p className="text-xs font-bold text-slate-500 uppercase">Para Aprovar</p><p className="text-2xl font-bold text-purple-600">{reviewCount}</p></div>
              <div className="p-3 bg-purple-50 text-purple-600 rounded-lg"><CheckCircle size={20} /></div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
              <div><p className="text-xs font-bold text-slate-500 uppercase">Entregues</p><p className="text-2xl font-bold text-emerald-600">{historyTasks.length}</p></div>
              <div className="p-3 bg-emerald-50 text-emerald-600 rounded-lg"><Sparkles size={20} /></div>
          </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
             <div className="flex items-center gap-4 border-b border-slate-200 pb-2">
                <button onClick={() => setViewFilter('ACTIVE')} className={`text-sm font-bold pb-2 transition-colors ${viewFilter === 'ACTIVE' ? 'text-pink-600 border-b-2 border-pink-600' : 'text-slate-500 hover:text-slate-700'}`}>Demandas em Aberto</button>
                <button onClick={() => setViewFilter('HISTORY')} className={`text-sm font-bold pb-2 transition-colors ${viewFilter === 'HISTORY' ? 'text-pink-600 border-b-2 border-pink-600' : 'text-slate-500 hover:text-slate-700'}`}>Arquivadas / Concluídas</button>
            </div>

            <div className="grid gap-4">
                {(viewFilter === 'ACTIVE' ? activeTasks : historyTasks).map(task => {
                    const progress = calculateProgress(task.status as TaskStatus, task.approvalStatus);
                    const statusInfo = getStatusLabel(task.status as TaskStatus, task.approvalStatus);
                    return (
                        <div key={task.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
                            <div className="flex flex-col md:flex-row justify-between items-start gap-4 mb-4">
                                <div className="flex-1">
                                    <h3 className="text-lg font-bold text-slate-800 mb-1">{task.title}</h3>
                                    <p className="text-slate-500 text-sm line-clamp-1">{task.description.split('\n\nBRIEFING:')[0]}</p>
                                </div>
                                <div className="flex items-center gap-3 shrink-0">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${statusInfo.color}`}>{statusInfo.text}</span>
                                    {task.dueDate && <span className="text-xs font-medium text-slate-500 flex items-center gap-1 bg-slate-100 px-2 py-1 rounded"><Calendar size={12}/> {new Date(task.dueDate).toLocaleDateString()}</span>}
                                </div>
                            </div>
                            <div className="relative pt-2">
                                <div className="flex mb-2 items-center justify-between text-xs font-semibold text-slate-500 uppercase"><span>Status da Produção</span><span>{progress}%</span></div>
                                <div className="overflow-hidden h-2 mb-2 text-xs flex rounded-full bg-slate-100">
                                    <div style={{ width: `${progress}%` }} className={`shadow-none flex flex-col text-center transition-all duration-1000 ${task.approvalStatus === 'REJECTED' ? 'bg-red-50' : task.status === 'DONE' ? 'bg-emerald-500' : 'bg-pink-500'}`}></div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
          </div>

          <div className="space-y-6">
              <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><Shield size={18} className="text-pink-600"/> Meu Suporte Estratégico</h3>
                  {accountManager ? (
                      <div className="flex flex-col items-center text-center">
                           <img src={accountManager.avatar} className="w-20 h-20 rounded-full border-4 border-slate-50 mb-3" />
                           <h4 className="font-bold text-slate-800 text-lg">{accountManager.name}</h4>
                           <p className="text-sm text-slate-500 mb-4">Gerente de Conta • {mySquad?.name}</p>
                           <div className="w-full space-y-2">
                               <button onClick={() => handleOpenContact('MEETING')} className="flex items-center justify-center gap-2 w-full py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-sm font-medium transition-colors"><Calendar size={16}/> Agendar Reunião</button>
                               <button onClick={() => handleOpenContact('CALL')} className="flex items-center justify-center gap-2 w-full py-2 border border-slate-200 hover:border-pink-200 text-slate-600 rounded-lg text-sm font-medium transition-colors"><Phone size={16}/> Solicitar Chamada</button>
                           </div>
                      </div>
                  ) : <div className="text-center py-6 text-slate-400 text-sm bg-slate-50 rounded-lg">Gerente não atribuído.</div>}
              </div>

              <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
                  <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><MessageSquare size={18} className="text-pink-600"/> Últimas Atualizações</h3>
                  <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                      {recentActivities.map(activity => (
                          <div key={activity.id} className="flex gap-3 items-start border-b border-slate-50 pb-3 last:border-0">
                              {activity.user && <img src={activity.user.avatar} className="w-8 h-8 rounded-full border border-slate-100 mt-1" />}
                              <div className="flex-1">
                                  <div className="flex justify-between items-start"><p className="text-xs font-bold text-slate-800">{activity.user?.name}</p><span className="text-[10px] text-slate-400">{new Date(activity.time).toLocaleDateString()}</span></div>
                                  <p className="text-xs text-slate-600 mt-0.5 line-clamp-2">"{activity.text}"</p>
                                  <p className="text-[10px] text-pink-500 font-medium mt-1 truncate">Em: {activity.taskTitle}</p>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      </div>

      {isModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[100] flex items-center justify-center p-4 transition-all duration-300" onClick={() => { setIsModalOpen(false); setFormError(null); }}>
              <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-pop" onClick={e => e.stopPropagation()}>
                  <div className="bg-slate-50 p-4 border-b border-slate-100 flex justify-between items-center"><h3 className="font-bold text-slate-800">Nova Demanda de Marketing</h3><button onClick={() => { setIsModalOpen(false); setFormError(null); }} className="text-slate-400 hover:text-slate-600"><X size={20}/></button></div>
                  <div className="px-8 pt-6 pb-2">
                      <div className="flex items-center justify-between relative">
                          <div className="absolute left-0 top-1/2 -translate-y-1/2 w-full h-1 bg-slate-100 -z-10"></div>
                          {[1,2,3].map(step => (
                            <div key={step} className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-colors ${currentStep >= step ? 'bg-pink-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{step}</div>
                          ))}
                      </div>
                  </div>
                  <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
                      {formError && (
                          <div className="bg-red-50 border border-red-100 p-3 rounded-lg mb-4 flex items-center gap-2 text-red-600 text-xs font-bold animate-pop">
                              <AlertCircle size={16}/> {formError}
                          </div>
                      )}

                      {currentStep === 1 && (
                          <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-pop">
                              {REQUEST_TYPES.map(type => (
                                  <button key={type.id} onClick={() => { setReqType(type.id as RequestType); setFormError(null); handleNextStep(); }} className={`flex flex-col items-center justify-center p-6 border-2 rounded-xl transition-all group ${reqType === type.id ? 'border-pink-500 bg-pink-50' : 'border-slate-100 hover:border-pink-200 hover:bg-slate-50'}`}>
                                      <div className={`p-3 bg-white rounded-full shadow-sm mb-3 group-hover:scale-110 transition-transform ${reqType === type.id ? 'text-pink-600' : 'text-slate-400 group-hover:text-pink-500'}`}><type.icon size={28}/></div>
                                      <h4 className={`font-bold text-xs text-center ${reqType === type.id ? 'text-pink-700' : 'text-slate-700'}`}>{type.label}</h4>
                                  </button>
                              ))}
                          </div>
                      )}
                      {currentStep === 2 && (
                          <div className="space-y-4 animate-pop">
                              <div><label className="block text-sm font-bold text-slate-700 mb-1">Título do Job <span className="text-red-500">*</span></label><input className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:border-pink-500 outline-none" placeholder="Ex: Banner para Black Friday" value={reqTitle} onChange={e => setReqTitle(e.target.value)} autoFocus/></div>
                              <div><label className="block text-sm font-bold text-slate-700 mb-1">Objetivo / Resultado Esperado <span className="text-red-500">*</span></label><input className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:border-pink-500 outline-none" placeholder="Ex: Aumentar cliques no anúncio" value={reqGoal} onChange={e => setReqGoal(e.target.value)}/></div>
                              {(reqType === 'SOCIAL' || reqType === 'VIDEO') && (
                                  <div><label className="block text-sm font-bold text-slate-700 mb-2">Formato Desejado (Selecione um ou mais)</label><div className="grid grid-cols-2 gap-2">{FORMAT_OPTIONS.map(fmt => (
                                    <button key={fmt.id} onClick={() => toggleFormat(fmt.id)} className={`flex items-center gap-2 p-3 rounded-lg border text-left transition-all ${reqFormats.includes(fmt.id) ? 'bg-pink-50 border-pink-500 text-pink-700 ring-2 ring-pink-100' : 'bg-white border-slate-200 text-slate-600'}`}><div className={`${reqFormats.includes(fmt.id) ? 'text-pink-600' : 'text-slate-400'}`}>{fmt.icon}</div><span className="text-xs font-bold">{fmt.label}</span></button>
                                  ))}</div></div>
                              )}
                              <div><label className="block text-sm font-bold text-slate-700 mb-1">Prazo Sugerido</label><input type="date" className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:border-pink-500 outline-none" value={reqDate} onChange={e => setReqDate(e.target.value)}/></div>
                              <div><label className="block text-sm font-bold text-slate-700 mb-1">Briefing Detalhado <span className="text-red-500">*</span></label><textarea className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:border-pink-500 outline-none h-24 resize-none" placeholder="Descreva os detalhes, textos e referências..." value={reqDesc} onChange={e => setReqDesc(e.target.value)}/></div>
                              <p className="text-[10px] text-slate-400 uppercase font-bold">* Campos obrigatórios</p>
                          </div>
                      )}
                      {currentStep === 3 && (
                          <div className="animate-pop text-center space-y-6 py-4">
                              <div className="w-16 h-16 bg-pink-100 rounded-full flex items-center justify-center mx-auto text-pink-600"><CheckCircle size={32} /></div>
                              <h3 className="text-xl font-bold text-slate-800">Enviar para Squad?</h3>
                              <div className="bg-slate-50 p-4 rounded-xl text-left border border-slate-100 max-w-sm mx-auto">
                                  <p className="text-xs text-slate-400 uppercase font-bold mb-1">Resumo da Demanda</p>
                                  <p className="font-bold text-slate-800">{reqTitle}</p>
                                  <p className="text-xs text-slate-500 mt-2"><b>Objetivo:</b> {reqGoal}</p>
                                  {reqFormats.length > 0 && <p className="text-xs text-slate-500 mt-1"><b>Formatos:</b> {reqFormats.join(', ')}</p>}
                              </div>
                          </div>
                      )}
                  </div>
                  <div className="p-4 border-t border-slate-100 flex justify-between bg-slate-50">
                      <button onClick={() => { if (currentStep > 1) { setCurrentStep(currentStep - 1); setFormError(null); } else { setIsModalOpen(false); setFormError(null); } }} className="px-4 py-2 text-slate-600 font-medium hover:bg-slate-200 rounded-lg transition-colors">{currentStep === 1 ? 'Cancelar' : 'Voltar'}</button>
                      {currentStep < 3 ? <button onClick={handleNextStep} className="px-6 py-2 bg-slate-800 text-white font-bold rounded-lg hover:bg-slate-900 transition-colors flex items-center gap-2">Próximo <ChevronRight size={16}/></button>
                      : <button onClick={handleSubmit} className="px-6 py-2 bg-pink-600 text-white font-bold rounded-lg hover:bg-pink-700 transition-colors shadow-lg shadow-pink-500/20">Criar Job de Marketing</button>}
                  </div>
              </div>
          </div>
      )}

      {contactModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setContactModalOpen(false)}>
              <div className="bg-white rounded-xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="bg-slate-50 p-4 border-b border-slate-100 flex justify-between items-center"><h3 className="font-bold text-slate-800 flex items-center gap-2">{contactType === 'CALL' ? <Phone size={20} className="text-pink-600"/> : <Calendar size={20} className="text-pink-600"/>}{contactType === 'CALL' ? 'Solicitar Ligação' : 'Agendar Reunião'}</h3></div>
                  <div className="p-6 space-y-4">
                      {contactType === 'CALL' && (
                          <div className="flex gap-2">
                              <button onClick={() => setContactPreference('WHATSAPP')} className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 transition-all ${contactPreference === 'WHATSAPP' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'border-slate-200 text-slate-600'}`}><MessageCircle size={18} /> WhatsApp</button>
                              <button onClick={() => setContactPreference('PHONE')} className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 transition-all ${contactPreference === 'PHONE' ? 'bg-blue-50 border-blue-500 text-blue-700' : 'border-slate-200 text-slate-600'}`}><Phone size={18} /> Telefone</button>
                          </div>
                      )}
                      <div><label className="block text-xs font-bold text-slate-500 uppercase mb-2">Pauta / Motivo <span className="text-red-500">*</span></label><textarea className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:border-pink-500 outline-none h-32 resize-none" placeholder="Sobre o que precisamos falar?" value={contactReason} onChange={e => setContactReason(e.target.value)} autoFocus/></div>
                      <button onClick={handleSubmitContact} disabled={!contactReason.trim()} className="w-full bg-slate-800 text-white font-bold py-3 rounded-lg hover:bg-slate-900 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"><Send size={16}/> Enviar Mensagem</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Client, Squad, ClientContact, AgencyService, User, ConfirmOptions } from '../types';
import { Plus, Edit2, Trash2, Folder, FileText, Calendar, Mail, Phone, ExternalLink, Search, DollarSign, Users, Briefcase, User as UserIcon, Star, Link, Shield, X, Check, ShoppingBag, Key, Lock, Unlock, AlertCircle, Ban, Power } from 'lucide-react';

interface ClientManagementProps {
  clients: Client[];
  setClients: React.Dispatch<React.SetStateAction<Client[]>>;
  squads: Squad[];
  services: AgencyService[];
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

export const ClientManagement: React.FC<ClientManagementProps> = ({ clients, setClients, squads, services, users, setUsers, openConfirm }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<'ALL' | 'RECURRING' | 'ONEOFF'>('ALL');
  const [activeTab, setActiveTab] = useState<'GENERAL' | 'CONTRACT' | 'CONTACTS' | 'ACCESS'>('GENERAL');

  const [editingClient, setEditingClient] = useState<Partial<Client>>({ 
      name: '',
      status: 'ACTIVE', 
      contacts: [],
      level: 'BASIC',
      isRecurring: true,
      serviceIds: [],
      squadId: ''
  });

  const [isAccessModalOpen, setIsAccessModalOpen] = useState(false);
  const [editingAccessUser, setEditingAccessUser] = useState<Partial<User>>({});

  useEffect(() => {
    if(isModalOpen || isAccessModalOpen) console.log("POPUP_OPENED", { type: 'ClientModal' });
  }, [isModalOpen, isAccessModalOpen]);

  // Stats Calculation
  const activeClients = clients.filter(c => c.status === 'ACTIVE');
  const totalMRR = activeClients.reduce((acc, c) => acc + (c.monthlyValue || 0), 0);
  const avgTicket = activeClients.length > 0 ? totalMRR / activeClients.length : 0;

  const handleSave = () => {
      if (!editingClient.name || !editingClient.name.trim()) {
          alert("O campo 'Nome do Cliente' é obrigatório.");
          return;
      }

      if (!editingClient.squadId) {
          alert("Por favor, selecione a 'Squad Responsável' na aba Visão Geral.");
          setActiveTab('GENERAL'); 
          return;
      }

      if (editingClient.id) {
          setClients(prev => prev.map(c => c.id === editingClient.id ? { ...c, ...editingClient } as Client : c));
      } else {
          setClients(prev => [...prev, { ...editingClient, id: Date.now().toString() } as Client]);
      }
      setIsModalOpen(false);
      resetForm();
  };

  const resetForm = () => {
      setEditingClient({ 
          name: '',
          status: 'ACTIVE', 
          contacts: [], 
          level: 'BASIC', 
          isRecurring: true, 
          serviceIds: [],
          squadId: ''
      });
      setActiveTab('GENERAL');
  };

  const handleCreateNew = () => {
      resetForm();
      setIsModalOpen(true);
  };

  const handleDeleteClient = async (id: string) => {
      const client = clients.find(c => c.id === id);
      if (!client) return;

      const ok = await openConfirm({
          title: `Excluir ${client.name}?`,
          description: "Deseja remover permanentemente este cliente? Todos os acessos de portal vinculados serão perdidos, mas o histórico de tarefas será mantido no sistema.",
          variant: "danger",
          confirmText: "Excluir Cliente"
      });

      if (ok) {
          setClients(prev => prev.filter(c => c.id !== id));
          setUsers(prev => prev.filter(u => u.clientId !== id));
      }
  };

  const addContact = () => {
      const newContacts = [...(editingClient.contacts || []), { name: '', email: '', phone: '', role: '' }];
      setEditingClient({...editingClient, contacts: newContacts});
  };

  const updateContact = (idx: number, field: keyof ClientContact, value: string) => {
      const newContacts = [...(editingClient.contacts || [])];
      newContacts[idx] = { ...newContacts[idx], [field]: value };
      setEditingClient({...editingClient, contacts: newContacts});
  };

  const removeContact = (idx: number) => {
      const newContacts = editingClient.contacts?.filter((_, i) => i !== idx);
      setEditingClient({...editingClient, contacts: newContacts});
  };

  const toggleService = (serviceId: string) => {
      const currentServices = editingClient.serviceIds || [];
      if (currentServices.includes(serviceId)) {
          setEditingClient({...editingClient, serviceIds: currentServices.filter(id => id !== serviceId)});
      } else {
          setEditingClient({...editingClient, serviceIds: [...currentServices, serviceId]});
      }
  };

  const openAccessModal = (user?: User) => {
      if (!editingClient.id) {
          alert("Salve o cliente antes de gerenciar acessos.");
          return;
      }
      if (user) {
          setEditingAccessUser({ ...user, password: '' }); 
      } else {
          setEditingAccessUser({ 
              name: '', 
              email: '', 
              password: '', 
              hasSystemAccess: true,
              role: 'CLIENT',
              clientId: editingClient.id
          });
      }
      setIsAccessModalOpen(true);
  };

  const handleSaveAccessUser = () => {
      if (!editingAccessUser.name || !editingAccessUser.email) {
          alert("Nome e Email são obrigatórios.");
          return;
      }

      if (!editingAccessUser.id && !editingAccessUser.password) {
          alert("Defina uma senha para o novo usuário.");
          return;
      }

      const emailExists = users.find(u => u.email.toLowerCase() === editingAccessUser.email?.toLowerCase() && u.id !== editingAccessUser.id);
      if (emailExists) {
          alert("Este email já está em uso por outro usuário.");
          return;
      }

      if (editingAccessUser.id) {
          setUsers(prev => prev.map(u => {
              if (u.id === editingAccessUser.id) {
                  const updatedUser = { ...u, ...editingAccessUser };
                  if (!editingAccessUser.password) {
                      updatedUser.password = u.password;
                  }
                  return updatedUser as User;
              }
              return u;
          }));
      } else {
          const newUser: User = {
              id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
              name: editingAccessUser.name || '',
              email: editingAccessUser.email || '',
              role: 'CLIENT',
              clientId: editingClient.id,
              avatar: `https://api.dicebear.com/7.x/initials/svg?seed=${editingAccessUser.name}`,
              hasSystemAccess: editingAccessUser.hasSystemAccess !== undefined ? editingAccessUser.hasSystemAccess : true,
              password: editingAccessUser.password
          };
          setUsers(prev => [...prev, newUser]);
      }
      setIsAccessModalOpen(false);
  };

  const handleToggleBlockUser = (e: React.MouseEvent, userId: string) => {
      e.preventDefault();
      e.stopPropagation();
      setUsers(prev => prev.map(u => u.id === userId ? { ...u, hasSystemAccess: !u.hasSystemAccess } : u));
  };

  const handleDeleteUserLogin = async (e: React.MouseEvent, userId: string) => {
      e.preventDefault();
      e.stopPropagation();
      if (!userId) return;

      const userToDelete = users.find(u => u.id === userId);
      const userName = userToDelete ? userToDelete.name : 'este usuário';

      const ok = await openConfirm({
          title: "Excluir acesso do cliente?",
          description: `Deseja remover permanentemente o acesso de "${userName}" ao portal? O histórico de pedidos será mantido no sistema central.`,
          variant: "danger",
          confirmText: "Excluir Acesso"
      });

      if (ok) {
          setUsers(currentUsers => currentUsers.filter(u => u.id !== userId));
          setIsAccessModalOpen(false);
      }
  };

  const getLevelColor = (level?: string) => {
      switch(level) {
          case 'ADVANCED': return 'bg-purple-100 text-purple-700 border-purple-200';
          case 'INTERMEDIATE': return 'bg-blue-100 text-blue-700 border-blue-200';
          default: return 'bg-slate-100 text-slate-600 border-slate-200';
      }
  };

  const filteredClients = clients.filter(client => {
      const matchesSearch = client.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            client.legalName?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesFilter = filterType === 'ALL' || 
                            (filterType === 'RECURRING' && client.isRecurring) || 
                            (filterType === 'ONEOFF' && !client.isRecurring);
      return matchesSearch && matchesFilter;
  });

  const linkedUsers = users.filter(u => u.role === 'CLIENT' && u.clientId === editingClient.id);

  return (
    <div className="space-y-6">

       <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
           <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
               <div>
                   <p className="text-xs font-bold text-slate-500 uppercase">Receita Recorrente (MRR)</p>
                   <p className="text-2xl font-bold text-slate-800">R$ {totalMRR.toLocaleString()}</p>
               </div>
               <div className="bg-emerald-50 p-3 rounded-full text-emerald-600"><DollarSign size={24}/></div>
           </div>
           <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
               <div>
                   <p className="text-xs font-bold text-slate-500 uppercase">Clientes Ativos</p>
                   <p className="text-2xl font-bold text-slate-800">{activeClients.length}</p>
               </div>
               <div className="bg-blue-50 p-3 rounded-full text-blue-600"><Users size={24}/></div>
           </div>
           <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
               <div>
                   <p className="text-xs font-bold text-slate-500 uppercase">Ticket Médio</p>
                   <p className="text-2xl font-bold text-slate-800">R$ {avgTicket.toLocaleString(undefined, { maximumFractionDigits: 0 })}</p>
               </div>
               <div className="bg-purple-50 p-3 rounded-full text-purple-600"><Star size={24}/></div>
           </div>
       </div>

       <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
           <div className="flex items-center gap-2 w-full md:w-auto">
               <div className="relative w-full md:w-64">
                   <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/>
                   <input 
                        className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg text-sm outline-none focus:border-pink-500"
                        placeholder="Buscar cliente..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                   />
               </div>
               <div className="flex bg-slate-100 p-1 rounded-lg">
                   <button onClick={() => setFilterType('ALL')} className={`px-3 py-1.5 text-xs font-bold rounded ${filterType === 'ALL' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}>Todos</button>
                   <button onClick={() => setFilterType('RECURRING')} className={`px-3 py-1.5 text-xs font-bold rounded ${filterType === 'RECURRING' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}>Recorrentes</button>
                   <button onClick={() => setFilterType('ONEOFF')} className={`px-3 py-1.5 text-xs font-bold rounded ${filterType === 'ONEOFF' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}>Pontuais</button>
               </div>
           </div>
           <button onClick={handleCreateNew} className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors shadow-lg shadow-pink-500/20 w-full md:w-auto justify-center">
             <Plus size={18} /> Novo Cliente
           </button>
       </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredClients.map(client => {
              const assignedSquad = squads.find(s => s.id === client.squadId);
              const accessCount = users.filter(u => u.clientId === client.id).length;

              return (
                <div key={client.id} className={`bg-white rounded-xl border shadow-sm overflow-hidden hover:shadow-md transition-all flex flex-col ${client.status === 'INACTIVE' ? 'opacity-60 border-slate-200' : 'border-slate-200'}`}>
                    <div className="p-4 border-b border-slate-100 flex justify-between items-start bg-slate-50/50">
                        <div className="flex items-start gap-3">
                            <div className={`w-10 h-10 rounded-lg flex items-center justify-center font-bold text-lg ${client.isRecurring ? 'bg-emerald-100 text-emerald-600' : 'bg-blue-100 text-blue-600'}`}>
                                {client.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-bold text-slate-800 leading-tight">{client.name}</h3>
                                <p className="text-xs text-slate-500 mt-0.5">{client.legalName}</p>
                            </div>
                        </div>
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold border ${getLevelColor(client.level)}`}>
                            {client.level}
                        </span>
                    </div>

                    <div className="p-4 space-y-4 flex-1">
                        <div className="flex justify-between items-center text-sm">
                            <span className="text-slate-500 flex items-center gap-1"><DollarSign size={14}/> Valor Mensal</span>
                            <span className="font-bold text-slate-800">R$ {client.monthlyValue ? client.monthlyValue.toLocaleString() : '0,00'}</span>
                        </div>

                         {assignedSquad ? (
                            <div className="flex justify-between items-center text-sm">
                                <span className="text-slate-500 flex items-center gap-1"><Shield size={14}/> Squad</span>
                                <span className="bg-slate-100 px-2 py-0.5 rounded text-xs font-medium text-slate-700">{assignedSquad.name}</span>
                            </div>
                        ) : (
                             <div className="flex justify-between items-center text-sm">
                                <span className="text-slate-500 flex items-center gap-1"><Shield size={14}/> Squad</span>
                                <span className="bg-red-50 px-2 py-0.5 rounded text-xs font-medium text-red-500 border border-red-100 flex items-center gap-1"><AlertCircle size={10}/> Não definida</span>
                            </div>
                        )}

                        <div className="flex justify-between items-center text-sm">
                            <span className="text-slate-500 flex items-center gap-1"><Users size={14}/> Acessos Ativos</span>
                            <span className={`px-2 py-0.5 rounded text-xs font-bold ${accessCount > 0 ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-400'}`}>
                                {accessCount}
                            </span>
                        </div>

                        {client.serviceIds && client.serviceIds.length > 0 && (
                            <div>
                                <p className="text-xs font-bold text-slate-400 mb-1 flex items-center gap-1"><ShoppingBag size={10}/> Serviços</p>
                                <div className="flex flex-wrap gap-1">
                                    {client.serviceIds.map(sid => {
                                        const svc = services.find(s => s.id === sid);
                                        return svc ? (
                                            <span key={sid} className="text-[10px] bg-indigo-50 text-indigo-700 px-1.5 py-0.5 rounded border border-indigo-100">
                                                {svc.name}
                                            </span>
                                        ) : null;
                                    })}
                                </div>
                            </div>
                        )}

                        {client.summary && (
                            <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                                <p className="text-xs text-slate-600 italic line-clamp-3">
                                    "{client.summary}"
                                </p>
                            </div>
                        )}

                        <div className="flex gap-2 text-xs pt-2">
                            {client.contractUrl ? (
                                <a href={client.contractUrl} target="_blank" className="flex-1 flex items-center justify-center gap-1 bg-blue-50 text-blue-600 py-1.5 rounded hover:bg-blue-100 transition-colors">
                                    <FileText size={14}/> Contrato
                                </a>
                            ) : (
                                <span className="flex-1 flex items-center justify-center gap-1 bg-slate-50 text-slate-300 py-1.5 rounded cursor-not-allowed"><FileText size={14}/> Sem Contrato</span>
                            )}
                            {client.assetsFolderUrl ? (
                                <a href={client.assetsFolderUrl} target="_blank" className="flex-1 flex items-center justify-center gap-1 bg-amber-50 text-amber-600 py-1.5 rounded hover:bg-amber-100 transition-colors">
                                    <Folder size={14}/> Materiais
                                </a>
                            ) : (
                                <span className="flex-1 flex items-center justify-center gap-1 bg-slate-50 text-slate-300 py-1.5 rounded cursor-not-allowed"><Folder size={14}/> Sem Pasta</span>
                            )}
                        </div>
                    </div>

                    <div className="p-3 border-t border-slate-100 flex justify-between items-center bg-slate-50/50">
                        <div className="flex -space-x-2">
                             {client.contacts.slice(0, 3).map((c, i) => (
                                 <div key={i} className="w-6 h-6 rounded-full bg-slate-200 border border-white flex items-center justify-center text-[10px] text-slate-600" title={c.name}>
                                     {c.name.charAt(0)}
                                 </div>
                             ))}
                             {client.contacts.length === 0 && <span className="text-xs text-slate-400 italic">Sem contatos</span>}
                        </div>
                        <div className="flex gap-1">
                            <button onClick={() => { setEditingClient(client); setIsModalOpen(true)}} className="text-slate-400 hover:text-blue-600 p-1 hover:bg-white rounded transition-colors"><Edit2 size={16}/></button>
                            <button onClick={() => handleDeleteClient(client.id)} className="text-slate-400 hover:text-red-600 p-1 hover:bg-white rounded transition-colors"><Trash2 size={16}/></button>
                        </div>
                    </div>
                </div>
              );
          })}
      </div>

      {isModalOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[100] flex items-center justify-center p-4 transition-all duration-300"
            onClick={() => setIsModalOpen(false)}
        >
            <div 
                className="bg-white rounded-2xl w-full max-w-4xl h-[85vh] flex flex-col shadow-2xl overflow-hidden animate-pop"
                onClick={e => e.stopPropagation()}
            >
                <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
                    <div className="w-full mr-8">
                        <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Nome do Cliente <span className="text-red-500">*</span></label>
                        <input 
                            className="text-2xl font-bold text-slate-800 bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 outline-none focus:border-pink-500 w-full"
                            placeholder="Digite o nome da empresa..."
                            value={editingClient.name || ''}
                            onChange={e => setEditingClient({...editingClient, name: e.target.value})}
                            autoFocus
                        />
                        <div className="flex items-center gap-4 mt-3">
                             <select 
                                className="bg-white border border-slate-300 text-xs rounded px-2 py-1 outline-none"
                                value={editingClient.status}
                                onChange={e => setEditingClient({...editingClient, status: e.target.value as any})}
                             >
                                 <option value="ACTIVE">Ativo</option>
                                 <option value="INACTIVE">Inativo</option>
                                 <option value="CHURNED">Churn (Cancelado)</option>
                             </select>
                             <div className="flex items-center gap-2">
                                <input type="checkbox" id="isRec" checked={editingClient.isRecurring} onChange={e => setEditingClient({...editingClient, isRecurring: e.target.checked})} className="rounded text-pink-600 focus:ring-pink-500" />
                                <label htmlFor="isRec" className="text-sm text-slate-600">Cliente Recorrente</label>
                            </div>
                        </div>
                    </div>
                    <button onClick={() => setIsModalOpen(false)}><X size={24} className="text-slate-400 hover:text-slate-600"/></button>
                </div>

                <div className="flex border-b border-slate-200">
                    <button onClick={() => setActiveTab('GENERAL')} className={`px-6 py-3 text-sm font-medium border-b-2 ${activeTab === 'GENERAL' ? 'border-pink-600 text-pink-600 bg-pink-50/50' : 'border-transparent text-slate-500'}`}>Visão Geral</button>
                    <button onClick={() => setActiveTab('CONTRACT')} className={`px-6 py-3 text-sm font-medium border-b-2 ${activeTab === 'CONTRACT' ? 'border-pink-600 text-pink-600 bg-pink-50/50' : 'border-transparent text-slate-500'}`}>Contrato & Financeiro</button>
                    <button onClick={() => setActiveTab('CONTACTS')} className={`px-6 py-3 text-sm font-medium border-b-2 ${activeTab === 'CONTACTS' ? 'border-pink-600 text-pink-600 bg-pink-50/50' : 'border-transparent text-slate-500'}`}>Contatos ({editingClient.contacts?.length || 0})</button>
                    <button onClick={() => setActiveTab('ACCESS')} className={`px-6 py-3 text-sm font-medium border-b-2 ${activeTab === 'ACCESS' ? 'border-pink-600 text-pink-600 bg-pink-50/50' : 'border-transparent text-slate-500'}`}>Acessos do Portal ({linkedUsers.length})</button>
                </div>

                <div className="p-8 overflow-y-auto flex-1 bg-slate-50/30 custom-scrollbar">
                    {activeTab === 'GENERAL' && (
                        <div className="space-y-6 max-2-xl">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="col-span-2">
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Razão Social</label>
                                    <input className="w-full border border-slate-300 rounded-lg p-2.5 text-sm" value={editingClient.legalName || ''} onChange={e => setEditingClient({...editingClient, legalName: e.target.value})} placeholder="Nome Legal da Empresa" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nível de Maturidade</label>
                                    <select className="w-full border border-slate-300 rounded-lg p-2.5 text-sm" value={editingClient.level} onChange={e => setEditingClient({...editingClient, level: e.target.value as any})}>
                                        <option value="BASIC">Básico (Start)</option>
                                        <option value="INTERMEDIATE">Intermediário (Growth)</option>
                                        <option value="ADVANCED">Avançado (Scale)</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Squad Responsável <span className="text-red-500">*</span></label>
                                    <select className={`w-full border rounded-lg p-2.5 text-sm ${!editingClient.squadId ? 'border-red-300 bg-red-50' : 'border-slate-300'}`} value={editingClient.squadId || ''} onChange={e => setEditingClient({...editingClient, squadId: e.target.value})}><option value="">Selecione...</option>{squads.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                                </div>
                                <div className="col-span-2">
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Resumo do Cliente</label>
                                    <textarea className="w-full border border-slate-300 rounded-lg p-2.5 text-sm h-32 resize-none outline-none" placeholder="Descreva o negócio do cliente, objetivos e informações chave..." value={editingClient.summary || ''} onChange={e => setEditingClient({...editingClient, summary: e.target.value})} />
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'CONTRACT' && (
                        <div className="space-y-6 max-w-2xl">
                             <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Valor Mensal (R$)</label>
                                    <input type="number" className="w-full border border-slate-300 rounded-lg p-2.5 text-sm font-bold" value={editingClient.monthlyValue || ''} onChange={e => setEditingClient({...editingClient, monthlyValue: parseFloat(e.target.value)})} placeholder="0.00"/>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Início do Contrato</label>
                                    <input type="date" className="w-full border border-slate-300 rounded-lg p-2.5 text-sm" value={editingClient.contractStartDate || ''} onChange={e => setEditingClient({...editingClient, contractStartDate: e.target.value})}/>
                                </div>
                                <div className="col-span-2">
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Link do Contrato</label>
                                    <div className="flex gap-2">
                                        <input className="flex-1 border border-slate-300 rounded-lg p-2.5 text-sm" value={editingClient.contractUrl || ''} onChange={e => setEditingClient({...editingClient, contractUrl: e.target.value})} placeholder="https://..." />
                                        {editingClient.contractUrl && <a href={editingClient.contractUrl} target="_blank" className="p-2.5 bg-blue-50 text-blue-600 rounded-lg border border-blue-100"><ExternalLink size={18}/></a>}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'ACCESS' && (
                        <div>
                            <div className="flex justify-between items-center mb-6">
                                <div><h4 className="font-bold text-slate-700">Acessos do Portal</h4><p className="text-xs text-slate-500">Gerencie logins para que membros da equipe do cliente acessem o portal.</p></div>
                                <button onClick={() => openAccessModal()} className="bg-slate-800 text-white px-3 py-1.5 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-slate-900"><Plus size={16}/> Novo Usuário</button>
                            </div>
                            <div className="space-y-3 mb-8">
                                {linkedUsers.length === 0 && <div className="p-8 bg-slate-50 rounded-xl text-center border border-slate-200 border-dashed"><Key size={32} className="mx-auto text-slate-300 mb-2"/><p className="text-sm font-bold text-slate-500">Nenhum acesso criado</p></div>}
                                {linkedUsers.map(u => (
                                    <div key={u.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl shadow-sm">
                                        <div className="flex items-center gap-4"><img src={u.avatar} className={`w-12 h-12 rounded-full border-2 ${u.hasSystemAccess ? 'border-emerald-100' : 'border-red-100'}`} /><div><p className={`font-bold text-sm ${u.hasSystemAccess ? 'text-slate-800' : 'text-slate-400'}`}>{u.name}</p><p className="text-xs text-slate-500">{u.email}</p></div></div>
                                        <div className="flex items-center gap-2"><button onClick={(e) => handleToggleBlockUser(e, u.id)} className="p-2 rounded-lg text-slate-400 hover:bg-slate-100">{u.hasSystemAccess ? <Unlock size={18} /> : <Lock size={18} />}</button><button onClick={(e) => { e.preventDefault(); openAccessModal(u); }} className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={18} /></button><button onClick={(e) => handleDeleteUserLogin(e, u.id)} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={18} /></button></div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
                <div className="p-6 border-t border-slate-100 flex justify-end gap-3 bg-white">
                    <button onClick={() => setIsModalOpen(false)} className="px-6 py-2.5 text-slate-500 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
                    <button onClick={handleSave} className="px-8 py-2.5 bg-pink-600 text-white font-bold rounded-lg hover:bg-pink-700 shadow-md">Salvar Cliente</button>
                </div>
            </div>
        </div>
      )}

      {/* MODAL DE GESTÃO DE ACESSO */}
      {isAccessModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[120] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsAccessModalOpen(false)}>
              <div className="bg-white rounded-xl w-full max-w-md shadow-2xl animate-pop overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="bg-slate-50 p-5 border-b border-slate-100 flex justify-between items-center"><h3 className="font-bold text-slate-800 flex items-center gap-2"><Key size={18} className="text-pink-600"/> {editingAccessUser.id ? 'Editar Acesso' : 'Novo Acesso'}</h3><button onClick={() => setIsAccessModalOpen(false)}><X size={20} className="text-slate-400"/></button></div>
                  <div className="p-6 space-y-4">
                      <div><label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nome do Usuário</label><input className="w-full border border-slate-200 rounded-lg p-2.5 text-sm" placeholder="Ex: João Silva" value={editingAccessUser.name || ''} onChange={e => setEditingAccessUser({...editingAccessUser, name: e.target.value})}/></div>
                      <div><label className="block text-xs font-bold text-slate-500 uppercase mb-1">Email de Login</label><input className="w-full border border-slate-200 rounded-lg p-2.5 text-sm" placeholder="joao@empresa.com" value={editingAccessUser.email || ''} onChange={e => setEditingAccessUser({...editingAccessUser, email: e.target.value})}/></div>
                      <div className="bg-blue-50 p-3 rounded-lg"><label className="block text-xs font-bold text-blue-700 uppercase mb-1">Definir Senha</label><input type="text" className="w-full border border-blue-200 rounded-lg p-2.5 text-sm" value={editingAccessUser.password || ''} onChange={e => setEditingAccessUser({...editingAccessUser, password: e.target.value})}/></div>
                      <button onClick={handleSaveAccessUser} className="w-full bg-slate-800 text-white font-bold py-3 rounded-lg hover:bg-slate-900 shadow-lg mt-2">{editingAccessUser.id ? 'Salvar Alterações' : 'Criar Usuário'}</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
import { 
  LayoutDashboard, Kanban, Users, DollarSign, Briefcase, LogOut, 
  PieChart, BarChart2, Shield, HeartHandshake, ShoppingBag, 
  ShoppingCart, Settings, HelpCircle, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { Role, RolePermissions, SystemSettings } from '../types';

interface SidebarProps {
  currentView: string;
  setView: (view: string) => void;
  currentUserRole: Role;
  permissions: RolePermissions;
  logout: () => void;
  systemSettings: SystemSettings;
  isOpen: boolean;
  onToggle: () => void;
  isCompact: boolean;
  onToggleCompact: () => void;
  isMobile: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  setView, 
  currentUserRole, 
  permissions, 
  logout, 
  systemSettings,
  isOpen,
  onToggle,
  isCompact,
  onToggleCompact,
  isMobile
}) => {
  const menuItems = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard },
    { id: 'kanban', label: 'Tarefas (Kanban)', icon: Kanban },
    { id: 'productivity', label: 'Produtividade', icon: BarChart2 },
    { id: 'requisitions', label: 'Solicitações', icon: ShoppingCart },
    { id: 'client-portal', label: 'Meus Pedidos', icon: PieChart },
    { id: 'clients', label: 'Gestão de Clientes', icon: HeartHandshake },
    { id: 'catalog', label: 'Produtos & Serviços', icon: ShoppingBag },
    { id: 'teams', label: 'Equipes & Squads', icon: Users },
    { id: 'crm', label: 'CRM / Vendas', icon: Briefcase },
    { id: 'finance', label: 'Financeiro', icon: DollarSign },
    { id: 'permissions', label: 'Acessos (Admin)', icon: Shield },
    { id: 'system-admin', label: 'Config. Sistema', icon: Settings },
    { id: 'help', label: 'Central de Ajuda', icon: HelpCircle },
  ];

  const allowedModules = permissions[currentUserRole] || [];

  return (
    <div 
        className={`fixed left-0 top-0 h-screen z-40 transition-all duration-300 ease-in-out border-r border-slate-800 flex flex-col
          ${!isOpen ? '-translate-x-full' : 'translate-x-0'}
          ${isCompact ? 'w-20' : 'w-64'}
        `}
        style={{ backgroundColor: systemSettings.sidebarColor || '#0f172a' }}
    >
      {/* SIDEBAR TOGGLE BUTTON (CHEVRON) */}
      <button 
        onClick={onToggle}
        aria-label={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        title={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        className={`absolute top-10 -right-4 w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-lg hover:scale-110 transition-all z-50 text-slate-800
          ${!isOpen ? 'translate-x-12 opacity-100' : ''}
        `}
      >
        {isOpen ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
      </button>

      {/* Header / Logo */}
      <div className={`p-6 flex items-center transition-all duration-300 ${isCompact ? 'justify-center p-4' : 'gap-3'}`}>
        {systemSettings.logo ? (
            <img src={systemSettings.logo} alt="Logo" className="w-8 h-8 object-contain rounded bg-white p-0.5 shrink-0" />
        ) : (
            <div 
                className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shrink-0"
                style={{ backgroundColor: systemSettings.primaryColor }}
            >
                {systemSettings.agencyName.charAt(0)}
            </div>
        )}
        {!isCompact && (
          <span className="text-lg font-bold text-white tracking-tight truncate animate-pop" title={systemSettings.agencyName}>
              {systemSettings.agencyName}
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 space-y-2 mt-4 overflow-y-auto hide-scrollbar">
        {menuItems.map((item) => {
           const isAllowed = allowedModules.includes(item.id) || item.id === 'help';
           if (!isAllowed) return null;

           const active = currentView === item.id;

           return (
            <button
              key={item.id}
              onClick={() => {
                  setView(item.id);
                  if (isMobile && !isCompact) onToggle(); // Fecha se for menu full no mobile
              }}
              title={isCompact ? item.label : ""}
              className={`w-full flex items-center rounded-lg transition-all duration-200 
                ${isCompact ? 'justify-center py-3' : 'px-4 py-3 gap-3'}
                ${active ? 'text-white shadow-lg shadow-pink-500/20' : 'text-slate-400 hover:bg-black/20 hover:text-white'}
              `}
              style={active ? { backgroundColor: systemSettings.primaryColor } : {}}
            >
              <item.icon size={20} className="shrink-0" />
              {!isCompact && (
                <span className="font-medium truncate text-sm animate-pop">{item.label}</span>
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer / Logout */}
      <div className={`p-4 border-t border-white/10 ${isCompact ? 'flex justify-center' : ''}`}>
        <button 
          onClick={logout} 
          title={isCompact ? "Sair" : ""}
          className={`flex items-center text-red-400 hover:text-red-300 w-full hover:bg-red-500/10 rounded-lg transition-colors
            ${isCompact ? 'justify-center p-3' : 'px-4 py-3 gap-3'}
          `}
        >
          <LogOut size={20} className="shrink-0" />
          {!isCompact && <span className="text-sm font-bold">Sair</span>}
        </button>
      </div>

      {/* Desktop-only toggle between Compact and Full (Optional UX) */}
      {!isMobile && isOpen && (
        <button 
          onClick={onToggleCompact}
          className="p-3 mx-4 mb-4 bg-white/5 hover:bg-white/10 rounded-lg flex items-center justify-center text-slate-500 transition-colors"
          title={isCompact ? "Expandir Menu" : "Recolher Menu"}
        >
          {isCompact ? <ChevronRight size={16}/> : <ChevronLeft size={16}/>}
        </button>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, FileText, AlertCircle, ShoppingBag, DollarSign, Clock, AlertTriangle, Phone, Calendar } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  // Estado para Criar Nova Requisição
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});

  // Estado para Filtros
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');

  // Estados para Processamento (Feedback Visual)
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Estados para Modal de Reprovação
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  useEffect(() => {
    if(isCreateModalOpen || isRejectModalOpen) {
        console.log("MODAL_OPEN", { screen: "Solicitacoes" });
        console.log("MODAL_OVERLAY_STYLE_APPLIED");
        console.log("MODAL_ZINDEX_FIX_APPLIED");
    }
  }, [isCreateModalOpen, isRejectModalOpen]);

  // 1. Permissões
  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  // Filtragem
  const displayedRequisitions = requisitions.filter(req => {
      if (filter === 'MY') return req.requesterId === currentUser.id;
      if (!canApprove) return req.requesterId === currentUser.id;
      return true;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) {
          alert("Preencha título e valor.");
          return;
      }

      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };

      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove) {
          alert("Erro 403: Sem permissão para aprovar.");
          return;
      }
      if (req.status === 'APPROVED') return;

      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...req,
              status: 'APPROVED',
              approvedBy: currentUser.id,
              approvedAt: now,
              rejectedBy: undefined,
              rejectedAt: undefined,
              rejectedReason: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          const isServiceRequest = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);
          if (!isServiceRequest && req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}-${Date.now()}`,
                  description: `REQ Aprovada: ${req.title} (${req.category})`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador Interno'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }

          const notif: Notification = {
              id: `notif-apr-${Date.now()}`,
              title: isServiceRequest ? 'Solicitação Agendada/Concluída' : 'Solicitação Aprovada',
              message: isServiceRequest 
                ? `Sua solicitação "${req.title}" foi confirmada pela equipe.`
                : `Sua solicitação "${req.title}" no valor de R$ ${req.estimatedCost.toLocaleString()} foi aprovada.`,
              type: 'SUCCESS',
              status: 'UNREAD',
              priority: 'MEDIUM',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: req.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
      }, 800);
  };

  const openRejectModal = (req: Requisition) => {
      setSelectedReqForReject(req);
      setRejectionReason('');
      setIsRejectModalOpen(true);
  };

  const confirmRejection = () => {
      if (!selectedReqForReject) return;
      if (!rejectionReason || rejectionReason.length < 3) {
          alert("O motivo da reprovação é obrigatório (mínimo 3 caracteres).");
          return;
      }
      if (!canApprove) {
          alert("Erro 403: Sem permissão.");
          return;
      }

      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);

      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...reqToReject,
              status: 'REJECTED',
              rejectedBy: currentUser.id,
              rejectedAt: now,
              rejectedReason: rejectionReason,
              approvedBy: undefined,
              approvedAt: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));

          const notif: Notification = {
              id: `notif-rej-${Date.now()}`,
              title: 'Solicitação Recusada',
              message: `Sua solicitação "${reqToReject.title}" foi recusada. Motivo: ${rejectionReason}`,
              type: 'REJECTED',
              status: 'UNREAD',
              priority: 'HIGH',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: reqToReject.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
          setSelectedReqForReject(null);
      }, 800);
  };

  const getCategoryIcon = (cat: string) => {
      switch(cat) {
          case 'Reunião': return <Calendar size={12}/>;
          case 'Atendimento': return <Phone size={12}/>;
          default: return <ShoppingBag size={12}/>;
      }
  };

  return (
    <div className="space-y-6 animate-pop">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Central de Solicitações</h2>
          <p className="text-slate-500">Gestão de compras, reembolsos e agendamentos.</p>
        </div>
        <div className="flex gap-2">
            {canApprove && (
                <div className="bg-slate-100 p-1 rounded-lg flex text-xs font-bold">
                    <button 
                        onClick={() => setFilter('ALL')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'ALL' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setFilter('MY')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'MY' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Minhas
                    </button>
                </div>
            )}
            <button 
                onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
                className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors shadow-lg shadow-pink-500/20"
            >
                <Plus size={18} /> Nova Solicitação
            </button>
        </div>
      </div>

      {/* Grid de Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {displayedRequisitions.length === 0 && (
              <div className="col-span-full p-12 text-center border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
                  <FileText className="mx-auto text-slate-300 mb-2" size={48}/>
                  <p className="text-slate-500 font-medium">Nenhuma solicitação encontrada.</p>
              </div>
          )}

          {displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;
              const isService = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);

              return (
                <div key={req.id} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-shadow relative">
                    {isProcessing && (
                        <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
                            <div className="flex flex-col items-center gap-2">
                                <Clock className="animate-spin text-pink-600" size={32}/>
                                <span className="text-xs font-bold text-pink-600">Processando...</span>
                            </div>
                        </div>
                    )}

                    <div className="p-5 flex-1">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                req.status === 'PENDING' ? 'bg-orange-50 text-orange-700 border-orange-100' : 
                                req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'
                            }`}>
                                {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? (isService ? 'Concluído' : 'Aprovada') : 'Recusada'}
                            </span>
                            <div className="flex items-center gap-1 text-xs text-slate-400">
                                <Clock size={12}/>
                                <span>{req.date.split('-').reverse().join('/')}</span>
                            </div>
                        </div>

                        <h3 className="font-bold text-slate-800 text-lg mb-1 line-clamp-1">{req.title}</h3>
                        <div className="flex items-center gap-2 text-xs text-slate-500 mb-4">
                            <span className="bg-slate-100 px-2 py-0.5 rounded border border-slate-200 flex items-center gap-1">{getCategoryIcon(req.category)} {req.category}</span>
                            {requester && (
                                <span className="flex items-center gap-1" title={requester.name}>
                                    • <img src={requester.avatar} className="w-4 h-4 rounded-full"/> <b>{requester.name.split(' ')[0]}</b>
                                </span>
                            )}
                        </div>

                        <p className="text-sm text-slate-600 mb-4 line-clamp-3 bg-slate-50 p-2 rounded-lg border border-slate-100 min-h-[60px]">
                            {req.description}
                        </p>

                        {req.status === 'REJECTED' && req.rejectedReason && (
                            <div className="bg-red-50 p-3 rounded-lg border border-red-100 mb-4 animate-pop">
                                <p className="text-xs text-red-800 font-bold flex items-center gap-1 mb-1"><AlertCircle size={12}/> Motivo da Recusa:</p>
                                <p className="text-xs text-red-600 italic">"{req.rejectedReason}"</p>
                                {req.rejectedAt && <p className="text-[10px] text-red-400 mt-1 text-right">{new Date(req.rejectedAt).toLocaleString()}</p>}
                            </div>
                        )}

                        {req.status === 'APPROVED' && req.approvedAt && (
                             <div className="bg-emerald-50 p-2 rounded border border-emerald-100 mb-4 text-center">
                                 <p className="text-[10px] text-emerald-600">{isService ? 'Confirmado' : 'Aprovado'} em {new Date(req.approvedAt).toLocaleDateString()}</p>
                             </div>
                        )}
                    </div>

                    <div className="p-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
                        <div>
                            {isService ? (
                                <p className="text-xs font-bold text-slate-500 uppercase">Solicitação de Serviço</p>
                            ) : (
                                <>
                                    <p className="text-[10px] text-slate-400 uppercase font-bold">Valor Solicitado</p>
                                    <p className="text-lg font-bold text-slate-800 flex items-center gap-1">
                                        <span className="text-slate-400 text-sm font-normal">R$</span> {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                    </p>
                                </>
                            )}
                        </div>

                        {canApprove && req.status === 'PENDING' && (
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => handleApproveReq(req)} 
                                    className="px-3 py-2 bg-emerald-100 hover:bg-emerald-200 text-emerald-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title={isService ? "Confirmar Agendamento" : "Aprovar e Lançar Despesa"}
                                >
                                    <Check size={16}/> {isService ? 'Confirmar' : 'Aprovar'}
                                </button>
                                <button 
                                    onClick={() => openRejectModal(req)} 
                                    className="px-3 py-2 bg-red-100 hover:bg-red-200 text-red-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title="Reprovar"
                                >
                                    <X size={16}/> {isService ? 'Recusar' : 'Reprovar'}
                                </button>
                            </div>
                        )}
                    </div>
                </div>
              );
          })}
      </div>

      {/* Modal de Nova Solicitação - PADRONIZADO */}
      {isCreateModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                      <div className="p-2 bg-pink-100 text-pink-600 rounded-xl">
                        <ShoppingBag size={20}/>
                      </div>
                      Nova Solicitação
                  </h3>
                  <div className="space-y-4">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Solicitação</label>
                          <select 
                             className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                             value={editingReq.category}
                             onChange={e => setEditingReq({...editingReq, category: e.target.value})}
                          >
                              {isClient ? (
                                  <>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Outros">Outros</option>
                                  </>
                              ) : (
                                  <>
                                    <option value="Compra">Compra de Material</option>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Vale">Vale / Adiantamento</option>
                                    <option value="Software">Software</option>
                                    <option value="Serviço">Serviço Terceiro</option>
                                  </>
                              )}
                          </select>
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título / Identificação</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder={isClient ? "Ex: Reembolso Uber Reunião" : "Ex: Monitor Dell 24pol"} 
                            value={editingReq.title || ''} 
                            onChange={e => setEditingReq({...editingReq, title: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Justificativa Detalhada</label>
                          <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50 resize-none"
                            placeholder="Descreva a necessidade..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor Estimado (R$)</label>
                          <input 
                            type="number" 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder="0.00" 
                            value={editingReq.estimatedCost || ''} 
                            onChange={e => setEditingReq({...editingReq, estimatedCost: parseFloat(e.target.value)})} 
                          />
                      </div>

                      <div className="pt-4 flex gap-3">
                          <button onClick={() => setIsCreateModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Cancelar</button>
                          <button onClick={handleSaveReq} className="flex-1 py-4 bg-pink-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-pink-700 shadow-xl shadow-pink-500/20 transition-all">Enviar Pedido</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Modal de Reprovação - PADRONIZADO */}
      {isRejectModalOpen && selectedReqForReject && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[210] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop border-t-4 border-red-500 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="flex items-start gap-4 mb-6">
                      <div className="p-3 bg-red-50 rounded-xl text-red-600">
                          <AlertTriangle size={24} />
                      </div>
                      <div>
                          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Recusar Solicitação</h3>
                          <p className="text-sm text-slate-500">Informe o motivo da decisão.</p>
                      </div>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-2xl mb-6 text-sm text-slate-600 border border-slate-100">
                      <p className="font-bold text-slate-800 mb-1">{selectedReqForReject.title}</p>
                      {selectedReqForReject.estimatedCost > 0 && <p className="text-xs font-bold text-slate-400">VALOR: R$ {selectedReqForReject.estimatedCost.toLocaleString()}</p>}
                  </div>

                  <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Motivo da Recusa <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-red-500 focus:bg-white transition-all bg-slate-50 resize-none"
                            placeholder="Descreva o porquê da reprovação..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>

                      <div className="flex gap-3">
                          <button onClick={() => setIsRejectModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Voltar</button>
                          <button 
                            onClick={confirmRejection} 
                            disabled={rejectionReason.length < 3}
                            className="flex-1 py-4 bg-red-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-red-700 shadow-xl shadow-red-500/20 transition-all disabled:opacity-50"
                          >
                              Confirmar Recusa
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, Eye, 
    CheckSquare, Users, CreditCard, Layout, Upload, Check, Activity, AlertCircle, Play, Pause, Calendar, Save,
    Flag, AlignLeft, ShieldCheck, Search, Palette, ExternalLink, UserPlus
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6', '#db2777', '#0f172a', '#64748b'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, setNotifications, openConfirm }) => {
    const [newComment, setNewComment] = useState('');
    const [mentionFilter, setMentionFilter] = useState('');
    const [showMentions, setShowMentions] = useState(false);
    const [newChecklistText, setNewChecklistText] = useState('');

    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [localDueDate, setLocalDueDate] = useState(task.dueDate || '');
    const [localPriority, setLocalPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>(task.priority || 'MEDIUM');
    const [isEditingDesc, setIsEditingDesc] = useState(false);

    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVER' | string | null>(null);
    const [memberSearch, setMemberSearch] = useState('');

    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const commentInputRef = useRef<HTMLTextAreaElement>(null);
    const popoverRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        console.log("MODAL_OPEN", { screen: 'KanbanJob' });
        console.log("MODAL_ZINDEX_FIX_APPLIED");
        return () => console.log("MODAL_CLOSED");
    }, [task.id]);

    useEffect(() => {
        setLocalTitle(task.title);
        setLocalDesc(task.description);
        setLocalDueDate(task.dueDate || '');
        setLocalPriority(task.priority || 'MEDIUM');
    }, [task.id, task.title, task.description, task.dueDate, task.priority]);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                setSecondsElapsed(s => s + 1);
            }, 1000);
        } else {
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [task.isTracking]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setActivePopover(null);
                setShowMentions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const isNewTask = task.history.length === 0;

    const renderBriefingWithLinks = (text: string) => {
        if (!text) return null;
        const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+|[a-zA-Z0-9.-]+\.(com|net|org|br|io|app|gov)(\/[^\s]*)?)/gi;

        return text.split('\n').map((line, i) => (
            <p key={i} className="mb-2 last:mb-0">
                {line.split(urlRegex).map((part, j) => {
                    if (part && part.match(urlRegex)) {
                        const href = part.toLowerCase().startsWith('http') ? part : `https://${part}`;
                        return (
                            <a 
                                key={j} 
                                href={href} 
                                target="_blank" 
                                rel="noopener noreferrer" 
                                className="text-pink-600 underline hover:text-pink-700 break-all inline-flex items-center gap-0.5"
                                onClick={(e) => e.stopPropagation()}
                            >
                                {part} <ExternalLink size={10} className="inline"/>
                            </a>
                        );
                    }
                    if (['com', 'net', 'org', 'br', 'io', 'app', 'gov'].includes(part?.toLowerCase())) return null;
                    return part;
                })}
            </p>
        ));
    };

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const calculateTotalSeconds = () => {
        const closedLogsDuration = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        if (task.isTracking) {
            const activeLog = task.timeLogs.find(l => !l.endTime);
            if (activeLog) {
                const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                return closedLogsDuration + elapsed;
            }
        }
        return closedLogsDuration;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedTaskProps: Partial<Task>, logAction: string) => {
        onUpdate({
            ...task,
            ...updatedTaskProps,
            history: [...task.history, createLog(logAction)]
        });
    };

    const handleFinalConfirmNewTask = () => {
        if (!localTitle.trim()) return;
        onUpdate({
            ...task,
            title: localTitle,
            description: localDesc,
            dueDate: localDueDate,
            priority: localPriority,
            history: [createLog('Tarefa criada no Kanban')]
        });
        onClose();
        confetti({ particleCount: 50, spread: 40, origin: { y: 0.7 } });
    };

    const toggleMember = (userId: string) => {
        const currentIds = task.assigneeIds || [];
        const isAssigned = currentIds.includes(userId);
        const newIds = isAssigned ? currentIds.filter(id => id !== userId) : [...currentIds, userId];
        const user = users.find(u => u.id === userId);
        updateWithLog({ assigneeIds: newIds }, isAssigned ? `removeu ${user?.name}` : `atribuiu ${user?.name}`);
    };

    const toggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    const duration = Math.floor((now - log.startTime) / 1000);
                    return { ...log, endTime: now, duration };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou a produção');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            const newStatus = (task.status === 'BACKLOG' || task.status === 'TODO') ? 'IN_PROGRESS' : task.status;
            updateWithLog({ isTracking: true, status: newStatus, timeLogs: [...task.timeLogs, newLog] }, 'iniciou a produção');
        }
    };

    const handleDueDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = e.target.value;
        setLocalDueDate(newVal);
        if (!isNewTask) updateWithLog({ dueDate: newVal }, `alterou o prazo para ${new Date(newVal).toLocaleDateString()}`);
    };

    const saveTitle = () => {
        if (!localTitle.trim() || localTitle === task.title) return;
        updateWithLog({ title: localTitle }, `alterou o título para "${localTitle}"`);
    };

    const saveDesc = () => {
        setIsEditingDesc(false);
        if (localDesc === task.description) return;
        updateWithLog({ description: localDesc }, `atualizou a descrição`);
    };

    const addChecklistItem = () => {
        if (newChecklistText.trim()) {
            const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
            updateWithLog({ checklists: [...(task.checklists || []), newItem] }, `adicionou etapa: "${newChecklistText}"`);
            setNewChecklistText('');
        }
    };

    const toggleChecklist = (itemId: string) => {
        const item = task.checklists.find(c => c.id === itemId);
        if (!item) return;
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, isCompleted: !c.isCompleted } : c);
        if (!item.isCompleted) updateWithLog({ checklists: newChecklists }, `concluiu "${item.text}"`);
        else onUpdate({...task, checklists: newChecklists});
    };

    const updateChecklistDetails = (itemId: string, updates: Partial<ChecklistItem>) => {
        const item = task.checklists.find(c => c.id === itemId);
        if (!item) return;
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, ...updates } : c);

        let logMsg = '';
        if (updates.assigneeId) {
            const user = users.find(u => u.id === updates.assigneeId);
            logMsg = `atribuiu ${user?.name} à etapa "${item.text}"`;
        } else if (updates.dueDate) {
            logMsg = `definiu prazo para etapa "${item.text}" em ${new Date(updates.dueDate).toLocaleDateString()}`;
        }

        if (logMsg) updateWithLog({ checklists: newChecklists }, logMsg);
        else onUpdate({...task, checklists: newChecklists});
        setActivePopover(null);
    };

    const setCoverColor = (color: string) => {
        updateWithLog({ cover: { type: 'COLOR', value: color } }, 'alterou a cor da capa');
        setActivePopover(null);
    };

    const handleCommentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const val = e.target.value;
        setNewComment(val);
        const cursorPosition = e.target.selectionStart;
        const textUntilCursor = val.slice(0, cursorPosition);
        const match = textUntilCursor.match(/@(\w*)$/);
        if (match) {
            setMentionFilter(match[1].toLowerCase());
            setShowMentions(true);
        } else {
            setShowMentions(false);
        }
    };

    const selectMention = (user: User) => {
        const cursorPosition = commentInputRef.current?.selectionStart || 0;
        const textBefore = newComment.slice(0, cursorPosition).replace(/@\w*$/, '');
        const textAfter = newComment.slice(cursorPosition);
        const updated = textBefore + '@' + user.name + ' ' + textAfter;
        setNewComment(updated);
        setShowMentions(false);
        setTimeout(() => commentInputRef.current?.focus(), 10);
    };

    const addComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        onUpdate({ ...task, comments: [...task.comments, comment] });
        setNewComment('');
    };

    const totalSecondsAccumulated = calculateTotalSeconds();
    const checklistProgress = task.checklists.length > 0 ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) : 0;
    const activityFeed = [...task.comments.map(c => ({ type: 'COMMENT', data: c, timestamp: c.timestamp })), ...task.history.map(h => ({ type: 'HISTORY', data: h, timestamp: h.timestamp }))].sort((a, b) => b.timestamp - a.timestamp);

    const renderMentionList = () => {
        const filtered = users.filter(u => u.role !== 'CLIENT' && u.name.toLowerCase().includes(mentionFilter));
        if (filtered.length === 0) return null;
        return (
            <div className="absolute left-14 bottom-full mb-2 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden z-[210] animate-pop">
                <div className="p-2 bg-slate-50 border-b text-[10px] font-black text-slate-400 uppercase tracking-widest">Mencionar Colaborador</div>
                <div className="max-h-48 overflow-y-auto custom-scrollbar">
                    {filtered.map(u => (
                        <button key={u.id} onClick={() => selectMention(u)} className="w-full flex items-center gap-3 p-3 hover:bg-pink-50 transition-colors text-left border-b border-slate-50 last:border-none">
                            <img src={u.avatar} className="w-6 h-6 rounded-full border border-slate-100" />
                            <div><p className="text-xs font-bold text-slate-700">{u.name}</p><p className="text-[9px] text-slate-400 uppercase">{u.role}</p></div>
                        </button>
                    ))}
                </div>
            </div>
        );
    };

    if (isNewTask) {
        return (
            <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex justify-center items-center p-4 transition-all duration-300" onClick={onClose}>
                <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                    <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-pink-600 rounded-lg"><Plus size={24} /></div>
                            <div><h2 className="text-xl font-bold">Nova Demanda de Trabalho</h2><p className="text-xs text-slate-400">Preencha os detalhes para iniciar a produção.</p></div>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
                    </div>
                    <div className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><CreditCard size={14} className="text-pink-600"/> Título do Job <span className="text-red-500">*</span></label>
                            <input className="w-full text-xl font-bold text-slate-800 bg-slate-50 border-2 border-slate-100 rounded-xl p-4 outline-none focus:border-pink-500 focus:bg-white transition-all" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} placeholder="Ex: Campanha de Natal 2024..." autoFocus />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><Calendar size={14} className="text-indigo-600"/> Data de Entrega</label>
                                <input type="date" className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl p-3 text-sm font-bold text-slate-700 outline-none focus:border-indigo-500 focus:bg-white transition-all" value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><Flag size={14} className="text-amber-600"/> Nível de Prioridade</label>
                                <div className="flex gap-2">
                                    {['LOW', 'MEDIUM', 'HIGH'].map(p => (
                                        <button key={p} onClick={() => setLocalPriority(p as any)} className={`flex-1 py-2.5 rounded-lg text-xs font-bold transition-all border-2 ${localPriority === p ? 'border-slate-800 scale-105' : 'border-transparent opacity-60'} ${p === 'HIGH' ? 'bg-red-100 text-red-600' : p === 'MEDIUM' ? 'bg-amber-100 text-amber-600' : 'bg-slate-200 text-slate-600'}`}>{p === 'HIGH' ? 'Urgente' : p === 'MEDIUM' ? 'Média' : 'Baixa'}</button>
                                    ))}
                                </div>
                            </div>
                        </div>
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><AlignLeft size={14} className="text-slate-600"/> Briefing / Descrição</label>
                            <textarea className="w-full min-h-[120px] bg-slate-50 border-2 border-slate-100 rounded-xl p-4 text-sm text-slate-700 outline-none focus:border-blue-500 focus:bg-white transition-all resize-none" placeholder="Descreva os detalhes da entrega..." value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} />
                        </div>
                    </div>
                    <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
                        <button onClick={onClose} className="px-6 py-3 rounded-xl text-slate-500 font-bold hover:bg-slate-200 transition-colors">Cancelar</button>
                        <button onClick={handleFinalConfirmNewTask} className="px-8 py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-xl shadow-lg shadow-pink-500/30 flex items-center gap-2 transition-all"><Save size={18}/> Iniciar Demanda</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex justify-center overflow-y-auto py-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl relative min-h-[500px] h-fit my-auto mx-4 animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                <button onClick={onClose} className="absolute top-4 right-4 p-2 rounded-full bg-black/5 hover:bg-black/10 z-20 transition-colors"><X size={20} className="text-slate-600"/></button>

                {task.cover && (
                    <div className={`w-full relative ${task.cover.type === 'COLOR' ? 'h-32' : 'h-64'} bg-cover bg-center rounded-t-2xl transition-all`} style={{ backgroundColor: task.cover.type === 'COLOR' ? task.cover.value : undefined, backgroundImage: task.cover.type === 'IMAGE' ? `url(${task.cover.value})` : undefined }}>
                        <button className="absolute bottom-4 right-4 bg-white/90 hover:bg-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase shadow-sm backdrop-blur-sm transition-all" onClick={() => onUpdate({...task, cover: undefined})}>Remover Capa</button>
                    </div>
                )}

                <div className="flex flex-col md:flex-row p-8 gap-8">
                    <div className="flex-1 space-y-6">
                        <div className="flex gap-4 items-start">
                            <CreditCard className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <div className={`relative transition-all rounded-lg p-1 ${localTitle !== task.title ? 'bg-amber-50 ring-2 ring-amber-200' : 'hover:bg-slate-50'}`}>
                                    <input className="text-2xl font-black text-slate-800 w-full bg-transparent border-none outline-none placeholder-slate-300" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} onBlur={saveTitle} onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()} />
                                </div>
                                <div className="text-xs text-slate-400 mt-2 pl-1 font-bold uppercase tracking-wider">Na coluna <span className="text-indigo-600">{task.status}</span></div>
                            </div>
                        </div>

                        {task.assigneeIds.length > 0 && (
                            <div className="flex gap-4 items-center ml-10">
                                <div className="flex -space-x-2">
                                    {task.assigneeIds.map(id => (
                                        <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" title={users.find(u => u.id === id)?.name} />
                                    ))}
                                    <button onClick={() => setActivePopover('MEMBERS')} className="w-10 h-10 rounded-full bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 hover:text-pink-600 hover:border-pink-300 transition-all"><Plus size={18}/></button>
                                </div>
                                <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Responsáveis</p><p className="text-xs text-slate-600 font-bold">{task.assigneeIds.length} pessoa(s) no job</p></div>
                            </div>
                        )}

                        <div className="flex flex-wrap gap-4 ml-10">
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-sm min-w-[200px] flex-1">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2 flex items-center gap-1"><Calendar size={10}/> Data de Entrega</h4>
                                <input type="date" className={`w-full text-sm font-black bg-transparent border-none outline-none ${!localDueDate ? 'text-amber-500' : 'text-slate-700'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-sm flex-1 min-w-[250px]">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2 flex items-center gap-1"><Clock size={10}/> Medição de Produção</h4>
                                <div className="flex items-center justify-between">
                                    <div className="text-xl font-black text-slate-800 font-mono tracking-tighter">{formatSeconds(totalSecondsAccumulated)}</div>
                                    <button onClick={toggleTimer} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${task.isTracking ? 'bg-amber-100 text-amber-700 hover:bg-amber-200 animate-pulse' : 'bg-pink-600 text-white hover:bg-pink-700 shadow-lg shadow-pink-500/30'}`}>
                                        {task.isTracking ? <><Pause size={14} fill="currentColor"/> Pausar</> : <><Play size={14} fill="currentColor"/> Iniciar</>}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <AlignLeft className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-3">Descrição / Briefing</h3>
                                <div className={`relative rounded-xl p-4 transition-all ${isEditingDesc ? 'bg-white ring-2 ring-pink-100 shadow-inner' : 'bg-slate-50 hover:bg-slate-100 cursor-text'}`} onClick={() => !isEditingDesc && setIsEditingDesc(true)}>
                                    {isEditingDesc ? (
                                        <textarea className="w-full min-h-[150px] border-none outline-none text-sm text-slate-700 resize-none bg-transparent" value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} onBlur={saveDesc} autoFocus placeholder="Descreva o job, adicione links de referência ou domínios..." />
                                    ) : (
                                        <div className="text-sm text-slate-700 leading-relaxed min-h-[150px]">{localDesc ? renderBriefingWithLinks(localDesc) : <span className="text-slate-400 italic">Clique para adicionar detalhes, referências ou domínios...</span>}</div>
                                    )}
                                    {!isEditingDesc && localDesc && <div className="absolute top-2 right-2 p-1 text-[8px] font-black text-slate-300 uppercase">Clique para editar</div>}
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <CheckSquare className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <div className="flex justify-between items-center mb-4"><h3 className="font-black text-xs text-slate-400 uppercase tracking-widest">Checklist de Etapas</h3><span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{checklistProgress}% concluído</span></div>
                                {task.checklists.length > 0 && <div className="w-full bg-slate-100 rounded-full h-1.5 mb-6"><div className="bg-emerald-500 h-1.5 rounded-full transition-all duration-700" style={{width: `${checklistProgress}%`}}></div></div>}
                                <div className="space-y-3 mb-4">
                                    {task.checklists.map((item: ChecklistItem) => {
                                        const assignee = users.find(u => u.id === item.assigneeId);
                                        const isOverdue = item.dueDate && new Date(item.dueDate) < new Date() && !item.isCompleted;

                                        return (
                                            <div key={item.id} className="flex items-center gap-3 group hover:bg-slate-50 p-2.5 rounded-xl transition-all border border-transparent hover:border-slate-100 relative">
                                                <input type="checkbox" checked={item.isCompleted} onChange={() => toggleChecklist(item.id)} className="w-5 h-5 rounded-md border-slate-300 text-pink-600 focus:ring-pink-500 cursor-pointer"/>

                                                <div className="flex-1 flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                                                    <span className={`text-sm font-medium transition-all ${item.isCompleted ? 'line-through text-slate-300' : 'text-slate-600'}`}>{item.text}</span>

                                                    <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 focus-within:opacity-100 transition-opacity">
                                                        <div className="relative">
                                                            <input 
                                                                type="date" 
                                                                className={`bg-white border text-[10px] font-bold rounded-lg px-2 py-1 outline-none transition-colors ${isOverdue ? 'border-red-300 text-red-500 bg-red-50' : 'border-slate-200 text-slate-500'}`}
                                                                value={item.dueDate || ''}
                                                                onChange={(e) => updateChecklistDetails(item.id, { dueDate: e.target.value })}
                                                            />
                                                        </div>

                                                        <div className="relative">
                                                            <button 
                                                                onClick={() => setActivePopover(activePopover === `ITEM_MEMBER_${item.id}` ? null : `ITEM_MEMBER_${item.id}`)}
                                                                className={`w-7 h-7 rounded-full border-2 border-white shadow-sm flex items-center justify-center transition-all ${assignee ? 'bg-transparent' : 'bg-slate-100 text-slate-400 hover:bg-pink-50 hover:text-pink-500'}`}
                                                                title={assignee ? `Atribuído a ${assignee.name}` : "Atribuir responsável"}
                                                            >
                                                                {assignee ? <img src={assignee.avatar} className="w-full h-full rounded-full" /> : <UserPlus size={14}/>}
                                                            </button>

                                                            {activePopover === `ITEM_MEMBER_${item.id}` && (
                                                                <div ref={popoverRef} className="absolute right-0 top-full mt-2 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden z-[210] animate-pop">
                                                                    <div className="p-2 bg-slate-50 border-b text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Delegar Etapa</div>
                                                                    <div className="max-h-48 overflow-y-auto custom-scrollbar">
                                                                        {users.filter(u => u.role !== 'CLIENT').map(u => (
                                                                            <button key={u.id} onClick={() => updateChecklistDetails(item.id, { assigneeId: u.id })} className={`w-full flex items-center gap-2 p-2 hover:bg-pink-50 transition-colors text-left ${item.assigneeId === u.id ? 'bg-pink-50' : ''}`}>
                                                                                <img src={u.avatar} className="w-6 h-6 rounded-full" />
                                                                                <span className="text-xs font-bold text-slate-700">{u.name}</span>
                                                                                {item.assigneeId === u.id && <Check size={12} className="ml-auto text-pink-600"/>}
                                                                            </button>
                                                                        ))}
                                                                        <button onClick={() => updateChecklistDetails(item.id, { assigneeId: undefined })} className="w-full p-2 text-center text-[10px] font-bold text-red-400 hover:bg-red-50 border-t">Remover Responsável</button>
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>

                                                        <button onClick={() => updateWithLog({ checklists: task.checklists.filter(c => c.id !== item.id) }, `removeu etapa "${item.text}"`)} className="text-slate-300 hover:text-red-500 p-1 transition-colors"><Trash2 size={16}/></button>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                                <div className="flex gap-2">
                                    <input type="text" placeholder="Nova etapa..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-pink-500 transition-all" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 text-white px-5 rounded-xl text-xs font-black uppercase hover:bg-slate-900 transition-colors">Adicionar</button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <Activity className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6">Atividade & Feed</h3>
                                <div className="flex gap-4 mb-8 relative">
                                    <img src={currentUser.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
                                    <div className="flex-1 space-y-2">
                                        <div className="relative">
                                            <textarea ref={commentInputRef} className="w-full bg-slate-50 border border-slate-100 rounded-xl p-4 text-sm outline-none transition-all resize-none focus:ring-2 focus:ring-pink-100" placeholder="Comente algo ou digite @ para mencionar..." rows={2} value={newComment} onChange={handleCommentChange} />
                                            {showMentions && renderMentionList()}
                                        </div>
                                        <div className="flex justify-end"><button onClick={addComment} disabled={!newComment.trim()} className="bg-indigo-600 text-white px-6 py-2 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-colors">Comentar</button></div>
                                    </div>
                                </div>
                                <div className="space-y-6">
                                    {activityFeed.map((item: any) => {
                                         const u = users.find(user => user.id === item.data.userId) || currentUser;
                                         return item.type === 'COMMENT' ? (
                                             <div key={item.data.id} className="flex gap-4 animate-pop">
                                                 <img src={u.avatar} className="w-10 h-10 rounded-full border border-slate-100" />
                                                 <div className="flex-1"><div className="flex items-baseline gap-2 mb-1"><span className="font-black text-sm text-slate-800">{u.name}</span><span className="text-[10px] font-bold text-slate-400">{new Date(item.timestamp).toLocaleString()}</span></div><div className="bg-white p-4 rounded-2xl border border-slate-100 text-sm text-slate-600 shadow-sm leading-relaxed">{item.data.text}</div></div>
                                             </div>
                                         ) : (
                                            <div key={item.data.id} className="flex gap-4 items-center ml-3 opacity-60"><div className="w-4 h-4 bg-slate-100 rounded-full flex items-center justify-center"><div className="w-1.5 h-1.5 bg-slate-300 rounded-full"></div></div><div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase"><span className="text-slate-600">{u.name}</span><span>{item.data.action}</span><span>• {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span></div></div>
                                         );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="w-full md:w-56 space-y-3 shrink-0">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Ações Rápidas</h4>
                        {task.status !== 'DONE' && <button onClick={() => updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job')} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white p-3 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 transition-all active:scale-95"><CheckCircle size={16}/> Finalizar Job</button>}
                        <div className="py-2"></div>
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Gerenciar</h4>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'MEMBERS' ? null : 'MEMBERS')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'MEMBERS' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><Users size={16}/> Membros</button>
                            {activePopover === 'MEMBERS' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-72 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[210] p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-3 text-center">Atribuir Colaboradores</h5>
                                    <div className="relative mb-4"><Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-100 rounded-lg text-xs outline-none" placeholder="Buscar..." value={memberSearch} onChange={e => setMemberSearch(e.target.value)} /></div>
                                    <div className="space-y-1 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
                                        {users.filter(u => u.role !== 'CLIENT' && u.name.toLowerCase().includes(memberSearch.toLowerCase())).map(u => {
                                            const isSelected = task.assigneeIds.includes(u.id);
                                            return <button key={u.id} onClick={() => toggleMember(u.id)} className={`w-full flex items-center justify-between p-2 rounded-lg transition-colors ${isSelected ? 'bg-pink-50 text-pink-700' : 'hover:bg-slate-50 text-slate-600'}`}><div className="flex items-center gap-2 text-left"><img src={u.avatar} className="w-6 h-6 rounded-full" /><div><p className="text-xs font-bold">{u.name}</p><p className="text-[9px] opacity-60 uppercase">{u.role}</p></div></div>{isSelected && <Check size={14}/>}</button>;
                                        })}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'COVER' ? null : 'COVER')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'COVER' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><ImageIcon size={16}/> Capa</button>
                            {activePopover === 'COVER' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-64 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[210] p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-4 text-center">Cor de Capa</h5>
                                    <div className="grid grid-cols-4 gap-2">{PRESET_COLORS.map(c => <button key={c} onClick={() => setCoverColor(c)} className="w-full aspect-square rounded-lg shadow-sm hover:scale-105 transition-transform" style={{ backgroundColor: c }} />)}</div>
                                </div>
                            )}
                        </div>
                        <div className="py-2 border-t border-slate-100"></div>
                        <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'restaurou o job' : 'arquivou o job')} className="w-full text-left p-3 rounded-xl text-xs font-bold text-slate-500 hover:bg-slate-100 flex items-center gap-2 transition-all"><Archive size={16}/> {task.archived ? 'Desarquivar' : 'Arquivar'}</button>
                        {(currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER') && <button onClick={() => onDeleteTask(task.id)} className="w-full text-left p-3 rounded-xl text-xs font-bold text-red-400 hover:bg-red-50 flex items-center gap-2 transition-all"><Trash2 size={16}/> Excluir permanentemente</button>}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Lead, ColumnConfig, LeadTask, ConfirmOptions, User } from '../types';
import { 
    DollarSign, Plus, Star, CheckSquare, Calendar, Phone, Mail, MessageSquare, 
    Trash2, Clock, User as UserIcon, Briefcase, AlertCircle, Save, X, Settings,
    GripHorizontal, Edit2, ArchiveRestore, Info, Tag
} from 'lucide-react';

interface CRMProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  leadSources: string[];
  setLeadSources: React.Dispatch<React.SetStateAction<string[]>>;
  currentUser: User;
}

export const CRM: React.FC<CRMProps> = ({ leads, setLeads, columns, setColumns, openConfirm, leadSources, setLeadSources, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingLead, setEditingLead] = useState<Partial<Lead>>({ stage: columns[0]?.id || 'NEW', rating: 0, tasks: [] });
  const [activeTab, setActiveTab] = useState<'DETAILS' | 'ACTIVITIES'>('DETAILS');
  const [showValidation, setShowValidation] = useState(false);

  // Column/Settings State
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  // Origin Management
  const [newOrigin, setNewOrigin] = useState('');

  // Task Form State
  const [newTaskText, setNewTaskText] = useState('');
  const [newTaskDate, setNewTaskDate] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');
  const [newTaskType, setNewTaskType] = useState<'CALL' | 'EMAIL' | 'MEETING' | 'TASK'>('TASK');

  const isAdmin = currentUser.role === 'ADMIN';

  useEffect(() => {
    if(isModalOpen || isSettingsOpen || isColumnModalOpen) {
        console.log("MODAL_OPEN", { screen: 'CRM' });
        console.log("MODAL_ZINDEX_FIX_APPLIED");
    }
  }, [isModalOpen, isSettingsOpen, isColumnModalOpen]);

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const handleSave = () => {
      if (!editingLead.company || !editingLead.name || (!editingLead.value && editingLead.value !== 0)) {
          setShowValidation(true);
          return;
      }

      if(editingLead.id) {
          setLeads(prev => prev.map(l => l.id === editingLead.id ? { ...l, ...editingLead } as Lead : l));
      } else {
          setLeads(prev => [...prev, { ...editingLead, id: Date.now().toString(), lastContact: new Date().toISOString() } as Lead]);
      }
      setIsModalOpen(false);
      resetForm();
  };

  const resetForm = () => {
    setEditingLead({ stage: activeColumns[0]?.id || 'NEW', rating: 0, tasks: [] });
    setActiveTab('DETAILS');
    setShowValidation(false);
  };

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'crm-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'bg-slate-50 border-slate-200',
            order: columns.length,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleDeleteColumn = async (colId: string) => {
      const hasLeads = leads.some(l => l.stage === colId);
      if (hasLeads) {
          alert("Mova os leads desta etapa antes de excluí-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Excluir Etapa?",
          description: "Esta ação removerá permanentemente esta etapa do funil.",
          confirmText: "Excluir"
      });
      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
      }
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) return;
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const newCols = [...columns];
      const draggedIdx = newCols.findIndex(c => c.id === draggedColumnId);
      const targetIdx = newCols.findIndex(c => c.id === targetColId);
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  const addOrigin = () => {
      if (!newOrigin.trim() || leadSources.includes(newOrigin)) return;
      setLeadSources(prev => [...prev, newOrigin.trim()]);
      setNewOrigin('');
  };

  const deleteOrigin = async (origin: string) => {
      const ok = await openConfirm({
          title: "Remover Origem?",
          description: `Deseja remover "${origin}" das opções? Leads existentes manterão esta origem.`,
          variant: "danger"
      });
      if (ok) setLeadSources(prev => prev.filter(o => o !== origin));
  };

  const handleDeleteLead = async (id: string) => {
      const ok = await openConfirm({
          title: "Excluir Oportunidade?",
          description: "Deseja remover permanentemente este Lead? Esta ação não pode ser desfeita.",
          variant: "danger",
          confirmText: "Excluir Definitivamente"
      });
      if (ok) {
          setLeads(prev => prev.filter(l => l.id !== id));
          setIsModalOpen(false);
          resetForm();
      }
  };

  const addTaskToLead = () => {
      if(!newTaskText) return;
      const newTask: LeadTask = { 
          id: Date.now().toString(), 
          text: newTaskText, 
          completed: false,
          dueDate: newTaskDate || new Date().toISOString().split('T')[0],
          time: newTaskTime || '09:00',
          type: newTaskType
      };
      setEditingLead({ ...editingLead, tasks: [newTask, ...(editingLead.tasks || [])] });
      setNewTaskText('');
      setNewTaskDate('');
      setNewTaskTime('');
  };

  const toggleTask = (taskId: string) => {
      const updatedTasks = editingLead.tasks?.map(t => t.id === taskId ? {...t, completed: !t.completed} : t);
      setEditingLead({...editingLead, tasks: updatedTasks});
  };

  const getTaskIcon = (type: string) => {
      switch(type) {
          case 'CALL': return <Phone size={14} className="text-blue-500"/>;
          case 'EMAIL': return <Mail size={14} className="text-yellow-500"/>;
          case 'MEETING': return <UserIcon size={14} className="text-purple-500"/>;
          default: return <CheckSquare size={14} className="text-emerald-500"/>;
      }
  };

  const handleDragStartLead = (e: React.DragEvent, leadId: string) => {
      setDraggedLeadId(leadId);
      e.dataTransfer.setData('type', 'lead');
      e.dataTransfer.effectAllowed = "move";
  };

  const handleDropLead = (e: React.DragEvent, targetStage: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;
      setLeads(prev => prev.map(l => l.id === draggedLeadId ? { ...l, stage: targetStage, lastContact: new Date().toISOString() } : l));
      setDraggedLeadId(null);
  };

  const getInputClass = (value: any) => {
      const baseClass = "w-full border rounded p-2 text-sm transition-all";
      if (showValidation && (!value || value === 0)) return `${baseClass} border-red-500 bg-red-50 focus:ring-red-200`;
      return `${baseClass} border-slate-200 focus:border-pink-500 focus:ring-4 focus:ring-pink-50 outline-none`;
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Pipeline de Vendas</h2>
          <p className="text-slate-500 text-sm font-medium">Gestão de oportunidades e previsão de fechamento</p>
        </div>
        <div className="flex gap-2">
            {isAdmin && (
                <button onClick={() => setIsSettingsOpen(true)} className="p-2.5 rounded-xl text-slate-500 bg-white border border-slate-200 hover:bg-slate-50 transition-all shadow-sm">
                    <Settings size={20}/>
                </button>
            )}
            <button onClick={() => { resetForm(); setIsModalOpen(true)}} className="bg-pink-600 hover:bg-pink-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-pink-500/20">
                <Plus size={18} /> Novo Lead
            </button>
        </div>
      </div>

      <div className="flex-1 flex gap-5 overflow-x-auto pb-6 hide-scrollbar">
          {activeColumns.map(col => (
              <div 
                key={col.id} 
                draggable={isAdmin}
                onDragStart={(e) => onColumnDragStart(e, col.id)}
                onDragOver={(e) => e.preventDefault()}
                onDrop={(e) => {
                    const type = e.dataTransfer.getData('type');
                    if (type === 'column') onColumnDrop(e, col.id);
                    else handleDropLead(e, col.id);
                }}
                className={`flex-shrink-0 w-80 flex flex-col rounded-2xl border transition-all ${col.color} bg-opacity-40 ${draggedColumnId === col.id ? 'opacity-20 scale-95' : ''}`}
              >
                  <div className="p-4 flex items-center justify-between border-b border-black/5 cursor-default">
                      <div className="flex items-center gap-2">
                         {isAdmin && <GripHorizontal size={14} className="text-slate-400 cursor-grab active:cursor-grabbing"/>}
                         <h3 className="font-black text-[10px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                      </div>
                      <span className="text-[10px] bg-white/80 px-2 py-0.5 rounded-full font-black text-slate-500 shadow-sm">
                          {leads.filter(l => l.stage === col.id).length}
                      </span>
                  </div>
                  <div className="p-3 flex-1 overflow-y-auto space-y-3 custom-scrollbar min-h-[150px]">
                      {leads.filter(l => l.stage === col.id).map(lead => (
                          <div 
                            key={lead.id} 
                            draggable
                            onDragStart={(e) => handleDragStartLead(e, lead.id)}
                            onClick={() => { setEditingLead(lead); setIsModalOpen(true) }} 
                            className="bg-white p-4 rounded-xl shadow-sm border-2 border-white hover:border-pink-200 transition-all cursor-grab active:cursor-grabbing group"
                          >
                                <div className="flex justify-between items-start mb-2">
                                    <h4 className="font-bold text-slate-800 group-hover:text-pink-600 transition-colors leading-tight flex-1">{lead.company}</h4>
                                    <div className="flex gap-0.5 text-amber-400">
                                        {[1,2,3].map(s => <Star key={s} size={10} fill={s <= (lead.rating || 0) ? "currentColor" : "none"} />)}
                                    </div>
                                </div>
                                <p className="text-xs text-slate-500 mb-4">{lead.name}</p>

                                <div className="flex justify-between items-center pt-3 border-t border-slate-50">
                                    <p className="text-sm font-black text-slate-800 flex items-center gap-1"><DollarSign size={14} className="text-emerald-500"/> {lead.value.toLocaleString()}</p>
                                    {lead.source && <span className="text-[9px] font-black uppercase text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">{lead.source}</span>}
                                </div>
                          </div>
                      ))}
                  </div>
              </div>
          ))}

          {isAdmin && (
               <button 
                onClick={() => { setEditingColumn({ label: '', color: 'bg-slate-50 border-slate-200' }); setIsColumnModalOpen(true); }}
