      )}

      {/* --- CRM SETTINGS MODAL --- */}
      {isSettingsOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsSettingsOpen(false)}>
