                                    <td className="p-4 text-xs font-bold text-slate-500 uppercase">{asset.type}</td>
                                    <td className="p-4 font-black">R$ {asset.cost.toLocaleString()}</td>
                                    <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${asset.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>{asset.status === 'ACTIVE' ? 'Em Uso' : 'Baixado'}</span></td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1">
                                            <button onClick={()=>{setEditingAsset(asset); setIsAssetModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={16}/></button>
                                            <button onClick={()=>handleStartDeleteAsset(asset)} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {activeAssets.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="p-12 text-center text-slate-400 font-medium italic">Nenhum ativo registrado no momento.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}

          {activeTab === 'TRANSACTIONS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50 flex flex-col sm:flex-row justify-between items-center gap-4">
                      <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest flex items-center gap-2"><FileText size={16} className="text-indigo-600"/> Razão Geral</h3>
                      <button onClick={()=>{setEditingTx({type:'EXPENSE', dueDate: new Date().toISOString().split('T')[0]}); setIsTxModalOpen(true)}} className="w-full sm:w-auto bg-pink-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase shadow-lg"><Plus size={14}/> Lançamento</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                      <table className="w-full text-sm text-left min-w-[600px]">
                          <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                              <tr><th className="p-4">Data</th><th className="p-4">Descrição</th><th className="p-4">Tipo</th><th className="p-4">Status</th><th className="p-4 text-right">Valor</th><th className="p-4 text-center">Ações</th></tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {transactions.map(t => (
                                  <tr key={t.id} className="hover:bg-slate-50 group transition-colors">
                                      <td className="p-4 text-slate-400 font-medium whitespace-nowrap">{t.dueDate.split('-').reverse().join('/')}</td>
                                      <td className="p-4 font-bold text-slate-800">{t.description}</td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>{t.type === 'INCOME' ? 'REC' : 'DES'}</span></td>
                                      <td className="p-4"><span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${t.status === 'PAID' ? 'bg-slate-100 text-slate-500' : 'bg-amber-50 text-amber-600'}`}>{t.status === 'PAID' ? 'LIQ' : 'PEN'}</span></td>
                                      <td className={`p-4 text-right font-black whitespace-nowrap ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {t.amount.toLocaleString()}</td>
                                      <td className="p-4 text-center">
                                          <div className="flex justify-center gap-1">
                                              <button onClick={() => setTransactions(prev => prev.map(x => x.id === t.id ? { ...x, status: x.status === 'PAID' ? 'PENDING' : 'PAID' } : x))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-emerald-600"><CheckCircle size={14}/></button>
                                              <button onClick={() => setTransactions(prev => prev.filter(x => x.id !== t.id))} className="p-1.5 hover:bg-white rounded text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
                                          </div>
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          )}

          {activeTab === 'STOCK' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2 text-sm"><Box size={18} className="text-pink-600"/> Insumos</h3>
                      <button onClick={() => {setEditingStock({category:'OFFICE', quantity:0, minQuantity:5}); setIsStockModalOpen(true)}} className="bg-slate-900 text-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase"><Plus size={12}/> Novo</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                    <table className="w-full text-sm text-left min-w-[500px]">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Item</th><th className="p-4 text-center">Qtd</th><th className="p-4 text-center">Min.</th><th className="p-4">Preço</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {stock.map(item => (
                                <tr key={item.id} className="hover:bg-slate-50">
                                    <td className="p-4"><p className="font-bold text-slate-800">{item.name}</p></td>
                                    <td className={`p-4 text-center font-black ${item.quantity <= item.minQuantity ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</td>
                                    <td className="p-4 text-center text-slate-400 font-bold">{item.minQuantity}</td>
                                    <td className="p-4 font-medium whitespace-nowrap">R$ {item.unitPrice.toLocaleString()}</td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center gap-1">
                                            <button onClick={()=>{setEditingStock(item); setIsStockModalOpen(true)}} className="p-1.5 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit2 size={14}/></button>
                                            <button onClick={()=>setStock(prev => prev.filter(i => i.id !== item.id))} className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={14}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                  </div>
              </div>
          )}
      </div>

      {/* --- MODAIS DE GESTÃO - PADRONIZADOS COM Z-INDEX ALTO --- */}

      {/* EXCLUSÃO DE PATRIMÔNIO */}
      {isAssetDeleteModalOpen && assetToExclude && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={handleCancelDeleteAsset}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border-t-4 border-red-600 border-x border-b border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-50 border-b flex items-center justify-between">
                      <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Excluir Patrimônio</h3>
                      <button onClick={handleCancelDeleteAsset} className="text-slate-400 hover:text-slate-600"><X/></button>
                  </div>
                  <div className="p-8 space-y-6">
                      <div className="bg-red-50 p-4 rounded-2xl border border-red-100 flex gap-3">
                          <AlertTriangle className="text-red-600 shrink-0" size={20}/>
                          <div className="text-xs text-red-800 leading-relaxed">
                              <p className="font-bold mb-1">Atenção!</p>
                              Esta exclusão removerá o item <b>{assetToExclude.name}</b> da visão operacional permanentemente. O registro será mantido apenas para histórico de auditoria.
                          </div>
                      </div>

                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2 ml-1">Motivo da Exclusão <span className="text-red-500">*</span></label>
                          <textarea 
                            className={`w-full border-2 rounded-2xl p-4 text-sm font-bold outline-none focus:bg-white transition-all resize-none h-32 ${exclusionError ? 'border-red-300 bg-red-50' : 'border-slate-100 bg-slate-50 focus:border-red-400'}`}
                            placeholder="Descreva detalhadamente o porquê desta exclusão (ex: venda, obsolescência, extravio...)"
                            value={exclusionReason}
                            onChange={e => { setExclusionReason(e.target.value); setExclusionError(''); }}
                          />
                          {exclusionError && <p className="text-[10px] text-red-500 font-bold mt-1 ml-1">{exclusionError}</p>}
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                          <button onClick={handleCancelDeleteAsset} className="w-full bg-slate-100 text-slate-500 py-4 rounded-2xl font-black uppercase text-xs hover:bg-slate-200 transition-all">Cancelar</button>
                          <button 
                            onClick={handleConfirmDeleteAsset} 
                            className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase text-xs shadow-xl shadow-red-200 hover:bg-red-700 active:scale-95 transition-all"
                          >
                              Confirmar Exclusão
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* PATRIMÔNIO (EDICAO/CADASTRO) */}
      {isAssetModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsAssetModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl animate-pop p-8 border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-black uppercase tracking-tight">{editingAsset.id ? 'Editar Patrimônio' : 'Registro de Patrimônio'}</h3>
                    <button onClick={()=>setIsAssetModalOpen(false)} className="text-slate-400 hover:text-slate-600"><X/></button>
                  </div>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Ativo (ex: MacBook Pro)" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nº Série / Licença" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.purchaseDate || ''} onChange={e => setEditingAsset({...editingAsset, purchaseDate: e.target.value})} />
                          <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" value={editingAsset.type} onChange={e => setEditingAsset({...editingAsset, type: e.target.value as any})}><option value="HARDWARE">Hardware</option><option value="SOFTWARE">Software (SaaS)</option><option value="OFFICE">Mobiliário</option></select>
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Salvar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashOpenModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashOpenModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between"><h3 className="text-xl font-black uppercase tracking-tighter">Novo Ciclo Mensal</h3><button onClick={()=>setIsCashOpenModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Conta Operacional</label><select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50" onChange={e => setEditingMove({ ...editingMove, cashAccountId: e.target.value })}><option value="">Selecione...</option>{cashAccounts.filter(a => a.isCashRegister).map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>
                      <div><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Fundo Inicial de Reserva (R$)</label><input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none focus:bg-white" placeholder="0.00" onChange={e => setEditingMove({ ...editingMove, amount: parseFloat(e.target.value) })} /></div>
                      <button onClick={() => handleOpenCash(editingMove.cashAccountId!, editingMove.amount!)} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"><Unlock size={20}/> Iniciar Ciclo</button>
                  </div>
              </div>
          </div>
      )}

      {isMoveModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsMoveModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 text-white flex justify-between ${editingMove.type === 'RECEBIMENTO' || editingMove.type === 'SUPRIMENTO' ? 'bg-emerald-600' : 'bg-red-600'}`}><h3 className="text-xl font-black uppercase tracking-tighter">{editingMove.type}</h3><button onClick={()=>setIsMoveModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Descrição da operação..." value={editingMove.description || ''} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-3xl font-black outline-none" placeholder="0.00" value={editingMove.amount || ''} onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => handleCreateMovement(editingMove)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Confirmar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashCloseModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashCloseModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between"><h3 className="text-xl font-black uppercase">Fechar Turno</h3><button onClick={()=>setIsCashCloseModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center"><p className="text-[10px] font-black text-slate-400 uppercase">Saldo Esperado</p><p className="text-2xl font-black">R$ {cashSessions.find(s => s.id === editingMove.cashRegisterId)?.expectedFinalAmount.toLocaleString()}</p></div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none" placeholder="Saldo Real Contado" onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <textarea className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50 resize-none outline-none focus:bg-white" placeholder="Observações..." rows={3} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <button onClick={() => handleCloseCash(editingMove.cashRegisterId!, editingMove.amount!, editingMove.description || '')} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase">Encerrar Ciclo Mensal</button>
                  </div>
              </div>
          </div>
      )}

      {selectedReportCycle && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setSelectedReportCycle(null)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[80vh] shadow-2xl animate-pop overflow-hidden flex flex-col border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="text-xl font-black uppercase tracking-tighter">Resumo Mensal: {selectedReportCycle.monthReference}</h3><button onClick={()=>setSelectedReportCycle(null)}><X/></button></div>
                  <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Abertura</p><p className="font-bold">R$ {selectedReportCycle.initialAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Esperado</p><p className="font-bold">R$ {selectedReportCycle.expectedFinalAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Furo / Dif.</p><p className={`font-black ${selectedReportCycle.differenceAmount === 0 ? 'text-emerald-600' : 'text-red-600'}`}>R$ {selectedReportCycle.differenceAmount?.toLocaleString()}</p></div>
                      </div>
                      <div>
                          <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-3 border-b pb-2">Movimentos do Período</h4>
                          <div className="space-y-2">
                              {cashMovements.filter(m => m.cashRegisterId === selectedReportCycle.id).map(m => (
                                  <div key={m.id} className="flex justify-between items-center p-3 bg-white border border-slate-50 rounded-xl shadow-sm">
                                      <div><p className="text-xs font-bold text-slate-800">{m.description}</p><p className="text-[9px] text-slate-400 uppercase">{m.type}</p></div>
                                      <p className={`font-black text-sm ${m.type === 'RECEBIMENTO' ? 'text-emerald-600' : 'text-red-600'}`}>R$ {m.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                      {selectedReportCycle.observations && <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100"><p className="text-[10px] font-black text-amber-700 uppercase mb-1">Notas de Auditoria</p><p className="text-xs italic text-amber-900">"{selectedReportCycle.observations}"</p></div>}
                  </div>
                  <div className="p-6 border-t bg-slate-50 flex justify-end gap-3"><button onClick={() => window.print()} className="px-6 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold text-xs uppercase transition-all flex items-center gap-2"><Download size={14}/> Imprimir PDF</button><button onClick={()=>setSelectedReportCycle(null)} className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase">Fechar Relatório</button></div>
              </div>
          </div>
      )}

      {isStockModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8 border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tight">{editingStock.id ? 'Editar Item' : 'Novo Item em Estoque'}</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Nome do Insumo" value={editingStock.name || ''} onChange={e => setEditingStock({...editingStock, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Qtd. Atual" value={editingStock.quantity || ''} onChange={e => setEditingStock({...editingStock, quantity: parseInt(e.target.value)})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Qtd. Min." value={editingStock.minQuantity || ''} onChange={e => setEditingStock({...editingStock, minQuantity: parseInt(e.target.value)})} />
                      </div>
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Preço Unit." value={editingStock.unitPrice || ''} onChange={e => setEditingStock({...editingStock, unitPrice: parseFloat(e.target.value)})} />
                      <select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" value={editingStock.category} onChange={e => setEditingStock({...editingStock, category: e.target.value as any})}><option value="OFFICE">Escritório</option><option value="IT">TI / Tecnologia</option><option value="CLEANING">Limpeza</option><option value="MARKETING">Eventos/Brindes</option></select>
                      <button onClick={handleSaveStock} className="w-full bg-pink-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-pink-700 transition-all">Salvar no Estoque</button>
                  </div>
              </div>
          </div>
      )}

      {isTxModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8 border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase">Novo Lançamento Geral</h3>
                  <div className="space-y-4">
                      <div className="flex gap-2 p-1 bg-slate-100 rounded-xl"><button onClick={()=>setEditingTx({...editingTx, type:'INCOME'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'INCOME' ? 'bg-white text-emerald-600' : 'text-slate-400'}`}>Receita (+)</button><button onClick={()=>setEditingTx({...editingTx, type:'EXPENSE'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${editingTx.type === 'EXPENSE' ? 'bg-white text-red-600' : 'text-slate-400'}`}>Despesa (-)</button></div>
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Descrição do Lançamento" value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" placeholder="Valor R$" onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                          <input type="date" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" value={editingTx.dueDate} onChange={e => setEditingTx({...editingTx, dueDate: e.target.value})} />
                      </div>
                      <button onClick={() => {if(editingTx.amount && editingTx.description){setTransactions(p=>[{...editingTx, id:`tx-${Date.now()}`, status:'PAID'} as FinancialRecord, ...p]); setIsTxModalOpen(false); setEditingTx({})}}} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Gravar no Fluxo</button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AgencyService, ConfirmOptions } from '../types';
import { Plus, Edit2, Trash2, ShoppingBag, CheckCircle, XCircle, X } from 'lucide-react';

interface ServiceCatalogProps {
  services: AgencyService[];
  setServices: React.Dispatch<React.SetStateAction<AgencyService[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

export const ServiceCatalog: React.FC<ServiceCatalogProps> = ({ services, setServices, openConfirm }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingService, setEditingService] = useState<Partial<AgencyService>>({ active: true });

  useEffect(() => {
    if(isModalOpen) {
        console.log("MODAL_OPEN", { screen: 'Catalogo' });
        console.log("MODAL_ZINDEX_FIX_APPLIED");
    }
  }, [isModalOpen]);

  const handleSave = () => {
    if (!editingService.name) return;

    if (editingService.id) {
        setServices(prev => prev.map(s => s.id === editingService.id ? { ...s, ...editingService } as AgencyService : s));
    } else {
        setServices(prev => [...prev, { ...editingService, id: Date.now().toString() } as AgencyService]);
    }
    setIsModalOpen(false);
    setEditingService({ active: true });
  };

  const handleDelete = async (id: string) => {
      const ok = await openConfirm({
          title: "Remover do Catálogo?",
          description: "Deseja realmente excluir este serviço? Clientes que já o possuem no contrato não serão afetados, mas ele não poderá ser vendido para novos clientes.",
          variant: "danger",
          confirmText: "Excluir Serviço"
      });

      if(ok) {
          setServices(prev => prev.filter(s => s.id !== id));
      }
  };

  return (
    <div className="space-y-6">
       <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Catálogo de Serviços</h2>
          <p className="text-slate-500">Gerencie os produtos e serviços oferecidos pela agência</p>
        </div>
        <button onClick={() => { setEditingService({ active: true }); setIsModalOpen(true)}} className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors shadow-lg shadow-pink-500/20">
          <Plus size={18} /> Novo Serviço
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {services.map(service => (
              <div key={service.id} className={`bg-white rounded-xl border shadow-sm p-6 relative group transition-all hover:shadow-md ${!service.active ? 'opacity-70 border-slate-100' : 'border-slate-200'}`}>
                  <div className="flex justify-between items-start mb-4">
                      <div className={`p-3 rounded-lg ${service.active ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-100 text-slate-400'}`}>
                          <ShoppingBag size={24} />
                      </div>
                      <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${service.active ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-200 text-slate-500'}`}>
                          {service.active ? 'Ativo' : 'Inativo'}
                      </span>
                  </div>

                  <h3 className="text-lg font-bold text-slate-800 mb-2">{service.name}</h3>
                  <p className="text-sm text-slate-500 mb-4 h-10 line-clamp-2">{service.description}</p>

                  <div className="flex justify-between items-end border-t border-slate-100 pt-4">
                      <div>
                          <p className="text-xs text-slate-400 font-bold uppercase">Preço Base</p>
                          <p className="text-xl font-bold text-slate-800">R$ {service.basePrice.toLocaleString()}</p>
                      </div>
                      <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => { setEditingService(service); setIsModalOpen(true); }} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded"><Edit2 size={16}/></button>
                          <button onClick={() => handleDelete(service.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={16}/></button>
                      </div>
                  </div>
              </div>
          ))}
      </div>

      {isModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[200] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-black text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                        <div className="p-2 bg-pink-100 text-pink-600 rounded-xl"><ShoppingBag size={20}/></div>
                        {editingService.id ? 'Editar Serviço' : 'Novo Serviço'}
                      </h3>
                      <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400"/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Nome do Serviço/Produto</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder="Ex: Gestão de Mídia Social"
                            value={editingService.name || ''}
                            onChange={e => setEditingService({...editingService, name: e.target.value})}
                          />
                      </div>
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Preço Base (R$)</label>
                          <input 
                            type="number"
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder="0.00"
                            value={editingService.basePrice || ''}
                            onChange={e => setEditingService({...editingService, basePrice: parseFloat(e.target.value)})}
                          />
                      </div>
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Descrição Curta</label>
                          <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50 resize-none"
                            placeholder="Detalhes do que está incluso..."
                            rows={3}
                            value={editingService.description || ''}
                            onChange={e => setEditingService({...editingService, description: e.target.value})}
                          />
                      </div>
                      <div className="flex items-center gap-3 pt-2 bg-slate-50 p-4 rounded-2xl border border-slate-100">
                          <input 
                            type="checkbox" 
                            id="serviceActive"
                            checked={editingService.active}
                            onChange={e => setEditingService({...editingService, active: e.target.checked})}
                            className="w-5 h-5 text-pink-600 rounded-md border-slate-300 focus:ring-pink-500"
                          />
                          <label htmlFor="serviceActive" className="text-xs text-slate-700 font-bold uppercase">Serviço Ativo no Catálogo</label>
                      </div>

                      <div className="flex justify-end gap-3 pt-4">
                          <button onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Cancelar</button>
                          <button onClick={handleSave} className="flex-1 py-4 bg-pink-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-pink-700 shadow-xl shadow-pink-500/20 transition-all">Salvar Serviço</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { NotificationService } from './services/notificationService';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, LeadTask, ConfirmOptions } from './types';
import { Users, Settings, Bell, Check, Gift, AlertTriangle, Info, Clock, CheckCircle, Shield, Trash2, Archive, Eye, DollarSign, Briefcase } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  // --- SIDEBAR STATE & PERSISTENCE ---
  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      // No mobile, se estiver aberto, garantimos que comece compacto para não tampar tudo
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
    console.log("SIDEBAR_TOGGLE", { isOpen: sidebarOpen, isCompact: sidebarCompact, viewport: isMobile ? "mobile" : "desktop" });
  }, [sidebarOpen, sidebarCompact, isMobile]);

  const toggleSidebar = () => {
      if (isMobile) {
          // No mobile: Oculto -> Compacto -> Oculto
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          // No desktop: Toggle Simples Aberto/Oculto
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  // --- REST OF STATE ---
  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const [activeNotifTab, setActiveNotifTab] = useState('ALL');
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Automations logic (Background worker simulator)
  useEffect(() => {
      if (!currentUser) return;
      const checkAutomations = () => {
          const now = new Date();
          let updatedNotifs = [...notifications];
          transactions.forEach(tx => {
              if (tx.status === 'PENDING' && tx.type === 'INCOME') {
                  const dueDate = new Date(tx.dueDate);
                  const diffDays = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
                  if ([7, 3, 1].includes(diffDays)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Fatura Próxima ao Vencimento',
                          message: `A fatura de R$ ${tx.amount} (${tx.description}) vence em ${diffDays} dia(s).`,
                          type: 'WARNING',
                          priority: diffDays === 1 ? 'HIGH' : 'MEDIUM',
                          originModule: 'FINANCE',
                          targetRole: 'FINANCE',
                          navToView: 'finance'
                      });
                  }
              }
          });
          leads.forEach(lead => {
              if (!lead.lastContact) return;
              const lastContact = new Date(lead.lastContact);
              const diffDays = Math.ceil((now.getTime() - lastContact.getTime()) / (1000 * 60 * 60 * 24));
              if (diffDays >= 3 && lead.stage !== 'WON') {
                  updatedNotifs = NotificationService.create(updatedNotifs, {
                      title: 'Lead Sem Follow-up',
                      message: `O lead ${lead.company} está sem contato há ${diffDays} dias.`,
                      type: 'WARNING',
                      priority: 'MEDIUM',
                      originModule: 'CRM',
                      targetUserId: currentUser.id, 
                      navToView: 'crm'
                  });
              }
          });
          tasks.forEach(task => {
              if (task.status !== 'DONE' && !task.archived) {
                  const dueDate = new Date(task.dueDate);
                  const diffMs = dueDate.getTime() - now.getTime();
                  const diffHours = diffMs / (1000 * 60 * 60);
                  if (diffHours > 0 && diffHours <= 24 && task.assigneeIds.includes(currentUser.id)) {
                      updatedNotifs = NotificationService.create(updatedNotifs, {
                          title: 'Prazo de Tarefa Próximo',
                          message: `A tarefa "${task.title}" vence em menos de 24h!`,
                          type: 'WARNING',
                          priority: diffHours <= 2 ? 'HIGH' : 'MEDIUM',
                          originModule: 'KANBAN',
                          targetUserId: currentUser.id,
                          navToView: 'kanban'
                      });
                  }
              }
          });
          if (updatedNotifs.length !== notifications.length) {
              setNotifications(updatedNotifs);
          }
      };
      const interval = setInterval(checkAutomations, 60000); 
      checkAutomations(); 
      return () => clearInterval(interval);
  }, [transactions, leads, tasks, currentUser, notifications]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const handleNotificationAction = (id: string, action: 'READ' | 'ARCHIVE') => {
      setNotifications(prev => prev.map(n => {
          if (n.id === id) {
              return { ...n, status: action === 'READ' ? 'READ' : 'ARCHIVED' };
          }
          return n;
      }));
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const filteredNotifs = NotificationService.filterByTab(notifications, activeNotifTab)
      .filter(n => !n.targetUserId || n.targetUserId === currentUser.id)
      .filter(n => !n.targetRole || n.targetRole === currentUser.role);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  // --- DYNAMIC LAYOUT CALCULATION ---
  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  const contentMargin = !isMobile ? getSidebarWidth() : '0px';
  const mobileMargin = (isMobile && sidebarOpen && sidebarCompact) ? '80px' : '0px';

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className="flex-1 flex flex-col min-h-screen transition-all duration-300 ease-in-out p-4 md:p-8"
        style={{ marginLeft: !isMobile ? contentMargin : mobileMargin }}
      >
        {/* TOP STICKY BAR: Notificações e Perfil */}
        <div className="sticky top-0 z-30 -mx-4 md:-mx-8 px-4 md:px-8 py-3 mb-6 md:mb-8 bg-slate-50/80 backdrop-blur-md border-b border-slate-200/50 flex justify-between items-center gap-4 shrink-0 transition-all">
            {/* Título de seção para mobile quando menu está oculto */}
            <div className="md:hidden font-black text-slate-400 text-xs uppercase tracking-widest truncate">
                {currentView}
            </div>

            <div className="flex items-center gap-2 ml-auto">
                <div className="relative" ref={notificationRef}>
                    <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 rounded-full border transition-all relative bg-white shadow-sm hover:shadow-md">
                        <Bell size={20} className="text-slate-500" />
                        {unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-white animate-bounce">
                                {unreadCount > 9 ? '9+' : unreadCount}
                            </span>
                        )}
                    </button>

                    {showNotifications && (
                        <div className="absolute right-0 top-full mt-3 w-[320px] md:w-[420px] bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden z-[100] animate-pop origin-top-right">
                            <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                                <h3 className="font-bold text-slate-800">Alertas</h3>
                                <button onClick={markAllAsRead} className="text-xs font-bold text-pink-600 hover:text-pink-700 flex items-center gap-1">
                                    <Check size={14}/> Lidas
                                </button>
                            </div>
                            <div className="max-h-[450px] overflow-y-auto custom-scrollbar">
                                {filteredNotifs.length === 0 ? (
                                    <div className="p-12 text-center flex flex-col items-center gap-3">
                                        <Bell size={32} className="text-slate-200"/>
                                        <p className="text-sm text-slate-400">Nenhuma notificação.</p>
                                    </div>
                                ) : (
                                    filteredNotifs.map(notif => (
                                        <div key={notif.id} className={`p-4 border-b border-slate-50 transition-all group relative ${notif.status === 'UNREAD' ? 'bg-blue-50/10' : 'opacity-70'}`}>
                                            <div className="flex gap-3">
                                                <div className="flex-1 cursor-pointer" onClick={() => { if(notif.navToView) setCurrentView(notif.navToView); handleNotificationAction(notif.id, 'READ'); setShowNotifications(false); }}>
                                                    <p className={`text-sm font-bold ${notif.status === 'UNREAD' ? 'text-slate-800' : 'text-slate-500'}`}>{notif.title}</p>
                                                    <p className="text-xs text-slate-600 leading-relaxed line-clamp-2">{notif.message}</p>
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="flex items-center gap-2 bg-white px-3 md:px-4 py-2 rounded-full shadow-sm border border-slate-100 hover:shadow-md transition-shadow cursor-pointer" onClick={() => setCurrentView('settings')}>
                    <div className="text-right hidden sm:block">
                        <p className="text-sm font-bold text-slate-800">{currentUser.name}</p>
                        <p className="text-[10px] text-slate-500 uppercase font-black">{currentUser.role}</p>
                    </div>
                    <img src={currentUser.avatar} alt="Perfil" className="w-8 h-8 md:w-10 md:h-10 rounded-full border-2 border-slate-100" />
                </div>
            </div>
        </div>

        <div className="flex-1 w-full max-w-full overflow-x-hidden">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} setNotifications={setNotifications} />}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Plus, Calendar, Archive, Eye, Inbox, Play, Pause, Clock, MoreVertical, Settings, 
    GripHorizontal, X, Edit2, ArchiveRestore, Info, Trash2
} from 'lucide-react';
import confetti from 'canvas-confetti';
import { TaskModal } from './TaskModal';
import { NotificationService } from '../services/notificationService';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ tasks, setTasks, users, currentUser, columns, setColumns, setNotifications, openConfirm }) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [columnMenuId, setColumnMenuId] = useState<string | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const isManagerOrAdmin = currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER';
  const pendingRequests = tasks.filter(t => t.clientRequest && t.approvalStatus === 'PENDING');

  useEffect(() => {
    if(isColumnModalOpen) console.log("POPUP_OPENED", { type: 'ColumnModal' });
    if(showArchivedColumns) console.log("POPUP_OPENED", { type: 'ArchivedColumnsModal' });
  }, [isColumnModalOpen, showArchivedColumns]);

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const archivedColumns = useMemo(() => 
    columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order),
  [columns]);

  const formatSeconds = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    if (h > 0) return `${h}h ${m}m`;
    return `${m}m`;
  };

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'col-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'border-slate-400',
            order: columns.length,
            wipLimit: editingColumn.wipLimit || null,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleArchiveColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;
      const hasTasks = tasks.some(t => t.status === colId && !t.archived);
      if (hasTasks) {
          alert("Mova as tarefas ativas desta coluna antes de arquivá-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Arquivar Lista?",
          description: `A lista "${col.label}" será ocultada.`,
          confirmText: "Arquivar"
      });
      if (ok) {
          setColumns(prev => prev.map(c => c.id === colId ? { ...c, isArchived: true } : c));
          setColumnMenuId(null);
      }
  };

  const handleDeleteColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;

      const hasTasks = tasks.some(t => t.status === colId);
      if (hasTasks) {
          alert("Esta coluna possui tarefas (ativas ou arquivadas). Exclua ou mova as tarefas antes de remover a coluna definitivamente.");
          return;
      }

      const ok = await openConfirm({
          title: "Excluir Lista Permanentemente?",
          description: `Deseja remover a lista "${col.label}" do sistema? Esta ação é irreversível.`,
          variant: "danger",
          confirmText: "Excluir Definitivamente"
      });

      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
          setColumnMenuId(null);
      }
  };

  const handleRestoreColumn = (colId: string) => {
      setColumns(prev => prev.map(c => c.id === colId ? { ...c, isArchived: false } : c));
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) {
          e.preventDefault();
          return;
      }
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
      e.dataTransfer.effectAllowed = 'move';
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const draggedIdx = columns.findIndex(c => c.id === draggedColumnId);
      const targetIdx = columns.findIndex(c => c.id === targetColId);
      const newCols = [...columns];
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  const handleApprove = (taskId: string) => {
      const task = tasks.find(t => t.id === taskId);
      if(!task) return;
      setTasks(prev => prev.map(t => t.id === taskId ? { 
          ...t, 
          approvalStatus: 'APPROVED', 
          status: activeColumns[0]?.id || 'BACKLOG',
          history: [...t.history, { id: Date.now().toString(), action: 'Aprovou a solicitação', userId: currentUser.id, timestamp: Date.now() }] 
      } : t));
      setNotifications(prev => NotificationService.create(prev, {
          title: 'Solicitação Aprovada',
          message: `O job "${task.title}" entrou em produção.`,
          type: 'SUCCESS',
          priority: 'MEDIUM',
          originModule: 'KANBAN',
          targetUserId: task.assigneeIds[0],
          navToView: 'kanban'
      }));
      confetti({ particleCount: 50, spread: 50, origin: { y: 0.6 } });
  };

  const updateTask = (updated: Task) => {
      setTasks(prev => {
          const exists = prev.some(t => t.id === updated.id);
          return exists ? prev.map(t => t.id === updated.id ? updated : t) : [...prev, updated];
      });
      if (selectedTask && selectedTask.id === updated.id) setSelectedTask(updated);
  };

  const toggleTimerQuick = (e: React.MouseEvent, task: Task) => {
    e.stopPropagation();
    const now = Date.now();
    let updatedTask = { ...task };
    if (task.isTracking) {
      const updatedLogs = task.timeLogs.map(log => {
        if (!log.endTime) {
          const endTime = now;
          const duration = Math.floor((endTime - log.startTime) / 1000);
          return { ...log, endTime, duration };
        }
        return log;
      });
      updatedTask = { ...task, isTracking: false, timeLogs: updatedLogs };
    } else {
      const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
      const newStatus = (task.status === 'BACKLOG' || task.status === 'TODO') ? 'IN_PROGRESS' : task.status;
      updatedTask = { ...task, isTracking: true, status: newStatus, timeLogs: [...task.timeLogs, newLog] };
    }
    updateTask(updatedTask);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (e.dataTransfer.getData('type') === 'column') return;
      if (!draggedTaskId) return;

      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          const col = columns.find(c => c.id === targetColId);
          const currentTasksInCol = tasks.filter(t => t.status === targetColId && !t.archived).length;
          if (col?.wipLimit && currentTasksInCol >= col.wipLimit) {
              alert(`Limite de WIP atingido para ${col.label} (${col.wipLimit}).`);
              setDraggedTaskId(null);
              return;
          }
          const isDone = targetColId === 'DONE';
          let updatedTask: Task = {
              ...task,
              status: targetColId,
              completedAt: isDone ? Date.now() : task.completedAt,
              history: [...task.history, { id: Date.now().toString(), action: `moveu para ${col?.label}`, userId: currentUser.id, timestamp: Date.now() }]
          };
          if (isDone && task.isTracking) {
            updatedTask.isTracking = false;
            updatedTask.timeLogs = task.timeLogs.map(log => {
              if (!log.endTime) {
                const endTime = Date.now();
                const duration = Math.floor((endTime - log.startTime) / 1000);
                return { ...log, endTime, duration };
              }
              return log;
            });
          }
          updateTask(updatedTask);
          if (targetColId === 'DONE') confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
      }
      setDraggedTaskId(null);
  };

  return (
    <div className="h-full flex flex-col">
      {/* STICKY KANBAN HEADER: Título e Botões de Ação */}
      <div className="sticky top-[76px] z-20 -mx-4 md:-mx-8 px-4 md:px-8 py-4 mb-4 bg-slate-50/90 backdrop-blur-sm flex justify-between items-center transition-all">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Quadro de Jobs</h2>
          <p className="text-slate-500 text-sm font-medium">Fluxo ágil de produção e entregas</p>
        </div>
        <div className="flex gap-2">
            {isAdmin && (
                <button onClick={() => setShowArchivedColumns(true)} className="px-3 py-2 rounded-xl text-xs font-black bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 flex items-center gap-2 transition-all uppercase tracking-wider shadow-sm">
                    <Settings size={16}/> Listas
                </button>
            )}
            <button onClick={() => setShowArchived(!showArchived)} className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider flex items-center gap-2 transition-all border shadow-sm ${showArchived ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}>
                {showArchived ? <Eye size={16}/> : <Archive size={16}/>} {showArchived ? 'Ver Ativos' : 'Arquivados'}
            </button>
            <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: new Date().toISOString().split('T')[0], estimatedTime: 0, timeLogs: [], isTracking: false, assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], archived: false } as Task)} className="bg-pink-600 text-white px-5 py-2 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-500/30 hover:bg-pink-700 transition-all transform hover:scale-105 active:scale-95">
                <Plus size={18} strokeWidth={3} /> Novo Job
            </button>
        </div>
      </div>

      {isManagerOrAdmin && pendingRequests.length > 0 && (
          <div className="mb-6 bg-amber-50 border-2 border-amber-100 rounded-2xl p-5 animate-pop">
              <div className="flex items-center gap-2 mb-4">
                  <div className="bg-amber-500 p-2 rounded-lg text-white shadow-md"><Inbox size={20}/></div>
                  <h3 className="font-black text-amber-900 uppercase text-xs tracking-widest">Triagem: Solicitações de Clientes ({pendingRequests.length})</h3>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {pendingRequests.map(req => (
                      <div key={req.id} className="bg-white p-4 rounded-xl border border-amber-200 shadow-sm flex flex-col">
                          <h4 className="font-bold text-slate-800 text-sm mb-1">{req.title}</h4>
                          <p className="text-xs text-slate-500 mb-4 line-clamp-2 leading-relaxed">{req.description}</p>
                          <div className="flex gap-2 mt-auto">
                              <button onClick={() => handleApprove(req.id)} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg text-[10px] font-black uppercase hover:bg-emerald-700 transition-all shadow-sm">Aprovar</button>
                              <button onClick={() => updateTask({...req, archived: true, approvalStatus: 'REJECTED'})} className="flex-1 bg-slate-100 text-slate-500 py-2 rounded-lg text-[10px] font-black uppercase hover:bg-slate-200 transition-all">Recusar</button>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      <div className="flex-1 flex gap-5 overflow-x-auto pb-6 hide-scrollbar">
        {activeColumns.map(col => {
          const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived));
          const isOverWip = col.wipLimit && colTasks.length > col.wipLimit;

          return (
            <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()}
                onDrop={e => {
                    const type = e.dataTransfer.getData('type');
                    if (type === 'column') onColumnDrop(e, col.id);
                    else handleDropTask(e, col.id);
                }}
                className={`flex-shrink-0 w-80 flex flex-col rounded-2xl bg-slate-100/40 border border-slate-200/50 transition-all ${draggedColumnId === col.id ? 'opacity-20 scale-95' : ''}`}
            >
              <div 
                draggable={isAdmin}
                onDragStart={e => onColumnDragStart(e, col.id)}
                className={`p-4 font-black text-[10px] uppercase tracking-widest text-slate-500 flex justify-between items-center bg-white/80 backdrop-blur rounded-t-2xl border-b border-slate-200 cursor-default ${isAdmin ? 'cursor-grab active:cursor-grabbing hover:bg-white transition-colors' : ''}`}
              >
                 <div className="flex items-center gap-2">
                    {isAdmin && <GripHorizontal size={14} className="text-slate-300"/>}
                    <span className="text-slate-700">{col.label}</span>
                    {col.wipLimit && (
                        <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-black ${isOverWip ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-200 text-slate-500'}`}>
                            {colTasks.length}/{col.wipLimit}
                        </span>
                    )}
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">{colTasks.length}</span>
                    {isAdmin && (
                        <div className="relative">
                            <button onClick={() => setColumnMenuId(columnMenuId === col.id ? null : col.id)} className="p-1 hover:bg-slate-200 rounded-lg text-slate-400">
                                <MoreVertical size={16}/>
                            </button>
                            {columnMenuId === col.id && (
                                <div className="absolute right-0 top-full mt-2 w-52 bg-white shadow-2xl rounded-xl border border-slate-100 z-50 py-2 animate-pop">
                                    <button onClick={() => { setEditingColumn(col); setIsColumnModalOpen(true); setColumnMenuId(null); }} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                                        <Edit2 size={14} className="text-blue-500"/> Editar Lista
                                    </button>
                                    <button onClick={() => handleArchiveColumn(col.id)} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-slate-600 hover:bg-slate-50 flex items-center gap-3">
                                        <Archive size={14} className="text-slate-500"/> Arquivar Lista
                                    </button>
                                    <button onClick={() => handleDeleteColumn(col.id)} className="w-full text-left px-4 py-2 text-[10px] font-black uppercase text-red-600 hover:bg-red-50 flex items-center gap-3 border-t border-slate-50 mt-1 pt-2">
                                        <Trash2 size={14}/> Excluir Definitivamente
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                 </div>
              </div>

              <div className="p-3 flex-1 overflow-y-auto space-y-3 custom-scrollbar min-h-[150px]">
                {colTasks.map(task => {
                    const totalSeconds = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
                    const isOverdue = task.dueDate && new Date(task.dueDate) < new Date() && task.status !== 'DONE';

                    return (
                      <div 
                        key={task.id} 
                        draggable 
                        onDragStart={e => { 
                            e.stopPropagation(); 
                            e.dataTransfer.setData('type', 'task'); 
                            setDraggedTaskId(task.id); 
                            e.dataTransfer.effectAllowed = 'move';
                        }} 
                        onClick={() => setSelectedTask(task)} 
                        className={`bg-white p-4 rounded-xl shadow-sm border-2 transition-all cursor-grab active:cursor-grabbing group ${task.isTracking ? 'border-pink-500 ring-4 ring-pink-50' : 'border-white hover:border-pink-200 hover:shadow-md'}`}
                      >
                          <div className="flex justify-between items-start mb-3">
                            <div className="flex flex-wrap gap-1">
                                {task.priority === 'HIGH' && <span className="bg-red-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-wider shadow-sm">Urgente</span>}
                                {task.isTracking && <span className="bg-amber-400 text-white text-[8px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-wider animate-pulse shadow-sm">Ativo</span>}
                            </div>
                            <div className="flex -space-x-2">
                                {task.assigneeIds.map(uid => {
                                    const u = users.find(u => u.id === uid);
                                    return <img key={uid} src={u?.avatar} className="w-6 h-6 rounded-full border-2 border-white shadow-sm" title={u?.name}/>
                                })}
                            </div>
                          </div>
                          <h4 className="text-sm font-bold text-slate-800 leading-snug mb-4 group-hover:text-pink-600 transition-colors">{task.title}</h4>

                          <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50">
                              <div className="flex flex-col gap-1.5">
                                  {task.dueDate && (
                                      <div className={`flex items-center gap-1.5 text-[9px] font-black uppercase tracking-tight ${isOverdue ? 'text-red-500' : 'text-slate-400'}`}>
                                          <Calendar size={12} className={isOverdue ? 'animate-pulse' : ''}/>
                                          {new Date(task.dueDate).toLocaleDateString()}
                                      </div>
                                  )}
                                  {totalSeconds > 0 && (
                                      <div className="flex items-center gap-1.5 text-[9px] font-black text-indigo-500 uppercase tracking-tight">
                                          <Clock size={12}/> {formatSeconds(totalSeconds)}
                                      </div>
                                  )}
                              </div>
                              <button 
                                  onClick={(e) => toggleTimerQuick(e, task)}
                                  className={`p-2 rounded-xl transition-all shadow-sm ${task.isTracking ? 'bg-amber-100 text-amber-600 hover:bg-amber-200' : 'bg-slate-50 text-slate-400 hover:bg-pink-50 hover:text-pink-600 opacity-0 group-hover:opacity-100'}`}
                                  title={task.isTracking ? "Pausar Produção" : "Iniciar Produção"}
                              >
                                  {task.isTracking ? <Pause size={16} fill="currentColor"/> : <Play size={16} fill="currentColor"/>}
                              </button>
                          </div>
                      </div>
                    );
                })}
              </div>
            </div>
          );
        })}

        {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }}
                className="flex-shrink-0 w-80 h-16 bg-slate-200/30 border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200/50 hover:text-slate-600 hover:border-slate-400 transition-all group"
            >
                <Plus size={20} className="group-hover:scale-125 transition-transform" /> Nova Lista
            </button>
        )}
      </div>

      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-sm p-8 shadow-2xl animate-pop" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-black text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                        <div className="p-2 bg-pink-100 text-pink-600 rounded-xl"><Settings size={20}/></div>
                        {editingColumn?.id ? 'Configurar Lista' : 'Nova Lista'}
                      </h3>
                      <button onClick={() => setIsColumnModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400"/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título da Lista</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 focus:bg-white transition-all bg-slate-50"
                            placeholder="Ex: Em Espera, Bloqueado..."
                            value={editingColumn?.label || ''}
                            onChange={e => setEditingColumn({...editingColumn, label: e.target.value})}
                          />
                      </div>

                      <div className="grid grid-cols-1 gap-6">
                          <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Limite WIP (Cartões)</label>
                              <input 
                                type="number"
                                className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 bg-slate-50"
                                placeholder="Ilimitado"
                                value={editingColumn?.wipLimit || ''}
                                onChange={e => setEditingColumn({...editingColumn, wipLimit: parseInt(e.target.value) || null})}
                              />
                          </div>
                      </div>

                      <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white font-black py-4 rounded-2xl hover:bg-slate-800 transition-all mt-4 uppercase tracking-widest text-xs shadow-xl shadow-slate-900/20 active:scale-95">
                          {editingColumn?.id ? 'Salvar Alterações' : 'Criar Lista'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {showArchivedColumns && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setShowArchivedColumns(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl animate-pop" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-black text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                        <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><Archive size={20}/></div>
                        Listas Arquivadas
                      </h3>
                      <button onClick={() => setShowArchivedColumns(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400"/></button>
                  </div>

                  <div className="space-y-3 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                      {archivedColumns.length === 0 && (
                          <div className="text-center p-12 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                              <Info size={40} className="mx-auto text-slate-300 mb-3"/>
                              <p className="text-xs text-slate-500 font-black uppercase tracking-widest">Nenhuma lista arquivada.</p>
                          </div>
                      )}
                      {archivedColumns.map(col => (
                          <div key={col.id} className="flex items-center justify-between p-5 bg-white border border-slate-200 rounded-2xl shadow-sm">
                              <div className="flex items-center gap-4">
                                  <div className="w-3 h-3 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)]"></div>
                                  <span className="font-bold text-slate-800">{col.label}</span>
                              </div>
                              <div className="flex gap-2">
                                  <button 
                                    onClick={() => handleRestoreColumn(col.id)}
                                    className="px-4 py-2 bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-indigo-700 flex items-center gap-2 transition-all shadow-lg shadow-indigo-200"
                                  >
                                      <ArchiveRestore size={14}/> Reativar
                                  </button>
                                  <button 
                                    onClick={() => handleDeleteColumn(col.id)}
                                    className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                                    title="Excluir Permanentemente"
                                  >
                                      <Trash2 size={18}/>
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
                  <button onClick={() => setShowArchivedColumns(false)} className="w-full mt-8 py-4 bg-slate-100 text-slate-500 font-black uppercase tracking-widest text-[10px] rounded-2xl hover:bg-slate-200 transition-all">Fechar Janela</button>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={updateTask}
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }}
            currentUser={currentUser}
            setNotifications={setNotifications}
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Plus, Calendar, Archive, Eye, Inbox, Play, Pause, Clock, MoreVertical, Settings, 
    GripHorizontal, X, Edit2, ArchiveRestore, Info, Trash2, CheckSquare, ListTodo
} from 'lucide-react';
import confetti from 'canvas-confetti';
import { TaskModal } from './TaskModal';
import { NotificationService } from '../services/notificationService';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ tasks, setTasks, users, currentUser, columns, setColumns, setNotifications, openConfirm }) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [columnMenuId, setColumnMenuId] = useState<string | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const isManagerOrAdmin = currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER';
  const pendingRequests = tasks.filter(t => t.clientRequest && t.approvalStatus === 'PENDING');

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const archivedColumns = useMemo(() => 
    columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order),
  [columns]);

  const formatSeconds = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
  };

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'col-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'border-slate-400',
            order: columns.length,
            wipLimit: editingColumn.wipLimit || null,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleArchiveColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;
      const hasTasks = tasks.some(t => t.status === colId && !t.archived);
      if (hasTasks) {
          alert("Mova as tarefas ativas desta coluna antes de arquivá-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Arquivar Lista?",
          description: `A lista "${col.label}" será ocultada.`,
          confirmText: "Arquivar"
      });
      if (ok) {
          setColumns(prev => prev.map(c => c.id === colId ? { ...c, isArchived: true } : c));
          setColumnMenuId(null);
      }
  };

  const handleDeleteColumn = async (colId: string) => {
      const col = columns.find(c => c.id === colId);
      if(!col) return;
      const ok = await openConfirm({
          title: "Excluir Lista?",
          description: `Deseja remover a lista "${col.label}" permanentemente?`,
          variant: "danger"
      });
      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
          setColumnMenuId(null);
      }
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) return;
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const newCols = [...columns];
      const draggedIdx = newCols.findIndex(c => c.id === draggedColumnId);
      const targetIdx = newCols.findIndex(c => c.id === targetColId);
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  const updateTask = (updated: Task) => {
      setTasks(prev => {
          const exists = prev.some(t => t.id === updated.id);
          return exists ? prev.map(t => t.id === updated.id ? updated : t) : [updated, ...prev];
      });
      if (selectedTask && selectedTask.id === updated.id) setSelectedTask(updated);
  };

  const toggleTimerQuick = (e: React.MouseEvent, task: Task) => {
    e.stopPropagation();
    const now = Date.now();
    let updatedTask = { ...task };
    if (task.isTracking) {
      const updatedLogs = task.timeLogs.map(log => {
        if (!log.endTime) {
          const endTime = now;
          const duration = Math.floor((endTime - log.startTime) / 1000);
          return { ...log, endTime, duration };
        }
        return log;
      });
      updatedTask = { ...task, isTracking: false, timeLogs: updatedLogs };
    } else {
      const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
      const newStatus = (task.status === 'BACKLOG' || task.status === 'TODO') ? 'IN_PROGRESS' : task.status;
      updatedTask = { ...task, isTracking: true, status: newStatus, timeLogs: [...task.timeLogs, newLog] };
    }
    updateTask(updatedTask);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (e.dataTransfer.getData('type') === 'column') return;
      if (!draggedTaskId) return;

      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          const isDone = targetColId === 'DONE' || targetColId.toLowerCase().includes('concluido');
          let updatedTask: Task = {
              ...task,
              status: targetColId,
              completedAt: isDone ? Date.now() : task.completedAt,
              history: [...task.history, { id: Date.now().toString(), action: `moveu para ${targetColId}`, userId: currentUser.id, timestamp: Date.now() }]
          };
          updateTask(updatedTask);
          if (isDone) confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
      }
      setDraggedTaskId(null);
  };

  return (
    <div className="h-full flex flex-col overflow-hidden">
      {/* HEADER INTEGRADO E SLIM */}
      <div className="sticky top-[76px] z-20 -mx-4 md:-mx-8 px-4 md:px-8 pb-4 bg-slate-50/95 backdrop-blur-md flex flex-wrap justify-between items-center gap-4 transition-all">
        <div className="flex items-center gap-3">
          <div className="bg-pink-600/10 p-2 rounded-lg text-pink-600">
            <ListTodo size={20} />
          </div>
          <div>
            <h2 className="text-xl font-bold text-slate-800 leading-none">Quadro de Jobs</h2>
            <p className="text-slate-500 text-xs font-medium mt-1">Fluxo de produção ágil</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
            {isAdmin && (
                <button 
                  onClick={() => setShowArchivedColumns(true)} 
                  className="p-2 bg-white text-slate-500 border border-slate-200 hover:bg-slate-50 rounded-lg transition-all shadow-sm"
                  title="Configurar Colunas"
                >
                    <Settings size={18}/>
                </button>
            )}
            <button 
              onClick={() => setShowArchived(!showArchived)} 
              className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-all border shadow-sm ${showArchived ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
            >
                {showArchived ? <Eye size={14}/> : <Archive size={14}/>} 
                <span className="hidden sm:inline">{showArchived ? 'Ver Ativos' : 'Arquivados'}</span>
            </button>
            <div className="h-6 w-px bg-slate-200 mx-1"></div>
            <button 
              onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: new Date().toISOString().split('T')[0], estimatedTime: 0, timeLogs: [], isTracking: false, assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], archived: false } as Task)} 
              className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-xs font-bold shadow-lg shadow-pink-500/20 transition-all transform hover:scale-[1.02] active:scale-95"
            >
                <Plus size={16} /> <span className="hidden sm:inline">Novo Job</span>
            </button>
        </div>
      </div>

      {/* ÁREA DO BOARD COM SCROLL HORIZONTAL LIMPO */}
      <div className="flex-1 flex gap-4 overflow-x-auto pb-4 custom-scrollbar items-start">
        {activeColumns.map(col => {
          const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived));
          const isOverWip = col.wipLimit && colTasks.length > col.wipLimit;

          return (
            <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()}
                onDrop={e => {
                    const type = e.dataTransfer.setData('type', 'column');
                    if (e.dataTransfer.getData('type') === 'column') onColumnDrop(e, col.id);
                    else handleDropTask(e, col.id);
                }}
                className={`flex-shrink-0 w-72 flex flex-col max-h-full rounded-xl bg-slate-200/50 border border-slate-300/30 transition-all ${draggedColumnId === col.id ? 'opacity-20' : ''}`}
            >
              {/* HEADER DA COLUNA */}
              <div 
                draggable={isAdmin}
                onDragStart={e => onColumnDragStart(e, col.id)}
                className={`group p-3 flex justify-between items-center cursor-default ${isAdmin ? 'cursor-grab active:cursor-grabbing' : ''}`}
              >
                 <div className="flex items-center gap-2 overflow-hidden">
                    <div className="w-1 h-4 rounded-full bg-slate-400 group-hover:bg-pink-500 transition-colors"></div>
                    <span className="text-[11px] font-black uppercase tracking-wider text-slate-600 truncate">{col.label}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-md font-bold ${isOverWip ? 'bg-red-500 text-white' : 'bg-slate-300 text-slate-600'}`}>
                        {colTasks.length}{col.wipLimit ? `/${col.wipLimit}` : ''}
                    </span>
                 </div>

                 {isAdmin && (
                    <button onClick={() => setColumnMenuId(columnMenuId === col.id ? null : col.id)} className="p-1 hover:bg-slate-300 rounded text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity">
                        <MoreVertical size={14}/>
                    </button>
                 )}
              </div>

              {/* LISTA DE CARDS */}
              <div className="flex-1 overflow-y-auto overflow-x-hidden p-2 space-y-3 custom-scrollbar min-h-[100px]">
                {colTasks.map(task => {
                    const totalSeconds = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
                    const isOverdue = task.dueDate && new Date(task.dueDate) < new Date() && task.status !== 'DONE';
                    const progress = task.checklists.length > 0 ? (task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100 : 0;

                    return (
                      <div 
                        key={task.id} 
                        draggable 
                        onDragStart={e => { 
                            e.stopPropagation(); 
                            setDraggedTaskId(task.id); 
                        }} 
                        onClick={() => setSelectedTask(task)} 
                        className={`bg-white p-3 rounded-lg shadow-sm border border-transparent hover:border-pink-200 transition-all cursor-grab active:cursor-grabbing group ring-pink-500/10 ${task.isTracking ? 'ring-4' : 'hover:shadow-md'}`}
                      >
                          {/* Top Row: Priority & Avatars */}
                          <div className="flex justify-between items-start mb-2">
                            <div className={`text-[9px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-tighter ${
                                task.priority === 'HIGH' ? 'bg-red-50 text-red-600' : 
                                task.priority === 'MEDIUM' ? 'bg-amber-50 text-amber-600' : 'bg-blue-50 text-blue-600'
                            }`}>
                                {task.priority}
                            </div>
                            <div className="flex -space-x-1.5">
                                {task.assigneeIds.slice(0, 3).map(uid => {
                                    const u = users.find(u => u.id === uid);
                                    return <img key={uid} src={u?.avatar} className="w-5 h-5 rounded-full border border-white shadow-sm" title={u?.name}/>
                                })}
                                {task.assigneeIds.length > 3 && (
                                    <div className="w-5 h-5 rounded-full bg-slate-100 border border-white flex items-center justify-center text-[8px] font-bold text-slate-500">
                                        +{task.assigneeIds.length - 3}
                                    </div>
                                )}
                            </div>
                          </div>

                          {/* Task Title */}
                          <h4 className="text-xs font-bold text-slate-700 leading-tight mb-2 group-hover:text-pink-600 transition-colors">
                              {task.title || <span className="italic opacity-50">Sem título</span>}
                          </h4>

                          {/* Progress Line (Only if exists) */}
                          {task.checklists.length > 0 && (
                              <div className="w-full h-1 bg-slate-100 rounded-full mb-3 overflow-hidden">
                                  <div className="h-full bg-pink-500 transition-all duration-500" style={{ width: `${progress}%` }}></div>
                              </div>
                          )}

                          {/* Bottom Row: Icons & Timer */}
                          <div className="flex items-center justify-between text-[10px] font-medium text-slate-400 mt-2 pt-2 border-t border-slate-50">
                              <div className="flex items-center gap-2">
                                  {task.dueDate && (
                                      <div className={`flex items-center gap-1 ${isOverdue ? 'text-red-500' : ''}`}>
                                          <Calendar size={12}/>
                                          {new Date(task.dueDate).toLocaleDateString([], {day:'2-digit', month:'2-digit'})}
                                      </div>
                                  )}
                                  {task.checklists.length > 0 && (
                                      <div className="flex items-center gap-1">
                                          <CheckSquare size={12}/>
                                          {task.checklists.filter(c => c.isCompleted).length}/{task.checklists.length}
                                      </div>
                                  )}
                              </div>

                              <div className="flex items-center gap-1">
                                  {task.isTracking && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-pulse"></div>}
                                  <span className={task.isTracking ? 'text-amber-600 font-bold' : ''}>
                                      {formatSeconds(totalSeconds)}
                                  </span>
                                  <button 
                                      onClick={(e) => toggleTimerQuick(e, task)}
                                      className={`ml-1 p-1 rounded-md transition-colors ${task.isTracking ? 'bg-amber-100 text-amber-600' : 'hover:bg-slate-100 opacity-0 group-hover:opacity-100'}`}
                                  >
                                      {task.isTracking ? <Pause size={10} fill="currentColor"/> : <Play size={10} fill="currentColor"/>}
                                  </button>
                              </div>
                          </div>
                      </div>
                    );
                })}

                {/* BOTÃO CONTEXTUAL "+" NO RODAPÉ DA COLUNA */}
                <button 
                    onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: new Date().toISOString().split('T')[0], estimatedTime: 0, timeLogs: [], isTracking: false, assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], archived: false } as Task)}
                    className="w-full py-2 flex items-center justify-center gap-2 text-slate-400 hover:text-pink-600 hover:bg-white/50 rounded-lg transition-all text-xs font-bold opacity-0 group-hover/col:opacity-100"
                >
                    <Plus size={14}/> Criar novo Job
                </button>
              </div>
            </div>
          );
        })}

        {/* COLUNA ADICIONAL PARA NOVA LISTA */}
        {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }}
                className="flex-shrink-0 w-72 h-12 bg-slate-200/30 border-2 border-dashed border-slate-300 rounded-xl flex items-center justify-center gap-2 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200/50 hover:text-slate-600 transition-all group"
            >
                <Plus size={16} /> Nova Lista
            </button>
        )}
      </div>

      {/* MODAL CONFIGURAÇÃO COLUNA */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-md z-[210] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-3 uppercase tracking-tighter">
                    <div className="p-2 bg-pink-100 text-pink-600 rounded-lg"><Settings size={18}/></div>
                    Configurar Coluna
                  </h3>

                  <div className="space-y-4">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 ml-1">Título da Lista</label>
                          <input 
                            className="w-full border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none focus:border-pink-500 bg-slate-50"
                            value={editingColumn?.label || ''}
                            onChange={e => setEditingColumn({...editingColumn, label: e.target.value})}
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 ml-1">Limite WIP (Opcional)</label>
                          <input 
                            type="number"
                            className="w-full border border-slate-200 rounded-xl p-3 text-sm font-bold outline-none focus:border-pink-500 bg-slate-50"
                            placeholder="Ilimitado"
                            value={editingColumn?.wipLimit || ''}
                            onChange={e => setEditingColumn({...editingColumn, wipLimit: parseInt(e.target.value) || null})}
                          />
                      </div>

                      <div className="flex gap-2 pt-2">
                        <button onClick={() => setIsColumnModalOpen(false)} className="flex-1 py-3 text-slate-500 font-bold text-xs uppercase hover:bg-slate-100 rounded-xl">Cancelar</button>
                        <button onClick={handleSaveColumn} className="flex-1 py-3 bg-slate-900 text-white font-bold text-xs uppercase rounded-xl shadow-lg">Salvar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={updateTask}
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }}
            currentUser={currentUser}
            setNotifications={setNotifications}
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { NotificationService } from './services/notificationService';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, LeadTask, ConfirmOptions } from './types';
import { Users, Settings, Bell, Check, Gift, AlertTriangle, Info, Clock, CheckCircle, Shield, Trash2, Archive, Eye, DollarSign, Briefcase } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  // --- SIDEBAR STATE & PERSISTENCE ---
  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  // --- REST OF STATE ---
  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const [activeNotifTab, setActiveNotifTab] = useState('ALL');
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const handleNotificationAction = (id: string, action: 'READ' | 'ARCHIVE') => {
      setNotifications(prev => prev.map(n => {
          if (n.id === id) {
              return { ...n, status: action === 'READ' ? 'READ' : 'ARCHIVED' };
          }
          return n;
      }));
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const filteredNotifs = NotificationService.filterByTab(notifications, activeNotifTab)
      .filter(n => !n.targetUserId || n.targetUserId === currentUser.id)
      .filter(n => !n.targetRole || n.targetRole === currentUser.role);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  const contentMargin = !isMobile ? getSidebarWidth() : '0px';
  const mobileMargin = (isMobile && sidebarOpen && sidebarCompact) ? '80px' : '0px';

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className="flex-1 flex flex-col min-h-screen transition-all duration-300 ease-in-out p-4 md:px-8 md:py-6"
        style={{ marginLeft: !isMobile ? contentMargin : mobileMargin }}
      >
        {/* TOP STICKY BAR */}
        <div className="sticky top-0 z-30 -mx-4 md:-mx-8 px-4 md:px-8 py-3 mb-2 md:mb-4 bg-slate-50/80 backdrop-blur-md border-b border-slate-200/50 flex justify-between items-center gap-4 shrink-0 transition-all">
            <div className="flex items-center gap-2 ml-auto">
                <div className="relative" ref={notificationRef}>
                    <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 rounded-lg border transition-all relative bg-white shadow-sm hover:shadow-md">
                        <Bell size={18} className="text-slate-500" />
                        {unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 border-white">
                                {unreadCount > 9 ? '9+' : unreadCount}
                            </span>
                        )}
                    </button>

                    {showNotifications && (
                        <div className="absolute right-0 top-full mt-3 w-[320px] md:w-[420px] bg-white rounded-xl shadow-2xl border border-slate-100 overflow-hidden z-[100] animate-pop origin-top-right">
                            <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                                <h3 className="text-xs font-black uppercase tracking-widest text-slate-500">Notificações</h3>
                                <button onClick={markAllAsRead} className="text-[10px] font-black text-pink-600 hover:text-pink-700 uppercase">Lidas</button>
                            </div>
                            <div className="max-h-[400px] overflow-y-auto custom-scrollbar">
                                {filteredNotifs.length === 0 ? (
                                    <div className="p-10 text-center flex flex-col items-center gap-3">
                                        <Bell size={24} className="text-slate-200"/>
                                        <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Tudo limpo por aqui.</p>
                                    </div>
                                ) : (
                                    filteredNotifs.map(notif => (
                                        <div key={notif.id} className={`p-4 border-b border-slate-50 transition-all group relative ${notif.status === 'UNREAD' ? 'bg-blue-50/10' : 'opacity-70'}`}>
                                            <div className="flex gap-3">
                                                <div className="flex-1 cursor-pointer" onClick={() => { if(notif.navToView) setCurrentView(notif.navToView); handleNotificationAction(notif.id, 'READ'); setShowNotifications(false); }}>
                                                    <p className={`text-sm font-bold ${notif.status === 'UNREAD' ? 'text-slate-800' : 'text-slate-500'}`}>{notif.title}</p>
                                                    <p className="text-xs text-slate-600 leading-relaxed line-clamp-2">{notif.message}</p>
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="flex items-center gap-3 bg-white pl-4 pr-1.5 py-1.5 rounded-xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow cursor-pointer group" onClick={() => setCurrentView('settings')}>
                    <div className="text-right hidden sm:block">
                        <p className="text-xs font-black text-slate-800 group-hover:text-pink-600 transition-colors leading-none">{currentUser.name}</p>
                        <p className="text-[9px] text-slate-400 uppercase font-black tracking-tighter mt-1">{currentUser.role}</p>
                    </div>
                    <img src={currentUser.avatar} alt="Perfil" className="w-8 h-8 rounded-lg border-2 border-white shadow-inner object-cover" />
                </div>
            </div>
        </div>

        <div className="flex-1 w-full max-w-full overflow-hidden flex flex-col">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} setNotifications={setNotifications} />}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, Eye, 
    CheckSquare, Users, CreditCard, Layout, Upload, Check, Activity, AlertCircle, Play, Pause, Calendar, Save,
    Flag, AlignLeft, ShieldCheck, Search, Palette, ExternalLink, UserPlus
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6', '#db2777', '#0f172a', '#64748b'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, setNotifications, openConfirm }) => {
    const [newComment, setNewComment] = useState('');
    const [mentionFilter, setMentionFilter] = useState('');
    const [showMentions, setShowMentions] = useState(false);
    const [newChecklistText, setNewChecklistText] = useState('');

    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [localDueDate, setLocalDueDate] = useState(task.dueDate || '');
    const [localPriority, setLocalPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>(task.priority || 'MEDIUM');
    const [isEditingDesc, setIsEditingDesc] = useState(false);

    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVER' | string | null>(null);
    const [memberSearch, setMemberSearch] = useState('');

    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const commentInputRef = useRef<HTMLTextAreaElement>(null);
    const popoverRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        console.log("MODAL_OPEN", { screen: 'KanbanJob' });
        return () => console.log("MODAL_CLOSED");
    }, [task.id]);

    useEffect(() => {
        setLocalTitle(task.title);
        setLocalDesc(task.description);
        setLocalDueDate(task.dueDate || '');
        setLocalPriority(task.priority || 'MEDIUM');
    }, [task.id, task.title, task.description, task.dueDate, task.priority]);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                setSecondsElapsed(s => s + 1);
            }, 1000);
        } else {
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [task.isTracking]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setActivePopover(null);
                setShowMentions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const isNewTask = task.history.length === 0;

    const renderBriefingWithLinks = (text: string) => {
        if (!text) return null;
        const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+|[a-zA-Z0-9.-]+\.(com|net|org|br|io|app|gov)(\/[^\s]*)?)/gi;

        return text.split('\n').map((line, i) => (
            <p key={i} className="mb-2 last:mb-0">
                {line.split(urlRegex).map((part, j) => {
                    if (part && part.match(urlRegex)) {
                        const href = part.toLowerCase().startsWith('http') ? part : `https://${part}`;
                        return (
                            <a 
                                key={j} 
                                href={href} 
                                target="_blank" 
                                rel="noopener noreferrer" 
                                className="text-pink-600 underline hover:text-pink-700 break-all inline-flex items-center gap-0.5"
                                onClick={(e) => e.stopPropagation()}
                            >
                                {part} <ExternalLink size={10} className="inline"/>
                            </a>
                        );
                    }
                    if (['com', 'net', 'org', 'br', 'io', 'app', 'gov'].includes(part?.toLowerCase())) return null;
                    return part;
                })}
            </p>
        ));
    };

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const calculateTotalSeconds = () => {
        const closedLogsDuration = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        if (task.isTracking) {
            const activeLog = task.timeLogs.find(l => !l.endTime);
            if (activeLog) {
                const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                return closedLogsDuration + elapsed;
            }
        }
        return closedLogsDuration;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedTaskProps: Partial<Task>, logAction: string) => {
        onUpdate({
            ...task,
            ...updatedTaskProps,
            history: [...task.history, createLog(logAction)]
        });
    };

    const handleFinalConfirmNewTask = () => {
        if (!localTitle.trim()) return;
        onUpdate({
            ...task,
            title: localTitle,
            description: localDesc,
            dueDate: localDueDate,
            priority: localPriority,
            history: [createLog('Tarefa criada no Kanban')]
        });
        onClose();
        confetti({ particleCount: 50, spread: 40, origin: { y: 0.7 } });
    };

    const toggleMember = (userId: string) => {
        const currentIds = task.assigneeIds || [];
        const isAssigned = currentIds.includes(userId);
        const newIds = isAssigned ? currentIds.filter(id => id !== userId) : [...currentIds, userId];
        const user = users.find(u => u.id === userId);
        updateWithLog({ assigneeIds: newIds }, isAssigned ? `removeu ${user?.name}` : `atribuiu ${user?.name}`);
    };

    const toggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    const duration = Math.floor((now - log.startTime) / 1000);
                    return { ...log, endTime: now, duration };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou a produção');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            const newStatus = (task.status === 'BACKLOG' || task.status === 'TODO') ? 'IN_PROGRESS' : task.status;
            updateWithLog({ isTracking: true, status: newStatus, timeLogs: [...task.timeLogs, newLog] }, 'iniciou a produção');
        }
    };

    const handleDueDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = e.target.value;
        setLocalDueDate(newVal);
        if (!isNewTask) updateWithLog({ dueDate: newVal }, `alterou o prazo para ${new Date(newVal).toLocaleDateString()}`);
    };

    const saveTitle = () => {
        if (!localTitle.trim() || localTitle === task.title) return;
        updateWithLog({ title: localTitle }, `alterou o título para "${localTitle}"`);
    };

    const saveDesc = () => {
        setIsEditingDesc(false);
        if (localDesc === task.description) return;
        updateWithLog({ description: localDesc }, `atualizou a descrição`);
    };

    const addChecklistItem = () => {
        if (newChecklistText.trim()) {
            const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
            updateWithLog({ checklists: [...(task.checklists || []), newItem] }, `adicionou etapa: "${newChecklistText}"`);
            setNewChecklistText('');
        }
    };

    const toggleChecklist = (itemId: string) => {
        const item = task.checklists.find(c => c.id === itemId);
        if (!item) return;
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, isCompleted: !c.isCompleted } : c);
        if (!item.isCompleted) updateWithLog({ checklists: newChecklists }, `concluiu "${item.text}"`);
        else onUpdate({...task, checklists: newChecklists});
    };

    const updateChecklistDetails = (itemId: string, updates: Partial<ChecklistItem>) => {
        const item = task.checklists.find(c => c.id === itemId);
        if (!item) return;
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, ...updates } : c);

        let logMsg = '';
        if (updates.assigneeId) {
            const user = users.find(u => u.id === updates.assigneeId);
            logMsg = `atribuiu ${user?.name} à etapa "${item.text}"`;
        } else if (updates.dueDate) {
            logMsg = `definiu prazo para etapa "${item.text}" em ${new Date(updates.dueDate).toLocaleDateString()}`;
        }

        if (logMsg) updateWithLog({ checklists: newChecklists }, logMsg);
        else onUpdate({...task, checklists: newChecklists});
        setActivePopover(null);
    };

    const setCoverColor = (color: string) => {
        updateWithLog({ cover: { type: 'COLOR', value: color } }, 'alterou a cor da capa');
        setActivePopover(null);
    };

    const handleCommentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const val = e.target.value;
        setNewComment(val);
        const cursorPosition = e.target.selectionStart;
        const textUntilCursor = val.slice(0, cursorPosition);
        const match = textUntilCursor.match(/@(\w*)$/);
        if (match) {
            setMentionFilter(match[1].toLowerCase());
            setShowMentions(true);
        } else {
            setShowMentions(false);
        }
    };

    const selectMention = (user: User) => {
        const cursorPosition = commentInputRef.current?.selectionStart || 0;
        const textBefore = newComment.slice(0, cursorPosition).replace(/@\w*$/, '');
        const textAfter = newComment.slice(cursorPosition);
        const updated = textBefore + '@' + user.name + ' ' + textAfter;
        setNewComment(updated);
        setShowMentions(false);
        setTimeout(() => commentInputRef.current?.focus(), 10);
    };

    const addComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        onUpdate({ ...task, comments: [...task.comments, comment] });
        setNewComment('');
    };

    const totalSecondsAccumulated = calculateTotalSeconds();
    const checklistProgress = task.checklists.length > 0 ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) : 0;
    const activityFeed = [...task.comments.map(c => ({ type: 'COMMENT', data: c, timestamp: c.timestamp })), ...task.history.map(h => ({ type: 'HISTORY', data: h, timestamp: h.timestamp }))].sort((a, b) => b.timestamp - a.timestamp);

    const renderMentionList = () => {
        const filtered = users.filter(u => u.role !== 'CLIENT' && u.name.toLowerCase().includes(mentionFilter));
        if (filtered.length === 0) return null;
        return (
            <div className="absolute left-14 bottom-full mb-2 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden z-[10000] animate-pop">
                <div className="p-2 bg-slate-50 border-b text-[10px] font-black text-slate-400 uppercase tracking-widest">Mencionar Colaborador</div>
                <div className="max-h-48 overflow-y-auto custom-scrollbar">
                    {filtered.map(u => (
                        <button key={u.id} onClick={() => selectMention(u)} className="w-full flex items-center gap-3 p-3 hover:bg-pink-50 transition-colors text-left border-b border-slate-50 last:border-none">
                            <img src={u.avatar} className="w-6 h-6 rounded-full border border-slate-100" />
                            <div><p className="text-xs font-bold text-slate-700">{u.name}</p><p className="text-[9px] text-slate-400 uppercase">{u.role}</p></div>
                        </button>
                    ))}
                </div>
            </div>
        );
    };

    if (isNewTask) {
        return (
            <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex justify-center items-center p-4 transition-all duration-300" onClick={onClose}>
                <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                    <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-pink-600 rounded-lg"><Plus size={24} /></div>
                            <div><h2 className="text-xl font-bold">Nova Demanda de Trabalho</h2><p className="text-xs text-slate-400">Preencha os detalhes para iniciar a produção.</p></div>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
                    </div>
                    <div className="p-8 space-y-6 max-h-[75vh] overflow-y-auto custom-scrollbar">
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><CreditCard size={14} className="text-pink-600"/> Título do Job <span className="text-red-500">*</span></label>
                            <input className="w-full text-xl font-bold text-slate-800 bg-slate-50 border-2 border-slate-100 rounded-xl p-4 outline-none focus:border-pink-500 focus:bg-white transition-all" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} placeholder="Ex: Campanha de Natal 2024..." autoFocus />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><Calendar size={14} className="text-indigo-600"/> Data de Entrega</label>
                                <input type="date" className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl p-3 text-sm font-bold text-slate-700 outline-none focus:border-indigo-500 focus:bg-white transition-all" value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><Flag size={14} className="text-amber-600"/> Nível de Prioridade</label>
                                <div className="flex gap-2">
                                    {['LOW', 'MEDIUM', 'HIGH'].map(p => (
                                        <button key={p} onClick={() => setLocalPriority(p as any)} className={`flex-1 py-2.5 rounded-lg text-xs font-bold transition-all border-2 ${localPriority === p ? 'border-slate-800 scale-105' : 'border-transparent opacity-60'} ${p === 'HIGH' ? 'bg-red-100 text-red-600' : p === 'MEDIUM' ? 'bg-amber-100 text-amber-600' : 'bg-slate-200 text-slate-600'}`}>{p === 'HIGH' ? 'Urgente' : p === 'MEDIUM' ? 'Média' : 'Baixa'}</button>
                                    ))}
                                </div>
                            </div>
                        </div>
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><AlignLeft size={14} className="text-slate-600"/> Briefing / Descrição</label>
                            <textarea className="w-full min-h-[120px] bg-slate-50 border-2 border-slate-100 rounded-xl p-4 text-sm text-slate-700 outline-none focus:border-blue-500 focus:bg-white transition-all resize-none" placeholder="Descreva os detalhes da entrega..." value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} />
                        </div>
                    </div>
                    <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
                        <button onClick={onClose} className="px-6 py-3 rounded-xl text-slate-500 font-bold hover:bg-slate-200 transition-colors">Cancelar</button>
                        <button onClick={handleFinalConfirmNewTask} className="px-8 py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-xl shadow-lg shadow-pink-500/30 flex items-center gap-2 transition-all"><Save size={18}/> Iniciar Demanda</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex justify-center overflow-y-auto py-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl relative min-h-[500px] h-fit my-auto mx-4 animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                <button onClick={onClose} className="absolute top-4 right-4 p-2 rounded-full bg-black/5 hover:bg-black/10 z-20 transition-colors"><X size={20} className="text-slate-600"/></button>

                {task.cover && (
                    <div className={`w-full relative ${task.cover.type === 'COLOR' ? 'h-32' : 'h-64'} bg-cover bg-center rounded-t-2xl transition-all`} style={{ backgroundColor: task.cover.type === 'COLOR' ? task.cover.value : undefined, backgroundImage: task.cover.type === 'IMAGE' ? `url(${task.cover.value})` : undefined }}>
                        <button className="absolute bottom-4 right-4 bg-white/90 hover:bg-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase shadow-sm backdrop-blur-sm transition-all" onClick={() => onUpdate({...task, cover: undefined})}>Remover Capa</button>
                    </div>
                )}

                <div className="flex flex-col md:flex-row p-8 gap-8">
                    <div className="flex-1 space-y-6">
                        <div className="flex gap-4 items-start">
                            <CreditCard className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <div className={`relative transition-all rounded-lg p-1 ${localTitle !== task.title ? 'bg-amber-50 ring-2 ring-amber-200' : 'hover:bg-slate-50'}`}>
                                    <input className="text-2xl font-black text-slate-800 w-full bg-transparent border-none outline-none placeholder-slate-300" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} onBlur={saveTitle} onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()} />
                                </div>
                                <div className="text-xs text-slate-400 mt-2 pl-1 font-bold uppercase tracking-wider">Na coluna <span className="text-indigo-600">{task.status}</span></div>
                            </div>
                        </div>

                        {task.assigneeIds.length > 0 && (
                            <div className="flex gap-4 items-center ml-10">
                                <div className="flex -space-x-2">
                                    {task.assigneeIds.map(id => (
                                        <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" title={users.find(u => u.id === id)?.name} />
                                    ))}
                                    <button onClick={() => setActivePopover('MEMBERS')} className="w-10 h-10 rounded-full bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 hover:text-pink-600 hover:border-pink-300 transition-all"><Plus size={18}/></button>
                                </div>
                                <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Responsáveis</p><p className="text-xs text-slate-600 font-bold">{task.assigneeIds.length} pessoa(s) no job</p></div>
                            </div>
                        )}

                        <div className="flex flex-wrap gap-4 ml-10">
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-sm min-w-[200px] flex-1">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2 flex items-center gap-1"><Calendar size={10}/> Data de Entrega</h4>
                                <input type="date" className={`w-full text-sm font-black bg-transparent border-none outline-none ${!localDueDate ? 'text-amber-500' : 'text-slate-700'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-sm flex-1 min-w-[250px]">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2 flex items-center gap-1"><Clock size={10}/> Medição de Produção</h4>
                                <div className="flex items-center justify-between">
                                    <div className="text-xl font-black text-slate-800 font-mono tracking-tighter">{formatSeconds(totalSecondsAccumulated)}</div>
                                    <button onClick={toggleTimer} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${task.isTracking ? 'bg-amber-100 text-amber-700 hover:bg-amber-200 animate-pulse' : 'bg-pink-600 text-white hover:bg-pink-700 shadow-lg shadow-pink-500/30'}`}>
                                        {task.isTracking ? <><Pause size={14} fill="currentColor"/> Pausar</> : <><Play size={14} fill="currentColor"/> Iniciar</>}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <AlignLeft className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-3">Descrição / Briefing</h3>
                                <div className={`relative rounded-xl p-4 transition-all ${isEditingDesc ? 'bg-white ring-2 ring-pink-100 shadow-inner' : 'bg-slate-50 hover:bg-slate-100 cursor-text'}`} onClick={() => !isEditingDesc && setIsEditingDesc(true)}>
                                    {isEditingDesc ? (
                                        <textarea className="w-full min-h-[150px] border-none outline-none text-sm text-slate-700 resize-none bg-transparent" value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} onBlur={saveDesc} autoFocus placeholder="Descreva o job, adicione links de referência ou domínios..." />
                                    ) : (
                                        <div className="text-sm text-slate-700 leading-relaxed min-h-[150px]">{localDesc ? renderBriefingWithLinks(localDesc) : <span className="text-slate-400 italic">Clique para adicionar detalhes, referências ou domínios...</span>}</div>
                                    )}
                                    {!isEditingDesc && localDesc && <div className="absolute top-2 right-2 p-1 text-[8px] font-black text-slate-300 uppercase">Clique para editar</div>}
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <CheckSquare className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <div className="flex justify-between items-center mb-4"><h3 className="font-black text-xs text-slate-400 uppercase tracking-widest">Checklist de Etapas</h3><span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{checklistProgress}% concluído</span></div>
                                {task.checklists.length > 0 && <div className="w-full bg-slate-100 rounded-full h-1.5 mb-6"><div className="bg-emerald-500 h-1.5 rounded-full transition-all duration-700" style={{width: `${checklistProgress}%`}}></div></div>}
                                <div className="space-y-3 mb-4">
                                    {task.checklists.map((item: ChecklistItem) => {
                                        const assignee = users.find(u => u.id === item.assigneeId);
                                        const isOverdue = item.dueDate && new Date(item.dueDate) < new Date() && !item.isCompleted;

                                        return (
                                            <div key={item.id} className="flex items-center gap-3 group hover:bg-slate-50 p-2.5 rounded-xl transition-all border border-transparent hover:border-slate-100 relative">
                                                <input type="checkbox" checked={item.isCompleted} onChange={() => toggleChecklist(item.id)} className="w-5 h-5 rounded-md border-slate-300 text-pink-600 focus:ring-pink-500 cursor-pointer"/>

                                                <div className="flex-1 flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                                                    <span className={`text-sm font-medium transition-all ${item.isCompleted ? 'line-through text-slate-300' : 'text-slate-600'}`}>{item.text}</span>

                                                    <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 focus-within:opacity-100 transition-opacity">
                                                        <div className="relative">
                                                            <input 
                                                                type="date" 
                                                                className={`bg-white border text-[10px] font-bold rounded-lg px-2 py-1 outline-none transition-colors ${isOverdue ? 'border-red-300 text-red-500 bg-red-50' : 'border-slate-200 text-slate-500'}`}
                                                                value={item.dueDate || ''}
                                                                onChange={(e) => updateChecklistDetails(item.id, { dueDate: e.target.value })}
                                                            />
                                                        </div>

                                                        <div className="relative">
                                                            <button 
                                                                onClick={() => setActivePopover(activePopover === `ITEM_MEMBER_${item.id}` ? null : `ITEM_MEMBER_${item.id}`)}
                                                                className={`w-7 h-7 rounded-full border-2 border-white shadow-sm flex items-center justify-center transition-all ${assignee ? 'bg-transparent' : 'bg-slate-100 text-slate-400 hover:bg-pink-50 hover:text-pink-500'}`}
                                                                title={assignee ? `Atribuído a ${assignee.name}` : "Atribuir responsável"}
                                                            >
                                                                {assignee ? <img src={assignee.avatar} className="w-full h-full rounded-full" /> : <UserPlus size={14}/>}
                                                            </button>

                                                            {activePopover === `ITEM_MEMBER_${item.id}` && (
                                                                <div ref={popoverRef} className="absolute right-0 top-full mt-2 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden z-[10001] animate-pop">
                                                                    <div className="p-2 bg-slate-50 border-b text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Delegar Etapa</div>
                                                                    <div className="max-h-48 overflow-y-auto custom-scrollbar">
                                                                        {users.filter(u => u.role !== 'CLIENT').map(u => (
                                                                            <button key={u.id} onClick={() => updateChecklistDetails(item.id, { assigneeId: u.id })} className={`w-full flex items-center gap-2 p-2 hover:bg-pink-50 transition-colors text-left ${item.assigneeId === u.id ? 'bg-pink-50' : ''}`}>
                                                                                <img src={u.avatar} className="w-6 h-6 rounded-full" />
                                                                                <span className="text-xs font-bold text-slate-700">{u.name}</span>
                                                                                {item.assigneeId === u.id && <Check size={12} className="ml-auto text-pink-600"/>}
                                                                            </button>
                                                                        ))}
                                                                        <button onClick={() => updateChecklistDetails(item.id, { assigneeId: undefined })} className="w-full p-2 text-center text-[10px] font-bold text-red-400 hover:bg-red-50 border-t">Remover Responsável</button>
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>

                                                        <button onClick={() => updateWithLog({ checklists: task.checklists.filter(c => c.id !== item.id) }, `removeu etapa "${item.text}"`)} className="text-slate-300 hover:text-red-500 p-1 transition-colors"><Trash2 size={16}/></button>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                                <div className="flex gap-2">
                                    <input type="text" placeholder="Nova etapa..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-pink-500 transition-all" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 text-white px-5 rounded-xl text-xs font-black uppercase hover:bg-slate-900 transition-colors">Adicionar</button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <Activity className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-xs text-slate-400 uppercase tracking-widest mb-6">Atividade & Feed</h3>
                                <div className="flex gap-4 mb-8 relative">
                                    <img src={currentUser.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
                                    <div className="flex-1 space-y-2">
                                        <div className="relative">
                                            <textarea ref={commentInputRef} className="w-full bg-slate-50 border border-slate-100 rounded-xl p-4 text-sm outline-none transition-all resize-none focus:ring-2 focus:ring-pink-100" placeholder="Comente algo ou digite @ para mencionar..." rows={2} value={newComment} onChange={handleCommentChange} />
                                            {showMentions && renderMentionList()}
                                        </div>
                                        <div className="flex justify-end"><button onClick={addComment} disabled={!newComment.trim()} className="bg-indigo-600 text-white px-6 py-2 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-colors">Comentar</button></div>
                                    </div>
                                </div>
                                <div className="space-y-6">
                                    {activityFeed.map((item: any) => {
                                         const u = users.find(user => user.id === item.data.userId) || currentUser;
                                         return item.type === 'COMMENT' ? (
                                             <div key={item.data.id} className="flex gap-4 animate-pop">
                                                 <img src={u.avatar} className="w-10 h-10 rounded-full border border-slate-100" />
                                                 <div className="flex-1"><div className="flex items-baseline gap-2 mb-1"><span className="font-black text-sm text-slate-800">{u.name}</span><span className="text-[10px] font-bold text-slate-400">{new Date(item.timestamp).toLocaleString()}</span></div><div className="bg-white p-4 rounded-2xl border border-slate-100 text-sm text-slate-600 shadow-sm leading-relaxed">{item.data.text}</div></div>
                                             </div>
                                         ) : (
                                            <div key={item.data.id} className="flex gap-4 items-center ml-3 opacity-60"><div className="w-4 h-4 bg-slate-100 rounded-full flex items-center justify-center"><div className="w-1.5 h-1.5 bg-slate-300 rounded-full"></div></div><div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase"><span className="text-slate-600">{u.name}</span><span>{item.data.action}</span><span>• {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span></div></div>
                                         );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="w-full md:w-56 space-y-3 shrink-0">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Ações Rápidas</h4>
                        {task.status !== 'DONE' && <button onClick={() => updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job')} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white p-3 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 transition-all active:scale-95"><CheckCircle size={16}/> Finalizar Job</button>}
                        <div className="py-2"></div>
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Gerenciar</h4>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'MEMBERS' ? null : 'MEMBERS')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'MEMBERS' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><Users size={16}/> Membros</button>
                            {activePopover === 'MEMBERS' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-72 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[10001] p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-3 text-center">Atribuir Colaboradores</h5>
                                    <div className="relative mb-4"><Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-100 rounded-lg text-xs outline-none" placeholder="Buscar..." value={memberSearch} onChange={e => setMemberSearch(e.target.value)} /></div>
                                    <div className="space-y-1 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
                                        {users.filter(u => u.role !== 'CLIENT' && u.name.toLowerCase().includes(memberSearch.toLowerCase())).map(u => {
                                            const isSelected = task.assigneeIds.includes(u.id);
                                            return <button key={u.id} onClick={() => toggleMember(u.id)} className={`w-full flex items-center justify-between p-2 rounded-lg transition-colors ${isSelected ? 'bg-pink-50 text-pink-700' : 'hover:bg-slate-50 text-slate-600'}`}><div className="flex items-center gap-2 text-left"><img src={u.avatar} className="w-6 h-6 rounded-full" /><div><p className="text-xs font-bold">{u.name}</p><p className="text-[9px] opacity-60 uppercase">{u.role}</p></div></div>{isSelected && <Check size={14}/>}</button>;
                                        })}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="relative">
                            <button onClick={() => setActivePopover(activePopover === 'COVER' ? null : 'COVER')} className={`w-full text-left p-3 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${activePopover === 'COVER' ? 'bg-slate-800 text-white shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}><ImageIcon size={16}/> Capa</button>
                            {activePopover === 'COVER' && (
                                <div ref={popoverRef} className="absolute left-0 top-full mt-2 w-64 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[10001] p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-4 text-center">Cor de Capa</h5>
                                    <div className="grid grid-cols-4 gap-2">{PRESET_COLORS.map(c => <button key={c} onClick={() => setCoverColor(c)} className="w-full aspect-square rounded-lg shadow-sm hover:scale-105 transition-transform" style={{ backgroundColor: c }} />)}</div>
                                </div>
                            )}
                        </div>
                        <div className="py-2 border-t border-slate-100"></div>
                        <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'restaurou o job' : 'arquivou o job')} className="w-full text-left p-3 rounded-xl text-xs font-bold text-slate-500 hover:bg-slate-100 flex items-center gap-2 transition-all"><Archive size={16}/> {task.archived ? 'Desarquivar' : 'Arquivar'}</button>
                        {(currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER') && <button onClick={() => onDeleteTask(task.id)} className="w-full text-left p-3 rounded-xl text-xs font-bold text-red-400 hover:bg-red-50 flex items-center gap-2 transition-all"><Trash2 size={16}/> Excluir permanentemente</button>}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Lead, ColumnConfig, LeadTask, ConfirmOptions, User } from '../types';
import { 
    DollarSign, Plus, Star, CheckSquare, Calendar, Phone, Mail, MessageSquare, 
    Trash2, Clock, User as UserIcon, Briefcase, AlertCircle, Save, X, Settings,
    GripHorizontal, Edit2, ArchiveRestore, Info, Tag
} from 'lucide-react';

interface CRMProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  leadSources: string[];
  setLeadSources: React.Dispatch<React.SetStateAction<string[]>>;
  currentUser: User;
}

export const CRM: React.FC<CRMProps> = ({ leads, setLeads, columns, setColumns, openConfirm, leadSources, setLeadSources, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingLead, setEditingLead] = useState<Partial<Lead>>({ stage: columns[0]?.id || 'NEW', rating: 0, tasks: [] });
  const [activeTab, setActiveTab] = useState<'DETAILS' | 'ACTIVITIES'>('DETAILS');
  const [showValidation, setShowValidation] = useState(false);

  // Column/Settings State
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [draggedColumnId, setDraggedColumnId] = useState<string | null>(null);

  // Origin Management
  const [newOrigin, setNewOrigin] = useState('');

  // Task Form State
  const [newTaskText, setNewTaskText] = useState('');
  const [newTaskDate, setNewTaskDate] = useState('');
  const [newTaskTime, setNewTaskTime] = useState('');
  const [newTaskType, setNewTaskType] = useState<'CALL' | 'EMAIL' | 'MEETING' | 'TASK'>('TASK');

  const isAdmin = currentUser.role === 'ADMIN';

  useEffect(() => {
    if(isModalOpen || isSettingsOpen || isColumnModalOpen) {
        console.log("MODAL_OPEN", { screen: 'CRM' });
    }
  }, [isModalOpen, isSettingsOpen, isColumnModalOpen]);

  const activeColumns = useMemo(() => 
    columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), 
  [columns]);

  const handleSave = () => {
      if (!editingLead.company || !editingLead.name || (!editingLead.value && editingLead.value !== 0)) {
          setShowValidation(true);
          return;
      }

      if(editingLead.id) {
          setLeads(prev => prev.map(l => l.id === editingLead.id ? { ...l, ...editingLead } as Lead : l));
      } else {
          setLeads(prev => [...prev, { ...editingLead, id: Date.now().toString(), lastContact: new Date().toISOString() } as Lead]);
      }
      setIsModalOpen(false);
      resetForm();
  };

  const resetForm = () => {
    setEditingLead({ stage: activeColumns[0]?.id || 'NEW', rating: 0, tasks: [] });
    setActiveTab('DETAILS');
    setShowValidation(false);
  };

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
        setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
        const newCol: ColumnConfig = {
            id: 'crm-' + Date.now(),
            label: editingColumn.label,
            color: editingColumn.color || 'bg-slate-50 border-slate-200',
            order: columns.length,
            isArchived: false
        };
        setColumns(prev => [...prev, newCol]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleDeleteColumn = async (colId: string) => {
      const hasLeads = leads.some(l => l.stage === colId);
      if (hasLeads) {
          alert("Mova os leads desta etapa antes de excluí-la.");
          return;
      }
      const ok = await openConfirm({
          title: "Excluir Etapa?",
          description: "Esta ação removerá permanentemente esta etapa do funil.",
          confirmText: "Excluir"
      });
      if (ok) {
          setColumns(prev => prev.filter(c => c.id !== colId));
      }
  };

  const onColumnDragStart = (e: React.DragEvent, id: string) => {
      if (!isAdmin) return;
      setDraggedColumnId(id);
      e.dataTransfer.setData('type', 'column');
  };

  const onColumnDrop = (e: React.DragEvent, targetColId: string) => {
      if (!isAdmin || !draggedColumnId || draggedColumnId === targetColId) return;
      const newCols = [...columns];
      const draggedIdx = newCols.findIndex(c => c.id === draggedColumnId);
      const targetIdx = newCols.findIndex(c => c.id === targetColId);
      const [removed] = newCols.splice(draggedIdx, 1);
      newCols.splice(targetIdx, 0, removed);
      setColumns(newCols.map((c, i) => ({ ...c, order: i })));
      setDraggedColumnId(null);
  };

  const addOrigin = () => {
      if (!newOrigin.trim() || leadSources.includes(newOrigin)) return;
      setLeadSources(prev => [...prev, newOrigin.trim()]);
      setNewOrigin('');
  };

  const deleteOrigin = async (origin: string) => {
      const ok = await openConfirm({
          title: "Remover Origem?",
          description: `Deseja remover "${origin}" das opções? Leads existentes manterão esta origem.`,
          variant: "danger"
      });
      if (ok) setLeadSources(prev => prev.filter(o => o !== origin));
  };

  const handleDeleteLead = async (id: string) => {
      const ok = await openConfirm({
          title: "Excluir Oportunidade?",
          description: "Deseja remover permanentemente este Lead? Esta ação não pode ser desfeita.",
          variant: "danger",
          confirmText: "Excluir Definitivamente"
      });
      if (ok) {
          setLeads(prev => prev.filter(l => l.id !== id));
          setIsModalOpen(false);
          resetForm();
      }
  };

  const addTaskToLead = () => {
      if(!newTaskText) return;
      const newTask: LeadTask = { 
          id: Date.now().toString(), 
          text: newTaskText, 
          completed: false,
          dueDate: newTaskDate || new Date().toISOString().split('T')[0],
          time: newTaskTime || '09:00',
          type: newTaskType
      };
      setEditingLead({ ...editingLead, tasks: [newTask, ...(editingLead.tasks || [])] });
      setNewTaskText('');
      setNewTaskDate('');
      setNewTaskTime('');
  };

  const toggleTask = (taskId: string) => {
      const updatedTasks = editingLead.tasks?.map(t => t.id === taskId ? {...t, completed: !t.completed} : t);
      setEditingLead({...editingLead, tasks: updatedTasks});
  };

  const getTaskIcon = (type: string) => {
      switch(type) {
          case 'CALL': return <Phone size={14} className="text-blue-500"/>;
          case 'EMAIL': return <Mail size={14} className="text-yellow-500"/>;
          case 'MEETING': return <UserIcon size={14} className="text-purple-500"/>;
          default: return <CheckSquare size={14} className="text-emerald-500"/>;
      }
  };

  const handleDragStartLead = (e: React.DragEvent, leadId: string) => {
      setDraggedLeadId(leadId);
      e.dataTransfer.setData('type', 'lead');
      e.dataTransfer.effectAllowed = "move";
  };

  const handleDropLead = (e: React.DragEvent, targetStage: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;
      setLeads(prev => prev.map(l => l.id === draggedLeadId ? { ...l, stage: targetStage, lastContact: new Date().toISOString() } : l));
      setDraggedLeadId(null);
  };

  const getInputClass = (value: any) => {
      const baseClass = "w-full border rounded p-2 text-sm transition-all";
      if (showValidation && (!value || value === 0)) return `${baseClass} border-red-500 bg-red-50 focus:ring-red-200`;
      return `${baseClass} border-slate-200 focus:border-pink-500 focus:ring-4 focus:ring-pink-50 outline-none`;
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Pipeline de Vendas</h2>
          <p className="text-slate-500 text-sm font-medium">Gestão de oportunidades e previsão de fechamento</p>
        </div>
        <div className="flex gap-2">
            {isAdmin && (
                <button onClick={() => setIsSettingsOpen(true)} className="p-2.5 rounded-xl text-slate-500 bg-white border border-slate-200 hover:bg-slate-50 transition-all shadow-sm">
                    <Settings size={20}/>
                </button>
            )}
            <button onClick={() => { resetForm(); setIsModalOpen(true)}} className="bg-pink-600 hover:bg-pink-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-pink-500/20">
                <Plus size={18} /> Novo Lead
            </button>
        </div>
      </div>

      <div className="flex-1 flex gap-5 overflow-x-auto pb-6 hide-scrollbar">
          {activeColumns.map(col => (
              <div 
                key={col.id} 
                draggable={isAdmin}
                onDragStart={(e) => onColumnDragStart(e, col.id)}
                onDragOver={(e) => e.preventDefault()}
                onDrop={(e) => {
                    const type = e.dataTransfer.getData('type');
                    if (type === 'column') onColumnDrop(e, col.id);
                    else handleDropLead(e, col.id);
                }}
                className={`flex-shrink-0 w-80 flex flex-col rounded-2xl border transition-all ${col.color} bg-opacity-40 ${draggedColumnId === col.id ? 'opacity-20 scale-95' : ''}`}
              >
                  <div className="p-4 flex items-center justify-between border-b border-black/5 cursor-default">
                      <div className="flex items-center gap-2">
                         {isAdmin && <GripHorizontal size={14} className="text-slate-400 cursor-grab active:cursor-grabbing"/>}
                         <h3 className="font-black text-[10px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                      </div>
                      <span className="text-[10px] bg-white/80 px-2 py-0.5 rounded-full font-black text-slate-500 shadow-sm">
                          {leads.filter(l => l.stage === col.id).length}
                      </span>
                  </div>
                  <div className="p-3 flex-1 overflow-y-auto space-y-3 custom-scrollbar min-h-[150px]">
                      {leads.filter(l => l.stage === col.id).map(lead => (
                          <div 
                            key={lead.id} 
                            draggable
                            onDragStart={(e) => handleDragStartLead(e, lead.id)}
                            onClick={() => { setEditingLead(lead); setIsModalOpen(true) }} 
                            className="bg-white p-4 rounded-xl shadow-sm border-2 border-white hover:border-pink-200 transition-all cursor-grab active:cursor-grabbing group"
                          >
                                <div className="flex justify-between items-start mb-2">
                                    <h4 className="font-bold text-slate-800 group-hover:text-pink-600 transition-colors leading-tight flex-1">{lead.company}</h4>
                                    <div className="flex gap-0.5 text-amber-400">
                                        {[1,2,3].map(s => <Star key={s} size={10} fill={s <= (lead.rating || 0) ? "currentColor" : "none"} />)}
                                    </div>
                                </div>
                                <p className="text-xs text-slate-500 mb-4">{lead.name}</p>

                                <div className="flex justify-between items-center pt-3 border-t border-slate-50">
                                    <p className="text-sm font-black text-slate-800 flex items-center gap-1"><DollarSign size={14} className="text-emerald-500"/> {lead.value.toLocaleString()}</p>
                                    {lead.source && <span className="text-[9px] font-black uppercase text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">{lead.source}</span>}
                                </div>
                          </div>
                      ))}
                  </div>
              </div>
          ))}

          {isAdmin && (
               <button 
                onClick={() => { setEditingColumn({ label: '', color: 'bg-slate-50 border-slate-200' }); setIsColumnModalOpen(true); }}
                className="flex-shrink-0 w-80 h-16 bg-slate-200/20 border-2 border-dashed border-slate-300 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200/40 hover:text-slate-600 transition-all"
               >
                   <Plus size={18}/> Nova Etapa
               </button>
          )}
      </div>

      {/* --- LEAD MODAL --- */}
      {isModalOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-4xl h-[85vh] flex flex-col overflow-hidden animate-pop shadow-2xl border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b flex justify-between items-start bg-slate-50">
                      <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                             <Briefcase size={22} className={showValidation && !editingLead.company ? "text-red-500" : "text-pink-600"}/>
                             <input 
                                className={`font-black text-2xl bg-transparent outline-none rounded px-1 text-slate-800 placeholder:text-slate-300 w-full ${showValidation && !editingLead.company ? "border-b-2 border-red-500 bg-red-50" : "border-none"}`}
                                placeholder="Nome da Empresa *"
                                value={editingLead.company || ''}
                                onChange={e => setEditingLead({...editingLead, company: e.target.value})}
                             />
                          </div>
                          <div className="flex gap-4 text-xs font-bold text-slate-400 ml-8 uppercase tracking-widest">
                              <span className="flex items-center gap-1"><UserIcon size={12}/> {editingLead.name || 'Sem contato'}</span>
                              <span className="flex items-center gap-1"><DollarSign size={12}/> R$ {editingLead.value || 0}</span>
                          </div>
                      </div>
                      <div className="flex items-center gap-4">
                          <select 
                            className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-xs font-black uppercase text-slate-700 outline-none focus:border-pink-500 shadow-sm"
                            value={editingLead.stage}
                            onChange={e => setEditingLead({...editingLead, stage: e.target.value})}
                          >
                              {activeColumns.map(c => <option key={c.id} value={c.id}>{c.label}</option>)}
                          </select>
                          <button onClick={() => setIsModalOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-full transition-colors"><X size={24}/></button>
                      </div>
                  </div>

                  <div className="flex flex-1 overflow-hidden">
                      <div className="w-56 bg-slate-50 border-r border-slate-200 p-4 space-y-2">
                          <button onClick={() => setActiveTab('DETAILS')} className={`w-full text-left px-4 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'DETAILS' ? 'bg-white text-pink-600 shadow-md scale-105' : 'text-slate-500 hover:bg-white/50'}`}>Informações</button>
                          <button onClick={() => setActiveTab('ACTIVITIES')} className={`w-full text-left px-4 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex justify-between items-center ${activeTab === 'ACTIVITIES' ? 'bg-white text-pink-600 shadow-md scale-105' : 'text-slate-500 hover:bg-white/50'}`}>
                              Atividades
                              {editingLead.tasks && editingLead.tasks.filter(t => !t.completed).length > 0 && (
                                  <span className="bg-red-500 text-white text-[10px] px-1.5 rounded-full">{editingLead.tasks.filter(t => !t.completed).length}</span>
                              )}
                          </button>
                      </div>

                      <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
                          {activeTab === 'DETAILS' && (
                              <div className="space-y-8 max-w-2xl">
                                  {showValidation && (
                                      <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3 text-red-600 text-xs font-bold animate-pop">
                                          <AlertCircle size={18}/>
                                          Preencha os campos obrigatórios marcados com (*) para salvar.
                                      </div>
                                  )}

                                  <div className="grid grid-cols-2 gap-6">
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contato Principal *</label>
                                          <input className={getInputClass(editingLead.name)} placeholder="Nome do prospect" value={editingLead.name || ''} onChange={e => setEditingLead({...editingLead, name: e.target.value})} />
                                      </div>
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor do Negócio *</label>
                                          <input className={getInputClass(editingLead.value)} type="number" placeholder="0.00" value={editingLead.value || ''} onChange={e => setEditingLead({...editingLead, value: parseFloat(e.target.value)})} />
                                      </div>
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
                                          <input className="w-full border border-slate-200 rounded-xl p-2.5 text-sm focus:border-pink-500 outline-none" value={editingLead.email || ''} onChange={e => setEditingLead({...editingLead, email: e.target.value})} />
                                      </div>
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone</label>
                                          <input className="w-full border border-slate-200 rounded-xl p-2.5 text-sm focus:border-pink-500 outline-none" value={editingLead.phone || ''} onChange={e => setEditingLead({...editingLead, phone: e.target.value})} />
                                      </div>
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Origem do Lead</label>
                                          <select className="w-full border border-slate-200 rounded-xl p-2.5 text-sm focus:border-pink-500 outline-none bg-white" value={editingLead.source} onChange={e => setEditingLead({...editingLead, source: e.target.value})}>
                                              <option value="">Selecione...</option>
                                              {leadSources.map(s => <option key={s} value={s}>{s}</option>)}
                                          </select>
                                      </div>
                                      <div className="space-y-1.5">
                                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Qualificação</label>
                                          <div className="flex gap-2 pt-1">
                                              {[1,2,3,4,5].map(s => (
                                                  <button key={s} onClick={() => setEditingLead({...editingLead, rating: s})} className="hover:scale-110 transition-transform">
                                                      <Star size={26} fill={s <= (editingLead.rating || 0) ? "#fbbf24" : "none"} stroke={s <= (editingLead.rating || 0) ? "#fbbf24" : "#cbd5e1"} />
                                                  </button>
                                              ))}
                                          </div>
                                      </div>
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Anotações da Negociação</label>
                                      <textarea 
                                        className="w-full border border-slate-200 rounded-2xl p-4 text-sm h-40 resize-none focus:border-pink-500 focus:ring-4 focus:ring-pink-50 outline-none" 
                                        placeholder="Histórico de conversas, dores do cliente, próximos passos..."
                                        value={editingLead.notes || ''}
                                        onChange={e => setEditingLead({...editingLead, notes: e.target.value})}
                                      />
                                  </div>
                              </div>
                          )}

                          {activeTab === 'ACTIVITIES' && (
                              <div className="space-y-6">
                                  {!editingLead.id ? (
                                      <div className="flex flex-col items-center justify-center h-full text-center p-12 bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl">
                                          <Save size={48} className="text-pink-300 mb-4"/>
                                          <h4 className="font-bold text-slate-700">Salve o Lead Primeiro</h4>
                                          <p className="text-sm text-slate-500 mt-1">É necessário registrar o lead antes de agendar atividades.</p>
                                      </div>
                                  ) : (
                                      <>
                                        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Agendar Ação de Vendas</h4>
                                            <div className="flex gap-2 mb-4">
                                                <button onClick={() => setNewTaskType('CALL')} className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl text-xs font-black uppercase transition-all border-2 ${newTaskType === 'CALL' ? 'bg-blue-50 border-blue-500 text-blue-600 shadow-sm' : 'bg-white border-slate-100 text-slate-500'}`}><Phone size={14}/> Ligação</button>
                                                <button onClick={() => setNewTaskType('EMAIL')} className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl text-xs font-black uppercase transition-all border-2 ${newTaskType === 'EMAIL' ? 'bg-yellow-50 border-yellow-500 text-yellow-600 shadow-sm' : 'bg-white border-slate-100 text-slate-500'}`}><Mail size={14}/> Email</button>
                                                <button onClick={() => setNewTaskType('MEETING')} className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl text-xs font-black uppercase transition-all border-2 ${newTaskType === 'MEETING' ? 'bg-purple-50 border-purple-500 text-purple-600 shadow-sm' : 'bg-white border-slate-100 text-slate-500'}`}><UserIcon size={14}/> Reunião</button>
                                            </div>
                                            <div className="grid grid-cols-2 gap-3 mb-3">
                                                <input className="col-span-2 border border-slate-200 rounded-xl p-3 text-sm focus:border-pink-500 outline-none" placeholder="O que precisa ser feito?" value={newTaskText} onChange={e => setNewTaskText(e.target.value)} onKeyDown={e => e.key === 'Enter' && addTaskToLead()}/>
                                                <input type="date" className="border border-slate-200 rounded-xl p-3 text-sm focus:border-pink-500 outline-none" value={newTaskDate} onChange={e => setNewTaskDate(e.target.value)}/>
                                                <input type="time" className="border border-slate-200 rounded-xl p-3 text-sm focus:border-pink-500 outline-none" value={newTaskTime} onChange={e => setNewTaskTime(e.target.value)}/>
                                            </div>
                                            <button onClick={addTaskToLead} className="w-full bg-slate-800 text-white font-black py-3 rounded-xl text-xs uppercase tracking-widest hover:bg-slate-900 transition-all">Agendar Atividade</button>
                                        </div>

                                        <div className="space-y-3">
                                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Próximos Passos</h4>
                                            {(!editingLead.tasks || editingLead.tasks.filter(t => !t.completed).length === 0) && (
                                                <p className="text-xs text-slate-400 italic">Sem tarefas pendentes para este lead.</p>
                                            )}
                                            {editingLead.tasks?.filter(t => !t.completed).map(task => (
                                                <div key={task.id} className="flex items-center gap-4 bg-white p-4 rounded-xl border border-slate-100 hover:border-pink-200 group transition-all">
                                                    <button onClick={() => toggleTask(task.id)} className="text-slate-300 hover:text-emerald-500 transition-colors"><CheckSquare size={20}/></button>
                                                    <div className="flex-1">
                                                        <div className="flex items-center gap-2 mb-0.5">
                                                            {getTaskIcon(task.type || 'TASK')}
                                                            <span className="text-sm font-bold text-slate-700">{task.text}</span>
                                                        </div>
                                                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight flex items-center gap-1">
                                                            <Calendar size={10}/> {new Date(task.dueDate || '').toLocaleDateString()} • {task.time}
                                                        </p>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                      </>
                                  )}
                              </div>
                          )}
                      </div>
                  </div>

                  <div className="p-6 border-t border-slate-100 flex justify-between gap-3 bg-slate-50">
                      <div>
                        {editingLead.id && (
                             <button onClick={() => handleDeleteLead(editingLead.id!)} className="px-5 py-3 rounded-xl text-red-500 text-xs font-black uppercase hover:bg-red-50 transition-colors flex items-center gap-2"><Trash2 size={16}/> Excluir Lead</button>
                        )}
                      </div>
                      <div className="flex gap-3">
                        <button onClick={() => setIsModalOpen(false)} className="px-6 py-3 rounded-xl text-slate-500 text-xs font-black uppercase hover:bg-slate-200 transition-colors">Sair</button>
                        <button onClick={handleSave} className="px-8 py-3 rounded-xl bg-pink-600 text-white font-black text-xs uppercase tracking-widest shadow-lg shadow-pink-500/20 hover:bg-pink-700 transition-all flex items-center gap-2"><Save size={18}/> Salvar Lead</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* --- CRM SETTINGS MODAL --- */}
      {isSettingsOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsSettingsOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl h-[70vh] flex flex-col overflow-hidden animate-pop shadow-2xl border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b bg-slate-50 flex justify-between items-center">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><Settings size={20}/></div>
                        <h3 className="font-black text-slate-800 uppercase tracking-tighter">Configurações do Pipeline</h3>
                      </div>
                      <button onClick={() => setIsSettingsOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24}/></button>
                  </div>

                  <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
                      {/* GESTÃO DE ETAPAS */}
                      <section>
                          <div className="flex justify-between items-center mb-4">
                              <div>
                                  <h4 className="font-black text-xs text-slate-400 uppercase tracking-widest">Etapas do Funil</h4>
                                  <p className="text-xs text-slate-500">Mova para reordenar ou edite os nomes das colunas.</p>
                              </div>
                              <button onClick={() => { setEditingColumn({ label: '', color: 'bg-slate-50 border-slate-200' }); setIsColumnModalOpen(true); }} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 hover:bg-indigo-100 transition-colors uppercase tracking-widest">+ Nova Etapa</button>
                          </div>
                          <div className="space-y-2">
                              {columns.sort((a,b) => a.order - b.order).map(col => (
                                  <div key={col.id} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl">
                                      <div className="flex items-center gap-3">
                                          <GripHorizontal size={16} className="text-slate-300"/>
                                          <span className="font-bold text-slate-700">{col.label}</span>
                                          <span className="text-[9px] font-black uppercase text-slate-400 bg-white px-2 py-0.5 rounded border border-slate-100">{leads.filter(l => l.stage === col.id).length} leads</span>
                                      </div>
                                      <div className="flex gap-2">
                                          <button onClick={() => { setEditingColumn(col); setIsColumnModalOpen(true); }} className="p-2 text-blue-500 hover:bg-white rounded-lg"><Edit2 size={16}/></button>
                                          <button onClick={() => handleDeleteColumn(col.id)} className="p-2 text-red-500 hover:bg-white rounded-lg"><Trash2 size={16}/></button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      </section>

                      {/* GESTÃO DE ORIGENS */}
                      <section>
                          <div className="mb-4">
                              <h4 className="font-black text-xs text-slate-400 uppercase tracking-widest">Origens de Leads</h4>
                              <p className="text-xs text-slate-500">Adicione ou remova canais de entrada de prospects.</p>
                          </div>
                          <div className="flex gap-2 mb-6">
                                <input 
                                    className="flex-1 border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:border-pink-500 outline-none"
                                    placeholder="Ex: TikTok, Indicação Parceiro..."
                                    value={newOrigin}
                                    onChange={e => setNewOrigin(e.target.value)}
                                    onKeyDown={e => e.key === 'Enter' && addOrigin()}
                                />
                                <button onClick={addOrigin} className="bg-slate-900 text-white px-6 rounded-xl text-xs font-black uppercase tracking-widest">Adicionar</button>
                          </div>
                          <div className="flex flex-wrap gap-2">
                              {leadSources.map(origin => (
                                  <div key={origin} className="flex items-center gap-2 bg-white border border-slate-200 pl-3 pr-1 py-1 rounded-full shadow-sm group">
                                      <span className="text-xs font-bold text-slate-600">{origin}</span>
                                      <button onClick={() => deleteOrigin(origin)} className="p-1 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><X size={14}/></button>
                                  </div>
                              ))}
                          </div>
                      </section>
                  </div>
                  <div className="p-4 bg-slate-50 border-t border-slate-200 text-center">
                      <button onClick={() => setIsSettingsOpen(false)} className="text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest">Fechar Configurações</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL CONFIGURAÇÃO DE COLUNA */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[10000] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-sm p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-3 uppercase tracking-tighter">
                    <div className="p-2 bg-pink-100 text-pink-600 rounded-xl"><Tag size={18}/></div>
                    {editingColumn?.id ? 'Editar Etapa' : 'Nova Etapa'}
                  </h3>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título da Etapa</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 focus:bg-white transition-all bg-slate-50"
                            placeholder="Ex: Qualificação, Envio de Proposta..."
                            value={editingColumn?.label || ''}
                            onChange={e => setEditingColumn({...editingColumn, label: e.target.value})}
                          />
                      </div>
                      <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white font-black py-4 rounded-2xl hover:bg-slate-800 transition-all uppercase tracking-widest text-xs shadow-xl active:scale-95">
                          {editingColumn?.id ? 'Salvar Alterações' : 'Criar Etapa'}
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
    FinancialRecord, Asset, StockItem, User, ConfirmOptions, 
    CashAccount, CashRegister, CashMovement, AssetDeletionHistory
} from '../types';
import { initialStock, initialCashAccounts } from '../utils/mockData';
import { 
    AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, 
    CartesianGrid, PieChart, Pie, Cell 
} from 'recharts';
import { 
    TrendingUp, DollarSign, Package, Plus, Trash2, FileText, AlertTriangle, 
    Search, Edit2, Calendar, Box, HardDrive, Calculator, 
    Wallet, Scale, CheckCircle, RefreshCcw, ArrowDownLeft, ArrowUpRight, 
    X, ArrowUp, Lock, Unlock, History, Download, Eye, ChevronRight, Clock, Ban
} from 'lucide-react';

interface FinancialsProps {
  transactions: FinancialRecord[];
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  currentUser: User;
  users: User[];
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

type TabType = 'DASHBOARD' | 'TRANSACTIONS' | 'CASH_MONTHLY' | 'REPORTS' | 'STOCK' | 'ASSETS';

export const Financials: React.FC<FinancialsProps> = ({ 
    transactions, 
    setTransactions,
    assets,
    setAssets,
    currentUser,
    users,
    openConfirm
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('DASHBOARD');
  const [startDate, setStartDate] = useState(new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState(new Date(new Date().setMonth(new Date().getMonth() + 1)).toISOString().split('T')[0]);

  const hasAccess = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';

  // -- Estados Locais --
  const [cashAccounts] = useState<CashAccount[]>(initialCashAccounts);
  const [cashSessions, setCashSessions] = useState<CashRegister[]>([]);
  const [cashMovements, setCashMovements] = useState<CashMovement[]>([]);
  const [stock, setStock] = useState<StockItem[]>(initialStock);
  const [deletionHistory, setDeletionHistory] = useState<AssetDeletionHistory[]>([]);

  // -- Modais --
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [editingTx, setEditingTx] = useState<Partial<FinancialRecord>>({});
  const [isCashOpenModalOpen, setIsCashOpenModalOpen] = useState(false);
  const [isCashCloseModalOpen, setIsCashCloseModalOpen] = useState(false);
  const [isMoveModalOpen, setIsMoveModalOpen] = useState(false);
  const [editingMove, setEditingMove] = useState<Partial<CashMovement>>({});
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [editingStock, setEditingStock] = useState<Partial<StockItem>>({});
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Partial<Asset>>({});
  const [selectedReportCycle, setSelectedReportCycle] = useState<CashRegister | null>(null);

  // -- Modal de Exclusão de Patrimônio --
  const [isAssetDeleteModalOpen, setIsAssetDeleteModalOpen] = useState(false);
  const [assetToExclude, setAssetToExclude] = useState<Asset | null>(null);
  const [exclusionReason, setExclusionReason] = useState('');
  const [exclusionError, setExclusionError] = useState('');

  useEffect(() => {
    if (isTxModalOpen || isCashOpenModalOpen || isCashCloseModalOpen || isMoveModalOpen || isStockModalOpen || isAssetModalOpen || selectedReportCycle || isAssetDeleteModalOpen) {
        console.log("MODAL_OPEN", { screen: 'Financeiro' });
    }
  }, [isTxModalOpen, isCashOpenModalOpen, isCashCloseModalOpen, isMoveModalOpen, isStockModalOpen, isAssetModalOpen, selectedReportCycle, isAssetDeleteModalOpen]);

  const stats = useMemo(() => {
      const filtered = transactions.filter(t => t.dueDate >= startDate && t.dueDate <= endDate);
      const income = filtered.filter(t => t.type === 'INCOME' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const expense = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PAID').reduce((a, b) => a + b.amount, 0);
      const pendingInc = filtered.filter(t => t.type === 'INCOME' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      const pendingExp = filtered.filter(t => t.type === 'EXPENSE' && t.status === 'PENDING').reduce((a, b) => a + b.amount, 0);
      return { balance: income - expense, income, expense, projected: (income + pendingInc) - (expense + pendingExp) };
  }, [transactions, startDate, endDate]);

  const handleOpenCash = (accId: string, amount: number) => {
      const month = new Date().toISOString().substring(0, 7);
      if (cashSessions.some(s => s.cashAccountId === accId && s.status === 'OPEN')) {
          alert("Já existe um caixa aberto.");
          return;
      }
      const newSession: CashRegister = { id: `cr-${Date.now()}`, cashAccountId: accId, openedBy: currentUser.id, openedAt: Date.now(), monthReference: month, initialAmount: amount, expectedFinalAmount: amount, status: 'OPEN' };
      setCashSessions(prev => [newSession, ...prev]);
      setIsCashOpenModalOpen(false);
  };

  const handleCreateMovement = (move: Partial<CashMovement>) => {
      if (!move.amount || !move.cashRegisterId) return;
      const newMove: CashMovement = { ...move, id: `mv-${Date.now()}`, date: new Date().toISOString(), createdBy: currentUser.id } as CashMovement;
      setCashMovements(prev => [...prev, newMove]);
      setCashSessions(prev => prev.map(s => {
          if (s.id === move.cashRegisterId) {
              const impact = (move.type === 'RECEBIMENTO' || move.type === 'SUPRIMENTO') ? move.amount! : -move.amount!;
              return { ...s, expectedFinalAmount: s.expectedFinalAmount + impact };
          }
          return s;
      }));
      if (move.type === 'RECEBIMENTO' || move.type === 'PAGAMENTO') {
          const ledgerEntry: FinancialRecord = { id: `lg-${Date.now()}`, description: `[CAIXA] ${move.description}`, amount: move.amount!, type: move.type === 'RECEBIMENTO' ? 'INCOME' : 'EXPENSE', status: 'PAID', dueDate: new Date().toISOString().split('T')[0], paymentDate: new Date().toISOString(), cashRegisterId: move.cashRegisterId };
          setTransactions(prev => [ledgerEntry, ...prev]);
      }
      setIsMoveModalOpen(false);
  };

  const handleCloseCash = (sessionId: string, counted: number, obs: string) => {
      setCashSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
              const diff = counted - s.expectedFinalAmount;
              return { ...s, status: 'CLOSED', countedFinalAmount: counted, differenceAmount: diff, closedBy: currentUser.id, closedAt: Date.now(), observations: obs };
          }
          return s;
      }));
      setIsCashCloseModalOpen(false);
  };

  const handleSaveStock = () => {
      if (!editingStock.name || editingStock.quantity === undefined) return;
      if (editingStock.id) setStock(prev => prev.map(i => i.id === editingStock.id ? { ...i, ...editingStock } as StockItem : i));
      else setStock(prev => [...prev, { ...editingStock, id: `stk-${Date.now()}`, lastRestock: new Date().toISOString() } as StockItem]);
      setIsStockModalOpen(false);
      setEditingStock({});
  };

  const handleSaveAsset = () => {
      if (!editingAsset.name || !editingAsset.cost) return;
      if (editingAsset.id) setAssets(prev => prev.map(a => a.id === editingAsset.id ? { ...a, ...editingAsset } as Asset : a));
      else setAssets(prev => [...prev, { ...editingAsset, id: `ast-${Date.now()}`, status: 'ACTIVE', isDeleted: false } as Asset]);
      setIsAssetModalOpen(false);
      setEditingAsset({});
  };

  const handleStartDeleteAsset = (asset: Asset) => {
      setAssetToExclude(asset);
      setExclusionReason('');
      setExclusionError('');
      setIsAssetDeleteModalOpen(true);
  };

  const handleCancelDeleteAsset = () => {
      setIsAssetDeleteModalOpen(false);
      setAssetToExclude(null);
      setExclusionReason('');
  };

  const handleConfirmDeleteAsset = () => {
      if (!assetToExclude) return;
      if (!exclusionReason.trim()) {
          setExclusionError("O motivo da exclusão é obrigatório.");
          return;
      }
      const historyEntry: AssetDeletionHistory = {
          id: `del-${Date.now()}`,
          assetId: assetToExclude.id,
          deletedByUserId: currentUser.id,
          deletedAt: Date.now(),
          reason: exclusionReason,
          assetSnapshot: {
              name: assetToExclude.name,
              type: assetToExclude.type,
              cost: assetToExclude.cost,
              serialNumber: assetToExclude.serialNumber,
              purchaseDate: assetToExclude.purchaseDate
          }
      };
      setDeletionHistory(prev => [...prev, historyEntry]);
      setAssets(prev => prev.map(a => a.id === assetToExclude.id ? { ...a, isDeleted: true } : a));
      setIsAssetDeleteModalOpen(false);
      setAssetToExclude(null);
      setExclusionReason('');
  };

  const activeAssets = useMemo(() => assets.filter(a => !a.isDeleted), [assets]);

  if (!hasAccess) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl border border-slate-200 p-8 text-center">
              <Ban size={48} className="text-red-400 mb-4" />
              <h2 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Acesso Restrito</h2>
              <p className="text-slate-500 max-w-sm mt-2 text-sm">Área exclusiva para CEOs e Diretores Financeiros.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6 animate-pop">
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
          <div className="flex flex-wrap bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-full md:w-fit overflow-x-auto">
              <button onClick={() => setActiveTab('DASHBOARD')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'DASHBOARD' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><TrendingUp size={14}/> Geral</button>
              <button onClick={() => setActiveTab('TRANSACTIONS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'TRANSACTIONS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><FileText size={14}/> Razão</button>
              <button onClick={() => setActiveTab('CASH_MONTHLY')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'CASH_MONTHLY' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Calculator size={14}/> Caixa</button>
              <button onClick={() => setActiveTab('REPORTS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'REPORTS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><History size={14}/> Auditoria</button>
              <button onClick={() => setActiveTab('STOCK')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'STOCK' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><Box size={14}/> Estoque</button>
              <button onClick={() => setActiveTab('ASSETS')} className={`px-4 py-2 rounded-lg text-[10px] font-bold flex items-center gap-2 transition-all uppercase tracking-wider whitespace-nowrap ${activeTab === 'ASSETS' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'}`}><HardDrive size={14}/> Patrimônio</button>
          </div>

          <div className="flex items-center gap-2 bg-white p-2 rounded-xl border shadow-sm w-full md:w-auto overflow-x-auto">
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-[10px] outline-none font-bold text-slate-700 bg-transparent" />
              <span className="text-slate-300">|</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-[10px] outline-none font-bold text-slate-700 bg-transparent" />
          </div>
      </div>

      <div className="min-h-[500px]">
          {activeTab === 'DASHBOARD' && (
              <div className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Scale size={12} className="text-emerald-600"/> Caixa Real</p>
                          <h3 className={`text-2xl font-black mt-2 ${stats.balance >= 0 ? 'text-slate-800' : 'text-red-600'}`}>R$ {stats.balance.toLocaleString()}</h3>
                      </div>
                      <div className="bg-slate-900 p-5 rounded-2xl shadow-xl text-white">
                          <p className="text-pink-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-1"><Wallet size={12}/> Projeção</p>
                          <h3 className="text-2xl font-black mt-2">R$ {stats.projected.toLocaleString()}</h3>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><ArrowUpRight size={12} className="text-blue-600"/> MRR Est.</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {(stats.income * 1.1).toLocaleString('pt-BR', { notation: 'compact' })}</h3>
                      </div>
                      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1"><Box size={12} className="text-pink-600"/> Ativos</p>
                          <h3 className="text-2xl font-black text-slate-800 mt-2">R$ {activeAssets.reduce((a,b)=>a+b.cost, 0).toLocaleString('pt-BR', { notation: 'compact' })}</h3>
                      </div>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-80">
                          <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-6">Gráfico de Fluxo</h3>
                          <ResponsiveContainer width="100%" height="100%">
                              <AreaChart data={transactions.slice(-10)}>
                                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9"/>
                                  <XAxis dataKey="dueDate" hide />
                                  <YAxis hide />
                                  <Tooltip />
                                  <Area type="monotone" dataKey="amount" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.1} />
                              </AreaChart>
                          </ResponsiveContainer>
                      </div>
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
                          <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-6">Vencimentos Próximos</h3>
                          <div className="space-y-3 flex-1 overflow-y-auto max-h-[200px] custom-scrollbar">
                              {transactions.filter(t => t.status === 'PENDING').slice(0, 5).map(t => (
                                  <div key={t.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                                      <div className="flex items-center gap-3">
                                          <div className={`p-2 rounded-lg ${t.type === 'INCOME' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                                              {t.type === 'INCOME' ? <ArrowUpRight size={14}/> : <ArrowDownLeft size={14}/>}
                                          </div>
                                          <div><p className="text-xs font-bold text-slate-800 line-clamp-1">{t.description}</p><p className="text-[10px] text-slate-400 font-black uppercase">{t.dueDate.split('-').reverse().join('/')}</p></div>
                                      </div>
                                      <p className="font-black text-xs text-slate-800 whitespace-nowrap">R$ {t.amount.toLocaleString()}</p>
                                  </div>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>
          )}

          {activeTab === 'ASSETS' && (
              <div className="bg-white rounded-xl border shadow-sm overflow-hidden animate-pop">
                  <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 flex items-center gap-2"><HardDrive size={18} className="text-indigo-600"/> Ativos Fixos (Hardware/Software)</h3>
                      <button onClick={()=>{setEditingAsset({type:'HARDWARE'}); setIsAssetModalOpen(true)}} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg"><Plus size={14}/> Registrar Ativo</button>
                  </div>
                  <div className="overflow-x-auto w-full">
                    <table className="w-full text-sm text-left min-w-[600px]">
                        <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] border-b">
                            <tr><th className="p-4">Ativo / SN</th><th className="p-4">Tipo</th><th className="p-4">Custo</th><th className="p-4">Status</th><th className="p-4 text-center">Ações</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {activeAssets.map(asset => (
                                <tr key={asset.id} className="hover:bg-slate-50 group">
                                    <td className="p-4"><p className="font-bold text-slate-800">{asset.name}</p><p className="text-[10px] text-slate-400 font-black">{asset.serialNumber}</p></td>
                                    <td className="p-4 text-xs font-bold text-slate-500 uppercase">{asset.type}</td>
                                    <td className="p-4 font-black">R$ {asset.cost.toLocaleString()}</td>
