import React, { useState, useMemo, useEffect } from 'react';
import { Task, TaskStatus, User, Client, Squad, Comment, Notification, Requisition } from '../types';
import { 
    CheckCircle, Clock, FileText, Plus, X, Video, Image, Megaphone, 
    Layout, ChevronRight, ChevronLeft, Calendar, Paperclip, MoreHorizontal, Hourglass, 
    MessageSquare, User as UserIcon, Mail, Phone, ExternalLink, Shield, MessageCircle, Send,
    Settings2, Target, Users2, Sparkles, AlertCircle
} from 'lucide-react';

interface ClientPortalProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  currentUser: User;
  users: User[];
  clients: Client[];
  squads: Squad[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  onNavigate: (view: string) => void;
}

type RequestType = 'SOCIAL' | 'VIDEO' | 'WEB' | 'CAMPAIGN' | 'OTHER';

const REQUEST_TYPES = [
    { id: 'CAMPAIGN', label: 'Campanha de Marketing', icon: Megaphone, desc: 'Lançamento, Promoção, Evento' },
    { id: 'SOCIAL', label: 'Social Media / Posts', icon: Image, desc: 'Feed, Stories, Reels' },
    { id: 'VIDEO', label: 'Vídeo & Edição', icon: Video, desc: 'YouTube, Reels, Institucional' },
    { id: 'WEB', label: 'Landing Pages / Web', icon: Layout, desc: 'Sites, LPs, E-mail Marketing' },
    { id: 'OTHER', label: 'Outras Demandas', icon: Sparkles, desc: 'Textos, Estratégia, Copy' },
];

const FORMAT_OPTIONS = [
    { id: '1:1', label: 'Feed Quadrado (1:1)', icon: <div className="w-4 h-4 border-2 border-current rounded-sm aspect-square"/> },
    { id: '9:16', label: 'Stories/Reels (9:16)', icon: <div className="w-3 h-5 border-2 border-current rounded-sm"/> },
    { id: '4:5', label: 'Feed Retrato (4:5)', icon: <div className="w-3 h-4 border-2 border-current rounded-sm"/> },
    { id: '16:9', label: 'YouTube/Widescreen (16:9)', icon: <div className="w-5 h-3 border-2 border-current rounded-sm"/> },
];

export const ClientPortal: React.FC<ClientPortalProps> = ({ tasks, setTasks, currentUser, users, clients, squads, setNotifications, setRequisitions, onNavigate }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);
  const [viewFilter, setViewFilter] = useState<'ACTIVE' | 'HISTORY'>('ACTIVE');
  const [formError, setFormError] = useState<string | null>(null);

  const [contactModalOpen, setContactModalOpen] = useState(false);
  const [contactType, setContactType] = useState<'CALL' | 'MEETING' | null>(null);
  const [contactReason, setContactReason] = useState('');
  const [contactPreference, setContactPreference] = useState<'PHONE' | 'WHATSAPP'>('WHATSAPP');

  const [reqType, setReqType] = useState<RequestType | null>(null);
  const [reqTitle, setReqTitle] = useState('');
  const [reqDesc, setReqDesc] = useState('');
  const [reqGoal, setReqGoal] = useState('');
  const [reqDate, setReqDate] = useState('');
  const [reqFormats, setReqFormats] = useState<string[]>([]);

  useEffect(() => {
    if(isModalOpen || contactModalOpen) {
        console.log("MODAL_OPEN", { screen: 'PortalCliente' });
    }
  }, [isModalOpen, contactModalOpen]);

  const myClientProfile = clients.find(c => c.id === currentUser.clientId);
  const mySquad = myClientProfile ? squads.find(s => s.id === myClientProfile.squadId) : null;
  const accountManager = mySquad 
    ? users.find(u => u.role === 'MANAGER' && mySquad.members.includes(u.id)) || users.find(u => u.role === 'ADMIN')
    : null;

  const myTasks = tasks.filter(t => t.clientRequest && t.assigneeIds.includes(currentUser.id));
  const activeTasks = myTasks.filter(t => t.status !== 'DONE' && !t.archived).sort((a,b) => b.id.localeCompare(a.id));
  const historyTasks = myTasks.filter(t => t.status === 'DONE' || t.archived).sort((a,b) => b.id.localeCompare(a.id));

  const pendingCount = activeTasks.filter(t => t.approvalStatus === 'PENDING').length;
  const inProgressCount = activeTasks.filter(t => t.status === 'IN_PROGRESS' || t.status === 'TODO').length;
  const reviewCount = activeTasks.filter(t => t.status === 'REVIEW').length;

  const recentActivities = useMemo(() => {
      const activities: { id: string, type: 'COMMENT' | 'STATUS', text: string, time: number, user?: User, taskTitle: string }[] = [];
      myTasks.forEach(task => {
          task.comments.forEach(c => {
              const u = users.find(user => user.id === c.userId);
              if (c.userId !== currentUser.id) {
                  activities.push({ id: c.id, type: 'COMMENT', text: c.text, time: c.timestamp, user: u, taskTitle: task.title });
              }
          });
      });
      return activities.sort((a,b) => b.time - a.time).slice(0, 5);
  }, [myTasks, users, currentUser.id]);

  const calculateProgress = (status: TaskStatus, approvalStatus?: string) => {
    if (approvalStatus === 'PENDING') return 5;
    if (approvalStatus === 'REJECTED') return 0;
    switch (status) {
        case 'BACKLOG': return 15;
        case 'TODO': return 25;
        case 'IN_PROGRESS': return 50;
        case 'REVIEW': return 85;
        case 'DONE': return 100;
        default: return 0;
    }
  };

  const getStatusLabel = (status: TaskStatus, approvalStatus?: string) => {
      if (approvalStatus === 'PENDING') return { text: 'Em Triagem', color: 'bg-orange-50 text-orange-600 border-orange-100' };
      if (approvalStatus === 'REJECTED') return { text: 'Recusado', color: 'bg-red-50 text-red-600 border-red-100' };
      switch (status) {
          case 'BACKLOG': return { text: 'Aguardando Início', color: 'bg-slate-100 text-slate-600 border-slate-200' };
          case 'TODO': return { text: 'Planejado', color: 'bg-blue-50 text-blue-600 border-blue-100' };
          case 'IN_PROGRESS': return { text: 'Em Produção', color: 'bg-indigo-50 text-indigo-600 border-indigo-100' };
          case 'REVIEW': return { text: 'Para sua Aprovação', color: 'bg-purple-50 text-purple-600 border-purple-100' };
          case 'DONE': return { text: 'Concluído', color: 'bg-emerald-50 text-emerald-600 border-emerald-100' };
          default: return { text: status, color: 'bg-gray-100' };
      }
  };

  const handleOpenContact = (type: 'CALL' | 'MEETING') => {
      setContactType(type);
      setContactReason('');
      setContactPreference('WHATSAPP');
      setContactModalOpen(true);
  };

  const handleSubmitContact = () => {
      if (!contactReason.trim() || !accountManager) return;
      setNotifications(prev => [{ id: Date.now().toString(), title: contactType === 'MEETING' ? 'Solicitação de Reunião' : 'Solicitação de Contato', message: `O cliente ${currentUser.name} solicita: ${contactReason}. Canal: ${contactPreference}`, type: 'INFO', status: 'UNREAD', priority: 'MEDIUM', originModule: 'CLIENTS', timestamp: Date.now(), targetUserId: accountManager.id, navToView: 'kanban' }, ...prev]);
