  const handleOpenWizard = () => {
      setReqType(null); setReqTitle(''); setReqDesc(''); setReqGoal(''); setReqDate(''); setReqFormats([]); setCurrentStep(1); setFormError(null); setIsModalOpen(true);
  };

  const toggleFormat = (id: string) => { setReqFormats(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]); };

  const handleNextStep = () => {
      setFormError(null);
      if (currentStep === 1 && !reqType) { setFormError("Selecione uma categoria."); return; }
      if (currentStep === 2) {
          if (!reqTitle.trim() || !reqGoal.trim() || !reqDesc.trim()) { setFormError("Preencha todos os campos obrigatórios."); return; }
