      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between"><div><p className="text-[10px] uppercase font-bold text-slate-500">Para Aprovar</p><p className="text-2xl font-bold text-purple-600">{reviewCount}</p></div><CheckCircle size={20} className="text-purple-600"/></div>
