            <button 
              onClick={() => setShowArchived(!showArchived)} 
              className={`p-2.5 rounded-xl transition-all border ${showArchived ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
              title={showArchived ? "Ver Ativos" : "Ver Arquivados"}
