            <button 
              onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [] } as any)} 
              className="bg-pink-600 hover:bg-pink-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-200 transition-all transform hover:scale-[1.02] active:scale-95"
