                        <button className="absolute bottom-4 right-4 bg-white/90 hover:bg-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase shadow-sm backdrop-blur-sm transition-all" onClick={() => onUpdate({...task, cover: undefined})}>Remover Capa</button>
