                                </div>
                                <div className="flex items-center gap-3 mt-2 pl-1">
                                    <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">Na coluna <span className="text-indigo-600">{task.status}</span></div>
                                    {showSavedFeedback && (
                                        <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-black uppercase animate-pop">
                                            <Check size={12}/> Salvo!
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>

                        {task.assigneeIds.length > 0 && (
                            <div className="flex gap-4 items-center ml-10">
                                <div className="flex -space-x-2">
