                                </div>
                                <div className="flex gap-2">
                                    <input type="text" placeholder="Nova etapa..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-pink-500 transition-all" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 text-white px-5 rounded-xl text-xs font-black uppercase hover:bg-slate-900 transition-colors">Adicionar</button>
                                </div>
