import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { 
    Plus, Archive, Settings, X, Search, Bell, Layers
} from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  sidebarOpen: boolean;
  sidebarCompact: boolean;
  isMobile: boolean;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  sidebarOpen, sidebarCompact, isMobile
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const activeColumns = useMemo(() => columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), [columns]);
  const archivedColumns = useMemo(() => columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order), [columns]);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD').length;

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) setShowNotifDropdown(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    else setColumns(prev => [...prev, { id: 'col-' + Date.now(), label: editingColumn.label, color: 'border-slate-400', order: columns.length, wipLimit: editingColumn.wipLimit || null, isArchived: false } as ColumnConfig]);
    setIsColumnModalOpen(false);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));

          // Dispara confete apenas se a tarefa for movida para a coluna de Concluído
          if (targetColId === 'DONE') {
              confetti({
                  particleCount: 150,
                  spread: 70,
                  origin: { y: 0.6 }
              });
          }
      }
      setDraggedTaskId(null);
  };

  const sidebarWidth = isMobile ? '0px' : (sidebarOpen ? (sidebarCompact ? '80px' : '256px') : '0px');

  // Lógica de UPSERT (Update or Insert) para as tarefas
  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      if (exists) {
        return prev.map(t => t.id === updatedTask.id ? updatedTask : t);
      } else {
        return [...prev, updatedTask];
      }
    });
    // MANTÉM O MODAL ABERTO: Atualiza a tarefa selecionada em vez de fechar
    setSelectedTask(updatedTask);
  };

  return (
    /* FIXED VIEWPORT SHELL ROOT */
    <div 
      className="fixed inset-0 flex flex-col bg-slate-50 overflow-hidden transition-all duration-300 ease-in-out"
      style={{ left: sidebarWidth }}
    >

      {/* HEADER ESTÁTICO: FLEX-NONE (SEMPRE VISÍVEL NO TOPO) */}
      <header className="flex-none w-full bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between z-50 shadow-sm">

        {/* Esquerda: Perfil & Notificações */}
        <div className="flex items-center gap-4 shrink-0">
          <div className="relative" ref={notifRef}>
            <button 
              onClick={() => setShowNotifDropdown(!showNotifDropdown)}
              className="w-11 h-11 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-500 hover:text-pink-600 transition-all hover:shadow-md relative"
            >
              <Bell size={20} />
              {unreadCount > 0 && (
                <span className="absolute top-2.5 right-2.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
              )}
            </button>

            {showNotifDropdown && (
              <div className="absolute left-0 top-full mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 z-[60] animate-pop overflow-hidden">
                <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                  <h3 className="text-[10px] font-black uppercase text-slate-400">Notificações</h3>
                </div>
                <div className="p-6 text-center text-slate-400 text-xs font-bold uppercase">Sem novidades</div>
              </div>
            )}
          </div>

          <div className="bg-white px-5 py-2 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4 group transition-all cursor-default">
            <div className="text-right">
              <p className="text-sm font-black text-slate-800 leading-none">{currentUser.name}</p>
              <p className="text-[9px] text-slate-400 uppercase font-black mt-1 tracking-widest">{currentUser.role}</p>
            </div>
            <div className="w-9 h-9 rounded-xl overflow-hidden border-2 border-white shadow-sm bg-slate-100">
              <img src={currentUser.avatar} alt="Perfil" className="w-full h-full object-cover" />
            </div>
          </div>
        </div>

        {/* Centro: Busca */}
        <div className="flex-1 max-w-lg mx-8 hidden md:block">
          <div className="relative group">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-pink-500 transition-colors" />
            <input 
              type="text" 
              placeholder="Pesquisar jobs..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="w-full bg-slate-100/60 border border-transparent focus:bg-white focus:border-pink-200 rounded-2xl pl-12 pr-4 py-3 text-sm font-bold text-slate-700 outline-none transition-all placeholder:text-slate-400 shadow-inner"
            />
          </div>
        </div>

        {/* Direita: Ações Globais */}
        <div className="flex items-center gap-3 shrink-0">
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowArchived(!showArchived)} 
              className={`w-11 h-11 rounded-2xl flex items-center justify-center transition-all border ${showArchived ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-200 hover:text-pink-600'}`}
              title="Jobs Arquivados"
            >
              <Archive size={18}/>
            </button>

            {isAdmin && (
              <button 
                onClick={() => setShowArchivedColumns(true)} 
                className="w-11 h-11 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-pink-600 transition-all"
                title="Configurações do Quadro"
              >
                <Settings size={18}/>
              </button>
            )}
          </div>

          <div className="w-px h-8 bg-slate-200 mx-1"></div>

          <button 
            onClick={() => setSelectedTask({ 
                id: Date.now().toString(), 
                title: '', 
                description: '',
                status: activeColumns[0]?.id || 'BACKLOG', 
                priority: 'MEDIUM', 
                dueDate: '', // Data de entrega vazia para validação obrigatória
                timeLogs: [], 
                assigneeIds: [currentUser.id], 
                checklists: [], 
                comments: [], 
                history: [],
                estimatedTime: 0,
                isTracking: false
            } as Task)} 
            className="h-11 px-6 bg-pink-600 hover:bg-pink-700 text-white rounded-2xl flex items-center gap-3 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-500/30 transition-all transform hover:scale-[1.02] active:scale-95 whitespace-nowrap"
          >
            <Plus size={18} strokeWidth={3} />
            NOVO JOB
          </button>
        </div>
      </header>

      {/* ÁREA DE SCROLL INDEPENDENTE (APENAS O CONTEÚDO ROLA) */}
      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-6 gap-6 items-start">
          {activeColumns.map(col => {
            const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived) && t.title.toLowerCase().includes(searchTerm.toLowerCase()));
            return (
              <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()} 
                onDrop={e => handleDropTask(e, col.id)} 
                className="flex-shrink-0 w-80 flex flex-col max-h-full rounded-[32px] bg-slate-200/40 border border-slate-200/50 backdrop-blur-sm"
              >
                <div className="p-5 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-2 h-6 rounded-full bg-pink-500"></div>
                    <h3 className="font-black text-[11px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                  </div>
                  <span className="bg-white/80 text-slate-500 text-[10px] px-2 py-0.5 rounded-full font-black shadow-sm border border-slate-100">{colTasks.length}</span>
                </div>

                <div className="px-3 pb-5 space-y-4 overflow-y-auto custom-scrollbar flex-1">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-3xl shadow-sm border-2 border-white hover:border-pink-200 cursor-grab active:cursor-grabbing transition-all group hover:shadow-xl overflow-hidden"
                    >
                      {/* CAPA DO CARD NO QUADRO */}
                      {task.coverType === 'color' && (
                        <div className="h-16 w-full rounded-t-2xl" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />
                      )}
                      {task.coverType === 'image' && (
                        <img src={task.coverValue || ''} className="h-24 w-full object-cover rounded-t-2xl" alt="Capa" />
                      )}

                      <div className="p-5">
                        <div className="flex justify-between items-start mb-3">
                          <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-tighter ${task.priority === 'HIGH' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>{task.priority}</span>
                          <div className="flex -space-x-2">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-snug group-hover:text-pink-600 transition-colors line-clamp-2">{task.title}</h4>
                      </div>
                    </div>
                  ))}

                  <button 
                    onClick={() => setSelectedTask({ 
                        id: Date.now().toString(), 
                        title: '', 
                        description: '',
                        status: col.id, 
                        priority: 'MEDIUM', 
                        dueDate: '', 
                        timeLogs: [], 
                        assigneeIds: [currentUser.id], 
                        checklists: [], 
                        comments: [], 
                        history: [],
                        estimatedTime: 0,
                        isTracking: false
                    } as Task)}
                    className="w-full py-4 border-2 border-dashed border-slate-300/50 rounded-3xl text-slate-400 hover:text-pink-500 hover:border-pink-200 transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/30"
                  >
                    <Plus size={16}/> ADICIONAR
                  </button>
                </div>
              </div>
            );
          })}

          {isAdmin && (
              <button 
                  onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }}
                  className="flex-shrink-0 w-80 h-20 bg-white/30 border-2 border-dashed border-slate-300 rounded-[32px] flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-xs tracking-widest hover:bg-white hover:text-slate-600 transition-all group"
              >
                  <Plus size={20} /> NOVA LISTA
              </button>
          )}
        </div>
      </main>

      {/* MODALS */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-sm p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 uppercase tracking-tighter">Configurar Coluna</h3>
                  <div className="space-y-4">
                    <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Título da Coluna" />
                    <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-slate-800 transition-all">Salvar Alterações</button>
                  </div>
              </div>
          </div>
      )}

      {showArchivedColumns && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setShowArchivedColumns(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-md p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tighter">Listas Arquivadas</h3>
                  <div className="space-y-3 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                      {archivedColumns.map(col => (
                          <div key={col.id} className="flex items-center justify-between p-4 border border-slate-100 rounded-2xl bg-slate-50">
                              <span className="font-bold text-slate-700">{col.label}</span>
                              <button onClick={() => setColumns(prev => prev.map(c => c.id === col.id ? {...c, isArchived: false} : c))} className="text-pink-600 font-black text-[10px] uppercase bg-white px-3 py-1.5 rounded-lg shadow-sm border">Reativar</button>
                          </div>
                      ))}
                      {archivedColumns.length === 0 && <p className="text-center text-slate-400 py-10 font-bold uppercase text-xs">Nenhuma lista arquivada.</p>}
                  </div>
                  <button onClick={() => setShowArchivedColumns(false)} className="w-full mt-6 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Fechar</button>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, Eye, 
    CheckSquare, Users, CreditCard, Layout, Upload, Check, Activity, AlertCircle, Play, Pause, Calendar, Save,
    Flag, AlignLeft, ShieldCheck, Search, Palette, ExternalLink, UserPlus, Camera, Trash, ImagePlus
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, setNotifications, openConfirm }) => {
    const [newComment, setNewComment] = useState('');
    const [mentionFilter, setMentionFilter] = useState('');
    const [showMentions, setShowMentions] = useState(false);
    const [newChecklistText, setNewChecklistText] = useState('');

    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [localDueDate, setLocalDueDate] = useState(task.dueDate || '');
    const [localPriority, setLocalPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>(task.priority || 'MEDIUM');
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [showSavedFeedback, setShowSavedFeedback] = useState(false);

    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COLOR_GRID' | string | null>(null);
    const [memberSearch, setMemberSearch] = useState('');

    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const commentInputRef = useRef<HTMLTextAreaElement>(null);
    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        console.log("MODAL_OPEN", { screen: 'KanbanJob' });
        return () => console.log("MODAL_CLOSED");
    }, [task.id]);

    useEffect(() => {
        setLocalTitle(task.title);
        setLocalDesc(task.description);
        setLocalDueDate(task.dueDate || '');
        setLocalPriority(task.priority || 'MEDIUM');
    }, [task.id, task.title, task.description, task.dueDate, task.priority]);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                setSecondsElapsed(s => s + 1);
            }, 1000);
        } else {
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [task.isTracking]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setActivePopover(null);
                setShowMentions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const isNewTask = task.history.length === 0;

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const calculateTotalSeconds = () => {
        const closedLogsDuration = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        if (task.isTracking) {
            const activeLog = task.timeLogs.find(l => !l.endTime);
            if (activeLog) {
                const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                return closedLogsDuration + elapsed;
            }
        }
        return closedLogsDuration;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const triggerSavedFeedback = () => {
        setShowSavedFeedback(true);
        setTimeout(() => setShowSavedFeedback(false), 2000);
    };

    const updateWithLog = (updatedTaskProps: Partial<Task>, logAction: string) => {
        onUpdate({
            ...task,
            ...updatedTaskProps,
            history: [...task.history, createLog(logAction)]
        });
        triggerSavedFeedback();
    };

    const handleFinalConfirmNewTask = () => {
        if (!localTitle.trim() || !localDueDate) return;
        onUpdate({
            ...task,
            title: localTitle,
            description: localDesc,
            dueDate: localDueDate,
            priority: localPriority,
            history: [createLog('Tarefa criada no Kanban')]
        });
        triggerSavedFeedback();
    };

    const handleCoverChange = (type: 'color' | 'image' | null, value: string | null) => {
        updateWithLog({ coverType: type, coverValue: value }, type ? `atualizou a capa (${type})` : 'removeu a capa');
        setActivePopover(null);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const imageUrl = URL.createObjectURL(file);
            handleCoverChange('image', imageUrl);
        }
    };

    const saveTitle = () => {
        if (!localTitle.trim() || localTitle === task.title) return;
        updateWithLog({ title: localTitle }, `alterou o título de "${task.title || 'Vazio'}" para "${localTitle}"`);
    };

    const saveDesc = () => {
        setIsEditingDesc(false);
        if (localDesc === task.description) return;
        updateWithLog({ description: localDesc }, `atualizou a descrição do job`);
    };

    const addChecklistItem = () => {
        if (newChecklistText.trim()) {
            const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
            updateWithLog({ checklists: [...(task.checklists || []), newItem] }, `adicionou etapa: "${newChecklistText}"`);
            setNewChecklistText('');
        }
    };

    const toggleChecklist = (itemId: string) => {
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, isCompleted: !c.isCompleted } : c);
        onUpdate({...task, checklists: newChecklists});
    };

    const handleDueDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = e.target.value;
        setLocalDueDate(newVal);
        if (!isNewTask && newVal) updateWithLog({ dueDate: newVal }, `alterou o prazo para ${new Date(newVal).toLocaleDateString()}`);
    };

    const toggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    const duration = Math.floor((now - log.startTime) / 1000);
                    return { ...log, endTime: now, duration };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou a produção');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou a produção');
        }
    };

    const totalSecondsAccumulated = calculateTotalSeconds();
    const checklistProgress = task.checklists.length > 0 ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) : 0;
    const activityFeed = [...task.comments.map(c => ({ type: 'COMMENT', data: c, timestamp: c.timestamp })), ...task.history.map(h => ({ type: 'HISTORY', data: h, timestamp: h.timestamp }))].sort((a, b) => b.timestamp - a.timestamp);

    if (isNewTask) {
        return (
            <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex justify-center items-center p-4 transition-all duration-300" onClick={onClose}>
                <div className="bg-white w-full max-w-2xl rounded-[32px] shadow-2xl overflow-hidden animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                    <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-pink-600 rounded-xl"><Plus size={24} /></div>
                            <div><h2 className="text-xl font-bold">Nova Demanda</h2><p className="text-xs text-slate-400">Inicie uma nova jornada de produção.</p></div>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
                    </div>
                    <div className="p-8 space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Título do Job <span className="text-red-500">*</span></label>
                            <input className="w-full text-xl font-bold text-slate-800 bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 outline-none focus:border-pink-500 focus:bg-white transition-all" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} placeholder="Ex: Campanha de Natal..." autoFocus />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Entrega <span className="text-red-500">*</span></label>
                                <input type="date" className={`w-full bg-slate-50 border-2 rounded-2xl p-4 text-sm font-bold outline-none transition-all ${!localDueDate ? 'border-red-200' : 'border-slate-100 focus:border-pink-500'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Prioridade</label>
                                <div className="flex gap-2 h-[54px]">
                                    {['LOW', 'MEDIUM', 'HIGH'].map(p => (
                                        <button key={p} onClick={() => setLocalPriority(p as any)} className={`flex-1 rounded-xl text-[10px] font-black uppercase transition-all border-2 ${localPriority === p ? 'border-slate-800 bg-white scale-105 shadow-sm' : 'border-transparent bg-slate-100 opacity-60'}`}>{p === 'HIGH' ? 'Urgente' : p === 'MEDIUM' ? 'Média' : 'Baixa'}</button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                    <div className="p-6 bg-slate-50 border-t flex justify-end gap-3">
                        <button onClick={onClose} className="px-6 py-3 font-bold text-slate-500">Cancelar</button>
                        <button onClick={handleFinalConfirmNewTask} disabled={!localDueDate || !localTitle} className="px-8 py-3 bg-pink-600 text-white font-black rounded-2xl shadow-lg shadow-pink-500/30 disabled:opacity-50">Criar Job</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex justify-center overflow-y-auto py-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-[32px] shadow-2xl relative min-h-[500px] h-fit my-auto mx-4 animate-pop border border-slate-200 overflow-hidden" onClick={e => e.stopPropagation()}>

                {/* --- SEÇÃO HERO: CAPA --- */}
                <div className={`w-full h-40 relative group transition-all duration-500 ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? (task.coverValue || '#f1f5f9') : undefined }}>
                    {task.coverType === 'image' && (
                        <img src={task.coverValue || ''} alt="Capa" className="w-full h-full object-cover" />
                    )}

                    {/* BOTÃO DISCRETO PARA QUANDO NÃO TEM CAPA */}
                    {!task.coverType && (
                        <div className="absolute inset-0 flex items-center justify-center">
                            <button 
                                onClick={() => setActivePopover('COLOR_GRID')}
                                className="flex items-center gap-2 px-4 py-2 bg-white/60 hover:bg-white text-slate-500 font-black text-[10px] uppercase rounded-xl transition-all border border-slate-200/50"
                            >
                                <Layout size={14}/> Adicionar Capa
                            </button>
                        </div>
                    )}

                    {/* TOOLBAR DA CAPA (OVERLAY) */}
                    <div className="absolute bottom-4 right-4 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <div className="relative">
                            <button 
                                onClick={() => setActivePopover(activePopover === 'COLOR_GRID' ? null : 'COLOR_GRID')}
                                className="p-2.5 bg-white/90 backdrop-blur-md hover:bg-white text-slate-700 rounded-xl shadow-lg border border-white/20 transition-all"
                                title="Mudar Cor"
                            >
                                <Palette size={16}/>
                            </button>

                            {activePopover === 'COLOR_GRID' && (
                                <div ref={popoverRef} className="absolute bottom-full right-0 mb-3 bg-white p-3 rounded-2xl shadow-2xl border border-slate-100 w-48 animate-pop">
                                    <div className="grid grid-cols-5 gap-2">
                                        {PRESET_COLORS.map(c => (
                                            <button 
                                                key={c} 
                                                onClick={() => handleCoverChange('color', c)}
                                                className="w-6 h-6 rounded-full border-2 border-white shadow-sm hover:scale-125 transition-transform" 
                                                style={{ backgroundColor: c }}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>

                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="p-2.5 bg-white/90 backdrop-blur-md hover:bg-white text-slate-700 rounded-xl shadow-lg border border-white/20 transition-all"
                            title="Upload de Imagem"
                        >
                            <Camera size={16}/>
                        </button>

                        {task.coverType && (
                            <button 
                                onClick={() => handleCoverChange(null, null)}
                                className="p-2.5 bg-red-500 hover:bg-red-600 text-white rounded-xl shadow-lg transition-all"
                                title="Remover Capa"
                            >
                                <Trash size={16}/>
                            </button>
                        )}
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </div>

                    <button onClick={onClose} className="absolute top-4 right-4 p-2 rounded-full bg-black/10 hover:bg-black/20 z-50 transition-colors backdrop-blur-sm"><X size={20} className="text-white"/></button>
                </div>

                {/* --- CONTEÚDO DO MODAL --- */}
                <div className="flex flex-col md:flex-row p-8 gap-8">
                    <div className="flex-1 space-y-8">
                        <div className="flex gap-4 items-start">
                            <CreditCard className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <input className="text-3xl font-black text-slate-800 w-full bg-transparent border-none outline-none placeholder-slate-300 mb-1" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} onBlur={saveTitle} onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()} />
                                <div className="flex items-center gap-3">
                                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status: <span className="text-pink-600">{task.status}</span></div>
                                    {showSavedFeedback && <div className="flex items-center gap-1 text-emerald-600 text-[10px] font-black uppercase animate-pop"><Check size={12}/> Salvo</div>}
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 ml-10">
                            <div className="bg-slate-50 p-5 rounded-[24px] border border-slate-100 shadow-sm">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2"><Calendar size={12}/> Entrega</h4>
                                <input type="date" className={`w-full text-sm font-black bg-transparent outline-none ${!localDueDate ? 'text-red-500' : 'text-slate-800'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="bg-slate-50 p-5 rounded-[24px] border border-slate-100 shadow-sm">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2"><Clock size={12}/> Cronômetro</h4>
                                <div className="flex items-center justify-between">
                                    <div className="text-xl font-black text-slate-800 font-mono">{formatSeconds(totalSecondsAccumulated)}</div>
                                    <button onClick={toggleTimer} className={`p-2 rounded-xl transition-all ${task.isTracking ? 'bg-amber-100 text-amber-600' : 'bg-pink-600 text-white'}`}>
                                        {task.isTracking ? <Pause size={18} fill="currentColor"/> : <Play size={18} fill="currentColor"/>}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <AlignLeft className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-4">Briefing Detalhado</h3>
                                <div className={`relative rounded-2xl p-5 transition-all ${isEditingDesc ? 'bg-white ring-2 ring-pink-100 shadow-inner' : 'bg-slate-50 hover:bg-slate-100 cursor-text'}`} onClick={() => !isEditingDesc && setIsEditingDesc(true)}>
                                    {isEditingDesc ? (
                                        <textarea className="w-full min-h-[150px] border-none outline-none text-sm text-slate-700 resize-none bg-transparent font-medium" value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} onBlur={saveDesc} autoFocus placeholder="Descreva os detalhes da entrega..." />
                                    ) : (
                                        <div className="text-sm text-slate-700 leading-relaxed min-h-[150px] font-medium whitespace-pre-wrap">{localDesc || <span className="text-slate-400 italic">Clique para adicionar briefing...</span>}</div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <CheckSquare className="mt-1 text-slate-400" size={24}/>
                            <div className="flex-1">
                                <div className="flex justify-between items-center mb-4"><h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest">Etapas de Produção</h3><span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{checklistProgress}%</span></div>
                                <div className="space-y-2 mb-6">
                                    {task.checklists.map(item => (
                                        <div key={item.id} className="flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 transition-all border border-transparent hover:border-slate-100">
                                            <input type="checkbox" checked={item.isCompleted} onChange={() => toggleChecklist(item.id)} className="w-5 h-5 rounded-md border-slate-300 text-pink-600 focus:ring-pink-500 cursor-pointer"/>
                                            <span className={`text-sm font-bold ${item.isCompleted ? 'line-through text-slate-300' : 'text-slate-600'}`}>{item.text}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex gap-2">
                                    <input type="text" placeholder="Adicionar nova etapa..." className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm outline-none focus:border-pink-500" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 text-white px-6 rounded-xl text-[10px] font-black uppercase">Add</button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* SIDEBAR DO MODAL */}
                    <div className="w-full md:w-56 space-y-4 shrink-0">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Ações Rápidas</h4>
                        {task.status !== 'DONE' && (
                            <button onClick={() => { updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job'); confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } }); }} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white p-4 rounded-2xl text-xs font-black uppercase flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 transition-all"><CheckCircle size={16}/> Finalizar Job</button>
                        )}
                        <div className="relative">
                            <button onClick={() => setActivePopover('MEMBERS')} className="w-full text-left p-4 rounded-2xl text-xs font-black uppercase flex items-center gap-3 bg-slate-100 text-slate-600 hover:bg-slate-200 transition-all"><Users size={18}/> Membros</button>
                            {activePopover === 'MEMBERS' && (
                                <div ref={popoverRef} className="absolute left-0 bottom-full mb-2 w-72 bg-white rounded-2xl shadow-2xl border border-slate-100 z-50 p-4 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-4 text-center">Atribuir Colaboradores</h5>
                                    <div className="space-y-1 max-h-60 overflow-y-auto custom-scrollbar">
                                        {users.filter(u => u.role !== 'CLIENT').map(u => (
                                            <button key={u.id} onClick={() => {
                                                const currentIds = task.assigneeIds || [];
                                                const newIds = currentIds.includes(u.id) ? currentIds.filter(id => id !== u.id) : [...currentIds, u.id];
                                                updateWithLog({ assigneeIds: newIds }, `atualizou responsáveis`);
                                            }} className={`w-full flex items-center justify-between p-2 rounded-xl ${task.assigneeIds.includes(u.id) ? 'bg-pink-50 text-pink-700' : 'hover:bg-slate-50 text-slate-600'}`}>
                                                <div className="flex items-center gap-2"><img src={u.avatar} className="w-8 h-8 rounded-full border border-white shadow-sm" /><span className="text-xs font-bold">{u.name}</span></div>
                                                {task.assigneeIds.includes(u.id) && <Check size={14}/>}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="pt-6 border-t border-slate-100">
                             <button onClick={() => updateWithLog({ archived: !task.archived }, 'arquivou o job')} className="w-full text-left p-3 rounded-xl text-[10px] font-black uppercase text-slate-400 hover:bg-slate-50 flex items-center gap-2"><Archive size={14}/> {task.archived ? 'Desarquivar' : 'Arquivar Job'}</button>
                             {(currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER') && <button onClick={() => onDeleteTask(task.id)} className="w-full text-left p-3 rounded-xl text-[10px] font-black uppercase text-red-400 hover:bg-red-50 flex items-center gap-2"><Trash2 size={14}/> Excluir Permanente</button>}
                        </div>
                        <button onClick={onClose} className="w-full bg-slate-900 text-white p-4 rounded-2xl text-xs font-black uppercase shadow-xl hover:bg-slate-800 transition-all mt-8">Fechar Janela</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { 
    Plus, Archive, Settings, X, Search, Bell, Layers
} from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  sidebarOpen: boolean;
  sidebarCompact: boolean;
  isMobile: boolean;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  sidebarOpen, sidebarCompact, isMobile
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const activeColumns = useMemo(() => columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), [columns]);
  const archivedColumns = useMemo(() => columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order), [columns]);

  const unreadCount = notifications.filter(n => n.status === 'UNREAD').length;

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) setShowNotifDropdown(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    else setColumns(prev => [...prev, { id: 'col-' + Date.now(), label: editingColumn.label, color: 'border-slate-400', order: columns.length, wipLimit: editingColumn.wipLimit || null, isArchived: false } as ColumnConfig]);
    setIsColumnModalOpen(false);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));

          if (targetColId === 'DONE') {
              confetti({
                  particleCount: 150,
                  spread: 70,
                  origin: { y: 0.6 }
              });
          }
      }
      setDraggedTaskId(null);
  };

  const sidebarWidth = isMobile ? '0px' : (sidebarOpen ? (sidebarCompact ? '80px' : '256px') : '0px');

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      if (exists) {
        return prev.map(t => t.id === updatedTask.id ? updatedTask : t);
      } else {
        return [...prev, updatedTask];
      }
    });
    setSelectedTask(updatedTask);
  };

  return (
    <div 
      className="fixed inset-0 flex flex-col bg-slate-50 overflow-hidden transition-all duration-300 ease-in-out"
      style={{ left: sidebarWidth }}
    >
      <header className="flex-none w-full bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between z-50 shadow-sm">
        <div className="flex items-center gap-4 shrink-0">
          <div className="relative" ref={notifRef}>
            <button 
              onClick={() => setShowNotifDropdown(!showNotifDropdown)}
              className="w-11 h-11 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-500 hover:text-pink-600 transition-all hover:shadow-md relative"
            >
              <Bell size={20} />
              {unreadCount > 0 && (
                <span className="absolute top-2.5 right-2.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
              )}
            </button>
            {showNotifDropdown && (
              <div className="absolute left-0 top-full mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 z-[60] animate-pop overflow-hidden">
                <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                  <h3 className="text-[10px] font-black uppercase text-slate-400">Notificações</h3>
                </div>
                <div className="p-6 text-center text-slate-400 text-xs font-bold uppercase">Sem novidades</div>
              </div>
            )}
          </div>
          <div className="bg-white px-5 py-2 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4 group transition-all cursor-default">
            <div className="text-right">
              <p className="text-sm font-black text-slate-800 leading-none">{currentUser.name}</p>
              <p className="text-[9px] text-slate-400 uppercase font-black mt-1 tracking-widest">{currentUser.role}</p>
            </div>
            <div className="w-9 h-9 rounded-xl overflow-hidden border-2 border-white shadow-sm bg-slate-100">
              <img src={currentUser.avatar} alt="Perfil" className="w-full h-full object-cover" />
            </div>
          </div>
        </div>
        <div className="flex-1 max-w-lg mx-8 hidden md:block">
          <div className="relative group">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-pink-500 transition-colors" />
            <input 
              type="text" 
              placeholder="Pesquisar jobs..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="w-full bg-slate-100/60 border border-transparent focus:bg-white focus:border-pink-200 rounded-2xl pl-12 pr-4 py-3 text-sm font-bold text-slate-700 outline-none transition-all placeholder:text-slate-400 shadow-inner"
            />
          </div>
        </div>
        <div className="flex items-center gap-3 shrink-0">
          <button onClick={() => setShowArchived(!showArchived)} className={`w-11 h-11 rounded-2xl flex items-center justify-center transition-all border ${showArchived ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-200 hover:text-pink-600'}`} title="Jobs Arquivados"><Archive size={18}/></button>
          {isAdmin && (<button onClick={() => setShowArchivedColumns(true)} className="w-11 h-11 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-pink-600 transition-all" title="Configurações do Quadro"><Settings size={18}/></button>)}
          <div className="w-px h-8 bg-slate-200 mx-1"></div>
          <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} className="h-11 px-6 bg-pink-600 hover:bg-pink-700 text-white rounded-2xl flex items-center gap-3 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-500/30 transition-all transform hover:scale-[1.02] active:scale-95 whitespace-nowrap"><Plus size={18} strokeWidth={3} /> NOVO JOB</button>
        </div>
      </header>

      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-6 gap-6 items-start">
          {activeColumns.map(col => {
            const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived) && t.title.toLowerCase().includes(searchTerm.toLowerCase()));
            return (
              <div key={col.id} onDragOver={e => e.preventDefault()} onDrop={e => handleDropTask(e, col.id)} className="flex-shrink-0 w-80 flex flex-col max-h-full rounded-[32px] bg-slate-200/40 border border-slate-200/50 backdrop-blur-sm">
                <div className="p-5 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-2 h-6 rounded-full bg-pink-500"></div>
                    <h3 className="font-black text-[11px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                  </div>
                  <span className="bg-white/80 text-slate-500 text-[10px] px-2 py-0.5 rounded-full font-black shadow-sm border border-slate-100">{colTasks.length}</span>
                </div>

                <div className="px-3 pb-5 space-y-4 overflow-y-auto custom-scrollbar flex-1">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-[32px] shadow-sm border-2 border-white hover:border-pink-200 cursor-grab active:cursor-grabbing transition-all group hover:shadow-xl overflow-hidden flex flex-col"
                    >
                      {/* CAPA SANGRE: SEM PADDING E SEM MARGEM */}
                      {task.coverType === 'color' && (
                        <div className="h-20 w-full border-b border-black/5" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />
                      )}
                      {task.coverType === 'image' && (
                        <img src={task.coverValue || ''} className="h-24 w-full object-cover border-b border-black/5" alt="Capa" />
                      )}

                      <div className="p-5">
                        <div className="flex justify-between items-start mb-3">
                          <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-tighter ${task.priority === 'HIGH' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>{task.priority}</span>
                          <div className="flex -space-x-2">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-snug group-hover:text-pink-600 transition-colors line-clamp-2">{task.title}</h4>
                      </div>
                    </div>
                  ))}

                  <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} className="w-full py-4 border-2 border-dashed border-slate-300/50 rounded-[32px] text-slate-400 hover:text-pink-500 hover:border-pink-200 transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/30"><Plus size={16}/> ADICIONAR</button>
                </div>
              </div>
            );
          })}
          {isAdmin && (<button onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} className="flex-shrink-0 w-80 h-20 bg-white/30 border-2 border-dashed border-slate-300 rounded-[32px] flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-xs tracking-widest hover:bg-white hover:text-slate-600 transition-all group"><Plus size={20} /> NOVA LISTA</button>)}
        </div>
      </main>

      {/* MODALS */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-sm p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 uppercase tracking-tighter">Configurar Coluna</h3>
                  <div className="space-y-4">
                    <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Título da Coluna" />
                    <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-slate-800 transition-all">Salvar Alterações</button>
                  </div>
              </div>
          </div>
      )}

      {showArchivedColumns && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setShowArchivedColumns(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-md p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tighter">Listas Arquivadas</h3>
                  <div className="space-y-3 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                      {archivedColumns.map(col => (
                          <div key={col.id} className="flex items-center justify-between p-4 border border-slate-100 rounded-2xl bg-slate-50">
                              <span className="font-bold text-slate-700">{col.label}</span>
                              <button onClick={() => setColumns(prev => prev.map(c => c.id === col.id ? {...c, isArchived: false} : c))} className="text-pink-600 font-black text-[10px] uppercase bg-white px-3 py-1.5 rounded-lg shadow-sm border">Reativar</button>
                          </div>
                      ))}
                      {archivedColumns.length === 0 && <p className="text-center text-slate-400 py-10 font-bold uppercase text-xs">Nenhuma lista arquivada.</p>}
                  </div>
                  <button onClick={() => setShowArchivedColumns(false)} className="w-full mt-6 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Fechar</button>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, FileText, AlertCircle, ShoppingBag, DollarSign, Clock, AlertTriangle, Phone, Calendar } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  // Estado para Criar Nova Requisição
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});

  // Estado para Filtros
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');

  // Estados para Processamento (Feedback Visual)
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Estados para Modal de Reprovação
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  useEffect(() => {
    if(isCreateModalOpen || isRejectModalOpen) {
        console.log("MODAL_OPEN", { screen: "Solicitacoes" });
    }
  }, [isCreateModalOpen, isRejectModalOpen]);

  // 1. Permissões
  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  // Filtragem
  const displayedRequisitions = requisitions.filter(req => {
      if (filter === 'MY') return req.requesterId === currentUser.id;
      if (!canApprove) return req.requesterId === currentUser.id;
      return true;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) {
          alert("Preencha título e valor.");
          return;
      }

      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };

      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove) {
          alert("Erro 403: Sem permissão para aprovar.");
          return;
      }
      if (req.status === 'APPROVED') return;

      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...req,
              status: 'APPROVED',
              approvedBy: currentUser.id,
              approvedAt: now,
              rejectedBy: undefined,
              rejectedAt: undefined,
              rejectedReason: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          const isServiceRequest = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);
          if (!isServiceRequest && req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}-${Date.now()}`,
                  description: `REQ Aprovada: ${req.title} (${req.category})`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador Interno'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }

          const notif: Notification = {
              id: `notif-apr-${Date.now()}`,
              title: isServiceRequest ? 'Solicitação Agendada/Concluída' : 'Solicitação Aprovada',
              message: isServiceRequest 
                ? `Sua solicitação "${req.title}" foi confirmada pela equipe.`
                : `Sua solicitação "${req.title}" no valor de R$ ${req.estimatedCost.toLocaleString()} foi aprovada.`,
              type: 'SUCCESS',
              status: 'UNREAD',
              priority: 'MEDIUM',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: req.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
      }, 800);
  };

  const openRejectModal = (req: Requisition) => {
      setSelectedReqForReject(req);
      setRejectionReason('');
      setIsRejectModalOpen(true);
  };

  const confirmRejection = () => {
      if (!selectedReqForReject) return;
      if (!rejectionReason || rejectionReason.length < 3) {
          alert("O motivo da reprovação é obrigatório (mínimo 3 caracteres).");
          return;
      }
      if (!canApprove) {
          alert("Erro 403: Sem permissão.");
          return;
      }

      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);

      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...reqToReject,
              status: 'REJECTED',
              rejectedBy: currentUser.id,
              rejectedAt: now,
              rejectedReason: rejectionReason,
              approvedBy: undefined,
              approvedAt: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));

          const notif: Notification = {
              id: `notif-rej-${Date.now()}`,
              title: 'Solicitação Recusada',
              message: `Sua solicitação "${reqToReject.title}" foi recusada. Motivo: ${rejectionReason}`,
              type: 'REJECTED',
              status: 'UNREAD',
              priority: 'HIGH',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: reqToReject.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
          setSelectedReqForReject(null);
      }, 800);
  };

  const getCategoryIcon = (cat: string) => {
      switch(cat) {
          case 'Reunião': return <Calendar size={12}/>;
          case 'Atendimento': return <Phone size={12}/>;
          default: return <ShoppingBag size={12}/>;
      }
  };

  return (
    <div className="space-y-6 animate-pop">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Central de Solicitações</h2>
          <p className="text-slate-500">Gestão de compras, reembolsos e agendamentos.</p>
        </div>
        <div className="flex gap-2">
            {canApprove && (
                <div className="bg-slate-100 p-1 rounded-lg flex text-xs font-bold">
                    <button 
                        onClick={() => setFilter('ALL')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'ALL' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setFilter('MY')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'MY' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Minhas
                    </button>
                </div>
            )}
            <button 
                onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
                className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors shadow-lg shadow-pink-500/20"
            >
                <Plus size={18} /> Nova Solicitação
            </button>
        </div>
      </div>

      {/* Grid de Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {displayedRequisitions.length === 0 && (
              <div className="col-span-full p-12 text-center border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
                  <FileText className="mx-auto text-slate-300 mb-2" size={48}/>
                  <p className="text-slate-500 font-medium">Nenhuma solicitação encontrada.</p>
              </div>
          )}

          {displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;
              const isService = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);

              return (
                <div key={req.id} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-shadow relative">
                    {isProcessing && (
                        <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
                            <div className="flex flex-col items-center gap-2">
                                <Clock className="animate-spin text-pink-600" size={32}/>
                                <span className="text-xs font-bold text-pink-600">Processando...</span>
                            </div>
                        </div>
                    )}

                    <div className="p-5 flex-1">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                req.status === 'PENDING' ? 'bg-orange-50 text-orange-700 border-orange-100' : 
                                req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'
                            }`}>
                                {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? (isService ? 'Concluído' : 'Aprovada') : 'Recusada'}
                            </span>
                            <div className="flex items-center gap-1 text-xs text-slate-400">
                                <Clock size={12}/>
                                <span>{req.date.split('-').reverse().join('/')}</span>
                            </div>
                        </div>

                        <h3 className="font-bold text-slate-800 text-lg mb-1 line-clamp-1">{req.title}</h3>
                        <div className="flex items-center gap-2 text-xs text-slate-500 mb-4">
                            <span className="bg-slate-100 px-2 py-0.5 rounded border border-slate-200 flex items-center gap-1">{getCategoryIcon(req.category)} {req.category}</span>
                            {requester && (
                                <span className="flex items-center gap-1" title={requester.name}>
                                    • <img src={requester.avatar} className="w-4 h-4 rounded-full"/> <b>{requester.name.split(' ')[0]}</b>
                                </span>
                            )}
                        </div>

                        <p className="text-sm text-slate-600 mb-4 line-clamp-3 bg-slate-50 p-2 rounded-lg border border-slate-100 min-h-[60px]">
                            {req.description}
                        </p>

                        {req.status === 'REJECTED' && req.rejectedReason && (
                            <div className="bg-red-50 p-3 rounded-lg border border-red-100 mb-4 animate-pop">
                                <p className="text-xs text-red-800 font-bold flex items-center gap-1 mb-1"><AlertCircle size={12}/> Motivo da Recusa:</p>
                                <p className="text-xs text-red-600 italic">"{req.rejectedReason}"</p>
                                {req.rejectedAt && <p className="text-[10px] text-red-400 mt-1 text-right">{new Date(req.rejectedAt).toLocaleString()}</p>}
                            </div>
                        )}

                        {req.status === 'APPROVED' && req.approvedAt && (
                             <div className="bg-emerald-50 p-2 rounded border border-emerald-100 mb-4 text-center">
                                 <p className="text-[10px] text-emerald-600">{isService ? 'Confirmado' : 'Aprovado'} em {new Date(req.approvedAt).toLocaleDateString()}</p>
                             </div>
                        )}
                    </div>

                    <div className="p-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
                        <div>
                            {isService ? (
                                <p className="text-xs font-bold text-slate-500 uppercase">Solicitação de Serviço</p>
                            ) : (
                                <>
                                    <p className="text-[10px] text-slate-400 uppercase font-bold">Valor Solicitado</p>
                                    <p className="text-lg font-bold text-slate-800 flex items-center gap-1">
                                        <span className="text-slate-400 text-sm font-normal">R$</span> {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                    </p>
                                </>
                            )}
                        </div>

                        {canApprove && req.status === 'PENDING' && (
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => handleApproveReq(req)} 
                                    className="px-3 py-2 bg-emerald-100 hover:bg-emerald-200 text-emerald-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title={isService ? "Confirmar Agendamento" : "Aprovar e Lançar Despesa"}
                                >
                                    <Check size={16}/> {isService ? 'Confirmar' : 'Aprovar'}
                                </button>
                                <button 
                                    onClick={() => openRejectModal(req)} 
                                    className="px-3 py-2 bg-red-100 hover:bg-red-200 text-red-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title="Reprovar"
                                >
                                    <X size={16}/> {isService ? 'Recusar' : 'Reprovar'}
                                </button>
                            </div>
                        )}
                    </div>
                </div>
              );
          })}
      </div>

      {/* Modal de Nova Solicitação */}
      {isCreateModalOpen && (
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                      <div className="p-2 bg-pink-100 text-pink-600 rounded-xl">
                        <ShoppingBag size={20}/>
                      </div>
                      Nova Solicitação
                  </h3>
                  <div className="space-y-4">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Solicitação</label>
                          <select 
                             className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                             value={editingReq.category}
                             onChange={e => setEditingReq({...editingReq, category: e.target.value})}
                          >
                              {isClient ? (
                                  <>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Outros">Outros</option>
                                  </>
                              ) : (
                                  <>
                                    <option value="Compra">Compra de Material</option>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Vale">Vale / Adiantamento</option>
                                    <option value="Software">Software</option>
                                    <option value="Serviço">Serviço Terceiro</option>
                                  </>
                              )}
                          </select>
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título / Identificação</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder={isClient ? "Ex: Reembolso Uber Reunião" : "Ex: Monitor Dell 24pol"} 
                            value={editingReq.title || ''} 
                            onChange={e => setEditingReq({...editingReq, title: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Justificativa Detalhada</label>
                          <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50 resize-none"
                            placeholder="Descreva a necessidade..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor Estimado (R$)</label>
                          <input 
                            type="number" 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder="0.00" 
                            value={editingReq.estimatedCost || ''} 
                            onChange={e => setEditingReq({...editingReq, estimatedCost: parseFloat(e.target.value)})} 
                          />
                      </div>

                      <div className="pt-4 flex gap-3">
                          <button onClick={() => setIsCreateModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Cancelar</button>
                          <button onClick={handleSaveReq} className="flex-1 py-4 bg-pink-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-pink-700 shadow-xl shadow-pink-500/20 transition-all">Enviar Pedido</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Modal de Reprovação */}
      {isRejectModalOpen && selectedReqForReject && (
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm z-[110] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop border-t-4 border-red-500 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="flex items-start gap-4 mb-6">
                      <div className="p-3 bg-red-50 rounded-xl text-red-600">
                          <AlertTriangle size={24} />
                      </div>
                      <div>
                          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Recusar Solicitação</h3>
                          <p className="text-sm text-slate-500">Informe o motivo da decisão.</p>
                      </div>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-2xl mb-6 text-sm text-slate-600 border border-slate-100">
                      <p className="font-bold text-slate-800 mb-1">{selectedReqForReject.title}</p>
                      {selectedReqForReject.estimatedCost > 0 && <p className="text-xs font-bold text-slate-400">VALOR: R$ {selectedReqForReject.estimatedCost.toLocaleString()}</p>}
                  </div>

                  <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Motivo da Recusa <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-red-500 focus:bg-white transition-all bg-slate-50 resize-none"
                            placeholder="Descreva o porquê da reprovação..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>

                      <div className="flex gap-3">
                          <button onClick={() => setIsRejectModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Voltar</button>
                          <button 
                            onClick={confirmRejection} 
                            disabled={rejectionReason.length < 3}
                            className="flex-1 py-4 bg-red-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-red-700 shadow-xl shadow-red-500/20 transition-all disabled:opacity-50"
                          >
                              Confirmar Recusa
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { NotificationService } from './services/notificationService';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, LeadTask, ConfirmOptions } from './types';
import { Users, Settings, Bell, Check, Gift, AlertTriangle, Info, Clock, CheckCircle, Shield, Trash2, Archive, Eye, DollarSign, Briefcase } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  const contentMargin = !isMobile ? getSidebarWidth() : '0px';

  const isKanban = currentView === 'kanban';

  return (
    <div className={`flex h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className={`flex-1 flex flex-col h-full transition-all duration-300 ease-in-out relative ${isKanban ? 'p-0' : 'px-4 py-6'}`}
        style={{ marginLeft: contentMargin }}
      >
        {/* TOP HEADER SECTION */}
        {!isKanban && (
            <div className="sticky top-0 z-40 flex justify-end items-center gap-4 mb-8">
                <div className="relative" ref={notificationRef}>
                    <button 
                      onClick={() => setShowNotifications(!showNotifications)} 
                      className="w-12 h-12 rounded-2xl border border-slate-200 bg-white shadow-sm flex items-center justify-center transition-all hover:shadow-md"
                    >
                        <Bell size={22} className="text-slate-500" />
                        {unreadCount > 0 && (
                            <span className="absolute top-2 right-2 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white"></span>
                        )}
                    </button>

                    {showNotifications && (
                        <div className="absolute right-0 top-full mt-3 w-80 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[100] animate-pop origin-top-right overflow-hidden">
                            <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                                <h3 className="text-xs font-black uppercase text-slate-500">Notificações</h3>
                                <button onClick={markAllAsRead} className="text-[10px] font-black text-pink-600">Marcar lidas</button>
                            </div>
                            <div className="max-h-60 overflow-y-auto p-4 text-center text-slate-400 text-xs">
                                Nenhuma notificação nova.
                            </div>
                        </div>
                    )}
                </div>

                <div 
                  className="bg-white px-6 py-2 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4 cursor-pointer hover:shadow-md transition-all group"
                  onClick={() => setCurrentView('settings')}
                >
                    <div className="text-right">
                        <p className="text-sm font-black text-slate-800 leading-none group-hover:text-pink-600">{currentUser.name}</p>
                        <p className="text-[10px] text-slate-400 uppercase font-black mt-1 tracking-wider">{currentUser.role}</p>
                    </div>
                    <div className="w-10 h-10 rounded-2xl overflow-hidden border-2 border-slate-50 bg-slate-100">
                      <img src={currentUser.avatar} alt="Perfil" className="w-full h-full object-cover" />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 w-full max-w-full flex flex-col overflow-hidden">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && (
              <KanbanBoard 
                tasks={tasks} 
                setTasks={setTasks} 
                users={users} 
                currentUser={currentUser} 
                columns={taskColumns} 
                setColumns={setTaskColumns} 
                openConfirm={openConfirm} 
                notifications={notifications} 
                setNotifications={setNotifications}
                sidebarOpen={sidebarOpen}
                sidebarCompact={sidebarCompact}
                isMobile={isMobile}
              />
            )}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React from 'react';
import { 
  LayoutDashboard, Kanban, Users, DollarSign, Briefcase, LogOut, 
  PieChart, BarChart2, Shield, HeartHandshake, ShoppingBag, 
  ShoppingCart, Settings, HelpCircle, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { Role, RolePermissions, SystemSettings } from '../types';

interface SidebarProps {
  currentView: string;
  setView: (view: string) => void;
  currentUserRole: Role;
  permissions: RolePermissions;
  logout: () => void;
  systemSettings: SystemSettings;
  isOpen: boolean;
  onToggle: () => void;
  isCompact: boolean;
  onToggleCompact: () => void;
  isMobile: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  setView, 
  currentUserRole, 
  permissions, 
  logout, 
  systemSettings,
  isOpen,
  onToggle,
  isCompact,
  onToggleCompact,
  isMobile
}) => {
  const menuItems = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard },
    { id: 'kanban', label: 'Tarefas (Kanban)', icon: Kanban },
    { id: 'productivity', label: 'Produtividade', icon: BarChart2 },
    { id: 'requisitions', label: 'Solicitações', icon: ShoppingCart },
    { id: 'client-portal', label: 'Meus Pedidos', icon: PieChart },
    { id: 'clients', label: 'Gestão de Clientes', icon: HeartHandshake },
    { id: 'catalog', label: 'Produtos & Serviços', icon: ShoppingBag },
    { id: 'teams', label: 'Equipes & Squads', icon: Users },
    { id: 'crm', label: 'CRM / Vendas', icon: Briefcase },
    { id: 'finance', label: 'Financeiro', icon: DollarSign },
    { id: 'permissions', label: 'Acessos (Admin)', icon: Shield },
    { id: 'system-admin', label: 'Config. Sistema', icon: Settings },
    { id: 'help', label: 'Central de Ajuda', icon: HelpCircle },
  ];

  const allowedModules = permissions[currentUserRole] || [];

  return (
    <div 
        className={`fixed left-0 top-0 h-screen z-[10000] transition-all duration-300 ease-in-out border-r border-slate-800 flex flex-col
          ${!isOpen ? '-translate-x-full' : 'translate-x-0'}
          ${isCompact ? 'w-20' : 'w-64'}
        `}
        style={{ backgroundColor: systemSettings.sidebarColor || '#0f172a' }}
    >
      {/* SIDEBAR TOGGLE BUTTON (CHEVRON) */}
      <button 
        onClick={onToggle}
        aria-label={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        title={isOpen ? "Ocultar menu lateral" : "Mostrar menu lateral"}
        className={`absolute top-10 -right-4 w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-lg hover:scale-110 transition-all z-50 text-slate-800
          ${!isOpen ? 'translate-x-12 opacity-100' : ''}
        `}
      >
        {isOpen ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
      </button>

      {/* Header / Logo */}
      <div className={`p-6 flex items-center transition-all duration-300 ${isCompact ? 'justify-center p-4' : 'gap-3'}`}>
        {systemSettings.logo ? (
            <img src={systemSettings.logo} alt="Logo" className="w-8 h-8 object-contain rounded bg-white p-0.5 shrink-0" />
        ) : (
            <div 
                className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shrink-0"
                style={{ backgroundColor: systemSettings.primaryColor }}
            >
                {systemSettings.agencyName.charAt(0)}
            </div>
        )}
        {!isCompact && (
          <span className="text-lg font-bold text-white tracking-tight truncate animate-pop" title={systemSettings.agencyName}>
              {systemSettings.agencyName}
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 space-y-2 mt-4 overflow-y-auto hide-scrollbar">
        {menuItems.map((item) => {
           const isAllowed = allowedModules.includes(item.id) || item.id === 'help';
           if (!isAllowed) return null;

           const active = currentView === item.id;

           return (
            <button
              key={item.id}
              onClick={() => {
                  setView(item.id);
                  if (isMobile && !isCompact) onToggle(); // Fecha se for menu full no mobile
              }}
              title={isCompact ? item.label : ""}
              className={`w-full flex items-center rounded-lg transition-all duration-200 
                ${isCompact ? 'justify-center py-3' : 'px-4 py-3 gap-3'}
                ${active ? 'text-white shadow-lg shadow-pink-500/20' : 'text-slate-400 hover:bg-black/20 hover:text-white'}
              `}
              style={active ? { backgroundColor: systemSettings.primaryColor } : {}}
            >
              <item.icon size={20} className="shrink-0" />
              {!isCompact && (
                <span className="font-medium truncate text-sm animate-pop">{item.label}</span>
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer / Logout */}
      <div className={`p-4 border-t border-white/10 ${isCompact ? 'flex justify-center' : ''}`}>
        <button 
          onClick={logout} 
          title={isCompact ? "Sair" : ""}
          className={`flex items-center text-red-400 hover:text-red-300 w-full hover:bg-red-500/10 rounded-lg transition-colors
            ${isCompact ? 'justify-center p-3' : 'px-4 py-3 gap-3'}
          `}
        >
          <LogOut size={20} className="shrink-0" />
          {!isCompact && <span className="text-sm font-bold">Sair</span>}
        </button>
      </div>

      {/* Desktop-only toggle between Compact and Full (Optional UX) */}
      {!isMobile && isOpen && (
        <button 
          onClick={onToggleCompact}
          className="p-3 mx-4 mb-4 bg-white/5 hover:bg-white/10 rounded-lg flex items-center justify-center text-slate-500 transition-colors"
          title={isCompact ? "Expandir Menu" : "Recolher Menu"}
        >
          {isCompact ? <ChevronRight size={16}/> : <ChevronLeft size={16}/>}
        </button>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, FileText, AlertCircle, ShoppingBag, DollarSign, Clock, AlertTriangle, Phone, Calendar } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  // Estado para Criar Nova Requisição
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});

  // Estado para Filtros
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');

  // Estados para Processamento (Feedback Visual)
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Estados para Modal de Reprovação
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  useEffect(() => {
    if(isCreateModalOpen || isRejectModalOpen) {
        console.log("MODAL_OPEN", { screen: "Solicitacoes" });
    }
  }, [isCreateModalOpen, isRejectModalOpen]);

  // 1. Permissões
  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  // Filtragem
  const displayedRequisitions = requisitions.filter(req => {
      if (filter === 'MY') return req.requesterId === currentUser.id;
      if (!canApprove) return req.requesterId === currentUser.id;
      return true;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) {
          alert("Preencha título e valor.");
          return;
      }

      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };

      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove) {
          alert("Erro 403: Sem permissão para aprovar.");
          return;
      }
      if (req.status === 'APPROVED') return;

      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...req,
              status: 'APPROVED',
              approvedBy: currentUser.id,
              approvedAt: now,
              rejectedBy: undefined,
              rejectedAt: undefined,
              rejectedReason: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          const isServiceRequest = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);
          if (!isServiceRequest && req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}-${Date.now()}`,
                  description: `REQ Aprovada: ${req.title} (${req.category})`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador Interno'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }

          const notif: Notification = {
              id: `notif-apr-${Date.now()}`,
              title: isServiceRequest ? 'Solicitação Agendada/Concluída' : 'Solicitação Aprovada',
              message: isServiceRequest 
                ? `Sua solicitação "${req.title}" foi confirmada pela equipe.`
                : `Sua solicitação "${req.title}" no valor de R$ ${req.estimatedCost.toLocaleString()} foi aprovada.`,
              type: 'SUCCESS',
              status: 'UNREAD',
              priority: 'MEDIUM',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: req.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
      }, 800);
  };

  const openRejectModal = (req: Requisition) => {
      setSelectedReqForReject(req);
      setRejectionReason('');
      setIsRejectModalOpen(true);
  };

  const confirmRejection = () => {
      if (!selectedReqForReject) return;
      if (!rejectionReason || rejectionReason.length < 3) {
          alert("O motivo da reprovação é obrigatório (mínimo 3 caracteres).");
          return;
      }
      if (!canApprove) {
          alert("Erro 403: Sem permissão.");
          return;
      }

      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);

      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...reqToReject,
              status: 'REJECTED',
              rejectedBy: currentUser.id,
              rejectedAt: now,
              rejectedReason: rejectionReason,
              approvedBy: undefined,
              approvedAt: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));

          const notif: Notification = {
              id: `notif-rej-${Date.now()}`,
              title: 'Solicitação Recusada',
              message: `Sua solicitação "${reqToReject.title}" foi recusada. Motivo: ${rejectionReason}`,
              type: 'REJECTED',
              status: 'UNREAD',
              priority: 'HIGH',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: reqToReject.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
          setSelectedReqForReject(null);
      }, 800);
  };

  const getCategoryIcon = (cat: string) => {
      switch(cat) {
          case 'Reunião': return <Calendar size={12}/>;
          case 'Atendimento': return <Phone size={12}/>;
          default: return <ShoppingBag size={12}/>;
      }
  };

  return (
    <div className="space-y-6 animate-pop">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Central de Solicitações</h2>
          <p className="text-slate-500">Gestão de compras, reembolsos e agendamentos.</p>
        </div>
        <div className="flex gap-2">
            {canApprove && (
                <div className="bg-slate-100 p-1 rounded-lg flex text-xs font-bold">
                    <button 
                        onClick={() => setFilter('ALL')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'ALL' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setFilter('MY')}
                        className={`px-3 py-1.5 rounded transition-all ${filter === 'MY' ? 'bg-white shadow text-slate-800' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Minhas
                    </button>
                </div>
            )}
            <button 
                onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
                className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors shadow-lg shadow-pink-500/20"
            >
                <Plus size={18} /> Nova Solicitação
            </button>
        </div>
      </div>

      {/* Grid de Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {displayedRequisitions.length === 0 && (
              <div className="col-span-full p-12 text-center border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
                  <FileText className="mx-auto text-slate-300 mb-2" size={48}/>
                  <p className="text-slate-500 font-medium">Nenhuma solicitação encontrada.</p>
              </div>
          )}

          {displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;
              const isService = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);

              return (
                <div key={req.id} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-shadow relative">
                    {isProcessing && (
                        <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm">
                            <div className="flex flex-col items-center gap-2">
                                <Clock className="animate-spin text-pink-600" size={32}/>
                                <span className="text-xs font-bold text-pink-600">Processando...</span>
                            </div>
                        </div>
                    )}

                    <div className="p-5 flex-1">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                req.status === 'PENDING' ? 'bg-orange-50 text-orange-700 border-orange-100' : 
                                req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'
                            }`}>
                                {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? (isService ? 'Concluído' : 'Aprovada') : 'Recusada'}
                            </span>
                            <div className="flex items-center gap-1 text-xs text-slate-400">
                                <Clock size={12}/>
                                <span>{req.date.split('-').reverse().join('/')}</span>
                            </div>
                        </div>

                        <h3 className="font-bold text-slate-800 text-lg mb-1 line-clamp-1">{req.title}</h3>
                        <div className="flex items-center gap-2 text-xs text-slate-500 mb-4">
                            <span className="bg-slate-100 px-2 py-0.5 rounded border border-slate-200 flex items-center gap-1">{getCategoryIcon(req.category)} {req.category}</span>
                            {requester && (
                                <span className="flex items-center gap-1" title={requester.name}>
                                    • <img src={requester.avatar} className="w-4 h-4 rounded-full"/> <b>{requester.name.split(' ')[0]}</b>
                                </span>
                            )}
                        </div>

                        <p className="text-sm text-slate-600 mb-4 line-clamp-3 bg-slate-50 p-2 rounded-lg border border-slate-100 min-h-[60px]">
                            {req.description}
                        </p>

                        {req.status === 'REJECTED' && req.rejectedReason && (
                            <div className="bg-red-50 p-3 rounded-lg border border-red-100 mb-4 animate-pop">
                                <p className="text-xs text-red-800 font-bold flex items-center gap-1 mb-1"><AlertCircle size={12}/> Motivo da Recusa:</p>
                                <p className="text-xs text-red-600 italic">"{req.rejectedReason}"</p>
                                {req.rejectedAt && <p className="text-[10px] text-red-400 mt-1 text-right">{new Date(req.rejectedAt).toLocaleString()}</p>}
                            </div>
                        )}

                        {req.status === 'APPROVED' && req.approvedAt && (
                             <div className="bg-emerald-50 p-2 rounded border border-emerald-100 mb-4 text-center">
                                 <p className="text-[10px] text-emerald-600">{isService ? 'Confirmado' : 'Aprovado'} em {new Date(req.approvedAt).toLocaleDateString()}</p>
                             </div>
                        )}
                    </div>

                    <div className="p-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
                        <div>
                            {isService ? (
                                <p className="text-xs font-bold text-slate-500 uppercase">Solicitação de Serviço</p>
                            ) : (
                                <>
                                    <p className="text-[10px] text-slate-400 uppercase font-bold">Valor Solicitado</p>
                                    <p className="text-lg font-bold text-slate-800 flex items-center gap-1">
                                        <span className="text-slate-400 text-sm font-normal">R$</span> {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                    </p>
                                </>
                            )}
                        </div>

                        {canApprove && req.status === 'PENDING' && (
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => handleApproveReq(req)} 
                                    className="px-3 py-2 bg-emerald-100 hover:bg-emerald-200 text-emerald-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title={isService ? "Confirmar Agendamento" : "Aprovar e Lançar Despesa"}
                                >
                                    <Check size={16}/> {isService ? 'Confirmar' : 'Aprovar'}
                                </button>
                                <button 
                                    onClick={() => openRejectModal(req)} 
                                    className="px-3 py-2 bg-red-100 hover:bg-red-200 text-red-700 rounded-lg transition-colors flex items-center gap-1 font-bold text-xs" 
                                    title="Reprovar"
                                >
                                    <X size={16}/> {isService ? 'Recusar' : 'Reprovar'}
                                </button>
                            </div>
                        )}
                    </div>
                </div>
              );
          })}
      </div>

      {/* Modal de Nova Solicitação */}
      {isCreateModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[9999] flex items-center justify-center p-4 transition-all duration-300 w-screen h-screen" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 flex items-center gap-3 uppercase tracking-tighter">
                      <div className="p-2 bg-pink-100 text-pink-600 rounded-xl">
                        <ShoppingBag size={20}/>
                      </div>
                      Nova Solicitação
                  </h3>
                  <div className="space-y-4">
                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Solicitação</label>
                          <select 
                             className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                             value={editingReq.category}
                             onChange={e => setEditingReq({...editingReq, category: e.target.value})}
                          >
                              {isClient ? (
                                  <>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Outros">Outros</option>
                                  </>
                              ) : (
                                  <>
                                    <option value="Compra">Compra de Material</option>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Vale">Vale / Adiantamento</option>
                                    <option value="Software">Software</option>
                                    <option value="Serviço">Serviço Terceiro</option>
                                  </>
                              )}
                          </select>
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Título / Identificação</label>
                          <input 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder={isClient ? "Ex: Reembolso Uber Reunião" : "Ex: Monitor Dell 24pol"} 
                            value={editingReq.title || ''} 
                            onChange={e => setEditingReq({...editingReq, title: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Justificativa Detalhada</label>
                          <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50 resize-none"
                            placeholder="Descreva a necessidade..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor Estimado (R$)</label>
                          <input 
                            type="number" 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50"
                            placeholder="0.00" 
                            value={editingReq.estimatedCost || ''} 
                            onChange={e => setEditingReq({...editingReq, estimatedCost: parseFloat(e.target.value)})} 
                          />
                      </div>

                      <div className="pt-4 flex gap-3">
                          <button onClick={() => setIsCreateModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Cancelar</button>
                          <button onClick={handleSaveReq} className="flex-1 py-4 bg-pink-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-pink-700 shadow-xl shadow-pink-500/20 transition-all">Enviar Pedido</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Modal de Reprovação */}
      {isRejectModalOpen && selectedReqForReject && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[9999] flex items-center justify-center p-4 transition-all duration-300 w-screen h-screen" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md p-8 shadow-2xl animate-pop border-t-4 border-red-500 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="flex items-start gap-4 mb-6">
                      <div className="p-3 bg-red-50 rounded-xl text-red-600">
                          <AlertTriangle size={24} />
                      </div>
                      <div>
                          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Recusar Solicitação</h3>
                          <p className="text-sm text-slate-500">Informe o motivo da decisão.</p>
                      </div>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-2xl mb-6 text-sm text-slate-600 border border-slate-100">
                      <p className="font-bold text-slate-800 mb-1">{selectedReqForReject.title}</p>
                      {selectedReqForReject.estimatedCost > 0 && <p className="text-xs font-bold text-slate-400">VALOR: R$ {selectedReqForReject.estimatedCost.toLocaleString()}</p>}
                  </div>

                  <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Motivo da Recusa <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-red-500 focus:bg-white transition-all bg-slate-50 resize-none"
                            placeholder="Descreva o porquê da reprovação..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>

                      <div className="flex gap-3">
                          <button onClick={() => setIsRejectModalOpen(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs hover:bg-slate-100 rounded-2xl transition-all">Voltar</button>
                          <button 
                            onClick={confirmRejection} 
                            disabled={rejectionReason.length < 3}
                            className="flex-1 py-4 bg-red-600 text-white font-black uppercase text-xs rounded-2xl hover:bg-red-700 shadow-xl shadow-red-500/20 transition-all disabled:opacity-50"
                          >
                              Confirmar Recusa
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

