      {isAssetDeleteModalOpen && assetToExclude && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={handleCancelDeleteAsset}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border-t-4 border-red-600 border-x border-b border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-50 border-b flex items-center justify-between">
                      <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Excluir Patrimônio</h3>
                      <button onClick={handleCancelDeleteAsset} className="text-slate-400 hover:text-slate-600"><X/></button>
