                  <div className="flex justify-between items-center mb-6"><h3 className="text-xl font-black uppercase">Registro de Patrimônio</h3><button onClick={()=>setIsAssetModalOpen(false)}><X/></button></div>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nome do Ativo" value={editingAsset.name || ''} onChange={e => setEditingAsset({...editingAsset, name: e.target.value})} />
                      <div className="grid grid-cols-2 gap-4">
                          <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Nº Série" value={editingAsset.serialNumber || ''} onChange={e => setEditingAsset({...editingAsset, serialNumber: e.target.value})} />
                          <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold" placeholder="Custo R$" value={editingAsset.cost || ''} onChange={e => setEditingAsset({...editingAsset, cost: parseFloat(e.target.value)})} />
                      </div>
                      <button onClick={handleSaveAsset} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Salvar Registro</button>
                  </div>
              </div>
          </div>
      )}

      {isCashOpenModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashOpenModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex items-center justify-between"><h3 className="text-xl font-black uppercase">Novo Ciclo</h3><button onClick={()=>setIsCashOpenModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <div><label className="text-[10px] font-black text-slate-400 uppercase mb-2">Conta</label><select className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold bg-slate-50" onChange={e => setEditingMove({ ...editingMove, cashAccountId: e.target.value } as any)}><option value="">Selecione...</option>{cashAccounts.filter(a => a.isCashRegister).map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>
                      <div><label className="text-[10px] font-black text-slate-400 uppercase mb-2">Fundo (R$)</label><input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none focus:bg-white" placeholder="0.00" onChange={e => setEditingMove({ ...editingMove, amount: parseFloat(e.target.value) })} /></div>
                      <button onClick={() => handleOpenCash((editingMove as any).cashAccountId!, editingMove.amount!)} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-emerald-700 transition-all">Iniciar Ciclo</button>
                  </div>
              </div>
          </div>
      )}

      {isMoveModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsMoveModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className={`p-6 text-white flex justify-between ${editingMove.type === 'RECEBIMENTO' || editingMove.type === 'SUPRIMENTO' ? 'bg-emerald-600' : 'bg-red-600'}`}><h3 className="text-xl font-black uppercase tracking-tighter">{editingMove.type}</h3><button onClick={()=>setIsMoveModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Descrição..." value={editingMove.description || ''} onChange={e => setEditingMove({...editingMove, description: e.target.value})} />
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-3xl font-black outline-none" placeholder="0.00" value={editingMove.amount || ''} onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => handleCreateMovement(editingMove)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Confirmar</button>
                  </div>
              </div>
          </div>
      )}

      {isCashCloseModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCashCloseModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop overflow-hidden border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between"><h3 className="text-xl font-black uppercase">Fechar Turno</h3><button onClick={()=>setIsCashCloseModalOpen(false)}><X/></button></div>
                  <div className="p-8 space-y-6">
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-2xl font-black outline-none" placeholder="Saldo Contado" onChange={e => setEditingMove({...editingMove, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => handleCloseCash(editingMove.cashRegisterId!, editingMove.amount!, editingMove.description || '')} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase">Encerrar Ciclo</button>
                  </div>
              </div>
          </div>
      )}

      {selectedReportCycle && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setSelectedReportCycle(null)}>
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[80vh] shadow-2xl animate-pop overflow-hidden flex flex-col border border-slate-200" onClick={e => e.stopPropagation()}>
                  <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="text-xl font-black uppercase">Resumo Mensal</h3><button onClick={()=>setSelectedReportCycle(null)}><X/></button></div>
                  <div className="p-8 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black uppercase">Abertura</p><p className="font-bold">R$ {selectedReportCycle.initialAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black uppercase">Esperado</p><p className="font-bold">R$ {selectedReportCycle.expectedFinalAmount.toLocaleString()}</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100"><p className="text-[9px] font-black uppercase">Diferença</p><p className={`font-black ${selectedReportCycle.differenceAmount === 0 ? 'text-emerald-600' : 'text-red-600'}`}>R$ {selectedReportCycle.differenceAmount?.toLocaleString()}</p></div>
                      </div>
                  </div>
                  <div className="p-6 border-t bg-slate-50 flex justify-end gap-3"><button onClick={()=>setSelectedReportCycle(null)} className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase">Fechar</button></div>
              </div>
          </div>
      )}

      {isStockModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsStockModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8 border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase">Estoque</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Item" value={editingStock.name || ''} onChange={e => setEditingStock({...editingStock, name: e.target.value})} />
                      <button onClick={handleSaveStock} className="w-full bg-pink-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-pink-700 transition-all">Salvar</button>
                  </div>
              </div>
          </div>
      )}

      {isTxModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsTxModalOpen(false)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop p-8 border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase">Lançamento</h3>
                  <div className="space-y-4">
                      <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Descrição" value={editingTx.description || ''} onChange={e => setEditingTx({...editingTx, description: e.target.value})} />
                      <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none" placeholder="Valor" onChange={e => setEditingTx({...editingTx, amount: parseFloat(e.target.value)})} />
                      <button onClick={() => {if(editingTx.amount && editingTx.description){setTransactions(p=>[{...editingTx, id:`tx-${Date.now()}`, status:'PAID'} as FinancialRecord, ...p]); setIsTxModalOpen(false); setEditingTx({})}}} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Gravar</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, Eye, 
    CheckSquare, Users, CreditCard, Layout, Upload, Check, Activity, AlertCircle, Play, Pause, Calendar, Save,
    Flag, AlignLeft, ShieldCheck, Search, Palette, ExternalLink, UserPlus, Camera, Trash, ImagePlus
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, setNotifications, openConfirm }) => {
    const [newComment, setNewComment] = useState('');
    const [mentionFilter, setMentionFilter] = useState('');
    const [showMentions, setShowMentions] = useState(false);
    const [newChecklistText, setNewChecklistText] = useState('');

    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [localDueDate, setLocalDueDate] = useState(task.dueDate || '');
    const [localPriority, setLocalPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>(task.priority || 'MEDIUM');
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [showSavedFeedback, setShowSavedFeedback] = useState(false);

    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COLOR_GRID' | string | null>(null);
    const [memberSearch, setMemberSearch] = useState('');

    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const commentInputRef = useRef<HTMLTextAreaElement>(null);
    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        console.log("MODAL_OPEN", { screen: 'KanbanJob' });
        return () => console.log("MODAL_CLOSED");
    }, [task.id]);

    useEffect(() => {
        setLocalTitle(task.title);
        setLocalDesc(task.description);
        setLocalDueDate(task.dueDate || '');
        setLocalPriority(task.priority || 'MEDIUM');
    }, [task.id, task.title, task.description, task.dueDate, task.priority]);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                setSecondsElapsed(s => s + 1);
            }, 1000);
        } else {
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [task.isTracking]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setActivePopover(null);
                setShowMentions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const isNewTask = task.history.length === 0;

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const calculateTotalSeconds = () => {
        const closedLogsDuration = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        if (task.isTracking) {
            const activeLog = task.timeLogs.find(l => !l.endTime);
            if (activeLog) {
                const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                return closedLogsDuration + elapsed;
            }
        }
        return closedLogsDuration;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const triggerSavedFeedback = () => {
        setShowSavedFeedback(true);
        setTimeout(() => setShowSavedFeedback(false), 2000);
    };

    const updateWithLog = (updatedTaskProps: Partial<Task>, logAction: string) => {
        onUpdate({
            ...task,
            ...updatedTaskProps,
            history: [...task.history, createLog(logAction)]
        });
        triggerSavedFeedback();
    };

    const handleFinalConfirmNewTask = () => {
        if (!localTitle.trim() || !localDueDate) return;
        onUpdate({
            ...task,
            title: localTitle,
            description: localDesc,
            dueDate: localDueDate,
            priority: localPriority,
            history: [createLog('Tarefa criada no Kanban')]
        });
        triggerSavedFeedback();
    };

    const handleCoverChange = (type: 'color' | 'image' | null, value: string | null) => {
        updateWithLog({ coverType: type, coverValue: value }, type ? `atualizou a capa (${type})` : 'removeu a capa');
        setActivePopover(null);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const imageUrl = URL.createObjectURL(file);
            handleCoverChange('image', imageUrl);
        }
    };

    const saveTitle = () => {
        if (!localTitle.trim() || localTitle === task.title) return;
        updateWithLog({ title: localTitle }, `alterou o título de "${task.title || 'Vazio'}" para "${localTitle}"`);
    };

    const saveDesc = () => {
        setIsEditingDesc(false);
        if (localDesc === task.description) return;
        updateWithLog({ description: localDesc }, `atualizou a descrição do job`);
    };

    const addChecklistItem = () => {
        if (newChecklistText.trim()) {
            const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
            updateWithLog({ checklists: [...(task.checklists || []), newItem] }, `adicionou etapa: "${newChecklistText}"`);
            setNewChecklistText('');
        }
    };

    const toggleChecklist = (itemId: string) => {
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, isCompleted: !c.isCompleted } : c);
        onUpdate({...task, checklists: newChecklists});
    };

    const handleDueDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = e.target.value;
        setLocalDueDate(newVal);
        if (!isNewTask && newVal) updateWithLog({ dueDate: newVal }, `alterou o prazo para ${new Date(newVal).toLocaleDateString()}`);
    };

    const toggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    const duration = Math.floor((now - log.startTime) / 1000);
                    return { ...log, endTime: now, duration };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou a produção');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou a produção');
        }
    };

    const totalSecondsAccumulated = calculateTotalSeconds();
    const checklistProgress = task.checklists.length > 0 ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) : 0;
    const activityFeed = [...task.comments.map(c => ({ type: 'COMMENT', data: c, timestamp: c.timestamp })), ...task.history.map(h => ({ type: 'HISTORY', data: h, timestamp: h.timestamp }))].sort((a, b) => b.timestamp - a.timestamp);

    if (isNewTask) {
        return (
            <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex justify-center items-center p-4 transition-all duration-300" onClick={onClose}>
                <div className="bg-white w-full max-w-2xl rounded-[2rem] shadow-2xl overflow-hidden animate-pop border border-slate-200/60" onClick={e => e.stopPropagation()}>
                    <div className="bg-slate-900 p-8 flex justify-between items-center text-white">
                        <div className="flex items-center gap-4">
                            <div className="p-3 bg-pink-600 rounded-2xl shadow-lg shadow-pink-600/20"><Plus size={28} strokeWidth={3} /></div>
                            <div>
                                <h2 className="text-2xl font-black tracking-tighter">Nova Demanda</h2>
                                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Setup do Job</p>
                            </div>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
                    </div>
                    <div className="p-10 space-y-8">
                        <div className="space-y-3">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Título do Job <span className="text-pink-500">*</span></label>
                            <input className="w-full text-xl font-bold text-slate-800 bg-slate-50 border-2 border-transparent rounded-2xl p-5 outline-none focus:border-pink-500 focus:bg-white focus:ring-4 focus:ring-pink-500/5 transition-all" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} placeholder="Ex: Campanha de Natal 2024..." autoFocus />
                        </div>
                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Data de Entrega <span className="text-pink-500">*</span></label>
                                <input type="date" className={`w-full bg-slate-50 border-2 rounded-2xl p-5 text-sm font-bold outline-none transition-all ${!localDueDate ? 'border-red-100' : 'border-transparent focus:border-pink-500 focus:bg-white focus:ring-4 focus:ring-pink-500/5'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Prioridade</label>
                                <div className="flex gap-2 h-[64px]">
                                    {['LOW', 'MEDIUM', 'HIGH'].map(p => (
                                        <button key={p} onClick={() => setLocalPriority(p as any)} className={`flex-1 rounded-2xl text-[10px] font-black uppercase transition-all border-2 ${localPriority === p ? 'border-slate-800 bg-white scale-105 shadow-md' : 'border-transparent bg-slate-100 text-slate-400 opacity-60'}`}>{p === 'HIGH' ? 'Urgente' : p === 'MEDIUM' ? 'Média' : 'Baixa'}</button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                    <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end gap-4">
                        <button onClick={onClose} className="px-8 py-4 font-bold text-slate-500 hover:text-slate-700 transition-colors uppercase text-xs tracking-widest">Cancelar</button>
                        <button onClick={handleFinalConfirmNewTask} disabled={!localDueDate || !localTitle} className="px-10 py-4 bg-pink-600 hover:bg-pink-700 text-white font-black rounded-2xl shadow-xl shadow-pink-500/30 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-50 uppercase text-xs tracking-widest">Criar Job</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex justify-center overflow-y-auto py-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl relative min-h-[500px] h-fit my-auto mx-4 animate-pop border border-slate-200/60 overflow-hidden" onClick={e => e.stopPropagation()}>

                {/* --- SEÇÃO HERO: CAPA --- */}
                <div className={`w-full h-48 relative group transition-all duration-500 ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? (task.coverValue || '#f1f5f9') : undefined }}>
                    {task.coverType === 'image' && (
                        <img src={task.coverValue || ''} alt="Capa" className="w-full h-full object-cover" />
                    )}

                    {!task.coverType && (
                        <div className="absolute inset-0 flex items-center justify-center">
                            <button 
                                onClick={() => setActivePopover('COLOR_GRID')}
                                className="flex items-center gap-2 px-6 py-2.5 bg-white/80 hover:bg-white text-slate-800 font-black text-[11px] uppercase rounded-2xl transition-all border border-slate-200/50 shadow-lg tracking-widest"
                            >
                                <Layout size={16}/> Adicionar Capa
                            </button>
                        </div>
                    )}

                    <div className="absolute bottom-6 right-8 flex items-center gap-3 opacity-0 group-hover:opacity-100 transition-all transform translate-y-2 group-hover:translate-y-0">
                        <div className="relative">
                            <button 
                                onClick={() => setActivePopover(activePopover === 'COLOR_GRID' ? null : 'COLOR_GRID')}
                                className="p-3 bg-white hover:bg-slate-50 text-slate-700 rounded-2xl shadow-xl border border-slate-200 transition-all"
                                title="Mudar Cor"
                            >
                                <Palette size={20}/>
                            </button>

                            {activePopover === 'COLOR_GRID' && (
                                <div ref={popoverRef} className="absolute bottom-full right-0 mb-4 bg-white p-4 rounded-3xl shadow-2xl border border-slate-100 w-56 animate-pop">
                                    <div className="grid grid-cols-5 gap-3">
                                        {PRESET_COLORS.map(c => (
                                            <button 
                                                key={c} 
                                                onClick={() => handleCoverChange('color', c)}
                                                className="w-7 h-7 rounded-full border-2 border-white shadow-sm hover:scale-125 transition-transform" 
                                                style={{ backgroundColor: c }}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>

                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="p-3 bg-white hover:bg-slate-50 text-slate-700 rounded-2xl shadow-xl border border-slate-200 transition-all"
                            title="Upload de Imagem"
                        >
                            <Camera size={20}/>
                        </button>

                        {task.coverType && (
                            <button 
                                onClick={() => handleCoverChange(null, null)}
                                className="p-3 bg-red-500 hover:bg-red-600 text-white rounded-2xl shadow-xl transition-all"
                                title="Remover Capa"
                            >
                                <Trash size={20}/>
                            </button>
                        )}
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </div>

                    <button onClick={onClose} className="absolute top-6 right-8 p-2.5 rounded-full bg-black/20 hover:bg-black/40 z-50 transition-colors backdrop-blur-sm"><X size={24} className="text-white"/></button>
                </div>

                {/* --- CONTEÚDO DO MODAL --- */}
                <div className="flex flex-col md:flex-row p-12 gap-12">
                    <div className="flex-1 space-y-10">
                        <div className="flex gap-6 items-start">
                            <CreditCard className="mt-1.5 text-slate-300" size={28}/>
                            <div className="flex-1">
                                <input className="text-4xl font-black text-slate-800 w-full bg-transparent border-none outline-none placeholder-slate-200 mb-2 tracking-tighter" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} onBlur={saveTitle} onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()} />
                                <div className="flex items-center gap-4">
                                    <div className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Job Status: <span className="text-pink-600">{task.status}</span></div>
                                    {showSavedFeedback && <div className="flex items-center gap-1.5 text-emerald-600 text-[11px] font-black uppercase animate-pop"><Check size={14} strokeWidth={3}/> Atualizado</div>}
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 ml-14">
                            <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100/50 shadow-sm group hover:bg-white hover:border-pink-200 transition-all">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2 tracking-widest"><Calendar size={14}/> Prazo de Entrega</h4>
                                <input type="date" className={`w-full text-lg font-black bg-transparent outline-none ${!localDueDate ? 'text-red-500' : 'text-slate-800'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="bg-slate-900 p-6 rounded-[2rem] shadow-xl relative overflow-hidden group">
                                <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity"><Clock size={48} className="text-white"/></div>
                                <h4 className="text-[10px] font-black text-slate-500 uppercase mb-3 flex items-center gap-2 tracking-widest"><Clock size={14}/> Cronômetro Ativo</h4>
                                <div className="flex items-center justify-between relative z-10">
                                    <div className="text-2xl font-black text-white font-mono tracking-wider">{formatSeconds(totalSecondsAccumulated)}</div>
                                    <button onClick={toggleTimer} className={`p-3 rounded-2xl transition-all shadow-lg ${task.isTracking ? 'bg-amber-500 text-white shadow-amber-500/20 scale-110' : 'bg-pink-600 text-white shadow-pink-600/20 hover:scale-110'}`}>
                                        {task.isTracking ? <Pause size={20} fill="currentColor"/> : <Play size={20} fill="currentColor"/>}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-6">
                            <AlignLeft className="mt-1.5 text-slate-300" size={28}/>
                            <div className="flex-1">
                                <h3 className="font-black text-[11px] text-slate-500 uppercase tracking-widest mb-4 ml-1">Briefing Detalhado</h3>
                                <div className={`relative rounded-[2rem] p-8 transition-all ${isEditingDesc ? 'bg-white border-pink-500 ring-4 ring-pink-500/5 shadow-xl' : 'bg-slate-50 border border-transparent hover:bg-slate-100 cursor-text'}`} onClick={() => !isEditingDesc && setIsEditingDesc(true)}>
                                    {isEditingDesc ? (
                                        <textarea className="w-full min-h-[200px] border-none outline-none text-base text-slate-700 resize-none bg-transparent font-medium leading-relaxed" value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} onBlur={saveDesc} autoFocus placeholder="Descreva os detalhes da entrega..." />
                                    ) : (
                                        <div className="text-base text-slate-600 leading-relaxed min-h-[200px] font-medium whitespace-pre-wrap">{localDesc || <span className="text-slate-300 italic">Clique aqui para escrever o briefing do projeto...</span>}</div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-6">
                            <CheckSquare className="mt-1.5 text-slate-300" size={28}/>
                            <div className="flex-1">
                                <div className="flex justify-between items-center mb-6 ml-1">
                                    <h3 className="font-black text-[11px] text-slate-500 uppercase tracking-widest">Etapas de Produção</h3>
                                    <span className="text-[11px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100 uppercase">{checklistProgress}% Concluído</span>
                                </div>
                                <div className="space-y-3 mb-8">
                                    {task.checklists.map(item => (
                                        <div key={item.id} className="flex items-center gap-4 p-5 rounded-[1.5rem] hover:bg-slate-50 transition-all border border-transparent hover:border-slate-100 group">
                                            <input type="checkbox" checked={item.isCompleted} onChange={() => toggleChecklist(item.id)} className="w-6 h-6 rounded-lg border-slate-200 text-pink-600 focus:ring-pink-500 cursor-pointer transition-all"/>
                                            <span className={`text-base font-bold transition-all ${item.isCompleted ? 'line-through text-slate-300' : 'text-slate-700'}`}>{item.text}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex gap-3 bg-slate-50 p-3 rounded-[2rem] border border-slate-100 focus-within:bg-white focus-within:border-pink-500 focus-within:ring-4 focus-within:ring-pink-500/5 transition-all">
                                    <input type="text" placeholder="Adicionar nova etapa..." className="flex-1 bg-transparent border-none px-4 py-2 text-sm font-bold outline-none placeholder:text-slate-300" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 hover:bg-slate-900 text-white px-8 py-3 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all">Add</button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* SIDEBAR DO MODAL */}
                    <div className="w-full md:w-64 space-y-6 shrink-0 border-l border-slate-100 pl-8">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 ml-1">Workflow & Ações</h4>
                        {task.status !== 'DONE' && (
                            <button onClick={() => { updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job'); confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } }); }} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white p-5 rounded-[1.5rem] text-xs font-black uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl shadow-emerald-600/20 transition-all hover:scale-[1.02] active:scale-95"><CheckCircle size={20}/> Finalizar Job</button>
                        )}
                        <div className="relative">
                            <button onClick={() => setActivePopover('MEMBERS')} className="w-full text-left p-5 rounded-[1.5rem] text-xs font-black uppercase tracking-widest flex items-center gap-3 bg-slate-100 text-slate-600 hover:bg-slate-200 transition-all"><Users size={20}/> Responsáveis</button>
                            {activePopover === 'MEMBERS' && (
                                <div ref={popoverRef} className="absolute left-0 bottom-full mb-4 w-72 bg-white rounded-[2rem] shadow-2xl border border-slate-200/60 z-50 p-6 animate-pop">
                                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-5 text-center tracking-widest">Alocar Time</h5>
                                    <div className="space-y-2 max-h-64 overflow-y-auto custom-scrollbar">
                                        {users.filter(u => u.role !== 'CLIENT').map(u => (
                                            <button key={u.id} onClick={() => {
                                                const currentIds = task.assigneeIds || [];
                                                const newIds = currentIds.includes(u.id) ? currentIds.filter(id => id !== u.id) : [...currentIds, u.id];
                                                updateWithLog({ assigneeIds: newIds }, `atualizou responsáveis`);
                                            }} className={`w-full flex items-center justify-between p-3 rounded-2xl transition-all ${task.assigneeIds.includes(u.id) ? 'bg-pink-50 text-pink-700 font-bold border border-pink-100' : 'hover:bg-slate-50 text-slate-500'}`}>
                                                <div className="flex items-center gap-3"><img src={u.avatar} className="w-9 h-9 rounded-xl border-2 border-white shadow-sm" /><span className="text-xs font-bold">{u.name}</span></div>
                                                {task.assigneeIds.includes(u.id) && <Check size={16} strokeWidth={3}/>}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                        <div className="pt-8 border-t border-slate-100 space-y-3">
                             <button onClick={() => updateWithLog({ archived: !task.archived }, 'arquivou o job')} className="w-full text-left p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 hover:text-slate-800 flex items-center gap-3 transition-all"><Archive size={16}/> {task.archived ? 'Reativar Job' : 'Arquivar Job'}</button>
                             {(currentUser.role === 'ADMIN' || currentUser.role === 'MANAGER') && <button onClick={() => onDeleteTask(task.id)} className="w-full text-left p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest text-red-400 hover:bg-red-50 flex items-center gap-3 transition-all"><Trash2 size={16}/> Excluir Job</button>}
                        </div>
                        <button onClick={onClose} className="w-full bg-slate-900 text-white p-5 rounded-[1.5rem] text-xs font-black uppercase tracking-widest shadow-2xl hover:bg-slate-800 transition-all hover:scale-[1.02] active:scale-95 mt-12">Fechar Janela</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, FileText, AlertCircle, ShoppingBag, DollarSign, Clock, AlertTriangle, Phone, Calendar } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  // Estado para Criar Nova Requisição
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});

  // Estado para Filtros
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');

  // Estados para Processamento (Feedback Visual)
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Estados para Modal de Reprovação
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  useEffect(() => {
    if(isCreateModalOpen || isRejectModalOpen) {
        console.log("MODAL_OPEN", { screen: "Solicitacoes" });
    }
  }, [isCreateModalOpen, isRejectModalOpen]);

  // 1. Permissões
  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  // Filtragem
  const displayedRequisitions = requisitions.filter(req => {
      if (filter === 'MY') return req.requesterId === currentUser.id;
      if (!canApprove) return req.requesterId === currentUser.id;
      return true;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) {
          alert("Preencha título e valor.");
          return;
      }

      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };

      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove) {
          alert("Erro 403: Sem permissão para aprovar.");
          return;
      }
      if (req.status === 'APPROVED') return;

      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...req,
              status: 'APPROVED',
              approvedBy: currentUser.id,
              approvedAt: now,
              rejectedBy: undefined,
              rejectedAt: undefined,
              rejectedReason: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          const isServiceRequest = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);
          if (!isServiceRequest && req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}-${Date.now()}`,
                  description: `REQ Aprovada: ${req.title} (${req.category})`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador Interno'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }

          const notif: Notification = {
              id: `notif-apr-${Date.now()}`,
              title: isServiceRequest ? 'Solicitação Agendada/Concluída' : 'Solicitação Aprovada',
              message: isServiceRequest 
                ? `Sua solicitação "${req.title}" foi confirmada pela equipe.`
                : `Sua solicitação "${req.title}" no valor de R$ ${req.estimatedCost.toLocaleString()} foi aprovada.`,
              type: 'SUCCESS',
              status: 'UNREAD',
              priority: 'MEDIUM',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: req.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
      }, 800);
  };

  const openRejectModal = (req: Requisition) => {
      setSelectedReqForReject(req);
      setRejectionReason('');
      setIsRejectModalOpen(true);
  };

  const confirmRejection = () => {
      if (!selectedReqForReject) return;
      if (!rejectionReason || rejectionReason.length < 3) {
          alert("O motivo da reprovação é obrigatório (mínimo 3 caracteres).");
          return;
      }
      if (!canApprove) {
          alert("Erro 403: Sem permissão.");
          return;
      }

      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);

      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...reqToReject,
              status: 'REJECTED',
              rejectedBy: currentUser.id,
              rejectedAt: now,
              rejectedReason: rejectionReason,
              approvedBy: undefined,
              approvedAt: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));

          const notif: Notification = {
              id: `notif-rej-${Date.now()}`,
              title: 'Solicitação Recusada',
              message: `Sua solicitação "${reqToReject.title}" foi recusada. Motivo: ${rejectionReason}`,
              type: 'REJECTED',
              status: 'UNREAD',
              priority: 'HIGH',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: reqToReject.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
          setSelectedReqForReject(null);
      }, 800);
  };

  const getCategoryIcon = (cat: string) => {
      switch(cat) {
          case 'Reunião': return <Calendar size={12}/>;
          case 'Atendimento': return <Phone size={12}/>;
          default: return <ShoppingBag size={12}/>;
      }
  };

  return (
    <div className="space-y-6 animate-pop">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-8 rounded-[2rem] border border-slate-200/60 shadow-sm">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Central de Solicitações</h2>
          <p className="text-slate-500 font-medium mt-1">Gestão de suprimentos e agendamentos.</p>
        </div>
        <div className="flex gap-3">
            {canApprove && (
                <div className="bg-slate-100 p-1.5 rounded-2xl flex text-[10px] font-black uppercase tracking-widest shadow-inner">
                    <button 
                        onClick={() => setFilter('ALL')}
                        className={`px-4 py-2 rounded-xl transition-all ${filter === 'ALL' ? 'bg-white shadow-md text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setFilter('MY')}
                        className={`px-4 py-2 rounded-xl transition-all ${filter === 'MY' ? 'bg-white shadow-md text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Minhas
                    </button>
                </div>
            )}
            <button 
                onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
                className="bg-pink-600 hover:bg-pink-700 text-white px-6 py-3 rounded-2xl flex items-center gap-2 text-xs font-black uppercase tracking-widest transition-all shadow-xl shadow-pink-500/20 hover:scale-[1.02] active:scale-95"
            >
                <Plus size={20} strokeWidth={3} /> Enviar Pedido
            </button>
        </div>
      </div>

      {/* Grid de Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {displayedRequisitions.length === 0 && (
              <div className="col-span-full p-20 text-center border-2 border-dashed border-slate-200 rounded-[2.5rem] bg-white/50 shadow-inner">
                  <div className="bg-slate-100 w-16 h-16 rounded-3xl flex items-center justify-center mx-auto mb-4">
                    <FileText className="text-slate-300" size={32}/>
                  </div>
                  <p className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Nenhuma solicitação ativa</p>
              </div>
          )}

          {displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;
              const isService = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);

              return (
                <div key={req.id} className="bg-white rounded-[2rem] border border-slate-200/60 shadow-sm overflow-hidden flex flex-col hover:shadow-xl transition-all group relative">
                    {isProcessing && (
                        <div className="absolute inset-0 bg-white/90 z-20 flex items-center justify-center">
                            <div className="flex flex-col items-center gap-3">
                                <Clock className="animate-spin text-pink-600" size={40}/>
                                <span className="text-[10px] font-black text-pink-600 uppercase tracking-widest">Processando...</span>
                            </div>
                        </div>
                    )}

                    <div className="p-8 flex-1">
                        <div className="flex justify-between items-start mb-4">
                            <span className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest border shadow-sm ${
                                req.status === 'PENDING' ? 'bg-orange-50 text-orange-700 border-orange-100' : 
                                req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'
                            }`}>
                                {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? (isService ? 'Concluído' : 'Aprovada') : 'Recusada'}
                            </span>
                            <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-300">
                                <Clock size={14}/>
                                <span>{req.date.split('-').reverse().join('/')}</span>
                            </div>
                        </div>

                        <h3 className="font-black text-slate-800 text-xl mb-2 line-clamp-1 group-hover:text-pink-600 transition-colors">{req.title}</h3>
                        <div className="flex items-center gap-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-6">
                            <span className="bg-slate-50 px-2.5 py-1 rounded-lg border border-slate-100 flex items-center gap-1.5">{getCategoryIcon(req.category)} {req.category}</span>
                            {requester && (
                                <span className="flex items-center gap-2" title={requester.name}>
                                    • <img src={requester.avatar} className="w-5 h-5 rounded-lg border-2 border-white shadow-sm"/> <b>{requester.name.split(' ')[0]}</b>
                                </span>
                            )}
