                            className="w-full border-2 border-transparent bg-slate-50 rounded-[1.5rem] p-5 text-sm font-bold outline-none focus:bg-white focus:border-pink-500 focus:ring-4 focus:ring-pink-500/5 transition-all resize-none"
                            placeholder="Descreva por que esse item é necessário..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
