                  <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end gap-4">
                      <button onClick={() => setIsCreateModalOpen(false)} className="px-8 py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-slate-800 transition-colors">Voltar</button>
                      <button onClick={handleSaveReq} className="px-10 py-4 bg-pink-600 hover:bg-pink-700 text-white font-black uppercase text-[10px] tracking-widest rounded-2xl shadow-xl shadow-pink-500/30 transition-all hover:scale-[1.02] active:scale-95">Enviar Pedido</button>
                  </div>
              </div>
          </div>
      )}

      {/* Modal de Reprovação */}
      {isRejectModalOpen && selectedReqForReject && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300 w-screen h-screen" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-[2rem] w-full max-w-md shadow-2xl animate-pop border-t-8 border-red-600 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-8 flex items-center gap-4">
                      <div className="p-4 bg-red-50 rounded-2xl text-red-600 shadow-sm">
