                          <p className="text-xs text-slate-400 font-bold uppercase mt-1">Ação de Auditoria</p>
                      </div>
                  </div>

                  <div className="px-10 space-y-6 pb-10">
                      <div className="bg-slate-50 p-6 rounded-[1.5rem] text-sm text-slate-600 border border-slate-100/60 shadow-inner">
                          <p className="font-black text-slate-800 mb-1 uppercase text-[10px] tracking-widest">Pedido de:</p>
                          <p className="font-bold text-slate-700">{selectedReqForReject.title}</p>
                          {selectedReqForReject.estimatedCost > 0 && <p className="text-[10px] font-black text-red-500 mt-1">VALOR: R$ {selectedReqForReject.estimatedCost.toLocaleString()}</p>}
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block ml-1">Motivo da Recusa <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full border-2 border-transparent bg-slate-50 rounded-[1.5rem] p-5 text-sm font-bold outline-none focus:border-red-500 focus:bg-white transition-all resize-none"
                            placeholder="Explique o porquê este pedido não pode ser atendido no momento..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>

                      <div className="flex gap-4 justify-end pt-4">
                          <button onClick={() => setIsRejectModalOpen(false)} className="px-8 py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-slate-800 transition-colors">Voltar</button>
                          <button 
                            onClick={confirmRejection} 
                            disabled={rejectionReason.length < 3}
                            className="px-10 py-4 bg-red-600 hover:bg-red-700 text-white font-black uppercase text-[10px] tracking-widest rounded-2xl shadow-xl shadow-red-600/30 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-50"
                          >
                              Recusar Agora
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

