import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, Notification, ConfirmOptions, TimeLog } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, Eye, 
    CheckSquare, Users, CreditCard, Layout, Upload, Check, Activity, AlertCircle, Play, Pause, Calendar, Save,
    Flag, AlignLeft, ShieldCheck, Search, Palette, ExternalLink, UserPlus, Camera, Trash, ImagePlus
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    setNotifications?: React.Dispatch<React.SetStateAction<Notification[]>>;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, setNotifications, openConfirm }) => {
    const [newComment, setNewComment] = useState('');
    const [mentionFilter, setMentionFilter] = useState('');
    const [showMentions, setShowMentions] = useState(false);
    const [newChecklistText, setNewChecklistText] = useState('');

    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [localDueDate, setLocalDueDate] = useState(task.dueDate || '');
    const [localPriority, setLocalPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>(task.priority || 'MEDIUM');
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [showSavedFeedback, setShowSavedFeedback] = useState(false);

    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COLOR_GRID' | string | null>(null);
    const [memberSearch, setMemberSearch] = useState('');

    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const commentInputRef = useRef<HTMLTextAreaElement>(null);
    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        console.log("MODAL_OPEN", { screen: 'KanbanJob' });
        return () => console.log("MODAL_CLOSED");
    }, [task.id]);

    useEffect(() => {
        setLocalTitle(task.title);
        setLocalDesc(task.description);
        setLocalDueDate(task.dueDate || '');
        setLocalPriority(task.priority || 'MEDIUM');
    }, [task.id, task.title, task.description, task.dueDate, task.priority]);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                setSecondsElapsed(s => s + 1);
            }, 1000);
        } else {
            clearInterval(interval);
        }
        return () => clearInterval(interval);
    }, [task.isTracking]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setActivePopover(null);
                setShowMentions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const isNewTask = task.history.length === 0;

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const calculateTotalSeconds = () => {
        const closedLogsDuration = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        if (task.isTracking) {
            const activeLog = task.timeLogs.find(l => !l.endTime);
            if (activeLog) {
                const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                return closedLogsDuration + elapsed;
            }
        }
        return closedLogsDuration;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const triggerSavedFeedback = () => {
        setShowSavedFeedback(true);
        setTimeout(() => setShowSavedFeedback(false), 2000);
    };

    const updateWithLog = (updatedTaskProps: Partial<Task>, logAction: string) => {
        onUpdate({
            ...task,
            ...updatedTaskProps,
            history: [...task.history, createLog(logAction)]
        });
        triggerSavedFeedback();
    };

    const handleFinalConfirmNewTask = () => {
        if (!localTitle.trim() || !localDueDate) return;
        onUpdate({
            ...task,
            title: localTitle,
            description: localDesc,
            dueDate: localDueDate,
            priority: localPriority,
            history: [createLog('Tarefa criada no Kanban')]
        });
        triggerSavedFeedback();
    };

    const handleCoverChange = (type: 'color' | 'image' | null, value: string | null) => {
        updateWithLog({ coverType: type, coverValue: value }, type ? `atualizou a capa (${type})` : 'removeu a capa');
        setActivePopover(null);
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const imageUrl = URL.createObjectURL(file);
            handleCoverChange('image', imageUrl);
        }
    };

    const saveTitle = () => {
        if (!localTitle.trim() || localTitle === task.title) return;
        updateWithLog({ title: localTitle }, `alterou o título de "${task.title || 'Vazio'}" para "${localTitle}"`);
    };

    const saveDesc = () => {
        setIsEditingDesc(false);
        if (localDesc === task.description) return;
        updateWithLog({ description: localDesc }, `atualizou a descrição do job`);
    };

    const addChecklistItem = () => {
        if (newChecklistText.trim()) {
            const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
            updateWithLog({ checklists: [...(task.checklists || []), newItem] }, `adicionou etapa: "${newChecklistText}"`);
            setNewChecklistText('');
        }
    };

    const toggleChecklist = (itemId: string) => {
        const newChecklists = task.checklists.map(c => c.id === itemId ? { ...c, isCompleted: !c.isCompleted } : c);
        onUpdate({...task, checklists: newChecklists});
    };

    const handleDueDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = e.target.value;
        setLocalDueDate(newVal);
        if (!isNewTask && newVal) updateWithLog({ dueDate: newVal }, `alterou o prazo para ${new Date(newVal).toLocaleDateString()}`);
    };

    const toggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    const duration = Math.floor((now - log.startTime) / 1000);
                    return { ...log, endTime: now, duration };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou a produção');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou a produção');
        }
    };

    const totalSecondsAccumulated = calculateTotalSeconds();
    const checklistProgress = task.checklists.length > 0 ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) : 0;
    const activityFeed = [...task.comments.map(c => ({ type: 'COMMENT', data: c, timestamp: c.timestamp })), ...task.history.map(h => ({ type: 'HISTORY', data: h, timestamp: h.timestamp }))].sort((a, b) => b.timestamp - a.timestamp);

    if (isNewTask) {
        return (
            <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex justify-center items-center p-4 transition-all duration-300" onClick={onClose}>
                <div className="bg-white w-full max-w-md rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden animate-pop border border-slate-100" onClick={e => e.stopPropagation()}>
                    <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-pink-600 rounded-xl shadow-lg shadow-pink-600/20"><Plus size={20} strokeWidth={3} /></div>
                            <div>
                                <h2 className="text-lg font-bold tracking-tight">Nova Demanda</h2>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Setup rápido</p>
                            </div>
                        </div>
                        <button onClick={onClose} className="p-1.5 hover:bg-white/10 rounded-full transition-colors"><X size={18} /></button>
                    </div>
                    <div className="p-6 space-y-4">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Título do Job <span className="text-pink-500">*</span></label>
                            <input className="w-full text-sm font-bold text-slate-800 bg-slate-50 border border-transparent rounded-xl p-3.5 outline-none focus:border-pink-500 focus:bg-white focus:ring-4 focus:ring-pink-500/5 transition-all" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} placeholder="Ex: Campanha de Natal..." autoFocus />
                        </div>
                        <div className="grid grid-cols-1 gap-4">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Entrega <span className="text-pink-500">*</span></label>
                                <input type="date" className={`w-full bg-slate-50 border text-sm font-bold rounded-xl p-3.5 outline-none transition-all ${!localDueDate ? 'border-red-100' : 'border-transparent focus:border-pink-500 focus:bg-white focus:ring-4 focus:ring-pink-500/5'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Prioridade</label>
                                <div className="flex gap-2 h-[44px]">
                                    {['LOW', 'MEDIUM', 'HIGH'].map(p => (
                                        <button key={p} onClick={() => setLocalPriority(p as any)} className={`flex-1 rounded-xl text-[10px] font-black uppercase transition-all border ${localPriority === p ? 'border-slate-800 bg-white shadow-sm' : 'border-transparent bg-slate-50 text-slate-400'}`}>{p === 'HIGH' ? 'Urgente' : p === 'MEDIUM' ? 'Média' : 'Baixa'}</button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                    <div className="p-6 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                        <button onClick={onClose} className="px-5 py-2.5 font-bold text-slate-500 hover:text-slate-700 transition-colors uppercase text-[10px] tracking-widest">Cancelar</button>
                        <button onClick={handleFinalConfirmNewTask} disabled={!localDueDate || !localTitle} className="px-6 h-10 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-xl shadow-lg shadow-pink-500/20 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-50 uppercase text-[10px] tracking-widest">Criar Job</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex justify-center overflow-y-auto py-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-xl rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.1)] relative min-h-[400px] h-fit my-auto mx-4 animate-pop border border-slate-100 overflow-hidden" onClick={e => e.stopPropagation()}>

                {/* --- SEÇÃO HERO: CAPA COMPACTA --- */}
                <div className={`w-full h-32 relative group transition-all duration-500 ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? (task.coverValue || '#f1f5f9') : undefined }}>
                    {task.coverType === 'image' && (
                        <img src={task.coverValue || ''} alt="Capa" className="w-full h-full object-cover" />
                    )}

                    {!task.coverType && (
                        <div className="absolute inset-0 flex items-center justify-center">
                            <button 
                                onClick={() => setActivePopover('COLOR_GRID')}
                                className="flex items-center gap-2 px-4 py-1.5 bg-white/80 hover:bg-white text-slate-800 font-black text-[9px] uppercase rounded-lg transition-all border border-slate-200/50 shadow-sm tracking-widest"
                            >
                                <Layout size={12}/> Adicionar Capa
                            </button>
                        </div>
                    )}

                    <div className="absolute bottom-3 right-4 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-all translate-y-1 group-hover:translate-y-0">
                        <button onClick={() => setActivePopover('COLOR_GRID')} className="p-2 bg-white hover:bg-slate-50 text-slate-700 rounded-lg shadow-md border border-slate-200"><Palette size={14}/></button>
                        <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-white hover:bg-slate-50 text-slate-700 rounded-lg shadow-md border border-slate-200"><Camera size={14}/></button>
                        {task.coverType && <button onClick={() => handleCoverChange(null, null)} className="p-2 bg-red-500 hover:bg-red-600 text-white rounded-lg shadow-md"><Trash size={14}/></button>}
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                    </div>

                    <button onClick={onClose} className="absolute top-4 right-4 p-1.5 rounded-full bg-black/10 hover:bg-black/20 z-50 transition-colors"><X size={18} className="text-white"/></button>
                </div>

                {/* --- CONTEÚDO DO MODAL COMPACTO --- */}
                <div className="p-6 gap-6">
                    <div className="space-y-6">
                        <div className="flex gap-4 items-start">
                            <CreditCard className="mt-1 text-slate-300" size={20}/>
                            <div className="flex-1">
                                <input className="text-xl font-bold text-slate-800 w-full bg-transparent border-none outline-none placeholder-slate-200 mb-1 tracking-tight" value={localTitle} onChange={(e) => setLocalTitle(e.target.value)} onBlur={saveTitle} onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()} />
                                <div className="flex items-center gap-3">
                                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status: <span className="text-pink-600">{task.status}</span></div>
                                    {showSavedFeedback && <div className="flex items-center gap-1 text-emerald-600 text-[9px] font-black uppercase animate-pop"><Check size={10} strokeWidth={3}/> Salvo</div>}
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4 ml-9">
                            <div className="bg-slate-50 p-4 rounded-xl border border-transparent hover:border-pink-200 transition-all">
                                <h4 className="text-[9px] font-black text-slate-400 uppercase mb-2 flex items-center gap-2 tracking-widest"><Calendar size={12}/> Prazo</h4>
                                <input type="date" className={`w-full text-sm font-bold bg-transparent outline-none ${!localDueDate ? 'text-red-500' : 'text-slate-800'}`} value={localDueDate} onChange={handleDueDateChange} />
                            </div>
                            <div className="bg-slate-900 p-4 rounded-xl shadow-lg relative overflow-hidden group">
                                <h4 className="text-[9px] font-black text-slate-500 uppercase mb-2 flex items-center gap-2 tracking-widest"><Clock size={12}/> Cronômetro</h4>
                                <div className="flex items-center justify-between relative z-10">
                                    <div className="text-base font-bold text-white font-mono tracking-wider">{formatSeconds(totalSecondsAccumulated)}</div>
                                    <button onClick={toggleTimer} className={`p-1.5 rounded-lg transition-all ${task.isTracking ? 'bg-amber-500 text-white' : 'bg-pink-600 text-white'}`}>
                                        {task.isTracking ? <Pause size={14} fill="currentColor"/> : <Play size={14} fill="currentColor"/>}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <AlignLeft className="mt-1 text-slate-300" size={20}/>
                            <div className="flex-1">
                                <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest mb-3 ml-1">Briefing</h3>
                                <div className={`relative rounded-xl p-4 transition-all ${isEditingDesc ? 'bg-white border-pink-500 ring-4 ring-pink-500/5 shadow-sm' : 'bg-slate-50 border border-transparent hover:bg-slate-100 cursor-text'}`} onClick={() => !isEditingDesc && setIsEditingDesc(true)}>
                                    {isEditingDesc ? (
                                        <textarea className="w-full min-h-[100px] border-none outline-none text-sm text-slate-700 resize-none bg-transparent font-medium" value={localDesc} onChange={(e) => setLocalDesc(e.target.value)} onBlur={saveDesc} autoFocus placeholder="Detalhes do job..." />
                                    ) : (
                                        <div className="text-sm text-slate-600 leading-relaxed min-h-[100px] font-medium whitespace-pre-wrap">{localDesc || <span className="text-slate-300 italic">Adicionar briefing...</span>}</div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <CheckSquare className="mt-1 text-slate-300" size={20}/>
                            <div className="flex-1">
                                <div className="flex justify-between items-center mb-3 ml-1">
                                    <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-widest">Etapas</h3>
                                    <span className="text-[9px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full uppercase">{checklistProgress}%</span>
                                </div>
                                <div className="space-y-1.5 mb-4">
                                    {task.checklists.map(item => (
                                        <div key={item.id} className="flex items-center gap-3 p-2 rounded-lg hover:bg-slate-50 transition-all border border-transparent">
                                            <input type="checkbox" checked={item.isCompleted} onChange={() => toggleChecklist(item.id)} className="w-4 h-4 rounded border-slate-200 text-pink-600 focus:ring-pink-500 cursor-pointer"/>
                                            <span className={`text-sm font-bold ${item.isCompleted ? 'line-through text-slate-300' : 'text-slate-700'}`}>{item.text}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex gap-2 bg-slate-50 p-2 rounded-xl border border-slate-100 focus-within:bg-white focus-within:border-pink-500 transition-all">
                                    <input type="text" placeholder="Nova etapa..." className="flex-1 bg-transparent border-none px-2 text-xs font-bold outline-none placeholder:text-slate-300" value={newChecklistText} onChange={(e) => setNewChecklistText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && addChecklistItem()}/>
                                    <button onClick={addChecklistItem} className="bg-slate-800 text-white px-4 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest">Add</button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* RODAPÉ DE AÇÕES COMPACTO */}
                    <div className="mt-8 pt-6 border-t border-slate-100 flex flex-wrap items-center justify-between gap-4">
                        <div className="flex gap-2">
                             <button onClick={() => setActivePopover('MEMBERS')} className="h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 bg-slate-100 text-slate-600 hover:bg-slate-200 transition-all"><Users size={14}/> Time</button>
                             <button onClick={() => updateWithLog({ archived: !task.archived }, 'arquivou o job')} className="h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-100 flex items-center gap-2 transition-all"><Archive size={14}/></button>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={onClose} className="h-10 px-6 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-colors">Fechar</button>
                            {task.status !== 'DONE' && (
                                <button onClick={() => { updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job'); confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } }); }} className="h-10 px-6 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-emerald-600/10 transition-all"><CheckCircle size={14}/> Concluir</button>
                            )}
                        </div>
                    </div>
                </div>

                {/* POPOVERS COMPACTOS */}
                {activePopover === 'MEMBERS' && (
                    <div ref={popoverRef} className="absolute bottom-20 left-6 w-64 bg-white rounded-2xl shadow-2xl border border-slate-100 z-50 p-4 animate-pop">
                        <h5 className="text-[9px] font-black text-slate-400 uppercase mb-3 text-center tracking-widest border-b pb-2">Responsáveis</h5>
                        <div className="space-y-1 max-h-48 overflow-y-auto custom-scrollbar">
                            {users.filter(u => u.role !== 'CLIENT').map(u => (
                                <button key={u.id} onClick={() => {
                                    const currentIds = task.assigneeIds || [];
                                    const newIds = currentIds.includes(u.id) ? currentIds.filter(id => id !== u.id) : [...currentIds, u.id];
                                    updateWithLog({ assigneeIds: newIds }, `atualizou responsáveis`);
                                }} className={`w-full flex items-center justify-between p-2 rounded-lg transition-all ${task.assigneeIds.includes(u.id) ? 'bg-pink-50 text-pink-700' : 'hover:bg-slate-50 text-slate-500'}`}>
                                    <div className="flex items-center gap-2"><img src={u.avatar} className="w-6 h-6 rounded-lg border border-white" /><span className="text-[10px] font-bold">{u.name}</span></div>
                                    {task.assigneeIds.includes(u.id) && <Check size={12} strokeWidth={3}/>}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
                {activePopover === 'COLOR_GRID' && (
                    <div ref={popoverRef} className="absolute top-36 right-6 bg-white p-3 rounded-xl shadow-2xl border border-slate-100 w-48 animate-pop z-50">
                        <div className="grid grid-cols-5 gap-2">
                            {PRESET_COLORS.map(c => (
                                <button key={c} onClick={() => handleCoverChange('color', c)} className="w-6 h-6 rounded-full border-2 border-white shadow-sm hover:scale-125 transition-transform" style={{ backgroundColor: c }} />
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, FileText, AlertCircle, ShoppingBag, DollarSign, Clock, AlertTriangle, Phone, Calendar } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  // Estado para Criar Nova Requisição
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});

  // Estado para Filtros
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');

  // Estados para Processamento (Feedback Visual)
  const [processingId, setProcessingId] = useState<string | null>(null);

  // Estados para Modal de Reprovação
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  useEffect(() => {
    if(isCreateModalOpen || isRejectModalOpen) {
        console.log("MODAL_OPEN", { screen: "Solicitacoes" });
    }
  }, [isCreateModalOpen, isRejectModalOpen]);

  // 1. Permissões
  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  // Filtragem
  const displayedRequisitions = requisitions.filter(req => {
      if (filter === 'MY') return req.requesterId === currentUser.id;
      if (!canApprove) return req.requesterId === currentUser.id;
      return true;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) {
          alert("Preencha título e valor.");
          return;
      }

      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };

      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove) {
          alert("Erro 403: Sem permissão para aprovar.");
          return;
      }
      if (req.status === 'APPROVED') return;

      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...req,
              status: 'APPROVED',
              approvedBy: currentUser.id,
              approvedAt: now,
              rejectedBy: undefined,
              rejectedAt: undefined,
              rejectedReason: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          const isServiceRequest = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);
          if (!isServiceRequest && req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}-${Date.now()}`,
                  description: `REQ Aprovada: ${req.title} (${req.category})`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador Interno'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }

          const notif: Notification = {
              id: `notif-apr-${Date.now()}`,
              title: isServiceRequest ? 'Solicitação Agendada/Concluída' : 'Solicitação Aprovada',
              message: isServiceRequest 
                ? `Sua solicitação "${req.title}" foi confirmada pela equipe.`
                : `Sua solicitação "${req.title}" no valor de R$ ${req.estimatedCost.toLocaleString()} foi aprovada.`,
              type: 'SUCCESS',
              status: 'UNREAD',
              priority: 'MEDIUM',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: req.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
      }, 800);
  };

  const openRejectModal = (req: Requisition) => {
      setSelectedReqForReject(req);
      setRejectionReason('');
      setIsRejectModalOpen(true);
  };

  const confirmRejection = () => {
      if (!selectedReqForReject) return;
      if (!rejectionReason || rejectionReason.length < 3) {
          alert("O motivo da reprovação é obrigatório (mínimo 3 caracteres).");
          return;
      }
      if (!canApprove) {
          alert("Erro 403: Sem permissão.");
          return;
      }

      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);

      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = {
              ...reqToReject,
              status: 'REJECTED',
              rejectedBy: currentUser.id,
              rejectedAt: now,
              rejectedReason: rejectionReason,
              approvedBy: undefined,
              approvedAt: undefined
          };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));

          const notif: Notification = {
              id: `notif-rej-${Date.now()}`,
              title: 'Solicitação Recusada',
              message: `Sua solicitação "${reqToReject.title}" foi recusada. Motivo: ${rejectionReason}`,
              type: 'REJECTED',
              status: 'UNREAD',
              priority: 'HIGH',
              originModule: 'REQUISITIONS',
              timestamp: Date.now(),
              targetUserId: reqToReject.requesterId,
              navToView: 'requisitions'
          };
          setNotifications(prev => [notif, ...prev]);
          setProcessingId(null);
          setSelectedReqForReject(null);
      }, 800);
  };

  const getCategoryIcon = (cat: string) => {
      switch(cat) {
          case 'Reunião': return <Calendar size={12}/>;
          case 'Atendimento': return <Phone size={12}/>;
          default: return <ShoppingBag size={12}/>;
      }
  };

  return (
    <div className="space-y-6 animate-pop">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl border border-slate-200/60 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Central de Solicitações</h2>
          <p className="text-slate-400 text-sm font-medium">Gestão de suprimentos e agendamentos.</p>
        </div>
        <div className="flex gap-2">
            {canApprove && (
                <div className="bg-slate-100 p-1 rounded-xl flex text-[9px] font-black uppercase tracking-widest shadow-inner">
                    <button 
                        onClick={() => setFilter('ALL')}
                        className={`px-3 py-1.5 rounded-lg transition-all ${filter === 'ALL' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Todas
                    </button>
                    <button 
                        onClick={() => setFilter('MY')}
                        className={`px-3 py-1.5 rounded-lg transition-all ${filter === 'MY' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Minhas
                    </button>
                </div>
            )}
            <button 
                onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
                className="bg-pink-600 hover:bg-pink-700 text-white px-5 h-10 rounded-xl flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all shadow-lg shadow-pink-500/10 hover:scale-[1.02] active:scale-95"
            >
                <Plus size={16} strokeWidth={3} /> Enviar Pedido
            </button>
        </div>
      </div>

      {/* Grid de Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {displayedRequisitions.length === 0 && (
              <div className="col-span-full p-16 text-center border-2 border-dashed border-slate-200 rounded-2xl bg-white/30 shadow-inner">
                  <div className="bg-slate-50 w-12 h-12 rounded-xl flex items-center justify-center mx-auto mb-3">
                    <FileText className="text-slate-300" size={24}/>
                  </div>
                  <p className="text-slate-400 font-bold uppercase text-[9px] tracking-widest">Nenhuma solicitação ativa</p>
              </div>
          )}

          {displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;
              const isService = ['Reunião', 'Atendimento', 'Contato'].includes(req.category);

              return (
                <div key={req.id} className="bg-white rounded-2xl border border-slate-200/60 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-all group relative">
                    {isProcessing && (
                        <div className="absolute inset-0 bg-white/90 z-20 flex items-center justify-center">
                            <Clock className="animate-spin text-pink-600" size={32}/>
                        </div>
                    )}

                    <div className="p-6 flex-1">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                                req.status === 'PENDING' ? 'bg-orange-50 text-orange-700 border-orange-100' : 
                                req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'
                            }`}>
                                {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? (isService ? 'Concluído' : 'Aprovada') : 'Recusada'}
                            </span>
                            <div className="text-[9px] font-bold text-slate-300">{req.date.split('-').reverse().join('/')}</div>
                        </div>

                        <h3 className="font-bold text-slate-800 text-base mb-1 line-clamp-1 group-hover:text-pink-600 transition-colors">{req.title}</h3>
                        <div className="flex items-center gap-2 text-[9px] text-slate-400 font-bold uppercase tracking-wider mb-4">
                            <span className="bg-slate-50 px-2 py-0.5 rounded border border-slate-100 flex items-center gap-1">{getCategoryIcon(req.category)} {req.category}</span>
                            {requester && <span className="flex items-center gap-1">• <b>{requester.name.split(' ')[0]}</b></span>}
                        </div>

                        <div className="text-xs text-slate-500 mb-4 line-clamp-2 bg-slate-50/50 p-3 rounded-xl border border-slate-100/50 min-h-[60px] leading-relaxed">
                            {req.description}
                        </div>

                        {req.status === 'REJECTED' && req.rejectedReason && (
                            <div className="bg-red-50 p-3 rounded-xl border border-red-100 mb-2 animate-pop">
                                <p className="text-[9px] text-red-800 font-black uppercase tracking-widest mb-1">Motivo da Recusa</p>
                                <p className="text-[11px] text-red-600 italic font-medium">"{req.rejectedReason}"</p>
                            </div>
                        )}
                    </div>

                    <div className="p-4 bg-slate-50/80 border-t border-slate-100/50 flex items-center justify-between">
                        <div>
                            {isService ? (
                                <p className="text-[9px] font-black text-slate-400 uppercase">Serviço</p>
                            ) : (
                                <p className="text-base font-black text-slate-800 flex items-baseline gap-1">
                                    <span className="text-slate-400 text-[10px] font-normal">R$</span> {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                </p>
                            )}
                        </div>

                        {canApprove && req.status === 'PENDING' && (
                            <div className="flex gap-1.5">
                                <button onClick={() => handleApproveReq(req)} className="p-2 bg-emerald-50 hover:bg-emerald-600 text-emerald-700 hover:text-white rounded-lg transition-all border border-emerald-100"><Check size={14} strokeWidth={3}/></button>
                                <button onClick={() => openRejectModal(req)} className="p-2 bg-red-50 hover:bg-red-600 text-red-700 hover:text-white rounded-lg transition-all border border-red-100"><X size={14} strokeWidth={3}/></button>
                            </div>
                        )}
                    </div>
                </div>
              );
          })}
      </div>

      {/* Modal de Nova Solicitação - COMPACTO (max-w-md) */}
      {isCreateModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden animate-pop border border-slate-100" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b border-slate-50 bg-slate-50 flex items-center justify-between">
                      <div className="flex items-center gap-3">
