import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, ShoppingBag, DollarSign, Clock, Calendar, AlertTriangle, User as UserIcon, Filter, Search, ChevronRight } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  const displayedRequisitions = requisitions.filter(req => {
      const matchesFilter = filter === 'ALL' ? (canApprove || req.requesterId === currentUser.id) : req.requesterId === currentUser.id;
      const matchesSearch = req.title.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesFilter && matchesSearch;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) return;
      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };
      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove || req.status === 'APPROVED') return;
      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = { ...req, status: 'APPROVED', approvedBy: currentUser.id, approvedAt: now };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          if (req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}`,
                  description: `REQ Aprovada: ${req.title}`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }
          setProcessingId(null);
      }, 600);
  };

  const handleRejectReq = () => {
      if (!selectedReqForReject || !rejectionReason) return;
      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);
      setTimeout(() => {
          const updatedReq: Requisition = { ...reqToReject, status: 'REJECTED', rejectedBy: currentUser.id, rejectedAt: new Date().toISOString(), rejectedReason: rejectionReason };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));
          setProcessingId(null);
          setSelectedReqForReject(null);
          setRejectionReason('');
      }, 600);
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden -m-4 md:-m-6">
      {/* 2. TOP BAR FIXA */}
      <header className="h-20 border-b border-slate-100 flex items-center justify-between px-8 bg-white shrink-0 z-10">
        <div className="flex items-center gap-6">
          <h2 className="text-2xl font-black tracking-tighter text-slate-800">Solicitações</h2>
          <div className="hidden md:flex bg-slate-50 p-1 rounded-xl border border-slate-100">
             <button onClick={() => setFilter('ALL')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'ALL' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}>Geral</button>
             <button onClick={() => setFilter('MY')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'MY' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}>Minhas</button>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative hidden sm:block">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16}/>
            <input 
              type="text" 
              placeholder="Buscar pedidos..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="pl-9 pr-4 py-2 bg-slate-50 border border-transparent focus:bg-white focus:border-slate-200 rounded-xl text-xs font-bold outline-none w-48 transition-all"
            />
          </div>
          <button 
            onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
            className="h-11 px-6 bg-pink-600 hover:bg-pink-700 text-white font-bold text-xs uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-pink-600/10 flex items-center gap-2 hover:scale-[1.02] active:scale-95"
          >
            <Plus size={16} strokeWidth={3}/> Nova Solicitação
          </button>
        </div>
      </header>

      {/* 3. CONTEÚDO PRINCIPAL (LISTA SLIM) */}
      <main className="flex-1 overflow-y-auto p-8 bg-slate-50/50 custom-scrollbar">
        <div className="max-w-5xl mx-auto space-y-3">
          {displayedRequisitions.length === 0 ? (
            <div className="py-20 text-center bg-white rounded-2xl border border-dashed border-slate-200">
              <ShoppingBag className="mx-auto text-slate-200 mb-4" size={48}/>
              <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Nenhum pedido encontrado</p>
            </div>
          ) : (
            displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;

              return (
                <div key={req.id} className="group bg-white p-4 rounded-2xl border border-slate-100 hover:border-pink-100 hover:shadow-xl hover:shadow-slate-200/40 transition-all flex items-center justify-between gap-6 relative">
                  {isProcessing && <div className="absolute inset-0 bg-white/80 z-10 flex items-center justify-center rounded-2xl"><Clock className="animate-spin text-pink-600" size={24}/></div>}

                  <div className="flex items-center gap-4 flex-1 min-w-0">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600' : req.status === 'REJECTED' ? 'bg-red-50 text-red-600' : 'bg-orange-50 text-orange-600'}`}>
                      {req.category === 'Reembolso' ? <DollarSign size={20}/> : <ShoppingBag size={20}/>}
                    </div>
                    <div className="min-w-0">
                      <h4 className="font-bold text-slate-800 text-sm truncate group-hover:text-pink-600 transition-colors">{req.title}</h4>
                      <div className="flex items-center gap-3 mt-0.5">
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1 uppercase tracking-tight"><Calendar size={10}/> {req.date.split('-').reverse().join('/')}</span>
                        <span className="text-slate-200">•</span>
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1 uppercase tracking-tight"><UserIcon size={10}/> {requester?.name.split(' ')[0]}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-8">
                    <div className="text-right hidden sm:block">
                      <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest leading-none mb-1">Valor</p>
                      <p className="font-black text-slate-700 text-sm">R$ {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>

                    <div className="w-28 text-center">
                       <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                          req.status === 'PENDING' ? 'bg-orange-50 text-orange-600 border-orange-100' : 
                          req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-600 border-red-100'
                       }`}>
                         {req.status === 'PENDING' ? 'Análise' : req.status === 'APPROVED' ? 'Aprovado' : 'Recusado'}
                       </span>
                    </div>

                    <div className="flex items-center gap-2">
                      {canApprove && req.status === 'PENDING' ? (
                        <>
                          <button onClick={() => handleApproveReq(req)} className="p-2.5 bg-slate-50 hover:bg-emerald-600 hover:text-white text-emerald-600 rounded-xl transition-all border border-slate-100 hover:border-emerald-600"><Check size={16} strokeWidth={3}/></button>
                          <button onClick={() => { setSelectedReqForReject(req); setIsRejectModalOpen(true); }} className="p-2.5 bg-slate-50 hover:bg-red-600 hover:text-white text-red-600 rounded-xl transition-all border border-slate-100 hover:border-red-600"><X size={16} strokeWidth={3}/></button>
                        </>
                      ) : (
                        <div className="p-2.5 text-slate-200"><ChevronRight size={16}/></div>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </main>

      {/* 4. O NOVO POPUP (REFINADO E COMPACTO) */}
      {isCreateModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden animate-pop border border-slate-100" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b border-slate-50 bg-white flex items-center justify-between">
                      <h3 className="text-xl font-bold text-slate-800 tracking-tight">Nova Solicitação</h3>
                      <button onClick={() => setIsCreateModalOpen(false)} className="text-slate-300 hover:text-slate-500 transition-colors"><X size={20}/></button>
                  </div>

                  <div className="p-6 space-y-4">
                      <div>
                          <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Categoria do Pedido</label>
                          <select 
                             className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white focus:border-pink-500 transition-all border"
                             value={editingReq.category}
                             onChange={e => setEditingReq({...editingReq, category: e.target.value})}
                          >
                              {isClient ? (
                                  <>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Outros">Outros</option>
                                  </>
                              ) : (
                                  <>
                                    <option value="Compra">Compra de Material</option>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Software">Software</option>
                                    <option value="Serviço">Serviço Terceiro</option>
                                  </>
                              )}
                          </select>
                      </div>

                      <div>
                          <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Título / Identificação</label>
                          <input 
                            className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white focus:border-pink-500 transition-all border"
                            placeholder="Ex: Teclado Mecânico" 
                            value={editingReq.title || ''} 
                            onChange={e => setEditingReq({...editingReq, title: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Justificativa Detalhada</label>
                          <textarea 
                            className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white focus:border-pink-500 transition-all border resize-none"
                            placeholder="Explique o motivo do pedido..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Valor Estimado (R$)</label>
                          <input 
                            type="number" 
                            className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-xl font-black outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white focus:border-pink-500 transition-all border"
                            placeholder="0.00" 
                            value={editingReq.estimatedCost || ''} 
                            onChange={e => setEditingReq({...editingReq, estimatedCost: parseFloat(e.target.value)})} 
                          />
                      </div>
                  </div>

                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                      <button onClick={() => setIsCreateModalOpen(false)} className="h-11 px-6 text-[11px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-colors">Cancelar</button>
                      <button onClick={handleSaveReq} className="h-11 px-8 bg-pink-600 hover:bg-pink-700 text-white font-bold text-[11px] uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-pink-600/10 hover:scale-[1.02]">Enviar Pedido</button>
                  </div>
              </div>
          </div>
      )}

      {isRejectModalOpen && selectedReqForReject && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden animate-pop border-t-4 border-red-500 border-x border-b border-slate-100" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b border-slate-50 bg-white flex items-center gap-4">
                      <div className="p-3 bg-red-50 text-red-600 rounded-xl"><AlertTriangle size={24}/></div>
                      <h3 className="text-xl font-bold text-slate-800 tracking-tight">Recusar Pedido</h3>
                  </div>

                  <div className="p-6 space-y-4">
                      <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 text-xs text-slate-500">
                        <p className="font-bold text-slate-700 uppercase text-[9px] tracking-widest mb-1">Item:</p>
                        {selectedReqForReject.title}
                      </div>

                      <div>
                        <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Motivo da Decisão <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-red-500/5 focus:bg-white focus:border-red-500 transition-all border resize-none"
                            placeholder="Informe por que o pedido foi negado..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>
                  </div>

                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                      <button onClick={() => setIsRejectModalOpen(false)} className="h-11 px-6 text-[11px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-colors">Voltar</button>
                      <button 
                        onClick={handleRejectReq} 
                        disabled={!rejectionReason}
                        className="h-11 px-8 bg-red-600 hover:bg-red-700 text-white font-bold text-[11px] uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-red-600/10 hover:scale-[1.02] disabled:opacity-50"
                      >
                        Recusar Agora
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
