        <span className="text-slate-300">-</span>
        <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="text-[10px] text-slate-600 outline-none bg-slate-50 border border-slate-200 rounded px-3 py-1.5 font-bold" />
