import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { Plus, Archive, Settings, Layout } from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  sidebarOpen: boolean;
  sidebarCompact: boolean;
  isMobile: boolean;
  searchTerm: string;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  sidebarOpen, sidebarCompact, isMobile, searchTerm
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const activeColumns = useMemo(() => columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), [columns]);
  const archivedColumns = useMemo(() => columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order), [columns]);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    else setColumns(prev => [...prev, { id: 'col-' + Date.now(), label: editingColumn.label, color: 'border-slate-400', order: columns.length, wipLimit: editingColumn.wipLimit || null, isArchived: false } as ColumnConfig]);
    setIsColumnModalOpen(false);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));
          if (targetColId === 'DONE') {
              confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          }
      }
      setDraggedTaskId(null);
  };

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      return exists ? prev.map(t => t.id === updatedTask.id ? updatedTask : t) : [...prev, updatedTask];
    });
    setSelectedTask(updatedTask);
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden">
      {/* Kanban Local Controls */}
      <div className="flex items-center justify-between px-6 py-3 border-b border-slate-200 bg-white/50">
          <div className="flex items-center gap-2">
              <button onClick={() => setShowArchived(!showArchived)} className={`h-8 px-3 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${showArchived ? 'bg-slate-800 text-white' : 'bg-white border text-slate-400 border-slate-200 hover:text-pink-600'}`} title="Jobs Arquivados">
                {showArchived ? 'Ocultar Arquivados' : 'Ver Arquivados'}
              </button>
              {isAdmin && <button onClick={() => setShowArchivedColumns(true)} className="h-8 px-3 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-pink-600 text-[10px] font-black uppercase tracking-widest transition-all">Listas Arquivadas</button>}
          </div>
          <button 
            onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)}
            className="h-9 px-5 bg-pink-600 hover:bg-pink-700 text-white rounded-xl flex items-center gap-2 text-[10px] font-black uppercase tracking-widest shadow-lg shadow-pink-500/10 transition-all hover:scale-[1.02]"
          >
            <Plus size={14} strokeWidth={3} /> NOVO JOB
          </button>
      </div>

      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-6 gap-6 items-start">
          {activeColumns.map(col => {
            const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived) && t.title.toLowerCase().includes(searchTerm.toLowerCase()));
            return (
              <div key={col.id} onDragOver={e => e.preventDefault()} onDrop={e => handleDropTask(e, col.id)} className="flex-shrink-0 w-80 flex flex-col max-h-full rounded-2xl bg-slate-200/30 border border-slate-200/50">
                <div className="p-4 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className="w-1.5 h-4 rounded-full bg-pink-500"></div>
                    <h3 className="font-black text-[10px] uppercase tracking-widest text-slate-500">{col.label}</h3>
                  </div>
                  <span className="bg-white/80 text-slate-500 text-[9px] px-1.5 py-0.5 rounded-full font-black shadow-sm border border-slate-100">{colTasks.length}</span>
                </div>

                <div className="px-3 pb-5 space-y-3 overflow-y-auto custom-scrollbar flex-1">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-xl shadow-sm border border-slate-200/60 cursor-grab active:cursor-grabbing transition-all group hover:shadow-md hover:border-pink-200 overflow-hidden flex flex-col"
                    >
                      {task.coverType === 'color' && <div className="h-12 w-full" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />}
                      {task.coverType === 'image' && <img src={task.coverValue || ''} className="h-16 w-full object-cover" alt="Capa" />}

                      <div className="p-4">
                        <div className="flex justify-between items-start mb-2">
                          <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter ${task.priority === 'HIGH' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>{task.priority}</span>
                          <div className="flex -space-x-1.5">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-5 h-5 rounded-md border border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-snug group-hover:text-pink-600 transition-colors line-clamp-2">{task.title}</h4>
                      </div>
                    </div>
                  ))}

                  <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} className="w-full py-3 border border-dashed border-slate-300 rounded-xl text-slate-400 hover:text-pink-500 hover:border-pink-200 transition-all flex items-center justify-center gap-2 text-[9px] font-black uppercase tracking-widest bg-white/20">ADICIONAR</button>
                </div>
              </div>
            );
          })}
          {isAdmin && (<button onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} className="flex-shrink-0 w-80 h-16 bg-white/30 border border-dashed border-slate-300 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-white hover:text-slate-600 transition-all">NOVA LISTA</button>)}
        </div>
      </main>

      {/* Column Modal - Reusing the compact Design System */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-pop border border-slate-100" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b bg-white flex items-center justify-between">
                    <h3 className="text-lg font-bold text-slate-800 tracking-tight">Nova Lista</h3>
                  </div>
                  <div className="p-6 space-y-4">
                    <div>
                      <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Nome da Coluna</label>
                      <input className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-2 focus:ring-pink-100 focus:bg-white transition-all" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Ex: Aguardando Feedback" autoFocus />
                    </div>
                  </div>
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button onClick={() => setIsColumnModalOpen(false)} className="h-10 px-6 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600">Cancelar</button>
                    <button onClick={handleSaveColumn} className="h-10 px-8 bg-pink-600 hover:bg-pink-700 text-white font-bold text-[10px] uppercase tracking-widest rounded-xl">Salvar</button>
                  </div>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, ShoppingBag, DollarSign, Clock, Calendar, AlertTriangle, User as UserIcon, ChevronRight } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
  searchTerm: string;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions,
    searchTerm
}) => {
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');
  const [processingId, setProcessingId] = useState<string | null>(null);

  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  const displayedRequisitions = requisitions.filter(req => {
      const matchesFilter = filter === 'ALL' ? (canApprove || req.requesterId === currentUser.id) : req.requesterId === currentUser.id;
      const matchesSearch = req.title.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesFilter && matchesSearch;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) return;
      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };
      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove || req.status === 'APPROVED') return;
      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = { ...req, status: 'APPROVED', approvedBy: currentUser.id, approvedAt: now };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          if (req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}`,
                  description: `REQ Aprovada: ${req.title}`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }
          setProcessingId(null);
      }, 600);
  };

  const handleRejectReq = () => {
      if (!selectedReqForReject || !rejectionReason) return;
      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);
      setTimeout(() => {
