import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { TopBar } from './components/TopBar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, ConfirmOptions } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');

  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  const getViewTitle = () => {
    switch (currentView) {
      case 'dashboard': return 'Visão Geral';
      case 'kanban': return 'Tarefas (Kanban)';
      case 'productivity': return 'Produtividade';
      case 'requisitions': return 'Solicitações';
      case 'client-portal': return 'Meus Pedidos';
      case 'clients': return 'Gestão de Clientes';
      case 'catalog': return 'Produtos & Serviços';
      case 'teams': return 'Equipes & Squads';
      case 'crm': return 'CRM / Vendas';
      case 'finance': return 'Financeiro';
      case 'permissions': return 'Acessos (Admin)';
      case 'system-admin': return 'Config. Sistema';
      case 'help': return 'Central de Ajuda';
      case 'settings': return 'Configurações';
      default: return 'Sistema';
    }
  };

  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  return (
    <div className="flex h-screen bg-white">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={() => setCurrentUser(null)} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className="flex-1 flex flex-col h-full transition-all duration-300 ease-in-out relative overflow-hidden"
        style={{ marginLeft: !isMobile ? getSidebarWidth() : '0px' }}
      >
        <TopBar 
          title={getViewTitle()}
          currentUser={currentUser}
          unreadCount={unreadCount}
          searchTerm={searchTerm}
          onSearchChange={setSearchTerm}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} notifications={notifications} setNotifications={setNotifications} sidebarOpen={sidebarOpen} sidebarCompact={sidebarCompact} isMobile={isMobile} searchTerm={searchTerm} />}
            {/* Fix: Pass searchTerm and onSearchChange to CRM component */}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={['Instagram', 'Google']} setLeadSources={() => {}} currentUser={currentUser} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} searchTerm={searchTerm} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { Plus, Archive, Settings, Layout, Eye, EyeOff, Search } from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  searchTerm: string;
  // Nova prop para passar ações para o TopBar
  setExtraActions?: (actions: React.ReactNode) => void;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  searchTerm, setExtraActions
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';
  const activeColumns = useMemo(() => columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), [columns]);

  // Sincroniza as ações específicas com o TopBar no App.tsx
  useEffect(() => {
    if (setExtraActions) {
      setExtraActions(
        <div className="flex items-center gap-2">
            <button 
                onClick={() => setShowArchived(prev => !prev)} 
                className={`h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 border ${showArchived ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-400 border-slate-200 hover:border-pink-200 hover:text-pink-600'}`}
                title={showArchived ? "Ocultar Arquivados" : "Mostrar Arquivados"}
            >
                {showArchived ? <EyeOff size={14}/> : <Eye size={14}/>}
                <span className="hidden lg:inline">{showArchived ? 'Ocultar Arquivo' : 'Ver Arquivo'}</span>
            </button>

            <button 
                onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)}
                className="h-10 px-6 bg-pink-600 hover:bg-pink-700 text-white rounded-xl flex items-center gap-2 text-[10px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/20 transition-all hover:scale-[1.02] active:scale-95"
            >
                <Plus size={16} strokeWidth={3} /> NOVO JOB
            </button>
        </div>
      );
    }
    // Limpa as ações ao sair da tela
    return () => setExtraActions?.(null);
  }, [showArchived, activeColumns, currentUser.id]);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    else setColumns(prev => [...prev, { id: 'col-' + Date.now(), label: editingColumn.label, color: 'border-slate-400', order: columns.length, wipLimit: editingColumn.wipLimit || null, isArchived: false } as ColumnConfig]);
    setIsColumnModalOpen(false);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));
          if (targetColId === 'DONE') {
              confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          }
      }
      setDraggedTaskId(null);
  };

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      return exists ? prev.map(t => t.id === updatedTask.id ? updatedTask : t) : [...prev, updatedTask];
    });
    setSelectedTask(updatedTask);
  };

  return (
    <div className="h-full flex flex-col bg-[#fcfdfe] -m-4 md:-m-8">
      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-8 gap-8 items-start min-w-full">
          {activeColumns.map(col => {
            const colTasks = tasks.filter(t => 
                t.status === col.id && 
                (showArchived ? t.archived : !t.archived) && 
                t.title.toLowerCase().includes(searchTerm.toLowerCase())
            );

            return (
              <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()} 
                onDrop={e => handleDropTask(e, col.id)} 
                className="flex-shrink-0 w-[320px] flex flex-col max-h-full"
              >
                {/* Header da Coluna Integrado */}
                <div className="flex items-center justify-between mb-4 px-1">
                  <div className="flex items-center gap-3">
                    <h3 className="font-black text-[11px] uppercase tracking-[0.1em] text-slate-400">{col.label}</h3>
                    <span className="bg-slate-100 text-slate-500 text-[10px] px-2 py-0.5 rounded-full font-black border border-slate-200/50">
                        {colTasks.length}
                    </span>
                  </div>
                  {isAdmin && (
                    <button className="text-slate-300 hover:text-slate-500 transition-colors p-1">
                        <MoreHorizontal size={14}/>
                    </button>
                  )}
                </div>

                {/* Container de Cards Suave */}
                <div className="flex-1 bg-slate-100/40 rounded-2xl border border-slate-200/40 p-3 space-y-4 overflow-y-auto custom-scrollbar shadow-inner">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-xl shadow-[0_2px_10px_rgba(0,0,0,0.02)] border border-slate-200/60 cursor-grab active:cursor-grabbing transition-all group hover:shadow-xl hover:shadow-slate-200/50 hover:border-pink-200/50 overflow-hidden flex flex-col transform hover:-translate-y-0.5"
                    >
                      {task.coverType === 'color' && <div className="h-1.5 w-full" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />}
                      {task.coverType === 'image' && <img src={task.coverValue || ''} className="h-20 w-full object-cover border-b border-slate-100" alt="Capa" />}

                      <div className="p-4">
                        <div className="flex justify-between items-start mb-3">
                          <span className={`text-[9px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-tighter ${
                              task.priority === 'HIGH' ? 'bg-red-50 text-red-600' : 
                              task.priority === 'MEDIUM' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-500'
                          }`}>
                              {task.priority === 'HIGH' ? 'Urgente' : task.priority === 'MEDIUM' ? 'Média' : 'Baixa'}
                          </span>
                          <div className="flex -space-x-2">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-relaxed group-hover:text-pink-600 transition-colors line-clamp-2">
                            {task.title}
                        </h4>

                        {(task.checklists?.length > 0 || task.comments?.length > 0) && (
                            <div className="mt-4 flex items-center gap-3 text-slate-300">
                                {task.checklists?.length > 0 && (
                                    <div className="flex items-center gap-1">
                                        <CheckSquare size={12}/>
                                        <span className="text-[9px] font-bold">
                                            {task.checklists.filter(i => i.isCompleted).length}/{task.checklists.length}
                                        </span>
                                    </div>
                                )}
                                {task.comments?.length > 0 && (
                                    <div className="flex items-center gap-1">
                                        <MessageCircle size={12}/>
                                        <span className="text-[9px] font-bold">{task.comments.length}</span>
                                    </div>
                                )}
                            </div>
                        )}
                      </div>
                    </div>
                  ))}

                  <button 
                    onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} 
                    className="w-full py-4 border-2 border-dashed border-slate-200/60 rounded-xl text-slate-300 hover:text-pink-500 hover:border-pink-200 hover:bg-white transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest"
                  >
                      <Plus size={14}/> Adicionar
                  </button>
                </div>
              </div>
            );
          })}
          {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} 
                className="flex-shrink-0 w-[320px] h-[60px] bg-slate-100/50 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-white hover:border-pink-200 hover:text-pink-500 transition-all mt-[42px]"
            >
                <Plus size={18}/> Nova Lista
            </button>
          )}
        </div>
      </main>

      {/* Reutilizando Modais Compactos */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-pop border border-slate-100 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b bg-white flex items-center justify-between">
                    <h3 className="text-lg font-bold text-slate-800 tracking-tight">Nova Lista</h3>
                  </div>
                  <div className="p-6 space-y-4">
                    <div>
                      <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Nome da Coluna</label>
                      <input className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white transition-all border" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Ex: Aguardando Feedback" autoFocus />
                    </div>
                  </div>
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button onClick={() => setIsColumnModalOpen(false)} className="h-10 px-6 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600">Cancelar</button>
                    <button onClick={handleSaveColumn} className="h-10 px-8 bg-pink-600 hover:bg-pink-700 text-white font-bold text-[10px] uppercase tracking-widest rounded-xl">Salvar</button>
                  </div>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

// Ícone MoreHorizontal para cabeçalhos
const MoreHorizontal = ({size}: {size: number}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="1"/><circle cx="19" cy="12" r="1"/><circle cx="5" cy="12" r="1"/></svg>
);

// Ícones de status para os cards
const CheckSquare = ({size}: {size: number}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>
);

const MessageCircle = ({size}: {size: number}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
);

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { TopBar } from './components/TopBar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, ConfirmOptions } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');
  const [searchTerm, setSearchTerm] = useState('');
  const [extraActions, setExtraActions] = useState<React.ReactNode>(null);

  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;

  const getViewTitle = () => {
    switch (currentView) {
      case 'dashboard': return 'Visão Geral';
      case 'kanban': return 'Tarefas (Kanban)';
      case 'productivity': return 'Produtividade';
      case 'requisitions': return 'Solicitações';
      case 'client-portal': return 'Meus Pedidos';
      case 'clients': return 'Gestão de Clientes';
      case 'catalog': return 'Produtos & Serviços';
      case 'teams': return 'Equipes & Squads';
      case 'crm': return 'CRM / Vendas';
      case 'finance': return 'Financeiro';
      case 'permissions': return 'Acessos (Admin)';
      case 'system-admin': return 'Config. Sistema';
      case 'help': return 'Central de Ajuda';
      case 'settings': return 'Configurações';
      default: return 'Sistema';
    }
  };

  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };

  return (
    <div className="flex h-screen bg-white">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={() => setCurrentUser(null)} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className="flex-1 flex flex-col h-full transition-all duration-300 ease-in-out relative overflow-hidden"
        style={{ marginLeft: !isMobile ? getSidebarWidth() : '0px' }}
      >
        <TopBar 
          title={getViewTitle()}
          currentUser={currentUser}
          unreadCount={unreadCount}
          searchTerm={searchTerm}
          onSearchChange={setSearchTerm}
          actions={extraActions}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && <KanbanBoard tasks={tasks} setTasks={setTasks} users={users} currentUser={currentUser} columns={taskColumns} setColumns={setTaskColumns} openConfirm={openConfirm} notifications={notifications} setNotifications={setNotifications} searchTerm={searchTerm} setExtraActions={setExtraActions} />}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={['Instagram', 'Google']} setLeadSources={() => {}} currentUser={currentUser} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} searchTerm={searchTerm} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { Plus, Archive, Settings, Layout, Eye, EyeOff, Search, MoreHorizontal, ChevronLeft, ChevronRight, Edit3, Trash2 } from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  searchTerm: string;
  setExtraActions?: (actions: React.ReactNode) => void;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  searchTerm, setExtraActions
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';

  // Lógica de ordenação: Outras colunas ordenadas por 'order', 'Concluído' sempre por último
  const activeColumns = useMemo(() => {
    const active = columns.filter(c => !c.isArchived);
    const others = active.filter(c => c.id !== 'DONE').sort((a, b) => a.order - b.order);
    const doneCol = active.find(c => c.id === 'DONE');
    return doneCol ? [...others, doneCol] : others;
  }, [columns]);

  useEffect(() => {
    if (setExtraActions) {
      setExtraActions(
        <div className="flex items-center gap-2">
            <button 
                onClick={() => setShowArchived(prev => !prev)} 
                className={`h-10 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 border ${showArchived ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-400 border-slate-200 hover:border-pink-200 hover:text-pink-600'}`}
                title={showArchived ? "Ocultar Arquivados" : "Mostrar Arquivados"}
            >
                {showArchived ? <EyeOff size={14}/> : <Eye size={14}/>}
                <span className="hidden lg:inline">{showArchived ? 'Ocultar Arquivo' : 'Ver Arquivo'}</span>
            </button>

            <button 
                onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)}
                className="h-10 px-6 bg-pink-600 hover:bg-pink-700 text-white rounded-xl flex items-center gap-2 text-[10px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/20 transition-all hover:scale-[1.02] active:scale-95"
            >
                <Plus size={16} strokeWidth={3} /> NOVO JOB
            </button>
        </div>
      );
    }
    return () => setExtraActions?.(null);
  }, [showArchived, activeColumns, currentUser.id]);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
      setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
      setColumns(prev => [...prev, { 
        id: 'col-' + Date.now(), 
        label: editingColumn.label, 
        color: 'border-slate-400', 
        order: columns.length, 
        wipLimit: editingColumn.wipLimit || null, 
        isArchived: false 
      } as ColumnConfig]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleMoveColumn = (colId: string, direction: 'left' | 'right') => {
    if (colId === 'DONE') return; // DONE é fixo
    const sortedOthers = activeColumns.filter(c => c.id !== 'DONE');
    const index = sortedOthers.findIndex(c => c.id === colId);

    if (direction === 'left' && index > 0) {
      const newOthers = [...sortedOthers];
      [newOthers[index - 1], newOthers[index]] = [newOthers[index], newOthers[index - 1]];
      // Atualiza ordens
      const updated = columns.map(c => {
        const newIdx = newOthers.findIndex(no => no.id === c.id);
        return newIdx !== -1 ? { ...c, order: newIdx } : c;
      });
      setColumns(updated);
    } else if (direction === 'right' && index < sortedOthers.length - 1) {
      const newOthers = [...sortedOthers];
      [newOthers[index + 1], newOthers[index]] = [newOthers[index], newOthers[index + 1]];
      const updated = columns.map(c => {
        const newIdx = newOthers.findIndex(no => no.id === c.id);
        return newIdx !== -1 ? { ...c, order: newIdx } : c;
      });
      setColumns(updated);
    }
    setActiveMenuId(null);
  };

  const handleDeleteColumn = async (colId: string) => {
    if (colId === 'DONE') return;
    const hasTasks = tasks.some(t => t.status === colId);
    if (hasTasks) {
      alert("Não é possível excluir uma coluna que contém tarefas. Mova as tarefas primeiro.");
      return;
    }
    const ok = await openConfirm({
      title: "Excluir Coluna?",
      description: "Esta ação removerá a lista permanentemente.",
      variant: "danger"
    });
    if (ok) {
      setColumns(prev => prev.filter(c => c.id !== colId));
    }
    setActiveMenuId(null);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));
          if (targetColId === 'DONE') {
              confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          }
      }
      setDraggedTaskId(null);
  };

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      return exists ? prev.map(t => t.id === updatedTask.id ? updatedTask : t) : [...prev, updatedTask];
    });
    setSelectedTask(updatedTask);
  };

  return (
    <div className="h-full flex flex-col bg-[#fcfdfe] -m-4 md:-m-8">
      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-8 gap-8 items-start min-w-full">
          {activeColumns.map((col, index) => {
            const colTasks = tasks.filter(t => 
                t.status === col.id && 
                (showArchived ? t.archived : !t.archived) && 
                t.title.toLowerCase().includes(searchTerm.toLowerCase())
            );

            const isDoneCol = col.id === 'DONE';

            return (
              <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()} 
                onDrop={e => handleDropTask(e, col.id)} 
                className="flex-shrink-0 w-[320px] flex flex-col max-h-full"
              >
                {/* Header da Coluna Integrado */}
                <div className="flex items-center justify-between mb-4 px-1 relative">
                  <div className="flex items-center gap-3">
                    <h3 className="font-black text-[11px] uppercase tracking-[0.1em] text-slate-400">{col.label}</h3>
                    <span className="bg-slate-100 text-slate-500 text-[10px] px-2 py-0.5 rounded-full font-black border border-slate-200/50">
                        {colTasks.length}
                    </span>
                  </div>
                  {isAdmin && (
                    <div className="relative">
                      <button 
                        onClick={() => setActiveMenuId(activeMenuId === col.id ? null : col.id)}
                        className="text-slate-300 hover:text-slate-500 transition-colors p-1"
                      >
                        <MoreHorizontal size={14}/>
                      </button>

                      {activeMenuId === col.id && (
                        <div className="absolute right-0 top-8 w-48 bg-white border border-slate-100 rounded-xl shadow-xl z-50 p-2 animate-pop">
                            <button onClick={() => { setEditingColumn(col); setIsColumnModalOpen(true); setActiveMenuId(null); }} className="w-full text-left px-3 py-2 text-[10px] font-bold uppercase tracking-wider text-slate-600 hover:bg-slate-50 rounded-lg flex items-center gap-2">
                                <Edit3 size={14} className="text-blue-500"/> Renomear
                            </button>

                            {!isDoneCol && (
                              <>
                                <div className="flex border-y border-slate-50 my-1 py-1">
                                    <button 
                                      disabled={index === 0}
                                      onClick={() => handleMoveColumn(col.id, 'left')} 
                                      className="flex-1 p-2 hover:bg-slate-50 rounded-lg flex justify-center disabled:opacity-30"
                                    >
                                      <ChevronLeft size={16} className="text-slate-400"/>
                                    </button>
                                    <button 
                                      disabled={index === activeColumns.length - 2} // -2 porque a ultima é DONE fixa
                                      onClick={() => handleMoveColumn(col.id, 'right')} 
                                      className="flex-1 p-2 hover:bg-slate-50 rounded-lg flex justify-center disabled:opacity-30"
                                    >
                                      <ChevronRight size={16} className="text-slate-400"/>
                                    </button>
                                </div>
                                <button onClick={() => handleDeleteColumn(col.id)} className="w-full text-left px-3 py-2 text-[10px] font-bold uppercase tracking-wider text-red-600 hover:bg-red-50 rounded-lg flex items-center gap-2">
                                    <Trash2 size={14}/> Excluir
                                </button>
                              </>
                            )}
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {/* Container de Cards Suave */}
                <div className="flex-1 bg-slate-100/40 rounded-2xl border border-slate-200/40 p-3 space-y-4 overflow-y-auto custom-scrollbar shadow-inner">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-xl shadow-[0_2px_10px_rgba(0,0,0,0.02)] border border-slate-200/60 cursor-grab active:cursor-grabbing transition-all group hover:shadow-xl hover:shadow-slate-200/50 hover:border-pink-200/50 overflow-hidden flex flex-col transform hover:-translate-y-0.5"
                    >
                      {task.coverType === 'color' && <div className="h-1.5 w-full" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />}
                      {task.coverType === 'image' && <img src={task.coverValue || ''} className="h-20 w-full object-cover border-b border-slate-100" alt="Capa" />}

                      <div className="p-4">
                        <div className="flex justify-between items-start mb-3">
                          <span className={`text-[9px] font-black px-1.5 py-0.5 rounded-md uppercase tracking-tighter ${
                              task.priority === 'HIGH' ? 'bg-red-50 text-red-600' : 
                              task.priority === 'MEDIUM' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-500'
                          }`}>
                              {task.priority === 'HIGH' ? 'Urgente' : task.priority === 'MEDIUM' ? 'Média' : 'Baixa'}
                          </span>
                          <div className="flex -space-x-2">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-relaxed group-hover:text-pink-600 transition-colors line-clamp-2">
                            {task.title}
                        </h4>

                        {(task.checklists?.length > 0 || task.comments?.length > 0) && (
                            <div className="mt-4 flex items-center gap-3 text-slate-300">
                                {task.checklists?.length > 0 && (
                                    <div className="flex items-center gap-1">
                                        <CheckSquare size={12}/>
                                        <span className="text-[9px] font-bold">
                                            {task.checklists.filter(i => i.isCompleted).length}/{task.checklists.length}
                                        </span>
                                    </div>
                                )}
                                {task.comments?.length > 0 && (
                                    <div className="flex items-center gap-1">
                                        <MessageCircle size={12}/>
                                        <span className="text-[9px] font-bold">{task.comments.length}</span>
                                    </div>
                                )}
                            </div>
                        )}
                      </div>
                    </div>
                  ))}

                  <button 
                    onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} 
                    className="w-full py-4 border-2 border-dashed border-slate-200/60 rounded-xl text-slate-300 hover:text-pink-500 hover:border-pink-200 hover:bg-white transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest"
                  >
                      <Plus size={14}/> Adicionar
                  </button>
                </div>
              </div>
            );
          })}
          {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} 
                className="flex-shrink-0 w-[320px] h-[60px] bg-slate-100/50 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-white hover:border-pink-200 hover:text-pink-500 transition-all mt-[42px]"
            >
                <Plus size={18}/> Nova Lista
            </button>
          )}
        </div>
      </main>

      {/* Column Modal - Reused for Create and Edit */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[10000] flex items-center justify-center p-4 transition-all duration-300" onClick={() => { setIsColumnModalOpen(false); setEditingColumn(null); }}>
              <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-pop border border-slate-100 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b bg-white flex items-center justify-between">
                    <h3 className="text-lg font-bold text-slate-800 tracking-tight">{editingColumn?.id ? 'Editar Lista' : 'Nova Lista'}</h3>
                  </div>
                  <div className="p-6 space-y-4">
                    <div>
                      <label className="text-[10px] uppercase text-slate-400 font-bold mb-1 block tracking-widest ml-1">Nome da Coluna</label>
                      <input className="w-full bg-slate-50 border-none rounded-xl p-3.5 text-sm font-bold outline-none focus:ring-4 focus:ring-pink-500/5 focus:bg-white transition-all border" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Ex: Aguardando Feedback" autoFocus onKeyDown={(e) => e.key === 'Enter' && handleSaveColumn()} />
                    </div>
                  </div>
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button onClick={() => { setIsColumnModalOpen(false); setEditingColumn(null); }} className="h-10 px-6 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600">Cancelar</button>
                    <button onClick={handleSaveColumn} className="h-10 px-8 bg-pink-600 hover:bg-pink-700 text-white font-bold text-[10px] uppercase tracking-widest rounded-xl">Salvar</button>
                  </div>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

// Ícone MoreHorizontal para cabeçalhos (já definido internamente para simplicidade)
const CheckSquare = ({size}: {size: number}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>
);

const MessageCircle = ({size}: {size: number}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
);

import React, { useState, useMemo, useEffect } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { Plus, Eye, EyeOff, MoreHorizontal, ChevronLeft, ChevronRight, Edit3, Trash2, Clock, CheckSquare, MessageCircle } from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  searchTerm: string;
  setExtraActions?: (actions: React.ReactNode) => void;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, notifications, setNotifications, openConfirm,
  searchTerm, setExtraActions
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  const isAdmin = currentUser.role === 'ADMIN';

  const activeColumns = useMemo(() => {
    const active = columns.filter(c => !c.isArchived);
    const others = active.filter(c => c.id !== 'DONE').sort((a, b) => a.order - b.order);
    const doneCol = active.find(c => c.id === 'DONE');
    return doneCol ? [...others, doneCol] : others;
  }, [columns]);

  useEffect(() => {
    if (setExtraActions) {
      setExtraActions(
        <div className="flex items-center gap-3">
            <button 
                onClick={() => setShowArchived(prev => !prev)} 
                className={`h-10 px-4 rounded-xl text-[11px] font-bold uppercase tracking-wider transition-all flex items-center gap-2 border ${showArchived ? 'bg-slate-800 text-white border-slate-800 shadow-lg shadow-slate-200' : 'bg-white text-slate-500 border-slate-200 hover:border-pink-200 hover:text-pink-600 shadow-sm'}`}
            >
                {showArchived ? <EyeOff size={14}/> : <Eye size={14}/>}
                <span className="hidden lg:inline">{showArchived ? 'Ocultar Arquivo' : 'Ver Arquivo'}</span>
            </button>

            <button 
                onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)}
                className="h-10 px-6 bg-pink-600 hover:bg-pink-700 text-white rounded-xl flex items-center gap-2 text-[11px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/20 transition-all hover:scale-[1.02] active:scale-95"
            >
                <Plus size={16} strokeWidth={3} /> NOVO JOB
            </button>
        </div>
      );
    }
    return () => setExtraActions?.(null);
  }, [showArchived, activeColumns, currentUser.id]);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) {
      setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    } else {
      setColumns(prev => [...prev, { 
        id: 'col-' + Date.now(), 
        label: editingColumn.label, 
        color: 'border-slate-400', 
        order: columns.length, 
        wipLimit: editingColumn.wipLimit || null, 
        isArchived: false 
      } as ColumnConfig]);
    }
    setIsColumnModalOpen(false);
    setEditingColumn(null);
  };

  const handleMoveColumn = (colId: string, direction: 'left' | 'right') => {
    if (colId === 'DONE') return;
    const sortedOthers = activeColumns.filter(c => c.id !== 'DONE');
    const index = sortedOthers.findIndex(c => c.id === colId);

    if (direction === 'left' && index > 0) {
      const newOthers = [...sortedOthers];
      [newOthers[index - 1], newOthers[index]] = [newOthers[index], newOthers[index - 1]];
      const updated = columns.map(c => {
        const newIdx = newOthers.findIndex(no => no.id === c.id);
        return newIdx !== -1 ? { ...c, order: newIdx } : c;
      });
      setColumns(updated);
    } else if (direction === 'right' && index < sortedOthers.length - 1) {
      const newOthers = [...sortedOthers];
      [newOthers[index + 1], newOthers[index]] = [newOthers[index], newOthers[index + 1]];
      const updated = columns.map(c => {
        const newIdx = newOthers.findIndex(no => no.id === c.id);
        return newIdx !== -1 ? { ...c, order: newIdx } : c;
      });
      setColumns(updated);
    }
    setActiveMenuId(null);
  };

  const handleDeleteColumn = async (colId: string) => {
    if (colId === 'DONE') return;
    const hasTasks = tasks.some(t => t.status === colId);
    if (hasTasks) {
      alert("Não é possível excluir uma coluna que contém tarefas. Mova as tarefas primeiro.");
      return;
    }
    const ok = await openConfirm({
      title: "Excluir Coluna?",
      description: "Esta ação removerá a lista permanentemente.",
      variant: "danger"
    });
    if (ok) {
      setColumns(prev => prev.filter(c => c.id !== colId));
    }
    setActiveMenuId(null);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));
          if (targetColId === 'DONE') {
              confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          }
      }
      setDraggedTaskId(null);
  };

  const formatTime = (seconds: number) => {
    if (!seconds) return null;
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h ${m}m`;
  };

  return (
    <div className="h-full flex flex-col bg-slate-50/50 -m-4 md:-m-8">
      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
        <div className="inline-flex h-full p-6 md:p-10 gap-8 items-start min-w-full">
          {activeColumns.map((col, index) => {
            const colTasks = tasks.filter(t => 
                t.status === col.id && 
                (showArchived ? t.archived : !t.archived) && 
                t.title.toLowerCase().includes(searchTerm.toLowerCase())
            );

            const isDoneCol = col.id === 'DONE';

            return (
              <div 
                key={col.id} 
                onDragOver={e => e.preventDefault()} 
                onDrop={e => handleDropTask(e, col.id)} 
                className="flex-shrink-0 w-[300px] flex flex-col max-h-full group/col"
              >
                {/* Header Column */}
                <div className="flex items-center justify-between mb-5 px-1 relative">
                  <div className="flex items-center gap-3">
                    <div className={`w-1.5 h-1.5 rounded-full ${isDoneCol ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>
                    <h3 className="font-black text-[10px] uppercase tracking-[0.15em] text-slate-500">{col.label}</h3>
                    <span className="bg-slate-200/60 text-slate-600 text-[9px] px-2 py-0.5 rounded-full font-black border border-white shadow-sm">
                        {colTasks.length}
                    </span>
                  </div>
                  {isAdmin && (
                    <div className="relative">
                      <button 
                        onClick={() => setActiveMenuId(activeMenuId === col.id ? null : col.id)}
                        className="text-slate-300 hover:text-slate-600 transition-colors p-1"
                      >
                        <MoreHorizontal size={14}/>
                      </button>

                      {activeMenuId === col.id && (
                        <div className="absolute right-0 top-8 w-48 bg-white border border-slate-100 rounded-xl shadow-xl z-50 p-2 animate-pop">
                            <button onClick={() => { setEditingColumn(col); setIsColumnModalOpen(true); setActiveMenuId(null); }} className="w-full text-left px-3 py-2 text-[10px] font-bold uppercase tracking-wider text-slate-600 hover:bg-slate-50 rounded-lg flex items-center gap-2">
                                <Edit3 size={14} className="text-blue-500"/> Renomear
                            </button>

                            {!isDoneCol && (
                              <>
                                <div className="flex border-y border-slate-50 my-1 py-1">
                                    <button 
                                      disabled={index === 0}
                                      onClick={() => handleMoveColumn(col.id, 'left')} 
                                      className="flex-1 p-2 hover:bg-slate-50 rounded-lg flex justify-center disabled:opacity-20"
                                    >
                                      <ChevronLeft size={16} className="text-slate-400"/>
                                    </button>
                                    <button 
                                      disabled={index === activeColumns.length - 2}
                                      onClick={() => handleMoveColumn(col.id, 'right')} 
                                      className="flex-1 p-2 hover:bg-slate-50 rounded-lg flex justify-center disabled:opacity-20"
                                    >
                                      <ChevronRight size={16} className="text-slate-400"/>
                                    </button>
                                </div>
                                <button onClick={() => handleDeleteColumn(col.id)} className="w-full text-left px-3 py-2 text-[10px] font-bold uppercase tracking-wider text-red-600 hover:bg-red-50 rounded-lg flex items-center gap-2">
                                    <Trash2 size={14}/> Excluir
                                </button>
                              </>
                            )}
                        </div>
                      )}
                    </div>
                  )}
                </div>

                {/* Cards Container */}
                <div className="flex-1 bg-slate-200/30 rounded-[24px] border border-slate-200/50 p-3 space-y-3 overflow-y-auto custom-scrollbar shadow-inner relative">
                  {colTasks.map(task => {
                    const totalTime = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);

                    return (
                        <div 
                          key={task.id} 
                          draggable 
                          onDragStart={e => setDraggedTaskId(task.id)}
                          onClick={() => setSelectedTask(task)}
                          className="bg-white rounded-2xl shadow-[0_1px_3px_rgba(0,0,0,0.05)] border border-slate-200/80 cursor-grab active:cursor-grabbing transition-all group hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:border-pink-200 hover:-translate-y-1 overflow-hidden flex flex-col"
                        >
                          {task.coverType === 'color' && <div className="h-1.5 w-full" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />}
                          {task.coverType === 'image' && <img src={task.coverValue || ''} className="h-24 w-full object-cover border-b border-slate-100" alt="Capa" />}

                          <div className="p-4">
                            <div className="flex justify-between items-start mb-3">
                              <div className="flex items-center gap-1.5">
                                <div className={`w-2 h-2 rounded-full ${
                                    task.priority === 'HIGH' ? 'bg-red-500 animate-pulse' : 
                                    task.priority === 'MEDIUM' ? 'bg-blue-500' : 'bg-slate-300'
                                }`}></div>
                                <span className={`text-[9px] font-black uppercase tracking-tighter text-slate-400`}>
                                    {task.priority === 'HIGH' ? 'Urgente' : task.priority === 'MEDIUM' ? 'Média' : 'Baixa'}
                                </span>
                              </div>
                              <div className="flex -space-x-2.5">
                                {task.assigneeIds.slice(0, 3).map(id => (
                                  <img 
                                    key={id} 
                                    src={users.find(u => u.id === id)?.avatar} 
                                    className="w-6 h-6 rounded-full border-2 border-white shadow-sm object-cover" 
                                    title={users.find(u => u.id === id)?.name}
                                  />
                                ))}
                                {task.assigneeIds.length > 3 && (
                                    <div className="w-6 h-6 rounded-full border-2 border-white bg-slate-100 flex items-center justify-center text-[8px] font-black text-slate-500 shadow-sm">
                                        +{task.assigneeIds.length - 3}
                                    </div>
                                )}
                              </div>
                            </div>

                            <h4 className="text-[13px] font-bold text-slate-700 leading-snug group-hover:text-pink-600 transition-colors line-clamp-3 mb-4">
                                {task.title}
                            </h4>

                            {/* Card Footer Metrics */}
                            <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50">
                                <div className="flex items-center gap-3 text-slate-300">
                                    {(task.checklists?.length > 0) && (
                                        <div className="flex items-center gap-1">
                                            <CheckSquare size={12} className={task.checklists.every(i=>i.isCompleted) ? 'text-emerald-500' : ''}/>
                                            <span className="text-[9px] font-bold">
                                                {task.checklists.filter(i => i.isCompleted).length}/{task.checklists.length}
                                            </span>
                                        </div>
                                    )}
                                    {(task.comments?.length > 0) && (
                                        <div className="flex items-center gap-1">
                                            <MessageCircle size={12}/>
                                            <span className="text-[9px] font-bold">{task.comments.length}</span>
                                        </div>
                                    )}
                                </div>

                                {totalTime > 0 && (
                                    <div className="flex items-center gap-1 text-slate-400 bg-slate-50 px-2 py-0.5 rounded-lg border border-slate-100">
                                        <Clock size={10}/>
                                        <span className="text-[9px] font-black">{formatTime(totalTime)}</span>
                                    </div>
                                )}
                            </div>
                          </div>
                        </div>
                    );
                  })}

                  {/* Subtle Add Button */}
                  <button 
                    onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} 
                    className="w-full py-4 border-2 border-dashed border-slate-200/80 rounded-2xl text-slate-400 opacity-40 hover:opacity-100 hover:text-pink-500 hover:border-pink-200 hover:bg-white transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest"
                  >
                      <Plus size={14}/> Novo Job
                  </button>
                </div>
              </div>
            );
          })}
          {isAdmin && (
            <button 
                onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} 
                className="flex-shrink-0 w-[300px] h-[64px] bg-slate-200/20 border-2 border-dashed border-slate-200/60 rounded-[24px] flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-white hover:border-pink-200 hover:text-pink-500 transition-all mt-[48px] shadow-sm"
            >
                <Plus size={18}/> Nova Lista
            </button>
          )}
        </div>
      </main>

      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[10000] flex items-center justify-center p-4 transition-all duration-300" onClick={() => { setIsColumnModalOpen(false); setEditingColumn(null); }}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-pop border border-slate-100 overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-8 border-b bg-white flex items-center justify-between">
                    <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase">{editingColumn?.id ? 'Editar Lista' : 'Nova Lista'}</h3>
                  </div>
                  <div className="p-8 space-y-4">
                    <div>
                      <label className="text-[10px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">Nome da Coluna</label>
                      <input className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 focus:bg-white transition-all" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Ex: Aguardando Feedback" autoFocus onKeyDown={(e) => e.key === 'Enter' && handleSaveColumn()} />
                    </div>
                  </div>
                  <div className="p-6 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                    <button onClick={() => { setIsColumnModalOpen(false); setEditingColumn(null); }} className="h-11 px-6 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600">Cancelar</button>
                    <button onClick={handleSaveColumn} className="h-11 px-10 bg-slate-900 hover:bg-slate-800 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-xl shadow-slate-200">Salvar</button>
                  </div>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={(updated) => {
                setTasks(prev => prev.map(t => t.id === updated.id ? updated : t));
                setSelectedTask(updated);
            }} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, TimeLog, ConfirmOptions } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, 
    CheckSquare, Users, Layout, Upload, Check, Activity, Play, Pause, 
    Calendar, Save, Palette, Camera, Trash, MoreHorizontal, MessageCircle,
    UserPlus, Hash, AlignLeft, Info
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, openConfirm }) => {
    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [newChecklistText, setNewChecklistText] = useState('');
    const [newComment, setNewComment] = useState('');
    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVERS' | null>(null);
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [secondsElapsed, setSecondsElapsed] = useState(0);

    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Efeito para o Cronômetro em tempo real
    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                const activeLog = task.timeLogs.find(l => !l.endTime);
                if (activeLog) {
                    const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                    setSecondsElapsed(elapsed);
                }
            }, 1000);
        } else {
            setSecondsElapsed(0);
        }
        return () => clearInterval(interval);
    }, [task.isTracking, task.timeLogs]);

    // Fechar popovers ao clicar fora
    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) setActivePopover(null);
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const getAccumulatedSeconds = () => {
        const closed = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        return closed + secondsElapsed;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedProps: Partial<Task>, action: string) => {
        onUpdate({
            ...task,
            ...updatedProps,
            history: [...task.history, createLog(action)]
        });
    };

    const handleToggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    return { ...log, endTime: now, duration: Math.floor((now - log.startTime) / 1000) };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou o cronômetro');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou produção');
        }
    };

    const handleAddChecklist = () => {
        if (!newChecklistText.trim()) return;
        const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
        updateWithLog({ checklists: [...task.checklists, newItem] }, `adicionou sub-tarefa: ${newChecklistText}`);
        setNewChecklistText('');
    };

    const handleAddComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        updateWithLog({ comments: [...task.comments, comment] }, 'adicionou um comentário');
        setNewComment('');
    };

    const checklistProgress = task.checklists.length > 0 
        ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) 
        : 0;

    return (
        <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex justify-center items-start overflow-y-auto p-4 md:p-10 transition-all duration-300 backdrop-blur-sm" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-[28px] shadow-2xl overflow-hidden animate-pop border border-slate-100 flex flex-col" onClick={e => e.stopPropagation()}>

                {/* --- HEADER / CAPA --- */}
                <div className={`w-full h-40 relative transition-all duration-500 flex items-center justify-center ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? task.coverValue! : undefined }}>
                    {task.coverType === 'image' && <img src={task.coverValue!} alt="Capa" className="w-full h-full object-cover" />}

                    <button onClick={() => setActivePopover('COVERS')} className="absolute bottom-4 right-4 bg-white/90 hover:bg-white text-slate-800 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center gap-2 transition-all">
                        <ImageIcon size={14}/> {task.coverType ? 'Trocar Capa' : 'Adicionar Capa'}
                    </button>

                    <button onClick={onClose} className="absolute top-4 right-4 p-2 bg-black/10 hover:bg-black/20 rounded-full transition-colors text-white">
                        <X size={20}/>
                    </button>
                </div>

                <div className="flex flex-col md:flex-row flex-1 p-6 md:p-10 gap-10">
                    {/* --- COLUNA PRINCIPAL (ESQUERDA) --- */}
                    <div className="flex-1 space-y-10">
                        {/* Título */}
                        <div className="flex gap-4">
                            <Layout className="mt-1 text-slate-300 shrink-0" size={24}/>
                            <div className="flex-1">
                                <input 
                                    className="w-full text-2xl font-black text-slate-800 bg-transparent border-none focus:ring-0 p-0 outline-none placeholder:text-slate-200"
                                    value={localTitle}
                                    onChange={e => setLocalTitle(e.target.value)}
                                    onBlur={() => updateWithLog({ title: localTitle }, 'alterou o título')}
                                    placeholder="Título do Job..."
                                />
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                                    Em <span className="text-pink-600">{task.status}</span>
                                </p>
                            </div>
                        </div>

                        {/* Responsáveis (Mobile/Tablet view inline) */}
                        <div className="ml-10 flex flex-wrap gap-8">
                            {task.assigneeIds.length > 0 && (
                                <div>
                                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Responsáveis</h4>
                                    <div className="flex -space-x-2">
                                        {task.assigneeIds.map(id => {
                                            const u = users.find(user => user.id === id);
                                            return <img key={id} src={u?.avatar} title={u?.name} className="w-9 h-9 rounded-full border-2 border-white shadow-sm object-cover" />;
                                        })}
                                        <button onClick={() => setActivePopover('MEMBERS')} className="w-9 h-9 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-slate-400 hover:bg-slate-200 transition-colors">
                                            <Plus size={16}/>
                                        </button>
                                    </div>
                                </div>
                            )}
                            <div>
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Prazo Final</h4>
                                <input 
                                    type="date" 
                                    className="bg-slate-100 rounded-lg px-3 py-1.5 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-pink-500/20"
                                    value={task.dueDate}
                                    onChange={e => updateWithLog({ dueDate: e.target.value }, 'alterou a data de entrega')}
                                />
                            </div>
                        </div>

                        {/* Descrição */}
                        <div className="flex gap-4">
                            <AlignLeft className="mt-1 text-slate-300 shrink-0" size={24}/>
                            <div className="flex-1">
                                <h3 className="font-black text-[11px] text-slate-400 uppercase tracking-[0.2em] mb-4">Descrição do Briefing</h3>
                                {isEditingDesc ? (
                                    <div className="space-y-3 animate-pop">
                                        <textarea 
                                            className="w-full min-h-[150px] bg-slate-50 border-2 border-slate-200 rounded-2xl p-4 text-sm font-medium outline-none focus:border-pink-500 focus:bg-white transition-all"
                                            value={localDesc}
                                            onChange={e => setLocalDesc(e.target.value)}
                                            autoFocus
                                        />
                                        <div className="flex gap-2">
                                            <button onClick={() => { updateWithLog({ description: localDesc }, 'atualizou o briefing'); setIsEditingDesc(false); }} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg">Salvar</button>
                                            <button onClick={() => { setLocalDesc(task.description); setIsEditingDesc(false); }} className="px-4 py-2 text-slate-400 font-bold text-[10px] uppercase">Cancelar</button>
                                        </div>
                                    </div>
                                ) : (
                                    <div 
                                        onClick={() => setIsEditingDesc(true)}
                                        className="bg-slate-50/50 hover:bg-slate-100 rounded-2xl p-5 text-sm text-slate-600 leading-relaxed cursor-text min-h-[100px] border border-transparent hover:border-slate-200 transition-all whitespace-pre-wrap"
                                    >
                                        {task.description || "Adicione um briefing detalhado para o time..."}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Checklist */}
                        <div className="flex gap-4">
                            <CheckSquare className="mt-1 text-slate-300 shrink-0" size={24}/>
                            <div className="flex-1">
                                <div className="flex items-center justify-between mb-4">
                                    <h3 className="font-black text-[11px] text-slate-400 uppercase tracking-[0.2em]">Etapas de Produção</h3>
                                    <span className="text-[10px] font-black text-pink-600 bg-pink-50 px-2 py-0.5 rounded-full">{checklistProgress}%</span>
                                </div>

                                <div className="w-full bg-slate-100 h-2 rounded-full mb-6 overflow-hidden">
                                    <div className="h-full bg-pink-500 transition-all duration-700" style={{ width: `${checklistProgress}%` }} />
                                </div>

                                <div className="space-y-2 mb-6">
                                    {task.checklists.map(item => (
                                        <div key={item.id} className="flex items-center gap-3 group">
                                            <input 
                                                type="checkbox" 
                                                checked={item.isCompleted} 
                                                onChange={() => {
                                                    const updated = task.checklists.map(c => c.id === item.id ? { ...c, isCompleted: !c.isCompleted } : c);
                                                    onUpdate({ ...task, checklists: updated });
                                                    if (!item.isCompleted && updated.every(u => u.isCompleted)) {
                                                        confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
                                                    }
                                                }}
                                                className="w-5 h-5 rounded-lg border-2 border-slate-200 text-pink-600 focus:ring-pink-500/20 cursor-pointer"
                                            />
                                            <span className={`text-sm font-bold flex-1 ${item.isCompleted ? 'text-slate-300 line-through' : 'text-slate-700'}`}>{item.text}</span>
                                            <button onClick={() => updateWithLog({ checklists: task.checklists.filter(c => c.id !== item.id) }, 'removeu uma sub-tarefa')} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all"><Trash2 size={14}/></button>
                                        </div>
                                    ))}
                                </div>

                                <div className="flex gap-3">
                                    <input 
                                        className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-xs font-bold outline-none focus:border-pink-500 focus:bg-white transition-all"
                                        placeholder="Adicionar nova etapa..."
                                        value={newChecklistText}
                                        onChange={e => setNewChecklistText(e.target.value)}
                                        onKeyDown={e => e.key === 'Enter' && handleAddChecklist()}
                                    />
                                    <button onClick={handleAddChecklist} className="bg-slate-900 text-white px-5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg">Add</button>
                                </div>
                            </div>
                        </div>

                        {/* Atividades / Comentários */}
                        <div className="flex gap-4 pt-4">
                            <Activity className="mt-1 text-slate-300 shrink-0" size={24}/>
                            <div className="flex-1 space-y-6">
                                <h3 className="font-black text-[11px] text-slate-400 uppercase tracking-[0.2em]">Atividades & Chat</h3>

                                <div className="flex gap-3">
                                    <img src={currentUser.avatar} className="w-8 h-8 rounded-full border shadow-sm object-cover" />
                                    <div className="flex-1 space-y-2">
                                        <textarea 
                                            className="w-full bg-white border border-slate-200 rounded-2xl p-3 text-sm font-medium outline-none focus:border-pink-500 shadow-sm resize-none h-20"
                                            placeholder="Escreva um comentário ou atualização..."
                                            value={newComment}
                                            onChange={e => setNewComment(e.target.value)}
                                        />
                                        <button onClick={handleAddComment} className="px-5 py-2 bg-pink-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/10 hover:scale-[1.02] transition-all">Enviar</button>
                                    </div>
                                </div>

                                <div className="space-y-6 pt-4 border-t border-slate-50">
                                    {[...task.comments.map(c => ({...c, type: 'COMMENT'})), ...task.history.map(h => ({...h, type: 'LOG', text: h.action, userId: h.userId, timestamp: h.timestamp}))]
                                        .sort((a,b) => b.timestamp - a.timestamp)
                                        .map((item: any) => {
                                            const user = users.find(u => u.id === item.userId);
                                            return (
                                                <div key={item.id} className="flex gap-4 group">
                                                    <img src={user?.avatar} className="w-8 h-8 rounded-full border shadow-sm shrink-0" />
                                                    <div className="flex-1">
                                                        <div className="flex items-center gap-2 mb-1">
                                                            <span className="font-black text-[11px] text-slate-700">{user?.name}</span>
                                                            <span className="text-[9px] text-slate-400 font-bold">{new Date(item.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                        </div>
                                                        <div className={`text-sm ${item.type === 'LOG' ? 'text-slate-400 italic' : 'bg-slate-50 p-3 rounded-2xl rounded-tl-none text-slate-600 inline-block shadow-sm border border-slate-100'}`}>
                                                            {item.text}
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* --- SIDEBAR DE AÇÕES (DIREITA) --- */}
                    <div className="w-full md:w-[180px] space-y-8">
                        {/* Status do Tempo */}
                        <div className={`p-5 rounded-3xl transition-all shadow-xl ${task.isTracking ? 'bg-slate-900 ring-4 ring-pink-500/20' : 'bg-white border border-slate-100'}`}>
                            <p className={`text-[9px] font-black uppercase tracking-widest mb-3 flex items-center gap-2 ${task.isTracking ? 'text-pink-500' : 'text-slate-400'}`}>
                                <Clock size={12}/> {task.isTracking ? 'Produzindo Agora' : 'Tempo Acumulado'}
                            </p>
                            <h3 className={`text-2xl font-black font-mono tracking-tighter mb-4 ${task.isTracking ? 'text-white' : 'text-slate-800'}`}>
                                {formatSeconds(getAccumulatedSeconds())}
                            </h3>
                            <button 
                                onClick={handleToggleTimer}
                                className={`w-full py-3 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${
                                    task.isTracking 
                                    ? 'bg-amber-500 text-white shadow-amber-500/20 hover:bg-amber-600' 
                                    : 'bg-pink-600 text-white shadow-pink-600/20 hover:bg-pink-700'
                                }`}
                            >
                                {task.isTracking ? <Pause size={14} fill="currentColor"/> : <Play size={14} fill="currentColor"/>}
                                {task.isTracking ? 'Pausar' : 'Iniciar'}
                            </button>
                        </div>

                        {/* Botões de Ação */}
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-2">Adicionar ao Card</h4>
                            <button onClick={() => setActivePopover('MEMBERS')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border border-transparent hover:border-slate-200">
                                <UserPlus size={16} className="text-indigo-500"/> Membros
                            </button>
                            <button onClick={() => setActivePopover('COVERS')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border border-transparent hover:border-slate-200">
                                <Palette size={16} className="text-pink-500"/> Capa
                            </button>
                            <button className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border border-transparent hover:border-slate-200">
                                <Plus size={16} className="text-blue-500"/> Anexo
                            </button>
                        </div>

                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-2">Ações</h4>
                            <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'reativou o job' : 'arquivou o job')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all">
                                <Archive size={16}/> {task.archived ? 'Reativar' : 'Arquivar'}
                            </button>
                            <button onClick={async () => {
                                const ok = await openConfirm({ title: "Excluir Job?", description: "Esta ação é irreversível.", variant: "danger" });
                                if (ok) onDeleteTask(task.id);
                            }} className="w-full flex items-center gap-3 p-3 bg-red-50 hover:bg-red-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-red-600 transition-all border border-red-100">
                                <Trash2 size={16}/> Excluir
                            </button>
                        </div>

                        <div className="pt-4 mt-4 border-t border-slate-100 flex flex-col items-center">
                            <p className="text-[8px] font-black text-slate-300 uppercase mb-2">ID: {task.id}</p>
                            {task.status !== 'DONE' && (
                                <button 
                                    onClick={() => {
                                        updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job');
                                        confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                                        onClose();
                                    }}
                                    className="w-full py-4 bg-emerald-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-xl shadow-emerald-200 hover:bg-emerald-700 hover:-translate-y-1 transition-all"
                                >
                                    Concluir Job
                                </button>
                            )}
                        </div>
                    </div>
                </div>

                {/* --- POPOVERS DE SUPORTE --- */}
                {activePopover === 'COVERS' && (
                    <div ref={popoverRef} className="absolute top-52 right-10 w-56 bg-white rounded-3xl shadow-2xl border border-slate-100 p-5 animate-pop z-[10000]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b pb-2">Selecionar Cor</h5>
                        <div className="grid grid-cols-4 gap-3 mb-6">
                            {PRESET_COLORS.map(c => (
                                <button 
                                    key={c} 
                                    onClick={() => { updateWithLog({ coverType: 'color', coverValue: c }, 'mudou a cor da capa'); setActivePopover(null); }}
                                    className="w-8 h-8 rounded-full border-2 border-white shadow-sm hover:scale-125 transition-transform" 
                                    style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b pb-2">Imagem</h5>
                        <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-2 py-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 transition-all border-2 border-dashed border-slate-200">
                            <Camera size={16}/> Upload Foto
                        </button>
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) {
                                const reader = new FileReader();
                                reader.onloadend = () => {
                                    updateWithLog({ coverType: 'image', coverValue: reader.result as string }, 'subiu imagem de capa');
                                    setActivePopover(null);
                                };
                                reader.readAsDataURL(file);
                            }
                        }} />
                    </div>
                )}

                {activePopover === 'MEMBERS' && (
                    <div ref={popoverRef} className="absolute bottom-40 right-10 w-64 bg-white rounded-3xl shadow-2xl border border-slate-100 p-5 animate-pop z-[10000]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 border-b pb-2">Membros da Equipe</h5>
                        <div className="space-y-1 max-h-60 overflow-y-auto custom-scrollbar">
                            {users.filter(u => u.role !== 'CLIENT').map(u => (
                                <button 
                                    key={u.id} 
                                    onClick={() => {
                                        const current = task.assigneeIds;
                                        const newIds = current.includes(u.id) ? current.filter(id => id !== u.id) : [...current, u.id];
                                        updateWithLog({ assigneeIds: newIds }, current.includes(u.id) ? `removeu ${u.name}` : `adicionou ${u.name}`);
                                    }}
                                    className={`w-full flex items-center justify-between p-2.5 rounded-xl transition-all ${task.assigneeIds.includes(u.id) ? 'bg-indigo-50 text-indigo-700' : 'hover:bg-slate-50 text-slate-500'}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <img src={u.avatar} className="w-7 h-7 rounded-full object-cover border-2 border-white shadow-sm" />
                                        <span className="text-[11px] font-bold">{u.name}</span>
                                    </div>
                                    {task.assigneeIds.includes(u.id) && <Check size={14} strokeWidth={4}/>}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, TimeLog, ConfirmOptions } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, 
    CheckSquare, Users, Layout, Upload, Check, Activity, Play, Pause, 
    Calendar, Save, Palette, Camera, Trash, MoreHorizontal, MessageCircle,
    UserPlus, Hash, AlignLeft, Info, History
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, openConfirm }) => {
    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [newChecklistText, setNewChecklistText] = useState('');
    const [newComment, setNewComment] = useState('');
    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVERS' | null>(null);
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [secondsElapsed, setSecondsElapsed] = useState(0);
    const [activeTab, setActiveTab] = useState<'CHAT' | 'HISTORY'>('CHAT');

    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                const activeLog = task.timeLogs.find(l => !l.endTime);
                if (activeLog) {
                    const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                    setSecondsElapsed(elapsed);
                }
            }, 1000);
        } else {
            setSecondsElapsed(0);
        }
        return () => clearInterval(interval);
    }, [task.isTracking, task.timeLogs]);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) setActivePopover(null);
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const getAccumulatedSeconds = () => {
        const closed = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        return closed + secondsElapsed;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedProps: Partial<Task>, action: string | null) => {
        const updatedTask = {
            ...task,
            ...updatedProps,
        };
        if (action) {
            updatedTask.history = [...task.history, createLog(action)];
        }
        onUpdate(updatedTask);
    };

    const handleToggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    return { ...log, endTime: now, duration: Math.floor((now - log.startTime) / 1000) };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou o cronômetro');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou produção');
        }
    };

    const handleAddChecklist = () => {
        if (!newChecklistText.trim()) return;
        const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
        updateWithLog({ checklists: [...task.checklists, newItem] }, `adicionou sub-tarefa: ${newChecklistText}`);
        setNewChecklistText('');
    };

    const handleAddComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        // Atualiza sem adicionar log ao histórico para evitar redundância
        onUpdate({
            ...task,
            comments: [...task.comments, comment]
        });
        setNewComment('');
    };

    const checklistProgress = task.checklists.length > 0 
        ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) 
        : 0;

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[9999] flex justify-center items-start overflow-y-auto p-4 md:p-10 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-5xl rounded-[32px] shadow-2xl overflow-hidden animate-pop border border-slate-100 flex flex-col my-auto" onClick={e => e.stopPropagation()}>

                {/* --- HEADER / CAPA --- */}
                <div className={`w-full h-48 relative transition-all duration-500 flex items-center justify-center ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? task.coverValue! : undefined }}>
                    {task.coverType === 'image' && <img src={task.coverValue!} alt="Capa" className="w-full h-full object-cover" />}

                    <button onClick={() => setActivePopover('COVERS')} className="absolute bottom-6 right-6 bg-white/95 hover:bg-white text-slate-800 px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.1em] shadow-xl flex items-center gap-2 transition-all hover:scale-105 active:scale-95">
                        <Palette size={16} className="text-pink-600"/> {task.coverType ? 'Mudar Capa' : 'Add Capa'}
                    </button>

                    <button onClick={onClose} className="absolute top-6 right-6 p-2 bg-black/10 hover:bg-black/20 rounded-full transition-colors text-white backdrop-blur-md">
                        <X size={20}/>
                    </button>
                </div>

                <div className="flex flex-col md:flex-row flex-1 p-6 md:p-12 gap-12">
                    {/* --- COLUNA PRINCIPAL (ESQUERDA) --- */}
                    <div className="flex-1 space-y-12">
                        {/* Título e Status */}
                        <div className="flex gap-5">
                            <div className="p-3 bg-slate-100 rounded-2xl text-slate-400 h-fit">
                                <Layout size={24}/>
                            </div>
                            <div className="flex-1">
                                <input 
                                    className="w-full text-3xl font-black text-slate-800 bg-transparent border-none focus:ring-0 p-0 outline-none placeholder:text-slate-200 tracking-tight"
                                    value={localTitle}
                                    onChange={e => setLocalTitle(e.target.value)}
                                    onBlur={() => updateWithLog({ title: localTitle }, 'alterou o título')}
                                    placeholder="Nome da Tarefa..."
                                />
                                <div className="flex items-center gap-2 mt-2">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status:</span>
                                    <span className="text-[10px] font-black text-pink-600 bg-pink-50 px-2.5 py-1 rounded-lg uppercase tracking-widest">{task.status}</span>
                                </div>
                            </div>
                        </div>

                        {/* Metadados: Responsáveis e Data */}
                        <div className="ml-16 flex flex-wrap gap-12">
                            {task.assigneeIds.length > 0 && (
                                <div>
                                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Membros</h4>
                                    <div className="flex -space-x-3">
                                        {task.assigneeIds.map(id => {
                                            const u = users.find(user => user.id === id);
                                            return <img key={id} src={u?.avatar} title={u?.name} className="w-10 h-10 rounded-full border-4 border-white shadow-sm object-cover hover:translate-y-[-2px] transition-transform cursor-pointer" />;
                                        })}
                                        <button onClick={() => setActivePopover('MEMBERS')} className="w-10 h-10 rounded-full bg-slate-100 border-4 border-white flex items-center justify-center text-slate-400 hover:bg-slate-200 transition-colors shadow-sm">
                                            <Plus size={18}/>
                                        </button>
                                    </div>
                                </div>
                            )}
                            <div>
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Entrega</h4>
                                <div className="flex items-center gap-3 bg-slate-50 border border-slate-100 px-4 py-2 rounded-xl">
                                    <Calendar size={16} className="text-slate-400"/>
                                    <input 
                                        type="date" 
                                        className="bg-transparent text-xs font-black text-slate-700 outline-none"
                                        value={task.dueDate}
                                        onChange={e => updateWithLog({ dueDate: e.target.value }, 'alterou o prazo')}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Descrição / Briefing */}
                        <div className="flex gap-5">
                            <div className="p-3 bg-slate-100 rounded-2xl text-slate-400 h-fit">
                                <AlignLeft size={24}/>
                            </div>
                            <div className="flex-1">
                                <h3 className="font-black text-[11px] text-slate-400 uppercase tracking-[0.2em] mb-5">Briefing Detalhado</h3>
                                {isEditingDesc ? (
                                    <div className="space-y-4 animate-pop">
                                        <textarea 
                                            className="w-full min-h-[180px] bg-slate-50 border-2 border-slate-200 rounded-3xl p-6 text-sm font-medium outline-none focus:border-pink-500 focus:bg-white transition-all shadow-inner"
                                            value={localDesc}
                                            onChange={e => setLocalDesc(e.target.value)}
                                            autoFocus
                                            placeholder="Detalhe o que precisa ser feito..."
                                        />
                                        <div className="flex gap-3">
                                            <button onClick={() => { updateWithLog({ description: localDesc }, 'atualizou o briefing'); setIsEditingDesc(false); }} className="px-6 py-2.5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-slate-200">Salvar Briefing</button>
                                            <button onClick={() => { setLocalDesc(task.description); setIsEditingDesc(false); }} className="px-6 py-2.5 text-slate-400 font-bold text-[10px] uppercase tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
                                        </div>
                                    </div>
                                ) : (
                                    <div 
                                        onClick={() => setIsEditingDesc(true)}
                                        className="bg-slate-50/50 hover:bg-slate-100 rounded-3xl p-6 text-sm text-slate-600 leading-relaxed cursor-text min-h-[120px] border-2 border-transparent hover:border-slate-200 transition-all whitespace-pre-wrap font-medium shadow-sm"
                                    >
                                        {task.description || "Nenhuma instrução adicionada ainda. Clique para editar..."}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Checklist */}
                        <div className="flex gap-5">
                            <div className="p-3 bg-slate-100 rounded-2xl text-slate-400 h-fit">
                                <CheckSquare size={24}/>
                            </div>
                            <div className="flex-1">
                                <div className="flex items-center justify-between mb-5">
                                    <h3 className="font-black text-[11px] text-slate-400 uppercase tracking-[0.2em]">Checklist de Etapas</h3>
                                    <span className="text-[10px] font-black text-pink-600 bg-pink-50 px-3 py-1 rounded-full">{checklistProgress}%</span>
                                </div>

                                <div className="w-full bg-slate-100 h-3 rounded-full mb-8 overflow-hidden border border-white shadow-inner">
                                    <div className="h-full bg-gradient-to-r from-pink-500 to-pink-600 transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(219,39,119,0.3)]" style={{ width: `${checklistProgress}%` }} />
                                </div>

                                <div className="space-y-3 mb-8">
                                    {task.checklists.map(item => (
                                        <div key={item.id} className="flex items-center gap-4 group bg-slate-50/50 hover:bg-white p-3 rounded-2xl border border-transparent hover:border-slate-100 transition-all">
                                            <div className="relative flex items-center justify-center">
                                                <input 
                                                    type="checkbox" 
                                                    checked={item.isCompleted} 
                                                    onChange={() => {
                                                        const updated = task.checklists.map(c => c.id === item.id ? { ...c, isCompleted: !c.isCompleted } : c);
                                                        onUpdate({ ...task, checklists: updated });
                                                        if (!item.isCompleted && updated.every(u => u.isCompleted)) {
                                                            confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                                                        }
                                                    }}
                                                    className="w-6 h-6 rounded-lg border-2 border-slate-200 text-pink-600 focus:ring-pink-500/20 cursor-pointer appearance-none checked:bg-pink-600 checked:border-pink-600 transition-all"
                                                />
                                                {item.isCompleted && <Check size={14} className="absolute text-white pointer-events-none" strokeWidth={4}/>}
                                            </div>
                                            <span className={`text-sm font-bold flex-1 transition-all ${item.isCompleted ? 'text-slate-300 line-through' : 'text-slate-700'}`}>{item.text}</span>
                                            <button onClick={() => updateWithLog({ checklists: task.checklists.filter(c => c.id !== item.id) }, `removeu: ${item.text}`)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                                        </div>
                                    ))}
                                </div>

                                <div className="flex gap-4">
                                    <input 
                                        className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-xs font-bold outline-none focus:border-pink-500 focus:bg-white transition-all shadow-inner"
                                        placeholder="Add nova sub-tarefa..."
                                        value={newChecklistText}
                                        onChange={e => setNewChecklistText(e.target.value)}
                                        onKeyDown={e => e.key === 'Enter' && handleAddChecklist()}
                                    />
                                    <button onClick={handleAddChecklist} className="bg-slate-900 hover:bg-slate-800 text-white px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">Add</button>
                                </div>
                            </div>
                        </div>

                        {/* Sessão Dupla: Chat vs Histórico */}
                        <div className="flex gap-5 border-t border-slate-50 pt-10">
                            <div className="p-3 bg-slate-100 rounded-2xl text-slate-400 h-fit">
                                {activeTab === 'CHAT' ? <MessageCircle size={24}/> : <History size={24}/>}
                            </div>
                            <div className="flex-1 space-y-8">
                                <div className="flex items-center gap-6 border-b border-slate-50">
                                    <button 
                                        onClick={() => setActiveTab('CHAT')}
                                        className={`pb-4 text-[11px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'CHAT' ? 'text-pink-600 border-pink-600' : 'text-slate-300 border-transparent hover:text-slate-400'}`}
                                    >
                                        Conversa & Chat
                                    </button>
                                    <button 
                                        onClick={() => setActiveTab('HISTORY')}
                                        className={`pb-4 text-[11px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'HISTORY' ? 'text-pink-600 border-pink-600' : 'text-slate-300 border-transparent hover:text-slate-400'}`}
                                    >
                                        Histórico Técnico
                                    </button>
                                </div>

                                {activeTab === 'CHAT' ? (
                                    <div className="space-y-8 animate-pop">
                                        <div className="flex gap-4">
                                            <img src={currentUser.avatar} className="w-10 h-10 rounded-2xl border-2 border-white shadow-md object-cover" />
                                            <div className="flex-1 space-y-3">
                                                <textarea 
                                                    className="w-full bg-white border border-slate-200 rounded-3xl p-5 text-sm font-medium outline-none focus:border-pink-500 shadow-sm resize-none h-24 focus:shadow-xl focus:shadow-slate-100 transition-all"
                                                    placeholder="Escreva sua dúvida ou atualização para o time..."
                                                    value={newComment}
                                                    onChange={e => setNewComment(e.target.value)}
                                                />
                                                <button onClick={handleAddComment} className="px-8 py-2.5 bg-pink-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/20 hover:bg-pink-700 hover:-translate-y-0.5 transition-all active:scale-95">Enviar Mensagem</button>
                                            </div>
                                        </div>

                                        <div className="space-y-8 pt-4">
                                            {task.comments.sort((a,b) => b.timestamp - a.timestamp).map(comment => {
                                                const user = users.find(u => u.id === comment.userId);
                                                const isMe = comment.userId === currentUser.id;
                                                return (
                                                    <div key={comment.id} className={`flex gap-4 ${isMe ? 'flex-row-reverse' : ''} group`}>
                                                        <img src={user?.avatar} className="w-10 h-10 rounded-2xl border shadow-sm shrink-0 object-cover" />
                                                        <div className={`flex-1 max-w-[85%] ${isMe ? 'text-right' : ''}`}>
                                                            <div className={`flex items-center gap-2 mb-2 ${isMe ? 'justify-end' : ''}`}>
                                                                <span className="font-black text-[11px] text-slate-700 uppercase">{user?.name}</span>
                                                                <span className="text-[9px] text-slate-300 font-bold">{new Date(comment.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                            </div>
                                                            <div className={`text-sm p-4 rounded-3xl inline-block shadow-sm border ${isMe ? 'bg-slate-900 text-white border-slate-800 rounded-tr-none' : 'bg-slate-50 text-slate-700 border-slate-100 rounded-tl-none'}`}>
                                                                {comment.text}
                                                            </div>
                                                        </div>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                ) : (
                                    <div className="space-y-6 animate-pop max-h-[400px] overflow-y-auto pr-4 custom-scrollbar">
                                        {task.history.sort((a,b) => b.timestamp - a.timestamp).map(log => {
                                            const user = users.find(u => u.id === log.userId);
                                            return (
                                                <div key={log.id} className="flex gap-4 items-start pl-2 relative before:absolute before:left-[1.35rem] before:top-8 before:bottom-[-1.5rem] before:w-px before:bg-slate-100 last:before:hidden">
                                                    <img src={user?.avatar} className="w-7 h-7 rounded-lg border-2 border-white shadow-sm shrink-0 relative z-10" />
                                                    <div className="pt-0.5">
                                                        <p className="text-[13px] text-slate-500">
                                                            <span className="font-black text-slate-800 uppercase text-[10px] mr-1">{user?.name}</span> 
                                                            {log.action}
                                                        </p>
                                                        <span className="text-[9px] text-slate-300 font-black uppercase tracking-widest">{new Date(log.timestamp).toLocaleString()}</span>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                        {task.history.length === 0 && (
                                            <div className="text-center py-10 text-slate-300 italic text-sm font-medium">Nenhuma alteração registrada ainda.</div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* --- SIDEBAR DE AÇÕES (DIREITA) --- */}
                    <div className="w-full md:w-[220px] space-y-10">
                        {/* Timer Status Card */}
                        <div className={`p-6 rounded-[32px] transition-all duration-500 shadow-2xl ${task.isTracking ? 'bg-slate-900 ring-[8px] ring-pink-500/10' : 'bg-white border border-slate-100'}`}>
                            <div className="flex items-center justify-between mb-4">
                                <p className={`text-[9px] font-black uppercase tracking-widest flex items-center gap-2 ${task.isTracking ? 'text-pink-500' : 'text-slate-400'}`}>
                                    <Clock size={14} className={task.isTracking ? 'animate-spin-slow' : ''}/> {task.isTracking ? 'Job Online' : 'Timer Off'}
                                </p>
                                {task.isTracking && <span className="w-2 h-2 bg-pink-500 rounded-full animate-ping"></span>}
                            </div>
                            <h3 className={`text-3xl font-black font-mono tracking-tighter mb-6 ${task.isTracking ? 'text-white' : 'text-slate-800'}`}>
                                {formatSeconds(getAccumulatedSeconds())}
                            </h3>
                            <button 
                                onClick={handleToggleTimer}
                                className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 text-[11px] font-black uppercase tracking-[0.15em] transition-all shadow-xl active:scale-95 ${
                                    task.isTracking 
                                    ? 'bg-amber-500 text-white shadow-amber-500/30 hover:bg-amber-600' 
                                    : 'bg-pink-600 text-white shadow-pink-600/30 hover:bg-pink-700'
                                }`}
                            >
                                {task.isTracking ? <Pause size={16} fill="currentColor"/> : <Play size={16} fill="currentColor"/>}
                                {task.isTracking ? 'Pausar' : 'Iniciar'}
                            </button>
                        </div>

                        {/* Ações Rápidas */}
                        <div className="space-y-3">
                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2 mb-4">Adicionar</h4>
                            <button onClick={() => setActivePopover('MEMBERS')} className="w-full flex items-center gap-4 p-4 bg-slate-50 hover:bg-white rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm group">
                                <div className="p-1.5 bg-indigo-50 text-indigo-500 rounded-lg group-hover:bg-indigo-500 group-hover:text-white transition-all"><UserPlus size={16}/></div> 
                                Membros
                            </button>
                            <button onClick={() => setActivePopover('COVERS')} className="w-full flex items-center gap-4 p-4 bg-slate-50 hover:bg-white rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm group">
                                <div className="p-1.5 bg-pink-50 text-pink-500 rounded-lg group-hover:bg-pink-500 group-hover:text-white transition-all"><Palette size={16}/></div> 
                                Alterar Capa
                            </button>
                            <button className="w-full flex items-center gap-4 p-4 bg-slate-50 hover:bg-white rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm group">
                                <div className="p-1.5 bg-blue-50 text-blue-500 rounded-lg group-hover:bg-blue-500 group-hover:text-white transition-all"><Plus size={16}/></div> 
                                Anexo
                            </button>
                        </div>

                        <div className="space-y-3 pt-6 border-t border-slate-50">
                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2 mb-4">Operações</h4>
                            <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'reativou o job' : 'arquivou o job')} className="w-full flex items-center gap-4 p-4 bg-slate-50 hover:bg-white rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm">
                                <Archive size={18} className="text-slate-400"/> {task.archived ? 'Reativar' : 'Arquivar'}
                            </button>
                            <button onClick={async () => {
                                const ok = await openConfirm({ title: "Excluir Definitivo?", description: "Esta ação apagará todos os dados desta tarefa permanentemente.", variant: "danger" });
                                if (ok) onDeleteTask(task.id);
                            }} className="w-full flex items-center gap-4 p-4 bg-red-50/50 hover:bg-red-500 hover:text-white rounded-2xl text-[10px] font-black uppercase tracking-widest text-red-600 transition-all border-2 border-transparent shadow-sm group">
                                <Trash2 size={18} className="group-hover:text-white transition-colors"/> Excluir Job
                            </button>
                        </div>

                        <div className="pt-10 flex flex-col items-center">
                            {task.status !== 'DONE' && (
                                <button 
                                    onClick={() => {
                                        updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job');
                                        confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                                        onClose();
                                    }}
                                    className="w-full py-5 bg-emerald-600 text-white rounded-[24px] text-[12px] font-black uppercase tracking-[0.25em] shadow-2xl shadow-emerald-200 hover:bg-emerald-700 hover:-translate-y-1 transition-all active:scale-95"
                                >
                                    Concluir Agora
                                </button>
                            )}
                            <p className="text-[8px] font-black text-slate-300 uppercase mt-4 tracking-widest">ID: {task.id}</p>
                        </div>
                    </div>
                </div>

                {/* --- POPOVERS DE SUPORTE --- */}
                {activePopover === 'COVERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10000]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Paleta de Cores</h5>
                        <div className="grid grid-cols-4 gap-4 mb-8">
                            {PRESET_COLORS.map(c => (
                                <button 
                                    key={c} 
                                    onClick={() => { updateWithLog({ coverType: 'color', coverValue: c }, 'mudou a cor da capa'); setActivePopover(null); }}
                                    className="w-10 h-10 rounded-xl border-4 border-white shadow-sm hover:scale-125 transition-transform" 
                                    style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Referências</h5>
                        <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-500 transition-all border-2 border-dashed border-slate-200">
                            <Camera size={18}/> Upload Foto
                        </button>
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) {
                                const reader = new FileReader();
                                reader.onloadend = () => {
                                    updateWithLog({ coverType: 'image', coverValue: reader.result as string }, 'subiu imagem de capa');
                                    setActivePopover(null);
                                };
                                reader.readAsDataURL(file);
                            }
                        }} />
                    </div>
                )}

                {activePopover === 'MEMBERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-72 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10000]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Atribuir Membros</h5>
                        <div className="space-y-2 max-h-72 overflow-y-auto custom-scrollbar">
                            {users.filter(u => u.role !== 'CLIENT').map(u => (
                                <button 
                                    key={u.id} 
                                    onClick={() => {
                                        const current = task.assigneeIds;
                                        const newIds = current.includes(u.id) ? current.filter(id => id !== u.id) : [...current, u.id];
                                        updateWithLog({ assigneeIds: newIds }, current.includes(u.id) ? `removeu ${u.name}` : `atribuiu a tarefa para ${u.name}`);
                                    }}
                                    className={`w-full flex items-center justify-between p-3 rounded-2xl transition-all border-2 ${task.assigneeIds.includes(u.id) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'hover:bg-slate-50 text-slate-500 border-transparent'}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <img src={u.avatar} className="w-8 h-8 rounded-full object-cover border-2 border-white shadow-sm" />
                                        <span className="text-[11px] font-bold">{u.name}</span>
                                    </div>
                                    {task.assigneeIds.includes(u.id) && <div className="bg-indigo-600 p-1 rounded-full text-white"><Check size={12} strokeWidth={4}/></div>}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, TimeLog, ConfirmOptions } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, 
    CheckSquare, Users, Layout, Upload, Check, Activity, Play, Pause, 
    Calendar, Save, Palette, Camera, Trash, MoreHorizontal, MessageCircle,
    UserPlus, Hash, AlignLeft, Info, History, User as UserIcon
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, openConfirm }) => {
    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [newChecklistText, setNewChecklistText] = useState('');
    const [newComment, setNewComment] = useState('');
    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVERS' | string | null>(null);
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [secondsElapsed, setSecondsElapsed] = useState(0);
    const [activeTab, setActiveTab] = useState<'CHAT' | 'HISTORY'>('CHAT');

    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                const activeLog = task.timeLogs.find(l => !l.endTime);
                if (activeLog) {
                    const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                    setSecondsElapsed(elapsed);
                }
            }, 1000);
        } else {
            setSecondsElapsed(0);
        }
        return () => clearInterval(interval);
    }, [task.isTracking, task.timeLogs]);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) setActivePopover(null);
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const getAccumulatedSeconds = () => {
        const closed = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        return closed + secondsElapsed;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedProps: Partial<Task>, action: string | null) => {
        const updatedTask = {
            ...task,
            ...updatedProps,
        };
        if (action) {
            updatedTask.history = [...task.history, createLog(action)];
        }
        onUpdate(updatedTask);
    };

    const handleToggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    return { ...log, endTime: now, duration: Math.floor((now - log.startTime) / 1000) };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou o cronômetro');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou produção');
        }
    };

    const handleAddChecklist = () => {
        if (!newChecklistText.trim()) return;
        const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
        updateWithLog({ checklists: [...task.checklists, newItem] }, `adicionou sub-tarefa: ${newChecklistText}`);
        setNewChecklistText('');
    };

    const handleUpdateChecklistItem = (itemId: string, updates: Partial<ChecklistItem>) => {
        const updatedChecklists = task.checklists.map(c => c.id === itemId ? { ...c, ...updates } : c);
        onUpdate({ ...task, checklists: updatedChecklists });
    };

    const handleAddComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        onUpdate({
            ...task,
            comments: [...task.comments, comment]
        });
        setNewComment('');
    };

    const checklistProgress = task.checklists.length > 0 
        ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) 
        : 0;

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[9999] flex justify-center items-start overflow-y-auto p-2 md:p-6 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-[28px] shadow-2xl overflow-hidden animate-pop border border-slate-100 flex flex-col my-auto" onClick={e => e.stopPropagation()}>

                {/* --- HEADER / CAPA --- */}
                <div className={`w-full h-36 relative transition-all duration-500 flex items-center justify-center ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? task.coverValue! : undefined }}>
                    {task.coverType === 'image' && <img src={task.coverValue!} alt="Capa" className="w-full h-full object-cover" />}

                    <button onClick={() => setActivePopover('COVERS')} className="absolute bottom-4 right-4 bg-white/95 hover:bg-white text-slate-800 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-[0.1em] shadow-xl flex items-center gap-2 transition-all hover:scale-105 active:scale-95">
                        <Palette size={14} className="text-pink-600"/> {task.coverType ? 'Mudar Capa' : 'Add Capa'}
                    </button>

                    <button onClick={onClose} className="absolute top-4 right-4 p-2 bg-black/10 hover:bg-black/20 rounded-full transition-colors text-white backdrop-blur-md">
                        <X size={18}/>
                    </button>
                </div>

                <div className="flex flex-col md:flex-row flex-1 p-5 md:p-8 gap-8">
                    {/* --- COLUNA PRINCIPAL (ESQUERDA) --- */}
                    <div className="flex-1 space-y-8">
                        {/* Título e Status */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit">
                                <Layout size={20}/>
                            </div>
                            <div className="flex-1">
                                <input 
                                    className="w-full text-2xl font-black text-slate-800 bg-transparent border-none focus:ring-0 p-0 outline-none placeholder:text-slate-200 tracking-tight"
                                    value={localTitle}
                                    onChange={e => setLocalTitle(e.target.value)}
                                    onBlur={() => updateWithLog({ title: localTitle }, 'alterou o título')}
                                    placeholder="Nome da Tarefa..."
                                />
                                <div className="flex items-center gap-2 mt-1">
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status:</span>
                                    <span className="text-[9px] font-black text-pink-600 bg-pink-50 px-2 py-0.5 rounded-lg uppercase tracking-widest">{task.status}</span>
                                </div>
                            </div>
                        </div>

                        {/* Metadados: Responsáveis e Data */}
                        <div className="ml-14 flex flex-wrap gap-8">
                            {task.assigneeIds.length > 0 && (
                                <div>
                                    <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Membros</h4>
                                    <div className="flex -space-x-2.5">
                                        {task.assigneeIds.map(id => {
                                            const u = users.find(user => user.id === id);
                                            return <img key={id} src={u?.avatar} title={u?.name} className="w-8 h-8 rounded-full border-2 border-white shadow-sm object-cover hover:translate-y-[-2px] transition-transform cursor-pointer" />;
                                        })}
                                        <button onClick={() => setActivePopover('MEMBERS')} className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-slate-400 hover:bg-slate-200 transition-colors shadow-sm">
                                            <Plus size={14}/>
                                        </button>
                                    </div>
                                </div>
                            )}
                            <div>
                                <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Entrega</h4>
                                <div className="flex items-center gap-2 bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-xl">
                                    <Calendar size={14} className="text-slate-400"/>
                                    <input 
                                        type="date" 
                                        className="bg-transparent text-[11px] font-black text-slate-700 outline-none"
                                        value={task.dueDate}
                                        onChange={e => updateWithLog({ dueDate: e.target.value }, 'alterou o prazo')}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Descrição / Briefing */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit">
                                <AlignLeft size={20}/>
                            </div>
                            <div className="flex-1">
                                <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-[0.2em] mb-3">Briefing Detalhado</h3>
                                {isEditingDesc ? (
                                    <div className="space-y-3 animate-pop">
                                        <textarea 
                                            className="w-full min-h-[120px] bg-slate-50 border-2 border-slate-200 rounded-2xl p-4 text-xs font-medium outline-none focus:border-pink-500 focus:bg-white transition-all shadow-inner"
                                            value={localDesc}
                                            onChange={e => setLocalDesc(e.target.value)}
                                            autoFocus
                                            placeholder="Detalhe o que precisa ser feito..."
                                        />
                                        <div className="flex gap-2">
                                            <button onClick={() => { updateWithLog({ description: localDesc }, 'atualizou o briefing'); setIsEditingDesc(false); }} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-slate-200">Salvar</button>
                                            <button onClick={() => { setLocalDesc(task.description); setIsEditingDesc(false); }} className="px-4 py-2 text-slate-400 font-bold text-[9px] uppercase tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
                                        </div>
                                    </div>
                                ) : (
                                    <div 
                                        onClick={() => setIsEditingDesc(true)}
                                        className="bg-slate-50/50 hover:bg-slate-100 rounded-2xl p-4 text-xs text-slate-600 leading-relaxed cursor-text min-h-[80px] border-2 border-transparent hover:border-slate-200 transition-all whitespace-pre-wrap font-medium shadow-sm"
                                    >
                                        {task.description || "Adicione instruções para o time..."}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Checklist */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit">
                                <CheckSquare size={20}/>
