                            <button 
                                onClick={handleToggleTimer}
                                className={`w-full py-3 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-[0.15em] transition-all shadow-xl active:scale-95 ${
                                    task.isTracking 
                                    ? 'bg-amber-500 text-white shadow-amber-500/30 hover:bg-amber-600' 
                                    : 'bg-pink-600 text-white shadow-pink-600/30 hover:bg-pink-700'
                                }`}
                            >
                                {task.isTracking ? <Pause size={14} fill="currentColor"/> : <Play size={14} fill="currentColor"/>}
