                            </button>
                        </div>

                        <div className="pt-6 flex flex-col items-center">
                            {task.status !== 'DONE' && (
                                <button 
                                    onClick={() => {
                                        updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job');
                                        confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                                        onClose();
                                    }}
                                    className="w-full py-4 bg-emerald-600 text-white rounded-[20px] text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl shadow-emerald-200 hover:bg-emerald-700 hover:-translate-y-1 transition-all active:scale-95"
                                >
                                    Concluir
                                </button>
                            )}
                            <p className="text-[7px] font-black text-slate-300 uppercase mt-3 tracking-widest">ID: {task.id}</p>
                        </div>
                    </div>
                </div>

                {/* --- POPOVERS DE SUPORTE --- */}
                {activePopover === 'COVERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10002]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Paleta de Cores</h5>
                        <div className="grid grid-cols-4 gap-4 mb-8">
                            {PRESET_COLORS.map(c => (
                                <button 
                                    key={c} 
                                    onClick={() => { updateWithLog({ coverType: 'color', coverValue: c }, 'mudou a cor da capa'); setActivePopover(null); }}
                                    className="w-10 h-10 rounded-xl border-4 border-white shadow-sm hover:scale-125 transition-transform" 
                                    style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Referências</h5>
                        <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-500 transition-all border-2 border-dashed border-slate-200">
                            <Camera size={18}/> Upload Foto
                        </button>
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) {
                                const reader = new FileReader();
                                reader.onloadend = () => {
                                    updateWithLog({ coverType: 'image', coverValue: reader.result as string }, 'subiu imagem de capa');
                                    setActivePopover(null);
                                };
                                reader.readAsDataURL(file);
                            }
                        }} />
                    </div>
                )}

                {activePopover === 'MEMBERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-72 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10002]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Atribuir Membros</h5>
                        <div className="space-y-2 max-h-72 overflow-y-auto custom-scrollbar">
                            {users.filter(u => u.role !== 'CLIENT').map(u => (
                                <button 
                                    key={u.id} 
                                    onClick={() => {
                                        const current = task.assigneeIds;
                                        const newIds = current.includes(u.id) ? current.filter(id => id !== u.id) : [...current, u.id];
                                        updateWithLog({ assigneeIds: newIds }, current.includes(u.id) ? `removeu ${u.name}` : `atribuiu a tarefa para ${u.name}`);
                                    }}
                                    className={`w-full flex items-center justify-between p-3 rounded-2xl transition-all border-2 ${task.assigneeIds.includes(u.id) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'hover:bg-slate-50 text-slate-500 border-transparent'}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <img src={u.avatar} className="w-8 h-8 rounded-full object-cover border-2 border-white shadow-sm" />
                                        <span className="text-[11px] font-bold">{u.name}</span>
                                    </div>
                                    {task.assigneeIds.includes(u.id) && <div className="bg-indigo-600 p-1 rounded-full text-white"><Check size={12} strokeWidth={4}/></div>}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { Task, User, Comment, ChecklistItem, HistoryLog, TimeLog, ConfirmOptions } from '../types';
import { 
    Clock, Plus, CheckCircle, X, Trash2, Archive, Image as ImageIcon, 
    CheckSquare, Users, Layout, Upload, Check, Activity, Play, Pause, 
    Calendar, Save, Palette, Camera, Trash, MoreHorizontal, MessageCircle,
    UserPlus, Hash, AlignLeft, Info, History, User as UserIcon, AtSign
} from 'lucide-react';
import confetti from 'canvas-confetti';

interface TaskModalProps {
    task: Task;
    users: User[];
    onClose: () => void;
    onUpdate: (t: Task) => void;
    onDeleteTask: (id: string) => void;
    currentUser: User;
    openConfirm: (options: ConfirmOptions) => Promise<boolean>;
}

const PRESET_COLORS = ['#db2777', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#0f172a', '#64748b', '#ec4899', '#6366f1'];

export const TaskModal: React.FC<TaskModalProps> = ({ task, users, onClose, onUpdate, onDeleteTask, currentUser, openConfirm }) => {
    const [localTitle, setLocalTitle] = useState(task.title);
    const [localDesc, setLocalDesc] = useState(task.description);
    const [newChecklistText, setNewChecklistText] = useState('');
    const [newComment, setNewComment] = useState('');
    const [activePopover, setActivePopover] = useState<'MEMBERS' | 'COVERS' | string | null>(null);
    const [isEditingDesc, setIsEditingDesc] = useState(false);
    const [secondsElapsed, setSecondsElapsed] = useState(0);
    const [activeTab, setActiveTab] = useState<'CHAT' | 'HISTORY'>('CHAT');

    // Estados para Menção
    const [mentionSearch, setMentionSearch] = useState('');
    const [showMentionFor, setShowMentionFor] = useState<'DESC' | 'CHAT' | null>(null);

    const popoverRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const descTextareaRef = useRef<HTMLTextAreaElement>(null);
    const chatTextareaRef = useRef<HTMLTextAreaElement>(null);

    useEffect(() => {
        let interval: any;
        if (task.isTracking) {
            interval = setInterval(() => {
                const activeLog = task.timeLogs.find(l => !l.endTime);
                if (activeLog) {
                    const elapsed = Math.floor((Date.now() - activeLog.startTime) / 1000);
                    setSecondsElapsed(elapsed);
                }
            }, 1000);
        } else {
            setSecondsElapsed(0);
        }
        return () => clearInterval(interval);
    }, [task.isTracking, task.timeLogs]);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
                setActivePopover(null);
                setShowMentionFor(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleTextChangeWithMention = (
        text: string, 
        setter: (v: string) => void, 
        type: 'DESC' | 'CHAT',
        cursorPos: number
    ) => {
        setter(text);

        // Pega o texto antes do cursor para ver se termina com @ ou @filtro
        const textBeforeCursor = text.slice(0, cursorPos);
        const mentionMatch = textBeforeCursor.match(/@(\w*)$/);

        if (mentionMatch) {
            setMentionSearch(mentionMatch[1].toLowerCase());
            setShowMentionFor(type);
        } else {
            setShowMentionFor(null);
        }
    };

    const insertMention = (user: User, type: 'DESC' | 'CHAT') => {
        const setter = type === 'DESC' ? setLocalDesc : setNewComment;
        const currentText = type === 'DESC' ? localDesc : newComment;
        const ref = type === 'DESC' ? descTextareaRef : chatTextareaRef;

        if (!ref.current) return;

        const cursorPos = ref.current.selectionStart;
        const textBefore = currentText.slice(0, cursorPos);
        const textAfter = currentText.slice(cursorPos);

        // Substitui o @filtro pelo nome do usuário
        const newTextBefore = textBefore.replace(/@(\w*)$/, `@${user.name} `);
        setter(newTextBefore + textAfter);
        setShowMentionFor(null);

        // Devolve o foco
        setTimeout(() => ref.current?.focus(), 0);
    };

    const filteredMentionUsers = users.filter(u => 
        u.role !== 'CLIENT' && 
        u.name.toLowerCase().includes(mentionSearch)
    );

    const formatSeconds = (totalSeconds: number) => {
        const h = Math.floor(totalSeconds / 3600);
        const m = Math.floor((totalSeconds % 3600) / 60);
        const s = totalSeconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const getAccumulatedSeconds = () => {
        const closed = task.timeLogs.reduce((acc, log) => acc + (log.duration || 0), 0);
        return closed + secondsElapsed;
    };

    const createLog = (action: string): HistoryLog => ({
        id: Date.now().toString(),
        action,
        userId: currentUser.id,
        timestamp: Date.now()
    });

    const updateWithLog = (updatedProps: Partial<Task>, action: string | null) => {
        const updatedTask = { ...task, ...updatedProps };
        if (action) {
            updatedTask.history = [...task.history, createLog(action)];
        }
        onUpdate(updatedTask);
    };

    const handleToggleTimer = () => {
        const now = Date.now();
        if (task.isTracking) {
            const updatedLogs = task.timeLogs.map(log => {
                if (!log.endTime) {
                    return { ...log, endTime: now, duration: Math.floor((now - log.startTime) / 1000) };
                }
                return log;
            });
            updateWithLog({ isTracking: false, timeLogs: updatedLogs }, 'pausou o cronômetro');
        } else {
            const newLog: TimeLog = { userId: currentUser.id, startTime: now, duration: 0 };
            updateWithLog({ isTracking: true, status: 'IN_PROGRESS', timeLogs: [...task.timeLogs, newLog] }, 'iniciou produção');
        }
    };

    const handleAddChecklist = () => {
        if (!newChecklistText.trim()) return;
        const newItem: ChecklistItem = { id: Date.now().toString(), text: newChecklistText, isCompleted: false };
        updateWithLog({ checklists: [...task.checklists, newItem] }, `adicionou sub-tarefa: ${newChecklistText}`);
        setNewChecklistText('');
    };

    const handleUpdateChecklistItem = (itemId: string, updates: Partial<ChecklistItem>) => {
        const updatedChecklists = task.checklists.map(c => c.id === itemId ? { ...c, ...updates } : c);
        onUpdate({ ...task, checklists: updatedChecklists });
    };

    const handleAddComment = () => {
        if (!newComment.trim()) return;
        const comment: Comment = { id: Date.now().toString(), userId: currentUser.id, text: newComment, timestamp: Date.now() };
        onUpdate({ ...task, comments: [...task.comments, comment] });
        setNewComment('');
    };

    const checklistProgress = task.checklists.length > 0 
        ? Math.round((task.checklists.filter(c => c.isCompleted).length / task.checklists.length) * 100) 
        : 0;

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[9999] flex justify-center items-start overflow-y-auto p-2 md:p-6 transition-all duration-300" onClick={onClose}>
            <div className="bg-white w-full max-w-4xl rounded-[28px] shadow-2xl overflow-hidden animate-pop border border-slate-100 flex flex-col my-auto" onClick={e => e.stopPropagation()}>

                {/* --- HEADER / CAPA --- */}
                <div className={`w-full h-36 relative transition-all duration-500 flex items-center justify-center ${!task.coverType ? 'bg-slate-100' : ''}`} style={{ backgroundColor: task.coverType === 'color' ? task.coverValue! : undefined }}>
                    {task.coverType === 'image' && <img src={task.coverValue!} alt="Capa" className="w-full h-full object-cover" />}
                    <button onClick={() => setActivePopover('COVERS')} className="absolute bottom-4 right-4 bg-white/95 hover:bg-white text-slate-800 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-[0.1em] shadow-xl flex items-center gap-2 transition-all hover:scale-105 active:scale-95">
                        <Palette size={14} className="text-pink-600"/> {task.coverType ? 'Mudar Capa' : 'Add Capa'}
                    </button>
                    <button onClick={onClose} className="absolute top-4 right-4 p-2 bg-black/10 hover:bg-black/20 rounded-full transition-colors text-white backdrop-blur-md"><X size={18}/></button>
                </div>

                <div className="flex flex-col md:flex-row flex-1 p-5 md:p-8 gap-8">
                    {/* --- COLUNA PRINCIPAL (ESQUERDA) --- */}
                    <div className="flex-1 space-y-8">
                        {/* Título */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit"><Layout size={20}/></div>
                            <div className="flex-1">
                                <input className="w-full text-2xl font-black text-slate-800 bg-transparent border-none focus:ring-0 p-0 outline-none placeholder:text-slate-200 tracking-tight" value={localTitle} onChange={e => setLocalTitle(e.target.value)} onBlur={() => updateWithLog({ title: localTitle }, 'alterou o título')} placeholder="Nome da Tarefa..."/>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status:</span>
                                    <span className="text-[9px] font-black text-pink-600 bg-pink-50 px-2.5 py-0.5 rounded-lg uppercase tracking-widest">{task.status}</span>
                                </div>
                            </div>
                        </div>

                        {/* Metadados */}
                        <div className="ml-14 flex flex-wrap gap-8">
                            {task.assigneeIds.length > 0 && (
                                <div>
                                    <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Membros</h4>
                                    <div className="flex -space-x-2.5">
                                        {task.assigneeIds.map(id => {
                                            const u = users.find(user => user.id === id);
                                            return <img key={id} src={u?.avatar} title={u?.name} className="w-8 h-8 rounded-full border-2 border-white shadow-sm object-cover hover:translate-y-[-2px] transition-transform cursor-pointer" />;
                                        })}
                                        <button onClick={() => setActivePopover('MEMBERS')} className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-slate-400 hover:bg-slate-200 transition-colors shadow-sm"><Plus size={14}/></button>
                                    </div>
                                </div>
                            )}
                            <div>
                                <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Entrega</h4>
                                <div className="flex items-center gap-2 bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-xl">
                                    <Calendar size={14} className="text-slate-400"/>
                                    <input type="date" className="bg-transparent text-[11px] font-black text-slate-700 outline-none" value={task.dueDate} onChange={e => updateWithLog({ dueDate: e.target.value }, 'alterou o prazo')}/>
                                </div>
                            </div>
                        </div>

                        {/* Descrição / Briefing com MENÇÃO */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit"><AlignLeft size={20}/></div>
                            <div className="flex-1 relative">
                                <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-[0.2em] mb-3">Briefing Detalhado</h3>
                                {isEditingDesc ? (
                                    <div className="space-y-3 animate-pop">
                                        <div className="relative">
                                            <textarea 
                                                ref={descTextareaRef}
                                                className="w-full min-h-[120px] bg-slate-50 border-2 border-slate-200 rounded-2xl p-4 text-xs font-medium outline-none focus:border-pink-500 focus:bg-white transition-all shadow-inner"
                                                value={localDesc}
                                                onChange={e => handleTextChangeWithMention(e.target.value, setLocalDesc, 'DESC', e.target.selectionStart)}
                                                autoFocus
                                                placeholder="Detalhe o briefing (use @ para citar)..."
                                            />
                                            {showMentionFor === 'DESC' && (
                                                <div className="absolute top-full left-0 z-[10005] mt-1 w-64 bg-white rounded-xl shadow-2xl border border-slate-100 p-2 animate-pop">
                                                    <p className="text-[8px] font-black text-slate-400 uppercase p-2 border-b">Citar Colaborador</p>
                                                    <div className="max-h-48 overflow-y-auto custom-scrollbar mt-1">
                                                        {filteredMentionUsers.map(u => (
                                                            <button key={u.id} onClick={() => insertMention(u, 'DESC')} className="w-full flex items-center gap-2 p-2 hover:bg-slate-50 rounded-lg text-left transition-colors">
                                                                <img src={u.avatar} className="w-6 h-6 rounded-full object-cover border" />
                                                                <span className="text-[10px] font-bold text-slate-700">{u.name}</span>
                                                            </button>
                                                        ))}
                                                        {filteredMentionUsers.length === 0 && <p className="p-3 text-[10px] text-slate-400 italic">Nenhum membro encontrado</p>}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                        <div className="flex gap-2">
                                            <button onClick={() => { updateWithLog({ description: localDesc }, 'atualizou o briefing'); setIsEditingDesc(false); }} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-slate-200">Salvar</button>
                                            <button onClick={() => { setLocalDesc(task.description); setIsEditingDesc(false); }} className="px-4 py-2 text-slate-400 font-bold text-[9px] uppercase tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
                                        </div>
                                    </div>
                                ) : (
                                    <div onClick={() => setIsEditingDesc(true)} className="bg-slate-50/50 hover:bg-slate-100 rounded-2xl p-4 text-xs text-slate-600 leading-relaxed cursor-text min-h-[80px] border-2 border-transparent hover:border-slate-200 transition-all whitespace-pre-wrap font-medium shadow-sm">
                                        {localDesc || "Adicione instruções (use @ para citar alguém)..."}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Checklist */}
                        <div className="flex gap-4">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit"><CheckSquare size={20}/></div>
                            <div className="flex-1">
                                <div className="flex items-center justify-between mb-3">
                                    <h3 className="font-black text-[10px] text-slate-400 uppercase tracking-[0.2em]">Checklist de Etapas</h3>
                                    <span className="text-[9px] font-black text-pink-600 bg-pink-50 px-2.5 py-0.5 rounded-full">{checklistProgress}%</span>
                                </div>
                                <div className="w-full bg-slate-100 h-2 rounded-full mb-6 overflow-hidden border border-white shadow-inner">
                                    <div className="h-full bg-gradient-to-r from-pink-500 to-pink-600 transition-all duration-1000 ease-out" style={{ width: `${checklistProgress}%` }} />
                                </div>
                                <div className="space-y-2 mb-6">
                                    {task.checklists.map(item => {
                                        const assignee = users.find(u => u.id === item.assigneeId);
                                        return (
                                            <div key={item.id} className="flex flex-col gap-2 group bg-slate-50/50 hover:bg-white p-3 rounded-2xl border border-transparent hover:border-slate-100 transition-all shadow-sm">
                                                <div className="flex items-center gap-3">
                                                    <div className="relative flex items-center justify-center shrink-0">
                                                        <input type="checkbox" checked={item.isCompleted} onChange={() => {
                                                            const updated = task.checklists.map(c => c.id === item.id ? { ...c, isCompleted: !c.isCompleted } : c);
                                                            onUpdate({ ...task, checklists: updated });
                                                            if (!item.isCompleted && updated.every(u => u.isCompleted)) confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                                                        }} className="w-5 h-5 rounded-lg border-2 border-slate-200 text-pink-600 focus:ring-pink-500/20 cursor-pointer appearance-none checked:bg-pink-600 checked:border-pink-600 transition-all"/>
                                                        {item.isCompleted && <Check size={12} className="absolute text-white pointer-events-none" strokeWidth={4}/>}
                                                    </div>
                                                    <span className={`text-xs font-bold flex-1 transition-all ${item.isCompleted ? 'text-slate-300 line-through' : 'text-slate-700'}`}>{item.text}</span>
                                                    <button onClick={() => updateWithLog({ checklists: task.checklists.filter(c => c.id !== item.id) }, `removeu: ${item.text}`)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all p-1 hover:bg-red-50 rounded-lg"><Trash2 size={14}/></button>
                                                </div>
                                                <div className="ml-8 flex items-center gap-4">
                                                    <div className="flex items-center gap-1.5 bg-white/50 px-2 py-1 rounded-lg border border-slate-100 relative group/date">
                                                        <Calendar size={10} className="text-slate-300"/>
                                                        <input type="date" className="bg-transparent text-[9px] font-bold text-slate-500 outline-none w-20" value={item.dueDate || ''} onChange={(e) => handleUpdateChecklistItem(item.id, { dueDate: e.target.value })}/>
                                                    </div>
                                                    <div className="relative">
                                                        <button onClick={() => setActivePopover(`CHECKLIST_USER_${item.id}`)} className="flex items-center gap-1.5 bg-white/50 px-2 py-1 rounded-lg border border-slate-100 hover:bg-indigo-50 transition-all">
                                                            {assignee ? <img src={assignee.avatar} className="w-3.5 h-3.5 rounded-full object-cover" /> : <UserPlus size={10} className="text-slate-300"/>}
                                                            <span className="text-[9px] font-bold text-slate-500">{assignee ? assignee.name.split(' ')[0] : 'Atribuir'}</span>
                                                        </button>
                                                        {activePopover === `CHECKLIST_USER_${item.id}` && (
                                                            <div ref={popoverRef} className="absolute left-0 bottom-full mb-2 w-48 bg-white rounded-xl shadow-2xl border border-slate-100 p-2 z-[10001] animate-pop">
                                                                <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2">Responsável Etapa</p>
                                                                <div className="space-y-1 max-h-40 overflow-y-auto custom-scrollbar">
                                                                    {users.filter(u => u.role !== 'CLIENT').map(u => (
                                                                        <button key={u.id} onClick={() => { handleUpdateChecklistItem(item.id, { assigneeId: item.assigneeId === u.id ? undefined : u.id }); setActivePopover(null); }} className={`w-full flex items-center gap-2 p-1.5 rounded-lg text-[10px] font-bold transition-all ${item.assigneeId === u.id ? 'bg-indigo-50 text-indigo-700' : 'hover:bg-slate-50 text-slate-500'}`}>
                                                                            <img src={u.avatar} className="w-4 h-4 rounded-full object-cover" /> {u.name}
                                                                        </button>
                                                                    ))}
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                                <div className="flex gap-2">
                                    <input className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-[11px] font-bold outline-none focus:border-pink-500 focus:bg-white transition-all shadow-inner" placeholder="Add nova sub-tarefa..." value={newChecklistText} onChange={e => setNewChecklistText(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddChecklist()}/>
                                    <button onClick={handleAddChecklist} className="bg-slate-900 hover:bg-slate-800 text-white px-4 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">Add</button>
                                </div>
                            </div>
                        </div>

                        {/* Sessão Dupla: Chat vs Histórico com MENÇÃO no Chat */}
                        <div className="flex gap-4 border-t border-slate-50 pt-8">
                            <div className="p-2.5 bg-slate-100 rounded-xl text-slate-400 h-fit">{activeTab === 'CHAT' ? <MessageCircle size={20}/> : <History size={20}/>}</div>
                            <div className="flex-1 space-y-6">
                                <div className="flex items-center gap-4 border-b border-slate-50">
                                    <button onClick={() => setActiveTab('CHAT')} className={`pb-3 text-[10px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'CHAT' ? 'text-pink-600 border-pink-600' : 'text-slate-300 border-transparent hover:text-slate-400'}`}>Chat</button>
                                    <button onClick={() => setActiveTab('HISTORY')} className={`pb-3 text-[10px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'HISTORY' ? 'text-pink-600 border-pink-600' : 'text-slate-300 border-transparent hover:text-slate-400'}`}>Logs</button>
                                </div>

                                {activeTab === 'CHAT' ? (
                                    <div className="space-y-6 animate-pop">
                                        <div className="flex gap-3">
                                            <img src={currentUser.avatar} className="w-8 h-8 rounded-xl border shadow-sm object-cover" />
                                            <div className="flex-1 space-y-2 relative">
                                                <textarea 
                                                    ref={chatTextareaRef}
                                                    className="w-full bg-white border border-slate-200 rounded-2xl p-3 text-xs font-medium outline-none focus:border-pink-500 shadow-sm resize-none h-20 focus:shadow-md transition-all"
                                                    placeholder="Digite sua mensagem (use @)..."
                                                    value={newComment}
                                                    onChange={e => handleTextChangeWithMention(e.target.value, setNewComment, 'CHAT', e.target.selectionStart)}
                                                />
                                                {showMentionFor === 'CHAT' && (
                                                    <div className="absolute bottom-full left-0 z-[10005] mb-2 w-64 bg-white rounded-xl shadow-2xl border border-slate-100 p-2 animate-pop">
                                                        <div className="max-h-40 overflow-y-auto custom-scrollbar">
                                                            {filteredMentionUsers.map(u => (
                                                                <button key={u.id} onClick={() => insertMention(u, 'CHAT')} className="w-full flex items-center gap-2 p-2 hover:bg-slate-50 rounded-lg text-left transition-colors">
                                                                    <img src={u.avatar} className="w-5 h-5 rounded-full object-cover border" />
                                                                    <span className="text-[10px] font-bold text-slate-700">{u.name}</span>
                                                                </button>
                                                            ))}
                                                        </div>
                                                    </div>
                                                )}
                                                <button onClick={handleAddComment} className="px-5 py-2 bg-pink-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-pink-600/20 hover:bg-pink-700 hover:-translate-y-0.5 transition-all active:scale-95">Enviar</button>
                                            </div>
                                        </div>
                                        <div className="space-y-6 pt-2">
                                            {task.comments.sort((a,b) => b.timestamp - a.timestamp).map(comment => {
                                                const user = users.find(u => u.id === comment.userId);
                                                const isMe = comment.userId === currentUser.id;
                                                return (
                                                    <div key={comment.id} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : ''} group`}>
                                                        <img src={user?.avatar} className="w-8 h-8 rounded-xl border shadow-sm shrink-0 object-cover" />
                                                        <div className={`flex-1 max-w-[85%] ${isMe ? 'text-right' : ''}`}>
                                                            <div className={`flex items-center gap-2 mb-1 ${isMe ? 'justify-end' : ''}`}>
                                                                <span className="font-black text-[9px] text-slate-700 uppercase">{user?.name}</span>
                                                                <span className="text-[8px] text-slate-300 font-bold">{new Date(comment.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                            </div>
                                                            <div className={`text-xs p-3 rounded-2xl inline-block shadow-sm border ${isMe ? 'bg-slate-900 text-white border-slate-800 rounded-tr-none' : 'bg-slate-50 text-slate-700 border-slate-100 rounded-tl-none'}`}>
                                                                {comment.text.split(/(@\w+ \w+)/g).map((part, i) => 
                                                                    part.startsWith('@') ? <span key={i} className="text-pink-500 font-black">{part}</span> : part
                                                                )}
                                                            </div>
                                                        </div>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                ) : (
                                    <div className="space-y-4 animate-pop max-h-[300px] overflow-y-auto pr-3 custom-scrollbar">
                                        {task.history.sort((a,b) => b.timestamp - a.timestamp).map(log => {
                                            const user = users.find(u => u.id === log.userId);
                                            return (
                                                <div key={log.id} className="flex gap-3 items-start pl-1 relative before:absolute before:left-[1.1rem] before:top-6 before:bottom-[-1.2rem] before:w-px before:bg-slate-100 last:before:hidden">
                                                    <img src={user?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm shrink-0 relative z-10" />
                                                    <div className="pt-0.5">
                                                        <p className="text-[11px] text-slate-500"><span className="font-black text-slate-800 uppercase text-[9px] mr-1">{user?.name}</span> {log.action}</p>
                                                        <span className="text-[8px] text-slate-300 font-black uppercase tracking-widest">{new Date(log.timestamp).toLocaleString()}</span>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* --- SIDEBAR DE AÇÕES (DIREITA) --- */}
                    <div className="w-full md:w-[180px] space-y-8">
                        <div className={`p-5 rounded-[24px] transition-all duration-500 shadow-xl ${task.isTracking ? 'bg-slate-900 ring-[6px] ring-pink-500/10' : 'bg-white border border-slate-100'}`}>
                            <div className="flex items-center justify-between mb-3">
                                <p className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1.5 ${task.isTracking ? 'text-pink-500' : 'text-slate-400'}`}>
                                    <Clock size={12} className={task.isTracking ? 'animate-spin-slow' : ''}/> {task.isTracking ? 'Job Online' : 'Timer Off'}
                                </p>
                                {task.isTracking && <span className="w-1.5 h-1.5 bg-pink-500 rounded-full animate-ping"></span>}
                            </div>
                            <h3 className={`text-2xl font-black font-mono tracking-tighter mb-4 ${task.isTracking ? 'text-white' : 'text-slate-800'}`}>{formatSeconds(getAccumulatedSeconds())}</h3>
                            <button onClick={handleToggleTimer} className={`w-full py-3 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-[0.15em] transition-all shadow-xl active:scale-95 ${task.isTracking ? 'bg-amber-500 text-white shadow-amber-500/30 hover:bg-amber-600' : 'bg-pink-600 text-white shadow-pink-600/30 hover:bg-pink-700'}`}>
                                {task.isTracking ? <Pause size={14} fill="currentColor"/> : <Play size={14} fill="currentColor"/>} {task.isTracking ? 'Pausar' : 'Iniciar'}
                            </button>
                        </div>
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 mb-3">Adicionar</h4>
                            <button onClick={() => setActivePopover('MEMBERS')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-white rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm group">
                                <div className="p-1 bg-indigo-50 text-indigo-500 rounded group-hover:bg-indigo-500 group-hover:text-white transition-all"><UserPlus size={14}/></div> Membros
                            </button>
                            <button onClick={() => setActivePopover('COVERS')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-white rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm group">
                                <div className="p-1 bg-pink-50 text-pink-500 rounded group-hover:bg-pink-500 group-hover:text-white transition-all"><Palette size={14}/></div> Alterar Capa
                            </button>
                        </div>
                        <div className="space-y-2 pt-4 border-t border-slate-50">
                            <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 mb-3">Operações</h4>
                            <button onClick={() => updateWithLog({ archived: !task.archived }, task.archived ? 'reativou o job' : 'arquivou o job')} className="w-full flex items-center gap-3 p-3 bg-slate-50 hover:bg-white rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-600 transition-all border-2 border-transparent hover:border-slate-100 shadow-sm">
                                <Archive size={14} className="text-slate-400"/> {task.archived ? 'Reativar' : 'Arquivar'}
                            </button>
                            <button onClick={async () => {
                                const ok = await openConfirm({ title: "Excluir Definitivo?", description: "Esta ação apagará todos os dados desta tarefa permanentemente.", variant: "danger" });
                                if (ok) onDeleteTask(task.id);
                            }} className="w-full flex items-center gap-3 p-3 bg-red-50/50 hover:bg-red-500 hover:text-white rounded-xl text-[9px] font-black uppercase tracking-widest text-red-600 transition-all border-2 border-transparent shadow-sm group">
                                <Trash2 size={14} className="group-hover:text-white transition-colors"/> Excluir Job
                            </button>
                        </div>
                        <div className="pt-6 flex flex-col items-center">
                            {task.status !== 'DONE' && (
                                <button onClick={() => { updateWithLog({ status: 'DONE', isTracking: false }, 'concluiu o job'); confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } }); onClose(); }} className="w-full py-4 bg-emerald-600 text-white rounded-[20px] text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl shadow-emerald-200 hover:bg-emerald-700 hover:-translate-y-1 transition-all active:scale-95">Concluir</button>
                            )}
                        </div>
                    </div>
                </div>

                {/* --- POPOVERS SUPORTE --- */}
                {activePopover === 'COVERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10002]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Cores</h5>
                        <div className="grid grid-cols-4 gap-4 mb-8">
                            {PRESET_COLORS.map(c => <button key={c} onClick={() => { updateWithLog({ coverType: 'color', coverValue: c }, 'mudou a cor da capa'); setActivePopover(null); }} className="w-10 h-10 rounded-xl border-4 border-white shadow-sm hover:scale-125 transition-transform" style={{ backgroundColor: c }}/>)}
                        </div>
                        <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-500 border-2 border-dashed border-slate-200"><Camera size={18}/> Upload Foto</button>
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) {
                                const reader = new FileReader();
                                reader.onloadend = () => { updateWithLog({ coverType: 'image', coverValue: reader.result as string }, 'subiu imagem de capa'); setActivePopover(null); };
                                reader.readAsDataURL(file);
                            }
                        }} />
                    </div>
                )}

                {activePopover === 'MEMBERS' && (
                    <div ref={popoverRef} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-72 bg-white rounded-[32px] shadow-2xl border border-slate-100 p-6 animate-pop z-[10002]">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5 border-b pb-3">Atribuir Membros</h5>
                        <div className="space-y-2 max-h-72 overflow-y-auto custom-scrollbar">
                            {users.filter(u => u.role !== 'CLIENT').map(u => (
                                <button key={u.id} onClick={() => {
                                    const current = task.assigneeIds;
                                    const newIds = current.includes(u.id) ? current.filter(id => id !== u.id) : [...current, u.id];
                                    updateWithLog({ assigneeIds: newIds }, current.includes(u.id) ? `removeu ${u.name}` : `atribuiu a tarefa para ${u.name}`);
                                }} className={`w-full flex items-center justify-between p-3 rounded-2xl transition-all border-2 ${task.assigneeIds.includes(u.id) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'hover:bg-slate-50 text-slate-500 border-transparent'}`}>
                                    <div className="flex items-center gap-3"><img src={u.avatar} className="w-8 h-8 rounded-full object-cover border-2 border-white shadow-sm" /><span className="text-[11px] font-bold">{u.name}</span></div>
                                    {task.assigneeIds.includes(u.id) && <div className="bg-indigo-600 p-1 rounded-full text-white"><Check size={12} strokeWidth={4}/></div>}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Requisition, User, Notification, FinancialRecord } from '../types';
import { Plus, Check, X, ShoppingBag, DollarSign, Clock, Calendar, AlertTriangle, User as UserIcon, Filter, Search, ChevronRight, ReceiptText } from 'lucide-react';

interface RequisitionsProps {
  requisitions: Requisition[];
  setRequisitions: React.Dispatch<React.SetStateAction<Requisition[]>>;
  currentUser: User;
  users: User[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  setTransactions: React.Dispatch<React.SetStateAction<FinancialRecord[]>>;
}

export const Requisitions: React.FC<RequisitionsProps> = ({ 
    requisitions, 
    setRequisitions, 
    currentUser, 
    users, 
    setNotifications,
    setTransactions 
}) => {
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [selectedReqForReject, setSelectedReqForReject] = useState<Requisition | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [editingReq, setEditingReq] = useState<Partial<Requisition>>({});
  const [filter, setFilter] = useState<'ALL' | 'MY'>('ALL');
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const canApprove = currentUser.role === 'ADMIN' || currentUser.role === 'FINANCE';
  const isClient = currentUser.role === 'CLIENT';

  const displayedRequisitions = requisitions.filter(req => {
      const matchesFilter = filter === 'ALL' ? (canApprove || req.requesterId === currentUser.id) : req.requesterId === currentUser.id;
      const matchesSearch = req.title.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesFilter && matchesSearch;
  }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const handleSaveReq = () => {
      if (!editingReq.title || !editingReq.estimatedCost) return;
      const newReq: Requisition = {
          id: Date.now().toString(),
          requesterId: currentUser.id,
          title: editingReq.title || '',
          description: editingReq.description || '',
          estimatedCost: editingReq.estimatedCost || 0,
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          category: editingReq.category || (isClient ? 'Reembolso' : 'Compra')
      };
      setRequisitions(prev => [newReq, ...prev]);
      setIsCreateModalOpen(false);
      setEditingReq({});
  };

  const handleApproveReq = (req: Requisition) => {
      if (!canApprove || req.status === 'APPROVED') return;
      setProcessingId(req.id);
      setTimeout(() => {
          const now = new Date().toISOString();
          const updatedReq: Requisition = { ...req, status: 'APPROVED', approvedBy: currentUser.id, approvedAt: now };
          setRequisitions(prev => prev.map(r => r.id === req.id ? updatedReq : r));

          if (req.estimatedCost > 0) {
              const newExpense: FinancialRecord = {
                  id: `exp-${req.id}`,
                  description: `REQ Aprovada: ${req.title}`,
                  amount: req.estimatedCost,
                  type: 'EXPENSE',
                  status: 'PENDING',
                  dueDate: new Date().toISOString().split('T')[0],
                  categoryId: req.category,
                  entityName: users.find(u => u.id === req.requesterId)?.name || 'Colaborador'
              };
              setTransactions(prev => [newExpense, ...prev]);
          }
          setProcessingId(null);
      }, 600);
  };

  const handleRejectReq = () => {
      if (!selectedReqForReject || !rejectionReason) return;
      const reqToReject = selectedReqForReject;
      setIsRejectModalOpen(false);
      setProcessingId(reqToReject.id);
      setTimeout(() => {
          const updatedReq: Requisition = { ...reqToReject, status: 'REJECTED', rejectedBy: currentUser.id, rejectedAt: new Date().toISOString(), rejectedReason: rejectionReason };
          setRequisitions(prev => prev.map(r => r.id === reqToReject.id ? updatedReq : r));
          setProcessingId(null);
          setSelectedReqForReject(null);
          setRejectionReason('');
      }, 600);
  };

  return (
    <div className="flex flex-col h-full animate-pop">
      {/* HEADER INTEGRADO */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-5 md:p-6 mb-6">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div className="space-y-1">
            <h2 className="text-2xl font-black tracking-tight text-slate-800 flex items-center gap-3">
              <ReceiptText className="text-pink-600" size={28}/> Solicitações & Reembolsos
            </h2>
            <p className="text-slate-500 text-sm font-medium">Controle de gastos extras e pedidos de insumos.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
               <button onClick={() => setFilter('ALL')} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'ALL' ? 'bg-white shadow-md text-pink-600' : 'text-slate-400 hover:text-slate-600'}`}>Geral</button>
               <button onClick={() => setFilter('MY')} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'MY' ? 'bg-white shadow-md text-pink-600' : 'text-slate-400 hover:text-slate-600'}`}>Minhas</button>
            </div>

            <div className="h-10 w-px bg-slate-200 mx-1 hidden sm:block"></div>

            <div className="relative group flex-1 sm:flex-none min-w-[200px]">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-pink-500 transition-colors" size={16}/>
              <input 
                type="text" 
                placeholder="Buscar pedido..." 
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-transparent focus:bg-white focus:border-pink-200 rounded-2xl text-xs font-bold outline-none transition-all shadow-inner"
              />
            </div>

            <button 
              onClick={() => { setEditingReq({ category: isClient ? 'Outros' : 'Compra' }); setIsCreateModalOpen(true); }}
              className="px-6 py-3 bg-pink-600 hover:bg-pink-700 text-white font-black text-[10px] uppercase tracking-[0.15em] rounded-2xl transition-all shadow-xl shadow-pink-500/20 flex items-center gap-3 hover:scale-[1.03] active:scale-95 whitespace-nowrap"
            >
              <Plus size={18} strokeWidth={3}/> Nova Solicitação
            </button>
          </div>
        </div>
      </div>

      {/* LISTAGEM DE CARDS */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 pb-10">
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          {displayedRequisitions.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[32px] border-2 border-dashed border-slate-200 flex flex-col items-center">
              <div className="p-6 bg-slate-50 rounded-full mb-4">
                <ShoppingBag className="text-slate-300" size={48}/>
              </div>
              <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Nenhum pedido registrado no período</p>
            </div>
          ) : (
            displayedRequisitions.map(req => {
              const requester = users.find(u => u.id === req.requesterId);
              const isProcessing = processingId === req.id;

              return (
                <div key={req.id} className="group bg-white p-5 rounded-[28px] border border-slate-100 hover:border-pink-200 hover:shadow-2xl hover:shadow-slate-200/50 transition-all flex flex-col md:flex-row md:items-center justify-between gap-5 relative overflow-hidden">
                  {isProcessing && <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center backdrop-blur-sm"><Clock className="animate-spin text-pink-600" size={32}/></div>}

                  <div className="flex items-center gap-5 flex-1 min-w-0">
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 shadow-sm border transition-colors ${req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : req.status === 'REJECTED' ? 'bg-red-50 text-red-600 border-red-100' : 'bg-orange-50 text-orange-600 border-orange-100'}`}>
                      {req.category === 'Reembolso' ? <DollarSign size={24}/> : <ShoppingBag size={24}/>}
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-slate-100 text-slate-500 border border-slate-200 tracking-widest">{req.category}</span>
                        <span className="text-[10px] text-slate-300 font-black">•</span>
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1 uppercase tracking-tight"><Calendar size={12} className="text-slate-300"/> {req.date.split('-').reverse().join('/')}</span>
                      </div>
                      <h4 className="font-black text-slate-800 text-base truncate group-hover:text-pink-600 transition-colors tracking-tight">{req.title}</h4>
                      <div className="flex items-center gap-2 mt-1">
                        <img src={requester?.avatar} className="w-5 h-5 rounded-full object-cover border border-slate-200" />
                        <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{requester?.name}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center justify-between md:justify-end gap-6 bg-slate-50 md:bg-transparent p-4 md:p-0 rounded-2xl border border-slate-100 md:border-none">
                    <div className="text-left md:text-right">
                      <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest leading-none mb-1.5">Valor Total</p>
                      <p className="font-black text-slate-800 text-lg leading-none">R$ {req.estimatedCost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>

                    <div className="flex items-center gap-3">
                       <span className={`px-4 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest border shadow-sm ${
                          req.status === 'PENDING' ? 'bg-amber-50 text-amber-600 border-amber-200' : 
                          req.status === 'APPROVED' ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-red-50 text-red-600 border-red-200'
                       }`}>
                         {req.status === 'PENDING' ? 'Aguardando' : req.status === 'APPROVED' ? 'Aprovado' : 'Recusado'}
                       </span>

                      {canApprove && req.status === 'PENDING' ? (
                        <div className="flex gap-2">
                          <button onClick={() => handleApproveReq(req)} title="Aprovar" className="p-2.5 bg-white hover:bg-emerald-600 hover:text-white text-emerald-600 rounded-xl transition-all border border-emerald-200 hover:border-emerald-600 shadow-sm"><Check size={18} strokeWidth={3}/></button>
                          <button onClick={() => { setSelectedReqForReject(req); setIsRejectModalOpen(true); }} title="Recusar" className="p-2.5 bg-white hover:bg-red-600 hover:text-white text-red-600 rounded-xl transition-all border border-red-200 hover:border-red-600 shadow-sm"><X size={18} strokeWidth={3}/></button>
                        </div>
                      ) : (
                        <button className="p-2.5 bg-slate-50 text-slate-300 rounded-xl border border-slate-100 cursor-default"><ChevronRight size={18}/></button>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* MODAL CRIAR SOLICITAÇÃO */}
      {isCreateModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsCreateModalOpen(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-md shadow-2xl overflow-hidden animate-pop border border-slate-200 flex flex-col" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b border-slate-50 bg-white flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-pink-50 text-pink-600 rounded-xl"><Plus size={20}/></div>
                        <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase">Novo Pedido</h3>
                      </div>
                      <button onClick={() => setIsCreateModalOpen(false)} className="p-2 text-slate-300 hover:bg-slate-50 rounded-full transition-colors"><X size={20}/></button>
                  </div>

                  <div className="p-8 space-y-5">
                      <div>
                          <label className="text-[9px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">Tipo de Solicitação</label>
                          <select 
                             className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:bg-white focus:border-pink-500 transition-all cursor-pointer"
                             value={editingReq.category}
                             onChange={e => setEditingReq({...editingReq, category: e.target.value})}
                          >
                              {isClient ? (
                                  <>
                                    <option value="Reembolso">Reembolso</option>
                                    <option value="Outros">Outros Pedidos</option>
                                  </>
                              ) : (
                                  <>
                                    <option value="Compra">Insumos / Hardware</option>
                                    <option value="Reembolso">Reembolso de Despesa</option>
                                    <option value="Software">Assinatura / Software</option>
                                    <option value="Serviço">Terceirização / Freelancer</option>
                                  </>
                              )}
                          </select>
                      </div>

                      <div>
                          <label className="text-[9px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">O que você precisa?</label>
                          <input 
                            className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:bg-white focus:border-pink-500 transition-all"
                            placeholder="Ex: Licença mensal Adobe Cloud" 
                            value={editingReq.title || ''} 
                            onChange={e => setEditingReq({...editingReq, title: e.target.value})} 
                            autoFocus
                          />
                      </div>

                      <div>
                          <label className="text-[9px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">Justificativa</label>
                          <textarea 
                            className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:bg-white focus:border-pink-500 transition-all resize-none"
                            placeholder="Descreva brevemente a necessidade..." 
                            rows={3} 
                            value={editingReq.description || ''} 
                            onChange={e => setEditingReq({...editingReq, description: e.target.value})} 
                          />
                      </div>

                      <div>
                          <label className="text-[9px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">Custo Estimado (R$)</label>
                          <div className="relative">
                            <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-slate-400">R$</span>
                            <input 
                              type="number" 
                              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 pl-12 text-2xl font-black outline-none focus:bg-white focus:border-pink-500 transition-all text-slate-800"
                              placeholder="0,00" 
                              value={editingReq.estimatedCost || ''} 
                              onChange={e => setEditingReq({...editingReq, estimatedCost: parseFloat(e.target.value)})} 
                            />
                          </div>
                      </div>
                  </div>

                  <div className="p-6 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-end gap-3">
                      <button onClick={() => setIsCreateModalOpen(false)} className="px-6 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-colors">Cancelar</button>
                      <button onClick={handleSaveReq} className="px-8 py-3 bg-slate-900 hover:bg-slate-800 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl transition-all shadow-xl shadow-slate-200">Enviar para Análise</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL RECUSAR SOLICITAÇÃO */}
      {isRejectModalOpen && selectedReqForReject && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsRejectModalOpen(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-md shadow-2xl overflow-hidden animate-pop border-t-4 border-red-600 border-x border-b border-slate-100" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b border-slate-50 bg-white flex items-center gap-4">
                      <div className="p-3 bg-red-50 text-red-600 rounded-2xl shadow-sm"><AlertTriangle size={24}/></div>
                      <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase">Negar Pedido</h3>
                  </div>

                  <div className="p-8 space-y-6">
                      <div className="p-4 bg-red-50 rounded-2xl border border-red-100 text-xs">
                        <p className="font-black text-red-800 uppercase text-[9px] tracking-widest mb-1.5">Item Solicitado:</p>
                        <p className="text-red-700 font-bold">{selectedReqForReject.title}</p>
                      </div>

                      <div>
                        <label className="text-[9px] uppercase text-slate-400 font-black mb-2 block tracking-[0.2em] ml-1">Motivo da Recusa <span className="text-red-500">*</span></label>
                        <textarea 
                            className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:bg-white focus:border-red-500 transition-all border resize-none"
                            placeholder="Explique ao colaborador o motivo da decisão..." 
                            rows={3} 
                            value={rejectionReason} 
                            onChange={e => setRejectionReason(e.target.value)} 
                            autoFocus
                        />
                      </div>
                  </div>

                  <div className="p-6 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row justify-end gap-3">
                      <button onClick={() => setIsRejectModalOpen(false)} className="px-6 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-600 transition-colors">Voltar</button>
                      <button 
                        onClick={handleRejectReq} 
                        disabled={!rejectionReason}
                        className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl transition-all shadow-xl shadow-red-200 disabled:opacity-50"
                      >
                        Confirmar Recusa
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, ConfirmOptions } from './types';
import { Bell, X } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  const [leadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;
  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };
  const contentMargin = !isMobile ? getSidebarWidth() : '0px';

  return (
    <div className={`flex h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className={`flex-1 flex flex-col h-full transition-all duration-300 ease-in-out relative`}
        style={{ marginLeft: contentMargin }}
      >
        {/* TOPBAR PADRONIZADA (FIXA) */}
        <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-3 flex justify-end items-center gap-4">
            <div className="relative" ref={notificationRef}>
                <button 
                  onClick={() => setShowNotifications(!showNotifications)} 
                  className="w-10 h-10 rounded-xl border border-slate-100 bg-white shadow-sm flex items-center justify-center transition-all hover:bg-slate-50 relative"
                >
                    <Bell size={20} className="text-slate-400" />
                    {unreadCount > 0 && (
                        <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
                    )}
                </button>

                {showNotifications && (
                    <div className="absolute right-0 top-full mt-3 w-80 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[100] animate-pop origin-top-right overflow-hidden">
                        <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                            <h3 className="text-[10px] font-black uppercase text-slate-400">Notificações</h3>
                            <button onClick={markAllAsRead} className="text-[9px] font-black text-pink-600 uppercase tracking-widest">Marcar lidas</button>
                        </div>
                        <div className="max-h-64 overflow-y-auto p-6 text-center text-slate-400 text-[11px] font-bold uppercase">
                            Nenhuma novidade por aqui.
                        </div>
                    </div>
                )}
            </div>

            <div 
              className="bg-white px-4 py-1.5 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-3 cursor-pointer hover:border-pink-200 transition-all group"
              onClick={() => setCurrentView('settings')}
            >
                <div className="text-right hidden sm:block">
                    <p className="text-[11px] font-black text-slate-800 leading-none group-hover:text-pink-600 transition-colors">{currentUser.name}</p>
                    <p className="text-[8px] text-slate-400 uppercase font-black mt-1 tracking-widest">{currentUser.role}</p>
                </div>
                <div className="w-8 h-8 rounded-xl overflow-hidden border-2 border-white shadow-sm bg-slate-100">
                  <img src={currentUser.avatar} alt="Perfil" className="w-full h-full object-cover" />
                </div>
            </div>
        </div>

        {/* ÁREA DE CONTEÚDO */}
        <div className="flex-1 w-full max-w-full flex flex-col overflow-hidden p-4 md:p-6">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && (
              <KanbanBoard 
                tasks={tasks} 
                setTasks={setTasks} 
                users={users} 
                currentUser={currentUser} 
                columns={taskColumns} 
                setColumns={setTaskColumns} 
                openConfirm={openConfirm} 
                notifications={notifications} 
                setNotifications={setNotifications}
                sidebarOpen={sidebarOpen}
                sidebarCompact={sidebarCompact}
                isMobile={isMobile}
              />
            )}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Task, User, ColumnConfig, Notification, ConfirmOptions } from '../types';
import { 
    Plus, Archive, Settings, Search, Layers, Filter
} from 'lucide-react';
import { TaskModal } from './TaskModal';
import confetti from 'canvas-confetti';

interface KanbanBoardProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  users: User[];
  currentUser: User;
  columns: ColumnConfig[];
  setColumns: React.Dispatch<React.SetStateAction<ColumnConfig[]>>;
  notifications: Notification[];
  setNotifications: React.Dispatch<React.SetStateAction<Notification[]>>;
  openConfirm: (options: ConfirmOptions) => Promise<boolean>;
  sidebarOpen: boolean;
  sidebarCompact: boolean;
  isMobile: boolean;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  tasks, setTasks, users, currentUser, columns, setColumns, openConfirm
}) => {
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showArchivedColumns, setShowArchivedColumns] = useState(false);
  const [draggedTaskId, setDraggedTaskId] = useState<string | null>(null);
  const [isColumnModalOpen, setIsColumnModalOpen] = useState(false);
  const [editingColumn, setEditingColumn] = useState<Partial<ColumnConfig> | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const isAdmin = currentUser.role === 'ADMIN';
  const activeColumns = useMemo(() => columns.filter(c => !c.isArchived).sort((a,b) => a.order - b.order), [columns]);
  const archivedColumns = useMemo(() => columns.filter(c => c.isArchived).sort((a,b) => a.order - b.order), [columns]);

  const handleSaveColumn = () => {
    if (!editingColumn?.label) return;
    if (editingColumn.id) setColumns(prev => prev.map(c => c.id === editingColumn.id ? { ...c, ...editingColumn } as ColumnConfig : c));
    else setColumns(prev => [...prev, { id: 'col-' + Date.now(), label: editingColumn.label, color: 'border-slate-400', order: columns.length, wipLimit: editingColumn.wipLimit || null, isArchived: false } as ColumnConfig]);
    setIsColumnModalOpen(false);
  };

  const handleDropTask = (e: React.DragEvent, targetColId: string) => {
      e.preventDefault();
      if (!draggedTaskId) return;
      const task = tasks.find(t => t.id === draggedTaskId);
      if (task && task.status !== targetColId) {
          setTasks(prev => prev.map(t => t.id === draggedTaskId ? { ...t, status: targetColId } : t));

          if (targetColId === 'DONE') {
              confetti({
                  particleCount: 150,
                  spread: 70,
                  origin: { y: 0.6 }
              });
          }
      }
      setDraggedTaskId(null);
  };

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => {
      const exists = prev.some(t => t.id === updatedTask.id);
      if (exists) {
        return prev.map(t => t.id === updatedTask.id ? updatedTask : t);
      } else {
        return [...prev, updatedTask];
      }
    });
    setSelectedTask(updatedTask);
  };

  return (
    <div className="flex flex-col h-full animate-pop">
      {/* TOOLBAR KANBAN - PADRONIZADA */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-4 mb-6 flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="bg-pink-50 p-2.5 rounded-2xl text-pink-600">
             <Layers size={22} />
          </div>
          <div>
            <h2 className="text-sm font-black text-slate-800 uppercase tracking-tighter leading-none">Quadro de Jobs</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Fluxo de Produção</p>
          </div>

          <div className="h-8 w-px bg-slate-200 mx-2 hidden md:block"></div>

          <div className="relative group flex-1 md:flex-none">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-pink-500 transition-colors" />
            <input 
              type="text" 
              placeholder="Buscar job..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-transparent focus:bg-white focus:border-pink-200 rounded-xl text-xs font-bold outline-none transition-all shadow-inner"
            />
          </div>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto justify-end">
          <button onClick={() => setShowArchived(!showArchived)} className={`p-2.5 rounded-xl transition-all border ${showArchived ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-200 hover:text-pink-600'}`} title="Jobs Arquivados">
            <Archive size={18}/>
          </button>

          {isAdmin && (
            <button onClick={() => setShowArchivedColumns(true)} className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-pink-600 transition-all shadow-sm">
              <Settings size={18}/>
            </button>
          )}

          <div className="w-px h-8 bg-slate-200 mx-1 hidden sm:block"></div>

          <button 
            onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: activeColumns[0]?.id || 'BACKLOG', priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} 
            className="bg-pink-600 hover:bg-pink-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-lg shadow-pink-500/20 transition-all transform hover:scale-[1.02] active:scale-95 whitespace-nowrap"
          >
            <Plus size={18} strokeWidth={3} /> NOVO JOB
          </button>
        </div>
      </div>

      <main className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar -mx-2">
        <div className="inline-flex h-full p-2 gap-6 items-start">
          {activeColumns.map(col => {
            const colTasks = tasks.filter(t => t.status === col.id && (showArchived ? t.archived : !t.archived) && t.title.toLowerCase().includes(searchTerm.toLowerCase()));
            return (
              <div key={col.id} onDragOver={e => e.preventDefault()} onDrop={e => handleDropTask(e, col.id)} className="flex-shrink-0 w-80 flex flex-col max-h-full rounded-[32px] bg-slate-200/40 border border-slate-200/50">
                <div className="p-5 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-2 h-6 rounded-full bg-pink-500"></div>
                    <h3 className="font-black text-[11px] uppercase tracking-widest text-slate-600">{col.label}</h3>
                  </div>
                  <span className="bg-white/80 text-slate-500 text-[10px] px-2 py-0.5 rounded-full font-black shadow-sm border border-slate-100">{colTasks.length}</span>
                </div>

                <div className="px-3 pb-5 space-y-4 overflow-y-auto custom-scrollbar flex-1">
                  {colTasks.map(task => (
                    <div 
                      key={task.id} 
                      draggable 
                      onDragStart={e => setDraggedTaskId(task.id)}
                      onClick={() => setSelectedTask(task)}
                      className="bg-white rounded-[32px] shadow-sm border-2 border-white hover:border-pink-200 cursor-grab active:cursor-grabbing transition-all group hover:shadow-xl overflow-hidden flex flex-col"
                    >
                      {task.coverType === 'color' && <div className="h-20 w-full border-b border-black/5" style={{ backgroundColor: task.coverValue || '#cbd5e1' }} />}
                      {task.coverType === 'image' && <img src={task.coverValue || ''} className="h-24 w-full object-cover border-b border-black/5" alt="Capa" />}

                      <div className="p-5">
                        <div className="flex justify-between items-start mb-3">
                          <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-tighter ${task.priority === 'HIGH' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>{task.priority}</span>
                          <div className="flex -space-x-2">
                            {task.assigneeIds.slice(0, 3).map(id => (
                              <img key={id} src={users.find(u => u.id === id)?.avatar} className="w-6 h-6 rounded-lg border-2 border-white shadow-sm object-cover" />
                            ))}
                          </div>
                        </div>
                        <h4 className="text-xs font-bold text-slate-700 leading-snug group-hover:text-pink-600 transition-colors line-clamp-2">{task.title}</h4>
                      </div>
                    </div>
                  ))}

                  <button onClick={() => setSelectedTask({ id: Date.now().toString(), title: '', description: '', status: col.id, priority: 'MEDIUM', dueDate: '', timeLogs: [], assigneeIds: [currentUser.id], checklists: [], comments: [], history: [], estimatedTime: 0, isTracking: false } as Task)} className="w-full py-4 border-2 border-dashed border-slate-300/50 rounded-[32px] text-slate-400 hover:text-pink-500 hover:border-pink-200 transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/30"><Plus size={16}/> ADICIONAR</button>
                </div>
              </div>
            );
          })}
          {isAdmin && (<button onClick={() => { setEditingColumn({ label: '', color: 'border-slate-400', wipLimit: null }); setIsColumnModalOpen(true); }} className="flex-shrink-0 w-80 h-20 bg-white/30 border-2 border-dashed border-slate-300 rounded-[32px] flex items-center justify-center gap-3 text-slate-400 font-black uppercase text-xs tracking-widest hover:bg-white hover:text-slate-600 transition-all group"><Plus size={20} /> NOVA LISTA</button>)}
        </div>
      </main>

      {/* MODALS */}
      {isColumnModalOpen && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setIsColumnModalOpen(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-sm p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 text-slate-800 uppercase tracking-tighter">Configurar Coluna</h3>
                  <div className="space-y-4">
                    <input className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-pink-500 transition-all bg-slate-50" value={editingColumn?.label || ''} onChange={e => setEditingColumn({...editingColumn, label: e.target.value})} placeholder="Título da Coluna" />
                    <button onClick={handleSaveColumn} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-slate-800 transition-all">Salvar Alterações</button>
                  </div>
              </div>
          </div>
      )}

      {showArchivedColumns && (activeColumns.length > 0) && (
          <div className="fixed inset-0 bg-slate-900/60 z-[9999] flex items-center justify-center p-4 transition-all duration-300" onClick={() => setShowArchivedColumns(false)}>
              <div className="bg-white rounded-[32px] w-full max-w-md p-8 shadow-2xl animate-pop border border-slate-200" onClick={e => e.stopPropagation()}>
                  <h3 className="text-xl font-black mb-6 uppercase tracking-tighter">Listas Arquivadas</h3>
                  <div className="space-y-3 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                      {archivedColumns.map(col => (
                          <div key={col.id} className="flex items-center justify-between p-4 border border-slate-100 rounded-2xl bg-slate-50">
                              <span className="font-bold text-slate-700">{col.label}</span>
                              <button onClick={() => setColumns(prev => prev.map(c => c.id === col.id ? {...c, isArchived: false} : c))} className="text-pink-600 font-black text-[10px] uppercase bg-white px-3 py-1.5 rounded-lg shadow-sm border">Reativar</button>
                          </div>
                      ))}
                      {archivedColumns.length === 0 && <p className="text-center text-slate-400 py-10 font-bold uppercase text-xs">Nenhuma lista arquivada.</p>}
                  </div>
                  <button onClick={() => setShowArchivedColumns(false)} className="w-full mt-6 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Fechar</button>
              </div>
          </div>
      )}

      {selectedTask && (
        <TaskModal 
            task={selectedTask} 
            users={users} 
            onClose={() => setSelectedTask(null)} 
            onUpdate={handleUpdateTask} 
            onDeleteTask={(id) => { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); }} 
            currentUser={currentUser} 
            openConfirm={openConfirm}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { KanbanBoard } from './components/KanbanBoard';
import { CRM } from './components/CRM';
import { Financials } from './components/Financials';
import { ClientPortal } from './components/ClientPortal';
import { ProductivityDashboard } from './components/ProductivityDashboard';
import { TeamManagement } from './components/TeamManagement';
import { DashboardOverview } from './components/DashboardOverview';
import { PermissionsManager } from './components/PermissionsManager';
import { ClientManagement } from './components/ClientManagement';
import { ServiceCatalog } from './components/ServiceCatalog';
import { ProfileSettings } from './components/ProfileSettings';
import { Requisitions } from './components/Requisitions';
import { SystemAdmin } from './components/SystemAdmin'; 
import { HelpCenter } from './components/HelpCenter';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { Login } from './components/Login';
import { ConfirmDialog } from './components/ConfirmDialog';
import { initialUsers, initialTasks, initialLeads, initialFinancialRecords, initialSquads, initialTaskColumns, initialCrmColumns, initialAssets, initialRolePermissions, initialClients, initialNotifications, initialServices, initialRequisitions } from './utils/mockData';
import { Task, User, Lead, FinancialRecord, Role, Squad, ColumnConfig, Asset, RolePermissions, Client, Notification, AgencyService, Requisition, SystemSettings, ConfirmOptions } from './types';
import { Bell, X } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  const [sidebarOpen, setSidebarOpen] = useState(() => {
    const saved = localStorage.getItem('sidebarOpen');
    return saved !== null ? JSON.parse(saved) : true;
  });
  const [sidebarCompact, setSidebarCompact] = useState(() => {
    const saved = localStorage.getItem('sidebarCompact');
    return saved !== null ? JSON.parse(saved) : false;
  });
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (mobile && sidebarOpen && !sidebarCompact) {
          setSidebarCompact(true);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [sidebarOpen, sidebarCompact]);

  useEffect(() => {
    localStorage.setItem('sidebarOpen', JSON.stringify(sidebarOpen));
    localStorage.setItem('sidebarCompact', JSON.stringify(sidebarCompact));
  }, [sidebarOpen, sidebarCompact]);

  const toggleSidebar = () => {
      if (isMobile) {
          if (!sidebarOpen) {
              setSidebarOpen(true);
              setSidebarCompact(true);
          } else {
              setSidebarOpen(false);
          }
      } else {
          setSidebarOpen(!sidebarOpen);
      }
  };

  const toggleCompact = () => setSidebarCompact(!sidebarCompact);

  const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
  const confirmResolveRef = useRef<(value: boolean) => void>(null);

  const openConfirm = (options: ConfirmOptions): Promise<boolean> => {
      return new Promise((resolve) => {
          setConfirmOptions(options);
          confirmResolveRef.current = resolve;
      });
  };

  const handleConfirmAction = (result: boolean) => {
      setConfirmOptions(null);
      if (confirmResolveRef.current) confirmResolveRef.current(result);
  };

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [leads, setLeads] = useState<Lead[]>(initialLeads);
  const [transactions, setTransactions] = useState<FinancialRecord[]>(initialFinancialRecords);
  const [assets, setAssets] = useState<Asset[]>(initialAssets);
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [squads, setSquads] = useState<Squad[]>(initialSquads);
  const [clients, setClients] = useState<Client[]>(initialClients);
  const [services, setServices] = useState<AgencyService[]>(initialServices);
  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
  const [requisitions, setRequisitions] = useState<Requisition[]>(initialRequisitions);
  // Fix: Added setLeadSources to state declaration to resolve "Cannot find name 'setLeadSources'" error.
  const [leadSources, setLeadSources] = useState<string[]>(['Instagram', 'Linkedin', 'Google Ads', 'Indicação', 'Site']);
  const [systemSettings, setSystemSettings] = useState<SystemSettings>({
      agencyName: 'Agência Chan',
      logo: '',
      primaryColor: '#db2777',
      sidebarColor: '#0f172a'
  });

  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);
  const [taskColumns, setTaskColumns] = useState<ColumnConfig[]>(initialTaskColumns);
  const [crmColumns, setCrmColumns] = useState<ColumnConfig[]>(initialCrmColumns);
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'CLIENT') setCurrentView('client-portal');
    else {
        const allowed = rolePermissions[user.role] || [];
        setCurrentView(allowed.includes('dashboard') ? 'dashboard' : (allowed[0] || 'dashboard'));
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('dashboard');
  };

  const markAllAsRead = () => {
      setNotifications(prev => prev.map(n => n.status === 'UNREAD' ? { ...n, status: 'READ' } : n));
  };

  if (!currentUser) {
      if (currentView === 'privacy') return <PrivacyPolicy onBack={() => setCurrentView('login')} agencyName={systemSettings.agencyName} />;
      if (currentView === 'help') return <div className="p-4 md:p-8"><HelpCenter currentUser={{id:'g', name:'G', email:'', role:'EMPLOYEE', avatar:''}} /></div>;
      return <Login onLogin={handleLogin} users={users} systemSettings={systemSettings} onNavigate={setCurrentView} />;
  }

  const unreadCount = notifications.filter(n => n.status === 'UNREAD' && (!n.targetUserId || n.targetUserId === currentUser.id)).length;
  const getSidebarWidth = () => {
    if (!sidebarOpen) return '0px';
    return sidebarCompact ? '80px' : '256px';
  };
  const contentMargin = !isMobile ? getSidebarWidth() : '0px';

  return (
    <div className={`flex h-screen transition-colors duration-300 ${currentUser.preferences?.theme === 'dark' ? 'bg-slate-900 text-slate-200' : 'bg-slate-50 text-slate-800'}`}>
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        currentUserRole={currentUser.role} 
        permissions={rolePermissions} 
        logout={handleLogout} 
        systemSettings={systemSettings}
        isOpen={sidebarOpen}
        onToggle={toggleSidebar}
        isCompact={sidebarCompact}
        onToggleCompact={toggleCompact}
        isMobile={isMobile}
      />

      <main 
        className={`flex-1 flex flex-col h-full transition-all duration-300 ease-in-out relative`}
        style={{ marginLeft: contentMargin }}
      >
        {/* TOPBAR PADRONIZADA (FIXA) */}
        <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-3 flex justify-end items-center gap-4">
            <div className="relative" ref={notificationRef}>
                <button 
                  onClick={() => setShowNotifications(!showNotifications)} 
                  className="w-10 h-10 rounded-xl border border-slate-100 bg-white shadow-sm flex items-center justify-center transition-all hover:bg-slate-50 relative"
                >
                    <Bell size={20} className="text-slate-400" />
                    {unreadCount > 0 && (
                        <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
                    )}
                </button>

                {showNotifications && (
                    <div className="absolute right-0 top-full mt-3 w-80 bg-white rounded-2xl shadow-2xl border border-slate-100 z-[100] animate-pop origin-top-right overflow-hidden">
                        <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                            <h3 className="text-[10px] font-black uppercase text-slate-400">Notificações</h3>
                            <button onClick={markAllAsRead} className="text-[9px] font-black text-pink-600 uppercase tracking-widest">Marcar lidas</button>
                        </div>
                        <div className="max-h-64 overflow-y-auto p-6 text-center text-slate-400 text-[11px] font-bold uppercase">
                            Nenhuma novidade por aqui.
                        </div>
                    </div>
                )}
            </div>

            <div 
              className="bg-white px-4 py-1.5 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-3 cursor-pointer hover:border-pink-200 transition-all group"
              onClick={() => setCurrentView('settings')}
            >
                <div className="text-right hidden sm:block">
                    <p className="text-[11px] font-black text-slate-800 leading-none group-hover:text-pink-600 transition-colors">{currentUser.name}</p>
                    <p className="text-[8px] text-slate-400 uppercase font-black mt-1 tracking-widest">{currentUser.role}</p>
                </div>
                <div className="w-8 h-8 rounded-xl overflow-hidden border-2 border-white shadow-sm bg-slate-100">
                  <img src={currentUser.avatar} alt="Perfil" className="w-full h-full object-cover" />
                </div>
            </div>
        </div>

        {/* ÁREA DE CONTEÚDO */}
        <div className="flex-1 w-full max-w-full flex flex-col overflow-hidden p-4 md:p-6">
            {currentView === 'dashboard' && <DashboardOverview tasks={tasks} leads={leads} finance={transactions} users={users} />}
            {currentView === 'kanban' && (
              <KanbanBoard 
                tasks={tasks} 
                setTasks={setTasks} 
                users={users} 
                currentUser={currentUser} 
                columns={taskColumns} 
                setColumns={setTaskColumns} 
                openConfirm={openConfirm} 
                notifications={notifications} 
                setNotifications={setNotifications}
                sidebarOpen={sidebarOpen}
                sidebarCompact={sidebarCompact}
                isMobile={isMobile}
              />
            )}
            {currentView === 'crm' && <CRM leads={leads} setLeads={setLeads} columns={crmColumns} setColumns={setCrmColumns} openConfirm={openConfirm} leadSources={leadSources} setLeadSources={setLeadSources} currentUser={currentUser} />}
            {currentView === 'requisitions' && <Requisitions requisitions={requisitions} setRequisitions={setRequisitions} currentUser={currentUser} users={users} setNotifications={setNotifications} setTransactions={setTransactions} />}
            {currentView === 'finance' && <Financials transactions={transactions} setTransactions={setTransactions} assets={assets} setAssets={setAssets} currentUser={currentUser} users={users} openConfirm={openConfirm} />}
            {currentView === 'client-portal' && <ClientPortal tasks={tasks} setTasks={setTasks} currentUser={currentUser} users={users} clients={clients} squads={initialSquads} setNotifications={setNotifications} setRequisitions={setRequisitions} onNavigate={setCurrentView} />}
            {currentView === 'productivity' && <ProductivityDashboard tasks={tasks} setTasks={setTasks} users={users} squads={initialSquads} clients={clients} currentUser={currentUser} setNotifications={setNotifications} />}
            {currentView === 'teams' && <TeamManagement users={users} setUsers={setUsers} squads={squads} setSquads={setSquads} openConfirm={openConfirm} />}
            {currentView === 'permissions' && <PermissionsManager permissions={rolePermissions} setPermissions={setRolePermissions} openConfirm={openConfirm} />}
            {currentView === 'clients' && <ClientManagement clients={clients} setClients={setClients} squads={initialSquads} services={services} users={users} setUsers={setUsers} openConfirm={openConfirm} />}
            {currentView === 'catalog' && <ServiceCatalog services={services} setServices={setServices} openConfirm={openConfirm} />}
            {currentView === 'system-admin' && <SystemAdmin settings={systemSettings} onUpdateSettings={setSystemSettings} />}
            {currentView === 'help' && <HelpCenter currentUser={currentUser} />}
            {currentView === 'settings' && <ProfileSettings currentUser={currentUser} onUpdateUser={(u) => { setUsers(users.map(us => us.id === u.id ? u : us)); setCurrentUser(u); }} />}
        </div>
      </main>

      {confirmOptions && <ConfirmDialog options={confirmOptions} onConfirm={() => handleConfirmAction(true)} onCancel={() => handleConfirmAction(false)} />}
    </div>
  );
};

export default App;
